INSERT INTO `director` (`id`, `biography`, `birth_date`, `created_at`, `death_date`, `imdb_id`, `name`, `nationality`, `photo_url`, `slug`, `tmdb_id`, `updated_at`) VALUES
	(1, 'Guillermo del Toro Gómez (Spanish: [ɡiˈʝeɾmo ðelˈtoɾo]; born 9 October 1964) is a Mexican filmmaker, author, and artist. His work has been characterized by a strong connection to fairy tales, gothicism, and horror, often blending the genres to infuse visual or poetic beauty into the grotesque. He has had a lifelong fascination with monsters, which he considers symbols of great power. He is known for pioneering dark fantasy in the film industry and using insectile and religious imagery, his themes of Catholicism, and celebrating imperfection, underworld motifs, practical special effects, and dominant amber lighting.\n\nThroughout his career, del Toro has shifted between Spanish-language films—such as Cronos (1993), The Devil\'s Backbone (2001), and Pan\'s Labyrinth (2006)—and English-language films, including Mimic (1997), Blade II (2002), Hellboy (2004) and its sequel Hellboy II: The Golden Army(2008), Pacific Rim (2013), Crimson Peak (2015), The Shape of Water (2017), Nightmare Alley (2021), and Pinocchio (2022).\n\nAs a producer or writer, he worked on the films The Orphanage (2007), Don\'t Be Afraid of the Dark (2010), The Hobbit film series (2012–2014), Mama (2013), The Book of Life (2014), Pacific Rim: Uprising (2018), Scary Stories to Tell in the Dark (2019), and The Witches (2020). In 2022, he created the Netflix anthology horror series Guillermo del Toro\'s Cabinet of Curiosities, featuring a collection of classical horror stories.\n\nWith Chuck Hogan, he co-authored The Strain trilogy of novels (2009–2011), which was later adapted into a comic book series (2011–15) and a live-action television series (2014–17). With DreamWorks Animation and Netflix, he created the animated franchise Tales of Arcadia, which includes the series Trollhunters (2016–18), 3Below (2018–19), and Wizards (2020) and the sequel film Trollhunters: Rise of the Titans (2021).\n\nDel Toro is close friends with fellow Mexican filmmakers Alfonso Cuarón and Alejandro G. Iñárritu, collectively known as "The Three Amigos of Mexican Cinema". He has received several awards, including three Academy Awards, three BAFTA Awards, two Golden Globe Awards, a Daytime Emmy Award, and a Golden Lion. He was included in Time magazine\'s list of the 100 most influential people in the world in 2018, and he received a motion picture star on the Hollywood Walk of Fame in 2019.', '1964-10-09', '2025-11-15 19:12:42.397704', NULL, 'nm0868219', 'Guillermo del Toro', 'Mexico', 'https://image.tmdb.org/t/p/w300/wpnPWMRasECq6DxtZjSVTZNeGja.jpg', 'guillermo-del-toro', 10828, '2025-11-15 20:21:19.830841'),
	(2, 'From Wikipedia, the free encyclopedia.\n\nLuke Greenfield (born February 5, 1972) is an American film director. Greenfield was born in Manhasset, New York and was raised in Westport, Connecticut. He is best known for directing The Animal and The Girl Next Door. In July 2007, he appeared as a guest judge on the filmmaking reality show On the Lot. Greenfield directed the critically acclaimed television pilot, Aliens in America, and produced the film, Role Models.\n\nDescription above from the Wikipedia article Luke Greenfield, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1972-02-05', '2025-11-15 19:12:42.599947', NULL, 'nm0339004', 'Luke Greenfield', 'USA', 'https://image.tmdb.org/t/p/w300/7SnVznKqIugfbHY6arxW7hIzvTE.jpg', 'luke-greenfield', 65734, '2025-11-15 20:21:20.281912'),
	(3, 'Dan Trachtenberg (born May 11, 1981) is an American filmmaker and podcast host.\n\nHe is best known for directing the films 10 Cloverfield Lane (2016) and Prey (2022), the former earning him a Directors Guild of America Award nomination for Outstanding Directing – First-Time Feature Film. For television, he directed the pilot episodes of The Boys (2019) and The Lost Symbol (2021), the latter of which he also served as an executive producer. \n\nTrachtenberg was one of three hosts of The Totally Rad Show podcast and a former co-host of the Geekdrome podcast. He also directed episodes for the Ctrl+Alt+Chicken podcast, all hosted at Revision3. He directed the 2011 short film Portal: No Escape, an episode of Black Mirror entitled "Playtest," and various television commercials and public service announcements.\n\nDescription above from the Wikipedia article Dan Trachtenberg, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1981-05-11', '2025-11-15 19:12:42.756646', NULL, 'nm0870469', 'Dan Trachtenberg', 'USA', 'https://image.tmdb.org/t/p/w300/ylZvSmwIOq2rAjHIaxKpw0HGGU1.jpg', 'dan-trachtenberg', 568322, '2025-11-15 20:21:20.698844'),
	(4, 'Director de cine y guionista estadounidense nacido en Studio City, California. Uno de los autores más influyentes y complejos del cine actual. Responsable también de los guiones de sus películas, ha creado ya una obra muy cohesionada pero en la que es apreciable, asimismo, una sugerente evolución. Si antes de cumplir los treinta años, Anderson era ya autor de dos obras capitales, Boogie Nights (1997) y Magnolia (1999), después de su también magnífica ópera prima, Sydney (1996), y tras el deslumbrante experimento que constituyó Embriagado de amor (2002), con Pozos de ambición (2007) ofreció una nueva obra maestra que, además, supone un trascendental paso en su trayectoria. Todas ellas son películas situadas en un difuso espacio entre la gloriosa tradición cinematográfica de su país y las corrientes más rigurosas e inventivas del cine contemporáneo, pero ante todo insobornablemente personales, ofreciendo con las mismas un complejo retrato de los EEUU que, como ocurre con los grandes autores, posee resonancias universales. Su siguiente trabajo fue, The Master (2012), un film inspirado en Ron L. Hubbard, el fundador de la Cienciología y protagonizado por Joaquin Phoenix y Philip Seymour Hoffman.', '1970-06-26', '2025-11-15 19:12:42.916746', NULL, 'nm0000759', 'Paul Thomas Anderson', 'USA', 'https://image.tmdb.org/t/p/w300/wKAs2LtLYSUzt3ZZ8pnxMwuEWuR.jpg', 'paul-thomas-anderson', 4762, '2025-11-15 20:21:20.996881'),
	(5, 'Christopher Leone is a Los Angeles–based filmmaker with a background in visual effects and CG animation. Wikipedia', '1971-10-13', '2025-11-15 19:12:43.175967', NULL, 'nm0002814', 'Christopher Leone', NULL, 'https://image.tmdb.org/t/p/w300/oakPUhNVGhbR2VZP8lR657XI8Zh.jpg', 'christopher-leone', 1234970, '2025-11-15 20:21:22.209642'),
	(6, 'Scott Derrickson (born July 16, 1966) is an American filmmaker. He is known for his work in the horror genre, directing films such as The Exorcism of Emily Rose (2005), Sinister (2012), and The Black Phone (2021). He is also known for the superhero film Doctor Strange (2016) based on the Marvel Comics character.\n\nDescription above from the Wikipedia article Scott Derrickson, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1966-07-16', '2025-11-15 19:12:43.334098', NULL, 'nm0220600', 'Scott Derrickson', 'USA', 'https://image.tmdb.org/t/p/w300/caapCMfXLifC7XveUiY653xWBsZ.jpg', 'scott-derrickson', 55499, '2025-11-15 20:21:21.337227'),
	(7, 'Richard "Rich" T. Lee is an American music video and commercial director. He has directed  one of the worst films, possibly ever made, called "War of the Worlds".', NULL, '2025-11-15 19:12:43.491141', NULL, 'nm1184240', 'Rich Lee', 'USA', 'https://image.tmdb.org/t/p/w300/r7WIjhtHWcnRJO3nlao6jwsrWG6.jpg', 'rich-lee', 1634181, '2025-12-21 17:47:22.718961'),
	(8, 'Nonzee Nimibutr is a Thai film director, film producer and screenwriter. Best known for his ghost thriller, Nang Nak, he is generally credited as the leader among a "New Wave" of Thai filmmakers that also includes Pen-Ek Ratanaruang, Wisit Sasanatieng and Apichatpong Weerasethakul.', '1962-12-18', '2025-11-15 19:12:43.639369', NULL, 'nm0632354', 'Nonzee Nimibutr', 'Thailand', 'https://image.tmdb.org/t/p/w300/5WFeCdlunAZkjGn7rAwrVIpRlze.jpg', 'nonzee-nimibutr', 31039, '2025-11-15 20:21:22.539967'),
	(9, NULL, NULL, '2025-11-15 19:12:43.797075', NULL, 'nm0441099', 'Hiroshi Katagiri', NULL, NULL, 'hiroshi-katagiri', 1745813, '2025-11-15 20:21:23.533922'),
	(10, 'Juan Carlos Medina is a film director and screenwriter known for his work in the horror and thriller genres. He directed Painless (2012), a horror film set during the Spanish Civil War, and The Limehouse Golem (2016), a Victorian-era thriller based on Peter Ackroyd\'s novel. Medina\'s films are noted for their atmospheric tension and intricate storytelling.', '1977-01-01', '2025-11-15 19:12:43.944789', NULL, 'nm0575726', 'Juan Carlos Medina', 'USA', NULL, 'juan-carlos-medina', 1077998, '2025-11-15 20:21:23.102302'),
	(11, 'Haruo Sotozaki is a Japanese anime and film director best known for his work on the Demon Slayer: Kimetsu no Yaiba series. He began his career in the animation industry in the mid-1990s, contributing as a key animator and storyboard artist on various projects. Sotozaki made his full directorial debut with the anime adaptation of Ninja Nonsense (2004). In 2019, he directed the critically acclaimed Demon Slayer: Kimetsu no Yaiba television series, followed by the record-breaking film Demon Slayer: Kimetsu no Yaiba – The Movie: Mugen Train (2020). His direction is noted for its dynamic action sequences and faithful adaptation of source material.', NULL, '2025-11-15 19:12:44.169822', NULL, 'nm1417038', 'Haruo Sotozaki', 'Japan', 'https://image.tmdb.org/t/p/w300/ylaWAuJB1PyAzaefqENBDEAKTLI.jpg', 'haruo-sotozaki', 1283010, '2025-11-15 20:21:23.923639'),
	(12, NULL, NULL, '2025-11-15 19:12:44.403113', NULL, 'nm8915138', 'Aditya Suhas Jambhale', NULL, NULL, 'aditya-suhas-jambhale', 3096978, '2025-11-15 20:21:26.317446'),
	(13, 'Tatsuya Yoshihara (吉原 達矢, Yoshihara Tatsuya) is a freelance animator born on December 9, 1988. He was formerly affiliated with Actas where he was attending its internal animation school and debuted as an animator at the age of 20. His work has been greatly influenced by contemporary Kanada school animators Seiya Numata and Hironori Tanaka. He made his debut as director in 2013 with Arve Rezzle as part of the Young Animator Training Project. He is married to fellow animator Kikuko Sadakata.', '1988-12-09', '2025-11-15 19:12:44.572385', NULL, 'nm4181283', 'Tatsuya Yoshihara', NULL, 'https://image.tmdb.org/t/p/w300/1OwKJz7rF39BatzfNIlClmVYL1P.jpg', 'tatsuya-yoshihara', 1286723, '2026-02-09 17:26:16.875593'),
	(14, 'Rob Cohen is an American film director, writer and producer, best known as the creator of Universal Pictures\' The Fast and the Furious movie franchise. He\'s a graduate in Anthropology and Visual Studies from Harvard University, Cambridge, Massachusetts, USA.', '1949-03-12', '2025-11-15 19:12:44.832069', NULL, 'nm0003418', 'Rob Cohen', 'USA', 'https://image.tmdb.org/t/p/w300/kVbB8Q0g8eXsn8l81flyC6TgMPW.jpg', 'rob-cohen', 18878, '2025-11-15 20:21:25.332326'),
	(15, NULL, NULL, '2025-11-15 19:12:44.985971', NULL, NULL, 'Lars Janssen', NULL, NULL, 'lars-janssen', 2236720, '2025-11-15 19:12:44.985971'),
	(16, 'J.J. Perry (born October 25, 1967) is a stunt performer, martial artist, film director, film producer, stunt coordinator and film actor who has made several uncredited appearances on 24.', '1967-10-25', '2025-11-15 19:12:45.241440', NULL, 'nm0675102', 'J.J. Perry', NULL, 'https://image.tmdb.org/t/p/w300/57assDPZceZ4x7YWrkPE5FqVn1f.jpg', 'j-j-perry', 131532, '2025-11-15 20:21:29.723223'),
	(17, 'Kourtney Roy’s studies in photography, at Emily Carr University of Art and Design in Vancouver and later at the Ecole Nationale Supérieure des Beaux-Arts in Paris, inspired her to develop her finicky aesthetic, which lends itself particularly well to both glossy paper and film. Roy works extensively as an independent photographer/filmmaker in the art world, as well as the advertising world of print and video.', NULL, '2025-11-15 19:12:45.383681', NULL, NULL, 'Kourtney Roy', NULL, NULL, 'kourtney-roy', 4476869, '2025-11-15 20:21:28.306312'),
	(18, 'Matt Shakman is an American director and former child actor. He directed The Fantastic Four: First Steps, WandaVision and has directed episodes of The Great, It\'s Always Sunny in Philadelphia, Fargo, and Game of Thrones. He was the artistic director of the Geffen Playhouse in Los Angeles, California, from 2017 to 2023.', '1975-08-08', '2025-11-15 19:12:45.537924', NULL, 'nm0787687', 'Matt Shakman', 'USA', 'https://image.tmdb.org/t/p/w300/kraLXlC9egJh4pTNTpKUYhkkNiu.jpg', 'matt-shakman', 1212522, '2025-11-15 20:21:28.668187'),
	(19, NULL, NULL, '2025-11-15 19:12:45.687809', NULL, 'nm3358621', 'Derek Barnes', NULL, 'https://image.tmdb.org/t/p/w300/ib6BOTSTCU8OXpy4wFUHJcY8Lmw.jpg', 'derek-barnes', 1854794, '2025-11-15 20:21:31.135817'),
	(20, 'Chris Appelhans (born April 28, 1980) is an American illustrator, production designer, and director known for writing/directing Sony Pictures Animation\'s Wish Dragon (2021) and co-directing KPop Demon Hunters (2025). He started as a concept artist for films like Monster House, The Princess and the Frog, and Coraline, earning an Annie Award nomination for Coraline, and has illustrated children\'s books like A Greyhound, a Groundhog. He studied at Art Center College of Design and resides in Los Angeles with his wife, author Maurene Goo. Their son was born in 2020.', '1980-04-28', '2025-11-15 19:12:45.867867', NULL, 'nm2282774', 'Chris Appelhans', 'USA', 'https://image.tmdb.org/t/p/w300/33jtvCKnmBTb1pPMTobUMca7BkS.jpg', 'chris-appelhans', 1453550, '2026-02-09 17:18:20.331433'),
	(21, NULL, NULL, '2025-11-15 19:25:00.931265', NULL, NULL, 'Peter McLeod', NULL, NULL, 'peter-mcleod', 2421169, '2025-11-15 19:25:00.931265'),
	(22, 'Stanley Tong Gwai-Lai (Chinese: 唐季禮, born April 7, 1960 in Hong Kong) is a film director from Hong Kong.\n\nAccording to IMDb, he customarily attempts stunts himself before asking actors to risk themselves. For example, Jackie Chan\'s leap from a parking garage roof to a fire escape in Rumble in the Bronx and the finale of Stone Age Warriors.\n\nDescription above from the Wikipedia article Stanley Tong, licensed under CC-BY-SA, full list of contributors on Wikipedia', '1960-04-07', '2025-11-15 19:25:01.854946', NULL, 'nm0867262', '唐季禮', 'China', 'https://image.tmdb.org/t/p/w300/cunufPnRrZuYwvz8M11c3cr6GVf.jpg', 'director-44916', 44916, '2025-11-15 20:21:25.687827'),
	(23, 'Ruben Samuel Fleischer (/ˈflaɪʃər/; born October 31, 1974) is an American film director, film producer, television producer, music video director, and commercial director who lives in Montclair, New Jersey. He is best known as the director of Zombieland (2009), his first feature film, and its sequel, Zombieland: Double Tap(2019). He has also directed the films 30 Minutes or Less, Gangster Squad, Uncharted, and 2018\'s Venom, which features the same Marvel Comics character. Before the features, he directed television commercials for brands like Cisco, Eurostar, ESPN, and Burger King and music videos for artists such as M.I.A., Electric Six, DJ Format and Gold Chains.\n\nFleischer was born and raised in Washington, D.C, the son of Karen Lee (née Samuel) and David Elliot Fleischer, a physician at the Mayo Clinic in Arizona and a professor of medicine. His brother, Lucas, works in new media. His father was born to a Jewish family, while his mother converted to Judaism. Fleischer was raised in Reform Judaism.\n\nAfter graduating with a history major from Wesleyan University, Fleischer moved to San Francisco, where he worked as a freelance HTML programmer, unsure what he wanted to do with his life.\n\nTaking the advice of close friend Mike White (also a Wesleyan graduate), Fleischer worked as a PA in the writers\' office of Dawson\'s Creek. He eventually turned to directing and worked his way through the industry, tackling music videos and television commercials before landing his first feature film, Zombieland, in 2009. His second feature, 30 Minutes or Less, opened in theaters on August 12, 2011.\n\nFleischer directed Gangster Squad, a 2013 action thriller film based on the special tactical group created by the LAPD to combat the Los Angeles crime family. He next directed Venom, a film about the Marvel Comics character Eddie Brock, starring Tom Hardy; it was released on October 5, 2018.\n\nIn 2019, he directed Zombieland: Double Tap, reuniting the four original leads. In February 2020, he was hired to direct Uncharted, based on the video game series of the same name. In September 2022, he was hired to direct Now You See Me 3.\n\nDescription above from the Wikipedia article Ruben Fleischer, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1974-10-31', '2025-11-15 19:25:02.918967', NULL, 'nm0281508', 'Ruben Fleischer', 'USA', 'https://image.tmdb.org/t/p/w300/3JLxOPFTLigSy8FjFjDyMwD9GIp.jpg', 'ruben-fleischer', 91268, '2025-11-15 20:21:27.458581'),
	(24, 'Derek M. Cianfrance (/ˈsiːənfræns/; born January 23, 1974) is an American film director, cinematographer, screenwriter, and editor. He is best known for writing and directing the films Blue Valentine, The Place Beyond the Pines, and The Light Between Oceans, as well as the HBO miniseries I Know This Much Is True. For his contributions to the story of Sound of Metal, he received a nomination for the Academy Award for Best Original Screenplay with its director Darius Marder, and Abraham Marder.\n\nDescription above from the Wikipedia article Derek Cianfrance, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1974-01-23', '2025-11-15 19:25:03.635036', NULL, 'nm0161834', 'Derek Cianfrance', 'USA', 'https://image.tmdb.org/t/p/w300/6y6RU9AJst5f5TxdeycWCVNyCEt.jpg', 'derek-cianfrance', 139098, '2025-11-15 20:21:27.880764'),
	(25, 'Fansu Njie is a celebrated Swedish film director and a leading voice in the action genre, with West-African Gambian roots.', NULL, '2025-11-15 19:25:04.101549', NULL, NULL, 'Fansu Njie', NULL, 'https://image.tmdb.org/t/p/w300/bNvUgUW5g4nVOvBWFtYZKXTM7xj.jpg', 'fansu-njie', 3076703, '2025-11-15 20:21:29.208987'),
	(26, 'Poj Arnon (Thai: พจน์ อานนท์) is a Thai film director. He is best known for his 2007 film Bangkok Love Story, that won him the Grand Prize (International Competition) at the Brussels International Independent Film Festival.', '1971-01-10', '2025-11-15 19:25:04.930518', NULL, 'nm1547925', 'พชร์ อานนท์', 'Thailand', 'https://image.tmdb.org/t/p/w300/bETWd45bkio5LDAewuVDTBB1S1u.jpg', 'director-111984', 111984, '2025-11-15 20:21:30.713394'),
	(27, NULL, '1980-01-01', '2025-11-15 19:25:05.525255', NULL, 'nm2305673', 'Waldemar Fast', 'Soviet Union', NULL, 'waldemar-fast', 4826007, '2025-11-15 20:21:31.729553'),
	(28, 'James Wan (born 26 February 1977) is an Australian filmmaker. He has primarily worked in the horror genre as the co-creator of the Saw and Insidious franchises and the creator of The Conjuring Universe. The lattermost is the highest-grossing horror franchise at over $2 billion. Wan is also the founder of the film and television production company Atomic Monster.\n\nBeginning his career with the Saw franchise, Wan made his feature directorial debut with his first film in 2004. The franchise became commercially successful and grossed more than $1 billion globally. Following a period of setbacks, Wan found new success with the Insidious series, in which he directed the first film in 2010 and its 2013 sequel. The same year as the second Insidious, Wan directed the first Conjuring film to critical and commercial success. He served as the director of the second installment in 2016 and produced subsequent films in the franchise.\n\nOutside of horror, Wan directed Furious 7 (2015), the seventh installment of the Fast & Furious franchise, and the DC Extended Universe superhero films Aquaman (2018) and its sequel Aquaman and the Lost Kingdom (2023). Both Furious 7 and Aquaman grossed over $1 billion, making Wan the eighth director with two films to reach the milestone. He is the 16th highest-grossing director of all time as of 2021, with his films having grossed over $3.7 billion worldwide.\n\nDescription above from the Wikipedia article James Wan, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1977-02-26', '2025-11-15 19:25:05.673629', NULL, 'nm1490123', 'James Wan', 'Malaysia', 'https://image.tmdb.org/t/p/w300/bNJccMIKzCtYnndcOKniSKCzo5Y.jpg', 'james-wan', 2127, '2025-11-15 20:21:32.039138'),
	(29, 'A. P. Arjun is an Indian film director, screenwriter and lyricist. He works in Kannada cinema. Making his entry as a lyricist for the film Thangigagi (2006), Arjun debuted as a director with the 2009 film Ambari. His second directorial Addhuri (2012) and won him multiple awards.', '1984-08-08', '2025-11-15 19:25:06.044839', NULL, 'nm5736440', 'A. P. Arjun', 'India', 'https://image.tmdb.org/t/p/w300/kXyQixLsDJlLm98rE2jTiYeplKI.jpg', 'a-p-arjun', 2052928, '2025-11-15 20:21:32.509302'),
	(30, NULL, '1962-01-01', '2025-11-15 19:25:06.295695', NULL, 'nm0448757', 'James Kent', 'UK', 'https://image.tmdb.org/t/p/w300/wVriFTqzZDHDgFaricNulLg13a4.jpg', 'james-kent', 211659, '2025-11-15 20:21:32.947676'),
	(31, 'Michael Chaves (born November 3, 1984) is an American filmmaker and visual effects artist. He is best known for directing the horror films The Curse of La Llorona (2019), The Conjuring: The Devil Made Me Do It (2021), The Nun II (2023) and The Conjuring: Last Rites (2025).\n\nDescription above from the Wikipedia article Michael Chaves, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1984-11-03', '2025-11-15 19:25:06.449929', NULL, 'nm1980431', 'Michael Chaves', 'U.S', 'https://image.tmdb.org/t/p/w300/kdY5UWdsLQvlBBkzuiR8upujNtn.jpg', 'michael-chaves', 1607672, '2025-11-15 20:21:33.402248'),
	(32, 'Kazimierz Kutz was born February 16, 1929, in Szopienice, since 1960 district of Katowice, to a railway worker and a former partisan of the Silesian Uprisings. After the World War II Kutz graduated from gymnasium in Mysłowice and in 1949 was admitted to the Łódź Film School. After finishing his studies in 1954 he started working as an assistant to Andrzej Wajda.\n\nHis film debut was Cross of Valor (1959). Since then he finished more than 20 pictures, including six about his home region - Silesia. He is also famous for directing theatre plays on some of the most prominent scenes of Poland, including the Teatr Stary in Kraków and National Theatre in Warsaw, as well as several plays for the Polish television. In 1972, he founded the Silesia Film Company in Katowice and, until 1978, was its Artistic Director.\n\nIn the 1970s he became the main director of the Polish Television branch in Katowice. He was also working for several branch and cultural organisations. After the Martial Law had been imposed in Poland in 1981 Kutz was interned by the communist authorities, but was released soon afterwards. Between 1981 and 1983, lectured in the Radio and Television Faculty at Silesian University in Katowice, and, between 1985 and 1991, taught directing at the Higher Theatre School in Kraków. Since 1987, was Principal Director in the Polish Television Centre in Katowice and, between 1990 and 1991, headed the Centre. After the peaceful transition to democracy in 1989 Kutz became the head of the Polish TV branch in Kraków (until 1991).\n\nFor his involvement in the matters of Silesia, and for his films depicting the traditions and problems of that part of Poland, he is considered by some the spokesman of all Silesians. In a plebiscite organised by Gazeta Wyborcza newspaper he was chosen the third most famous Silesian ever and the first among the living people. In 1997 he was awarded with the title of doctor honoris causa by the University of Opole. He is currently a promotor and patron of several Silesia-based cultural feasts and societies, including the Festiwal Filmów Kultowych, Festiwal Sztuki Reżyserskiej, Cultural Congress of the Upper Silesia, Council of Culture of the Silesian Voivodship, Academy of Fine Arts in Katowice and Committee for the Construction of Silesian Museum. He is also one of the supporters of development of the Silesian language.\n\nHis 1995 film Reverted was entered into the 19th Moscow International Film Festival.\n\nIn 1997 Kutz took part in the elections to the Senate of Poland (from the list of Freedom Union party, Katowice constituency) and was supported by approximately 500,000 Silesians. In 2001 he was elected for his second term as a non-partisan candidate, and in 2005 re-elected for the third term. Currently he is the deputy speaker of the Senate of Poland. For his social involvements, he was awarded with many of the highest Polish awards.\n\nKazimierz Kutz is married to Iwona and has two sons (Gabriel and Tymek) and two daughters (Wiktoria and Kamila).\n\nFrom Wikipedia, the free encyclopedia', '1929-02-16', '2025-11-15 19:25:06.820028', '2018-12-18', 'nm0476591', 'Kazimierz Kutz', 'Polska', 'https://image.tmdb.org/t/p/w300/3BSD70THTCIbN5dpFdlohn57UFP.jpg', 'kazimierz-kutz', 591241, '2025-11-15 20:21:33.927752'),
	(33, 'Valerie Buhagiar (born May 12, 1964) is a Maltese-Canadian actress, film director and television host.\n\nDescription above from the Wikipedia article Valerie Buhagiar, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1963-05-12', '2025-11-15 19:25:07.073224', NULL, 'nm0119541', 'Valerie Buhagiar', 'Malta', 'https://image.tmdb.org/t/p/w300/sbYDziH3yhiFfzqIL7RSgr8QUEd.jpg', 'valerie-buhagiar', 55188, '2025-11-15 20:21:34.294070'),
	(34, 'Macon Blair (born 1974) is an American film director, producer, screenwriter, comic book writer and actor known for his roles in the films Blue Ruin (2013) and Green Room (2015), as well as his directorial debut I Don\'t Feel at Home in This World Anymore (2017).\n\nDescription above from the Wikipedia article Macon Blair, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1974-11-14', '2025-11-15 19:25:07.345656', NULL, 'nm0086301', 'Macon Blair', 'USA', 'https://image.tmdb.org/t/p/w300/sNhgAh7TBBYNGR2ExnINXIQ4U5x.jpg', 'macon-blair', 209513, '2025-11-15 20:21:34.774784'),
	(35, 'Edgar Howard Wright (born 18 April 1974) is an English filmmaker. He is known for his fast-paced and kinetic, satirical genre films, which feature extensive utilisation of expressive popular music, Steadicam tracking shots, dolly zooms and a signature editing style that includes transitions, whip pans and wipes. He first made independent short films before making his first feature film, A Fistful of Fingers, in 1995. Wright created and directed the comedy series Asylum in 1996, written with David Walliams. After directing several other television shows, Wright directed the sitcom Spaced (1999–2001), which aired for two series and starred frequent collaborators Simon Pegg and Nick Frost.\n\nIn 2004, Wright directed the zombie comedy Shaun of the Dead, starring Pegg and Frost, the first film in Wright\'s Three Flavours Cornetto trilogy. The film was co-written with Pegg—as were the next two entries in the trilogy, the buddy cop film Hot Fuzz (2007) and the science fiction comedy The World\'s End (2013). In 2010, Wright co-wrote and directed the action comedy film Scott Pilgrim vs. the World, an adaptation of the graphic novel series. Along with Joe Cornish and Steven Moffat, he adapted The Adventures of Tintin (2011) for Steven Spielberg. Wright and Cornish co-wrote the screenplay for the Marvel Cinematic Universe film Ant-Man in 2015, which Wright intended to direct but abandoned, citing creative differences. He has also written and directed the action film Baby Driver (2017), the documentary The Sparks Brothers, and the psychological horror film Last Night in Soho (both 2021).\n\nDescription above from the Wikipedia article Edgar Wright, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1974-04-18', '2025-11-15 19:25:07.502670', NULL, 'nm0942367', 'Edgar Wright', 'UK', 'https://image.tmdb.org/t/p/w300/dQzv5Ml2SkelS33hgl7E2oh0a9S.jpg', 'edgar-wright', 11090, '2025-11-15 20:21:35.104972'),
	(36, 'Jared Bush (born June 12, 1974) is an American screenwriter, producer, and director who has served as the chief creative officer of Walt Disney Animation Studios since 2024. He is best known for co-writing and co-directing the Walt Disney Animation Studios film Zootopia (2016) and its upcoming sequel Zootopia 2 (2025), writing the movie Moana (2016), its sequel Moana 2 (2024) and the 2026 upcoming live-action remake, and writing, directing, and winning an Academy Award for Best Animated Feature for the film Encanto(2021), besides co-creating and executive producing the Disney XD animated series Penn Zero: Part-Time Hero. Bush is a graduate of Harvard University.\n\nDescription above from the Wikipedia article Jared Bush, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1974-06-12', '2025-11-15 19:25:07.757930', NULL, 'nm1158544', 'Jared Bush', 'USA', 'https://image.tmdb.org/t/p/w300/2gIwj1cnqZIKWaFg0ihmZnuZypR.jpg', 'jared-bush', 1318201, '2025-11-15 20:21:35.427950'),
	(37, NULL, NULL, '2025-11-15 19:25:08.267442', NULL, 'nm2940110', 'Cyprian T. Olencki', NULL, NULL, 'cyprian-t-olencki', 1731424, '2025-11-15 20:21:36.018367'),
	(38, NULL, '1992-10-07', '2025-11-15 19:25:08.593295', NULL, 'nm14292204', 'Shota Goshozono', 'Japan', NULL, 'director-2784807', 2784807, '2026-02-09 17:26:09.595396'),
	(39, 'Christopher McQuarrie (born October 25, 1968) is an American screenwriter, film director, and producer. He received the BAFTA Award, Independent Spirit Award, and Academy Award for Best Original Screenplay for the neo-noir mystery film The Usual Suspects (1995). He made his directorial debut with the crime thriller film The Way of the Gun (2000). \n\nMcQuarrie is a frequent collaborator with Tom Cruise, having written and directed the action films Jack Reacher (2012), as well as four instalments of the Mission: Impossible film series: Rogue Nation (2015), Fallout (2018), Dead Reckoning (2023), and The Final Reckoning (2025). He was also a part of the writing and/or producing team on the Cruise films Valkyrie (2008), Edge of Tomorrow (2014), Jack Reacher: Never Go Back (2016), The Mummy (2017), and Top Gun: Maverick (2022), the last of which received Academy Award nominations for Best Adapted Screenplay and Best Picture.\n\nDescription above from the Wikipedia article about Christopher McQuarrie, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1968-10-25', '2025-11-15 19:25:08.772653', NULL, 'nm0003160', 'Christopher McQuarrie', 'USA', 'https://image.tmdb.org/t/p/w300/xVbQBRpqzKkllUAvjJbgnAmTwaZ.jpg', 'christopher-mcquarrie', 9033, '2025-11-15 20:21:36.740490'),
	(40, NULL, NULL, '2025-11-15 19:25:09.072459', NULL, 'nm2718960', 'Seabold Krebs', NULL, NULL, 'seabold-krebs', 3988430, '2025-11-15 20:21:37.303092'),
	(41, NULL, NULL, '2025-11-15 19:27:23.784790', NULL, NULL, 'Thom Arizmendi', NULL, NULL, 'thom-arizmendi', 4669838, '2025-11-15 19:27:23.784790'),
	(42, 'Santiago Segura Silva (Madrid, 17 de julio de 1965) es un actor, guionista, director y productor de cine español, popular por su pentalogía de Torrente. Ha trabajado también, y en menor medida, como presentador de televisión, actor de doblaje y guionista de historietas, siendo además coleccionista de cómics originales.', '1965-07-17', '2025-11-15 19:27:24.207427', NULL, 'nm0782213', 'Santiago Segura', 'Espagne', 'https://image.tmdb.org/t/p/w300/w5gSHzLWoivAN2g4z2yaxCSFyTY.jpg', 'santiago-segura', 10847, '2025-11-15 20:21:38.191470'),
	(43, 'Emilie Kristine Blichfeldt is a Norwegian filmmaker and actress. She is best known for directing the body horror film The Ugly Stepsister (2025).', '1991-05-20', '2025-11-15 19:27:24.629033', NULL, 'nm5132581', 'Emilie Blichfeldt', NULL, 'https://image.tmdb.org/t/p/w300/7sMDeTqW5ZXztzhHi54c2FqSVbz.jpg', 'emilie-blichfeldt', 1480411, '2025-11-15 20:21:38.648063'),
	(44, NULL, NULL, '2025-11-15 19:27:26.224904', NULL, 'nm9685503', 'Alex Woo', NULL, 'https://image.tmdb.org/t/p/w300/rzC3BqnVuLPt4oDxDZziy72WHnA.jpg', 'alex-woo', 2504360, '2025-11-15 20:21:39.066414'),
	(45, NULL, '1975-09-26', '2025-11-15 19:27:27.394224', NULL, NULL, 'Lim Dae-hee', NULL, NULL, 'lim-dae-hee', 2964273, '2025-11-15 19:27:27.394224'),
	(46, 'Steve Carr is an American film director and producer of several movies, mostly of the comedy and family genre.', '1965-04-07', '2025-11-15 19:27:27.725973', NULL, 'nm0139867', 'Steve Carr', 'USA', 'https://image.tmdb.org/t/p/w300/zf3tcqGz6pijSCpvkLXCC33ncEJ.jpg', 'steve-carr', 52112, '2025-11-15 20:21:39.820365'),
	(47, NULL, NULL, '2025-11-15 19:27:29.297870', NULL, NULL, 'Choi Jong-gyoo', NULL, NULL, 'choi-jong-gyoo', 4483695, '2025-11-15 19:27:29.297870'),
	(48, 'John Campbell McTiernan Jr. (born January 8, 1951) is an American filmmaker. He is best known for his action films, especially Predator (1987), Die Hard (1988), and The Hunt for Red October (1990). His later well-known films include the action-comedy-fantasy film Last Action Hero (1993), the action film sequel Die Hard with a Vengeance (1995), the heist-film remake The Thomas Crown Affair (1999), and The 13th Warrior (1999). His last completed feature film was the mystery-thriller Basic, released in 2003.\n\nHe pleaded guilty to perjury and lying to an FBI investigator in regard to his hiring of the private investigator Anthony Pellicano in late 2000 to illegally wiretap the phone calls of two people, one of whom was Charles Roven, a co-producer of his dystopian science-fiction action film remake Rollerball (2002). He was incarcerated in federal prison from April 2013 to February 2014. During his imprisonment, he filed for bankruptcy amidst foreclosure proceedings for his large ranch residence.', '1951-01-08', '2025-11-15 19:27:29.493880', NULL, 'nm0001532', 'John McTiernan', 'USA', 'https://image.tmdb.org/t/p/w300/yVfDkVbgQHD1A7JSV8Z47EjB1mU.jpg', 'john-mctiernan', 1090, '2025-11-15 20:21:40.781250'),
	(49, 'James Gunn (5 de agosto de 1966) es un director, guionista y productor de cine estadounidense. Es conocido por ser el director, guionista y productor de grandes éxitos como Super (2010) y la adaptación cinematográfica del cómic de Marvel Guardianes de la Galaxia (2014) y su secuela Guardianes de la Galaxia Vol. 2 (2017). Como escritor ha trabajado en los guiones de Tromeo y Julieta (1996), Scooby-Doo (2002) y su secuela, Scooby-Doo 2: Monsters Unleashed (2004), y la versión Dawn of the Dead (2004). Es el hermano mayor del actor Sean Gunn.', '1966-08-05', '2025-11-15 19:27:29.777784', NULL, 'nm0348181', 'James Gunn', 'USA', 'https://image.tmdb.org/t/p/w300/pnKqZub3IlKYbyH9RRTMDOoqEn0.jpg', 'james-gunn', 15218, '2025-11-15 20:21:41.063367'),
	(50, NULL, NULL, '2025-11-15 19:27:30.092042', NULL, NULL, 'Elie El Semaan', 'Lebanon', 'https://image.tmdb.org/t/p/w300/dWK66OoCY0nTUecS1mR9L9faVnH.jpg', 'elie-el-semaan', 4669913, '2025-11-15 19:27:30.092042'),
	(51, 'Gareth James Edwards (born 13 July 1975) is a British film director and screenwriter. He gained recognition for Monsters (2010), an independent film in which he served as writer, director, cinematographer, and visual effects artist. He subsequently directed the big-budget adventure film Godzilla (2014) and the science fiction films Rogue One: A Star Wars Story (2016), The Creator (2023), and Jurassic World Rebirth (2025).\n\nDescription above from the Wikipedia article Gareth Edwards, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1975-06-01', '2025-11-15 19:27:30.418516', NULL, 'nm2284484', 'Gareth Edwards', 'UK', 'https://image.tmdb.org/t/p/w300/dyJwZCdIOBqq80sB8pE0yZErGv7.jpg', 'gareth-edwards', 129894, '2025-11-15 20:21:41.883375'),
	(52, NULL, NULL, '2025-11-15 19:27:30.856101', NULL, 'nm1543645', 'Luke Sparke', 'Australia', 'https://image.tmdb.org/t/p/w300/i3jtTar8GjNNmyyKzFPNofBNlAV.jpg', 'luke-sparke', 1670908, '2025-11-15 20:21:42.303899'),
	(53, 'Aziz Ismail Ansari (/ɑːnˈsɑːri/ ahn-SAR-ee; born February 23, 1983) is an American actor, comedian, and filmmaker. He played Tom Haverford on the NBC series Parks and Recreation (2009–2015) and created and starred in the Netflix series Master of None (2015–2021), for which he won several acting and writing awards, including two Emmys and a Golden Globe, which was the first award received by an Asian American actor for acting on television.\n\nAnsari began performing comedy in New York City while a student at NYU Stern in 2000. He later co-created and starred in the MTV sketch comedy show Human Giant, after which he had acting roles in a number of feature films. From 2009 to 2015, Ansari played Tom Haverford in the NBC sitcom Parks and Recreation. In 2015, Ansari co-created and starred in the first two seasons of Netflix\'s critically acclaimed series Master of None, for which he also served as a writer and director.\n\nAs a stand-up comedian, Ansari released his first comedy special, Intimate Moments for a Sensual Evening, in January 2010 on Comedy Central Records. He continues to perform stand-up on tour and on Netflix. His first book, Modern Romance: An Investigation, was released in June 2015. He was included in the Time 100 list of most influential people in 2016. In July 2019, Ansari released his fifth comedy special, Aziz Ansari: Right Now, which was nominated for a Grammy Award for Best Comedy Album. In 2021, Netflix released Master of None Presents: Moments in Love, which Ansari wrote and directed. The following year, he released his comedy special Aziz Ansari: Nightclub Comedian on Netflix.\n\nDescription above from the Wikipedia article Aziz Ansari, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1983-02-23', '2025-11-15 19:27:31.410347', NULL, 'nm2106637', 'Aziz Ansari', 'USA', 'https://image.tmdb.org/t/p/w300/yUeQHM4ycUXrUgRWgKVYKNmKxfJ.jpg', 'aziz-ansari', 86626, '2025-11-15 20:21:42.708161'),
	(54, NULL, NULL, '2025-11-15 19:27:31.732593', NULL, NULL, 'Haneef Adeni', NULL, 'https://image.tmdb.org/t/p/w300/jsuiJYAvw5pGnkK9hMNg0ddtPm7.jpg', 'haneef-adeni', 1717375, '2025-11-15 19:27:31.732593'),
	(55, NULL, NULL, '2025-11-15 19:27:33.177825', NULL, 'nm0328126', 'Domingo González', NULL, 'https://image.tmdb.org/t/p/w300/bTf1OPwNZSIbVHl7SII6Yv429G4.jpg', 'domingo-gonzalez', 1739102, '2025-11-15 20:21:43.578109'),
	(56, 'Jonathan Murray Chu (born November 2, 1979) is an American film director, producer, and screenwriter. He is known for directing the romantic comedy "Crazy Rich Asians" (2018) and the musical fantasy "Wicked" (2024), the former being one of the first films by a major Hollywood studio to feature a majority cast of Asian descent. For his direction for "Wicked," Chu won the National Board of Review Award for Best Director and Critics’ Choice Award for Best Director.\n\nAn alumnus of the USC School of Cinematic Arts, other films he has directed often include musical elements, including the dance films "Step Up 2: The Streets" (2008) and "Step Up 3D" (2010), the musicals "Jem and the Holograms" (2015) and "In the Heights" (2021), as well as the live concert films "Justin Bieber: Never Say Never" (2011) and "Justin Bieber\'s Believe" (2013).\n\nDescription above from the Wikipedia article Jon M. Chu, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1979-11-02', '2025-11-15 19:27:34.497797', NULL, 'nm0160840', 'Jon M. Chu', 'USA', 'https://image.tmdb.org/t/p/w300/85kOxm7w4nGRwyhquj9wtUM8KUW.jpg', 'jon-m-chu', 54507, '2025-11-15 20:21:43.977832'),
	(57, NULL, NULL, '2025-11-15 19:27:36.058799', NULL, NULL, 'Ram Narayan', NULL, NULL, 'ram-narayan', 5240969, '2025-11-15 19:27:36.058799'),
	(58, NULL, NULL, '2025-11-15 19:27:39.427240', NULL, 'nm2956989', 'Alejandro G. Alegre', NULL, NULL, 'alejandro-g-alegre', 1323007, '2025-11-15 20:21:45.125073'),
	(59, 'Larry Yang is a Director, Screenwriter,  Actor and Art Designer.  He was born as Zi Yang in Baoquanling, Heilongjiang, China.  His career started as an actor in a  short horror film "Dimension 13". Yang represents the new generation of bi-cultural talent in Chinese film, having honed his craft by earning Master\'s degrees in Film from both the Beijing Film Academy and the University of Edinburgh.', '1981-02-11', '2025-11-15 19:27:40.922495', NULL, 'nm6225858', '杨子', 'Китай', 'https://image.tmdb.org/t/p/w300/67ofxstctYR9sK2Vg1m6YStsafT.jpg', 'larry-yang', 1452270, '2026-01-10 21:41:27.944790'),
	(60, 'Realizador de cine, guionista y productor francés. Nació en París el 18 de abril de 1959, hijo de un matrimonio de monitores de submarinismo, y creció en Yugoslavia y Grecia. A raíz de un accidente de buceo se vio obligado a abandonar su idea de convertirse en biólogo marino y se dedicó al cine. Después de trabajar como ayudante de realización y dirigir cuatro cortometrajes, debutó como director con Kamikaze 1999 (1982), un impresionante drama visual apocalíptico que se desarrolla totalmente sin diálogos. Luego vino la película policiaca Subway (1985), con Christopher Lambert e Isabelle Adjani en los papeles principales. Su obra sobre el tema del submarinismo El gran azul (1988) se convirtió en una película de culto, pero fue rechazada mayoritariamente por la crítica. Nikita (1991, con Anne Parillaud), un largometraje sobre una joven criminal que recibe formación por parte de los servicios secretos para convertirse en una asesina, tuvo tal éxito en Estados Unidos, que John Badham rodó en 1993 una segunda versión con el título de La asesina (1993). El documental marino Atlantis (1991) causó gran impresión por la belleza de la fotografía. Besson trabaja preferentemente con el actor francés Jean Reno, que interpretó el papel principal en El profesional (1994). La costosa producción de ciencia ficción El quinto elemento (1997), con Bruce Willis y Milla Jovovich en los papeles estelares, fue un gran éxito de taquilla. En 1999 rodó Juana de Arco, una película de corte histórico que recrea la historia de la ‘Doncella de Orleans’.', '1959-03-18', '2025-11-15 19:27:41.502373', NULL, 'nm0000108', 'Luc Besson', 'France', 'https://image.tmdb.org/t/p/w300/dXJdczT1NcvcZtnoWVGT0NmG11v.jpg', 'luc-besson', 59, '2025-11-15 20:21:45.826154'),
	(61, NULL, NULL, '2025-11-15 19:27:42.687977', NULL, 'nm2717110', 'Hicham Hajji', NULL, 'https://image.tmdb.org/t/p/w300/pJuUDvgzqpbpp8UhUVL6U01s8GB.jpg', 'hicham-hajji', 1321390, '2025-11-15 20:21:46.330373'),
	(62, NULL, NULL, '2025-11-15 19:27:43.606751', NULL, NULL, 'Bernardo Hernández', NULL, 'https://image.tmdb.org/t/p/w300/2UFRLQGcaRmMYeZvkzkKFY4O4au.jpg', 'bernardo-hernandez', 3446970, '2025-11-15 19:27:43.606751'),
	(63, 'Joseph Kosinski (born May 3, 1974) is an American film director. He directed the films Tron: Legacy (2010), Oblivion (2013), Only the Brave (2017), Top Gun: Maverick (2022), Spiderhead (2022), and F1 (2025). His previous work in computer graphics and computer-generated imagery (CGI) primarily involved CGI-related television commercials, including the "Starry Night" commercial for Halo 3 and the award-winning "Mad World" commercial for Gears of War.', '1974-05-03', '2025-11-15 19:27:44.038684', NULL, 'nm2676052', 'Joseph Kosinski', 'USA', 'https://image.tmdb.org/t/p/w300/oWLUXWY0j8TYzwnf2wETYWO181S.jpg', 'joseph-kosinski', 86270, '2025-11-15 20:21:47.185648'),
	(64, 'Shane Black (born December 16, 1961) is an American filmmaker and actor who has written such films as Lethal Weapon, The Monster Squad, The Last Boy Scout, Last Action Hero, and The Long Kiss Goodnight. He is also known as the original creator of the Lethal Weapon franchise. As an actor, Black is best known for his role as Rick Hawkins in Predator (1987).\n\nHe made his directorial debut with the film Kiss Kiss Bang Bang in 2005. Black went on to write and direct Iron Man 3 (2013), The Nice Guys (2016), and The Predator (2018).\n\nDescription above from the Wikipedia article Shane Black, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1961-12-16', '2025-11-15 19:27:45.000204', NULL, 'nm0000948', 'Shane Black', 'USA', 'https://image.tmdb.org/t/p/w300/fafBg8LjtQqsXyFg8ZgW7DHQXKt.jpg', 'shane-black', 1108, '2025-11-15 20:21:47.511893'),
	(65, 'George Vincent Gilligan Jr. (born February 10, 1967) is an American screenwriter and filmmaker. He is best known as the creator, primary writer, executive producer, and occasional director of the AMC crime drama series Breaking Bad (2008–2013) and its spin-off prequel series Better Call Saul (2015–2022). He also wrote, directed, and produced the Breaking Bad sequel film El Camino (2019).\n\nGilligan\'s other work includes writing, directing, and producing some episodes of the Fox science fiction series The X-Files (1993–2002) and co-creating its spin-off series The Lone Gunmen (2001), as well as co-writing the screenplay for the superhero film Hancock (2008). His numerous accolades include four Primetime Emmy Awards, six Writers Guild of America Awards, two Critics\' Choice Television Awards, two Producers Guild of America Awards, a Directors Guild of America Award, and a BAFTA Television Award.\n\nDescription above from the Wikipedia article Vince Gilligan, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1967-02-10', '2025-11-15 19:27:45.548817', NULL, 'nm0319213', 'Vince Gilligan', 'USA', 'https://image.tmdb.org/t/p/w300/z3E0DhBg1V1PZVEtS9vfFPzOWYB.jpg', 'vince-gilligan', 66633, '2025-11-15 20:21:47.881368'),
	(66, 'Joachim Rønning (born 30 May 1972) is a Norwegian film director, producer, and writer best known for the Academy Award and Golden Globe-nominated Kon-Tiki and the Disney action-adventure films Pirates of the Caribbean: Dead Men Tell No Tales starring Johnny Depp and Maleficent: Mistress of Evil starring Angelina Jolie. Rønning\'s films have grossed over 1.3 billion dollars at the box office.\n\nDescription above from the Wikipedia article Joachim Rønning, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1972-05-30', '2025-11-15 19:27:45.978509', NULL, 'nm1461392', 'Joachim Rønning', 'Norway', 'https://image.tmdb.org/t/p/w300/xzICGCcXFI7p5dNRyDnqdiUwFuI.jpg', 'joachim-r-nning', 20307, '2025-11-15 20:21:48.331502'),
	(67, 'Jessica Yu (Chinese: 虞琳敏; pinyin: Yú Línmǐn) is an American film director, writer, producer, and editor. She has directed documentary films, dramatic films, and television shows.\n\nYu won the Academy Award for Best Documentary Short Subject in 1996 for Breathing Lessons: The Life and Work of Mark O\'Brien (1996). Yu\'s film Last Call at the Oasis (2012) is based on Alex Prud\'homme\'s Ripple Effect. Her more recent films have been Misconception (2014), ForEveryone.Net (2016), a documentary film about the inventor of the World Wide Web, Sir Tim Berners-Lee, and a Netflix comedy Maria Bamford: Old Baby (2017). In 2019, Yu was nominated for an Emmy Award for "Outstanding Direction for a Limited Series, Movie, or Dramatic Special" for the Fosse/Verdon episode "Glory".\n\nDescription above from the Wikipedia article Jessica Yu, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1966-02-14', '2025-11-15 19:27:46.773827', NULL, 'nm0950506', 'Jessica Yu', 'USA', 'https://image.tmdb.org/t/p/w300/eUkt2afdBtx261l5xz4fNSeFWIp.jpg', 'jessica-yu', 19509, '2025-11-15 20:21:48.650856'),
	(68, 'Dean Allan DeBlois (/dəˈblwɑː/ də-BLWAH; born June 7, 1970) is a Canadian filmmaker and writer. He is best known for writing and directing the Oscar-nominated animated feature films Lilo & Stitch for Walt Disney Animation Studios (with Chris Sanders), the How to Train Your Dragon film trilogy for DreamWorks Animation (the first film also with Sanders), and directing the documentary Heima about the Icelandic band Sigur Rós.\n\nDescription above from the Wikipedia article Dean DeBlois, licensed under CC-BY-SA, full list of contributors on Wikipedia', '1970-06-07', '2025-11-15 19:27:47.929563', NULL, 'nm0213450', 'Dean DeBlois', 'Canada', 'https://image.tmdb.org/t/p/w300/nnaiwvrJdfjpsdqjuyYlq9S0uMA.jpg', 'dean-deblois', 69797, '2025-11-15 20:21:49.581477'),
	(69, 'Zachary Michael Cregger (born March 1, 1981) is an American comedian, actor, writer, director and producer. He is among the founding members of the New York City-based comedy troupe The Whitest Kids U\' Know, which is composed of Trevor Moore, Sam Brown, Timmy Williams, and Darren Trumeter. He later starred in the sitcoms Friends with Benefits, Guys with Kids, and Wrecked. In 2022, Cregger wrote and directed the horror film Barbarian, a commercial success that opened to positive critical reviews.\n\nDescription above from the Wikipedia article Zach Cregger, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1981-03-01', '2025-11-15 19:27:48.485972', NULL, 'nm1199107', 'Zach Cregger', 'USA', 'https://image.tmdb.org/t/p/w300/bpFGFfWYIrZVK7WjwkVLwIoMKEb.jpg', 'zach-cregger', 84833, '2025-11-15 20:21:49.900968'),
	(70, 'Ayan Mukherjee is an Indian film director who works in Hindi cinema. Mukherjee made his directorial debut at the age of 26 with the coming-of-age comedy Wake Up Sid (2009), produced by Karan Johar. The film opened to strong reviews and box-office returns. His next release, the 2013 musical romantic comedy-drama, Yeh Jawaani Hai Deewani, ranks among the highest-grossing Hindi films ever.', '1983-08-15', '2025-11-15 19:27:49.048118', NULL, 'nm2209781', 'Ayan Mukerji', 'India', 'https://image.tmdb.org/t/p/w300/h2je0la48xmeXazM61bZ4hwlWcs.jpg', 'ayan-mukerji', 87378, '2025-11-15 20:21:50.256319'),
	(71, 'Francis Lawrence (born March 26, 1971) is an American filmmaker and producer. After establishing himself as a director of music videos and commercials, Lawrence made his feature-length directorial debut with the superhero thriller Constantine (2005) and has since directed the post-apocalyptic horror film I Am Legend (2007), the romantic drama Water for Elephants (2011), four of the five films in The Hunger Games film series, and the spy thriller Red Sparrow (2018).\n\nDescription above from the Wikipedia article Francis Lawrence, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1971-03-26', '2025-11-15 19:27:49.582697', NULL, 'nm1349376', 'Francis Lawrence', 'Austria', 'https://image.tmdb.org/t/p/w300/pyGWo5mAwZ2Koe6leB2RjKd7vmc.jpg', 'francis-lawrence', 10943, '2025-11-15 20:21:50.612740'),
	(72, 'Motoki Tanaka (田中 基樹, Tanaka Motoki, 7 de junio de 1976), también conocido como Tensho (天衝, Tenshō), es un director, animador y guionista gráfico japonés de la prefectura de Chiba. Después de trabajar en White Fox, se hizo autónomo y actualmente es el representante del estudio de animación Bibury Animation Studios.', '1976-06-07', '2025-11-15 19:27:50.571926', NULL, 'nm4092456', '天衝', 'Japan', 'https://image.tmdb.org/t/p/w300/beZTw4bOZk50vKknxOJXTmVDzWR.jpg', 'director-1371373', 1371373, '2025-11-15 20:21:50.969061'),
	(73, NULL, NULL, '2025-11-15 19:27:51.410323', NULL, 'nm0055987', 'Steve Barnett', NULL, 'https://image.tmdb.org/t/p/w300/jsoAorIihuziTGuwJ3GcODqyyLU.jpg', 'steve-barnett', 3767680, '2025-11-15 20:21:51.667885'),
	(74, 'Stefan Ruzowitzky (born December 25, 1961) is an Academy Award-winning Austrian film director and screenwriter.', '1961-12-25', '2025-11-15 19:27:52.150193', NULL, 'nm0752328', 'Stefan Ruzowitzky', 'Austria', 'https://image.tmdb.org/t/p/w300/38AgCYbF46HIoKHPVKGRwOVnInH.jpg', 'stefan-ruzowitzky', 15115, '2025-11-15 20:21:52.095708'),
	(75, 'Timo Tjahjanto (Indonesian: [tʃahˈjanto]; born Timothy Tjahjanto; 4 September 1980) is an Indonesian film director, producer, and screenwriter known for his film works mainly on the horror and action genres. Tjahjanto owns the film production company Merah Production.\n\nApart from directing, producing, and writing stories for his own films, Tjahjanto is also known as one half of The Mo Brothers with friend and fellow filmmaker Kimo Stamboel. The duo received a Citra Award nomination for Best Director in 2016 for Headshot, while Tjahjanto himself won the Maya Award for Best Director in 2019 for May the Devil Take You.\n\nDescription above from the Wikipedia article Timo Tjahjanto, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1980-01-01', '2025-11-15 19:27:52.902017', NULL, 'nm3464186', 'Timo Tjahjanto', 'Germany', 'https://image.tmdb.org/t/p/w300/Aw0IoH1gMRihDiSyqcjxIQ02SWP.jpg', 'timo-tjahjanto', 235430, '2025-11-15 20:21:52.551761'),
	(76, NULL, NULL, '2025-11-15 19:27:53.467459', NULL, NULL, 'Colin Krawchuk', NULL, 'https://image.tmdb.org/t/p/w300/aHlJ8UkG3jaZO1tb3FgoozSJiwZ.jpg', 'colin-krawchuk', 2735733, '2025-11-15 19:27:53.467459'),
	(77, 'Dean Fleischer Camp (born February 28, 1982) is an American author and filmmaker. He is best known for creating Marcel the Shell with Shoes On, and for directing the feature film of the same name in 2023. He also directed the 2024 live-action remake of Lilo & Stitch.', '1982-02-28', '2025-11-15 19:27:53.904230', NULL, 'nm3255797', 'Dean Fleischer Camp', 'U.S.', 'https://image.tmdb.org/t/p/w300/oZTIL77jVfcz8iEQnYC892jvqY3.jpg', 'dean-fleischer-camp', 1540069, '2025-11-15 20:21:53.436989'),
	(78, 'Josh Boone (born April 5, 1979) is an American filmmaker. He is best known for directing the romantic drama The Fault in Our Stars (2014), based on the novel of the same name. Boone also wrote and directed the romantic comedy Stuck in Love (2012) and the superhero horror film The New Mutants (2020). In 2020, he directed the first and last episode of the miniseries The Stand.\n\nDescription above from the Wikipedia article Josh Boone (director), licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1979-04-05', '2025-11-15 19:27:54.835206', NULL, 'nm1837748', 'Josh Boone', 'USA', 'https://image.tmdb.org/t/p/w300/Ak9d9uoTVIAJYOsl8vfcLICBIc5.jpg', 'josh-boone', 1053420, '2025-11-15 20:21:56.533450'),
	(79, 'Pierre Perifel is a French filmmaker and animator, best known for his work at DreamWorks Animation. He is the director of the feature film The Bad Guys and the award-winning short films Bilby and Le Building. He is an alumnus of École Émile-Cohl and Gobelins, l\'Ecole de l\'image.', NULL, '2025-11-15 19:27:55.561075', NULL, 'nm2010048', 'Pierre Perifel', 'France', 'https://image.tmdb.org/t/p/w300/wNKzhbKZxbO7ODIP9TW6x7T4M1k.jpg', 'pierre-perifel', 1261455, '2025-11-15 20:21:56.204037'),
	(80, NULL, NULL, '2025-11-15 19:27:56.157145', NULL, NULL, 'Bronagh O\'Hanlon', NULL, NULL, 'bronagh-o-hanlon', 3263963, '2025-11-15 19:27:56.157145'),
	(81, 'Hijo de padre inglés y de madre estadounidense, Nolan nació en Westminster, un barrio del centro de Londres donde empezó a realizar películas a la edad de siete años usando la cámara Súper 8 de su padre y sus juguetes como personajes. Fue educado en Haileybury College, una escuela independiente en Hertfordshire, Inglaterra. Después estudió literatura inglesa en la University College de Londres, mientras realizaba varios cortometrajes en una escuela de cine. Su corto Tarantella fue proyectado en Image Union, una exhibición de cine independiente en PBS, en 1989. Otro de sus cortos, Larceny, fue proyectado durante el Cambridge Film Festival en 1996. Otro de sus más notables cortos fue Doodlebug, protagonizado por el actor Jeremy Theobald, quien luego también aparecería en Following, el primer largometraje de Nolan.\n\nSe casó con la productora Emma Thomas en 1997. Tienen cuatro hijos juntos y residen en Los Ángeles, California.', '1970-07-30', '2025-11-15 19:27:56.627511', NULL, 'nm0634240', 'Christopher Nolan', 'UK', 'https://image.tmdb.org/t/p/w300/xuAIuYSmsUzKlUMBFGVZaWsY3DZ.jpg', 'christopher-nolan', 525, '2025-11-15 20:21:57.513051'),
	(82, NULL, '1980-01-01', '2025-11-15 19:27:57.776884', NULL, 'nm1169562', '饺子', 'China', 'https://image.tmdb.org/t/p/w300/9GVX1PAomTgqlAQplBfYCtblPE6.jpg', 'director-2367353', 2367353, '2025-11-15 20:21:58.806053'),
	(83, NULL, '1985-04-21', '2025-11-15 19:27:58.223794', NULL, NULL, '이태성', 'South Korea', NULL, 'director-3987900', 3987900, '2025-11-15 19:27:58.223794'),
	(84, 'Yorgos Lanthimos (Greek: Γιώργος Λάνθιμος, born 23 September 1973) is a Greek filmmaker. He has received multiple accolades, including a BAFTA Award and a Golden Lion, as well as nominations for five Academy Awards and a Golden Globe Award.\n\nLanthimos started his career in experimental theatre before making his directorial film debut with the sex comedy My Best Friend (2001). He rose to prominence by directing the psychological drama film Dogtooth (2009), which won the Un Certain Regard prize at the Cannes Film Festival and was nominated for the Academy Award for Best Foreign Language Film. Lanthimos transitioned to making English-language films with the black comedy The Lobster (2015), which earned him an Academy Award nomination for Best Original Screenplay, and the psychological thriller The Killing of a Sacred Deer (2017).\n\nHe collaborated with actress Emma Stone in the period black comedies The Favourite (2018) and Poor Things (2023) and the anthology film Kinds of Kindness (2024). He received nominations for the Academy Award for Best Director and Best Picture for The Favourite and Poor Things, in addition to winning the Golden Lion for the latter.\n\nDescription above from the Wikipedia article Yorgos Lanthimos, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1973-09-23', '2025-11-15 19:27:58.675359', NULL, 'nm0487166', 'Yorgos Lánthimos', 'Greece', 'https://image.tmdb.org/t/p/w300/dvtv8eV1O8Fl385ctOu3sqO2PbD.jpg', 'giorgos-lanthimos', 122423, '2026-02-09 17:26:30.717718'),
	(85, 'Director y productor de cine estadounidense nacido en Norwalk, Connecticut. Debutó en el año 1997 con Cyclops, baby. Es conocido por haber dirigido las películas Vidas ajenas (2004), nacida de la mente del exitoso productor ejecutivo Steven Spielberg, Soy el número cuatro (2011) y xXx: Reactivated (2017), entre otras. Ha trabajado junto a Shia LaBeouf, Michelle Monaghan, Rosario Dawson, Billy Bob Thornton, Anthony Mackie y Vin Diesel.', '1965-01-17', '2025-11-15 19:27:59.094038', NULL, 'nm0142286', 'D.J. Caruso', 'USA', 'https://image.tmdb.org/t/p/w300/f1SZVhhjvzVot596JYVJdf60dWY.jpg', 'd-j-caruso', 40256, '2025-11-15 20:22:18.902766'),
	(86, NULL, NULL, '2025-11-15 19:28:00.018711', NULL, NULL, 'John Berardo', NULL, NULL, 'john-berardo', 1679765, '2025-11-15 19:28:00.018711'),
	(87, NULL, '1972-08-14', '2025-11-15 19:28:00.586638', NULL, 'nm0215543', 'Claudio Del Falco', 'Italy', 'https://image.tmdb.org/t/p/w300/ojjonAKO38RN7fzWPfzXOPcMPrt.jpg', 'claudio-del-falco', 1180671, '2025-11-15 20:22:07.095042'),
	(88, NULL, NULL, '2025-11-15 19:28:01.111489', NULL, NULL, 'Claire D\'Intorni', NULL, NULL, 'claire-d-intorni', 1766704, '2025-11-15 19:28:01.111489'),
	(89, 'Len Ryan Wiseman (born March 4, 1973) is an American film director, screenwriter, and producer. He is best known for his work on the Underworld series, Live Free or Die Hard, and the 2012 film Total Recall. Wiseman runs the production company Sketch Films.', '1973-03-04', '2025-11-15 19:28:01.441710', NULL, 'nm0936482', 'Len Wiseman', 'USA', 'https://image.tmdb.org/t/p/w300/aXsTPBb6dQ2T3PxLqy2ijf2nxrG.jpg', 'len-wiseman', 3950, '2025-11-15 20:22:03.835952'),
	(90, NULL, NULL, '2025-11-15 19:28:02.641162', NULL, 'nm2382268', 'Philippe Mechelen', NULL, 'https://image.tmdb.org/t/p/w300/j3JphtaWHehVZMpcUPQQw93E6Y5.jpg', 'philippe-mechelen', 1096487, '2025-11-15 20:22:03.509944'),
	(91, NULL, NULL, '2025-11-15 19:28:02.958137', NULL, 'nm2176088', 'Jean-Christian Tassy', NULL, NULL, 'jean-christian-tassy', 930739, '2025-11-15 20:22:03.012513'),
	(92, NULL, NULL, '2025-11-15 19:28:04.017910', NULL, 'nm3112957', 'Ryan Crego', NULL, 'https://image.tmdb.org/t/p/w300/uWxJl02AvEWbqfmo40EAm24CEJx.jpg', 'ryan-crego', 936667, '2025-11-15 20:22:04.857567'),
	(93, NULL, NULL, '2025-11-15 19:28:04.972288', NULL, 'nm0103404', 'Stephen Bradley', NULL, NULL, 'stephen-bradley', 1373168, '2025-11-15 20:22:19.403525'),
	(94, NULL, '1980-06-11', '2025-11-15 19:28:05.416949', NULL, 'nm5743648', 'Jui-Chih Chiang', 'Taiwan', 'https://image.tmdb.org/t/p/w300/195kJnU44IJaI2kJ270Ytz152Ym.jpg', 'jui-chih-chiang', 2640695, '2025-11-15 20:22:04.332917'),
	(95, 'Lee Edward Unkrich (born August 8, 1967) is an American film director, editor and writer. He is best known for his work with the animation studio Pixar, which he joined in 1994 as an editor before being credited as a co-director on Toy Story 2 (1999).\n\nFollowing the film\'s success, Unkrich served a similar role for the films Monsters, Inc. (2001) and Finding Nemo (2003) before making his solo directorial debut with Toy Story 3 (2010). The film and the second he directed, Coco (2017), won two Academy Awards: Best Animated Feature and Best Original Song.\n\nAfter 25 years at the company, Unkrich retired in January 2019 to spend more time with his family and pursue other interests.\n\nDescription above from the Wikipedia article Lee Unkrich, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1967-08-08', '2025-11-15 19:28:06.126766', NULL, 'nm0881279', 'Lee Unkrich', 'USA', 'https://image.tmdb.org/t/p/w300/crb297utC6W4HSstOe5djDPTwEN.jpg', 'lee-unkrich', 8, '2025-11-15 20:22:12.938098'),
	(96, NULL, NULL, '2025-11-15 19:28:06.649641', NULL, 'nm0021772', 'Mairzee Almas', 'Canada', 'https://image.tmdb.org/t/p/w300/wGOEgnJZtELk4SQpQEVFoMChAyl.jpg', 'mairzee-almas', 1400942, '2025-11-15 20:22:17.486766'),
	(97, 'Directora norteamericana nacida en San Carlos, California. Apadrinada por Oliver Stone y James Cameron en distintas fases de su carrera, es una de las pocas cineastas que ha hecho suyo el género de la acción física como sello de su cine. Hija del administrador de una tienda de arte, comenzó su carrera artística como pintora, labor que fue combinando con la filmación de pequeños cortos sobre artes visuales. Excelente fotógrafa y pintora, profesional culta y con muchos conocimientos de bellas artes, ha mezclado sus temas y obsesiones con su dominio de la técnica y su visión plástica, en una carrera a redescubrir más allá de aciertos y errores. Ha dirigido una road movie y western de vampiros, Los viajeros de la noche (1987), el thriller psicológico Acero Azul (1989), la popular película Le llaman Bodhi (1991), el ciberthriller apocalíptico finisecular Días extraños (1995) la inclasificable El peso del agua (2000), y K-19: The Widowmaker (2002). En 2009 presentó su obra maestra, En tierra hostil, un drama bélico que narra la vida de un sargento y su equipo de soldados de élite dedicados a desactivar explosivos en uno de los frentes en la Guerra de Irak. Un filme de bajo presupuesto que sorprendió tanto a los espectadores como críticos de cine por su fenomenal dirección. Una cinta que no pasó desapercibida en todos los premios de cine en especial en los Oscar, que tras competir con Avatar, de su ex marido James Cameron, ganó seis estatuillas de las nueve categorías en las que estuvo nominada. Entre ellas, Mejor Película y Mejor dirección, un premio muy relevante en la historia del cine debido a que Bigelow es la primera mujer en llevarse la estatuilla a la mejor dirección. En el año 2012 rodó, La noche más oscura, acerca de la misión de las fuerzas de operaciones especiales para capturar o matar a Osama bin Laden.', '1951-11-27', '2025-11-15 19:28:08.256100', NULL, 'nm0000941', 'Kathryn Bigelow', 'USA', 'https://image.tmdb.org/t/p/w300/llfsTIvItT7IEmX5qK1qUX0dbqc.jpg', 'kathryn-bigelow', 14392, '2025-11-15 20:22:05.209866'),
	(98, NULL, NULL, '2025-11-15 19:28:08.439442', NULL, 'nm6995804', 'Mehdi Avaz', 'Iran', 'https://image.tmdb.org/t/p/w300/s8PBUU680VtW7HYA8mExTk4CTTo.jpg', 'mehdi-avaz', 1828982, '2025-11-15 20:22:24.627745'),
	(99, 'James Mark is a director, producer and actor.', NULL, '2025-11-15 19:28:09.301667', NULL, 'nm2415859', 'James Mark', NULL, NULL, 'james-mark', 1955091, '2025-11-15 20:22:12.070552'),
	(100, 'A native to Los Angeles, Mike Mendez was in the backyard making movies since the age of 10. At the age of 23, Mike made his first feature film "Killers," which was accepted into the Sundance Film Festival in 1997. The film was picked up by Alpine Pictures, who distributed the feature in the U.S. The film also received a worldwide theatrical release.\n\nHe followed that up with the horror comedy "The Convent," which was also accepted into the Sundance Film Festival in 2000, as well as over 30 other film festivals worldwide. The film was released by Lionsgate in the U.S.\n\nIn 2002, he produced a documentary for Universal Television and Showtime entitled "Masters of Horror," featuring interviews with some of the genre\'s most legendary filmmakers. In 2006, Mike\'s film "The Gravedancers" premiered at the Tribeca Film Festival and was released in theaters nationally by Lionsgate & After Dark Films as part of "8 Films To Die For".\n\nAlong with producing short films for X-box and working on the television series "Beavis & Butthead", Mike\'s newest film is "Big Ass Spider!" for Epic Pictures, which premiered at the 2013 SXSW Film Festival. Starring "Heroes" alumni Greg Grunberg, it had a limited theatrical worldwide.', '1973-01-01', '2025-11-15 19:28:09.692762', NULL, 'nm0579079', 'Mike Mendez', 'USA', 'https://image.tmdb.org/t/p/w300/nfnA85ghqx95dNhxb7DThpnWCcN.jpg', 'mike-mendez', 73409, '2025-11-15 20:22:25.008624'),
	(101, 'Kimo Stamboel (born Muhammad Stamboel on 25 June 1980) is an Indonesian film director, producer, and screenwriter. He is known for his works on the horror genres both as himself and also as part of The Mo Brothers with friend Timo Tjahjanto.\n\nStamboel launched his filmmaking career in 2004 with the release of his directorial debut Bunian in 2004 and achieved mainstream success with the release of slasher hit Macabre (also known as Rumah Dara) in 2009. The duo received a Citra Award for Best Director nomination in 2016 for Headshot.', '1980-06-25', '2025-11-15 19:28:10.211521', NULL, 'nm3125415', 'Kimo Stamboel', 'Indonesia', 'https://image.tmdb.org/t/p/w300/wUMwiprPvvNoPaS5uGeTk2s75LW.jpg', 'kimo-stamboel', 235432, '2025-11-15 20:22:22.008361'),
	(102, 'Adam Stein is an American film director and screenwriter working in Vancouver, British Columbia and Los Angeles, California.\n\nStein graduated from Harvard University and the directing program at the USC School of Cinematic Arts. He co-directed Final Destination Bloodlines for New Line Cinema and the Disney live-action movie Kim Possible. He co-wrote and directed the award-winning independent film Freaks, all with his partner, Zach Lipovsky. In 2019, he was nominated for an Emmy award for Outstanding Directing for his work on the TV series Mech-X4.\n\nBefore directing, Stein edited several independent features that played at film festivals such as Sundance, Tribeca, and SXSW.\n\nDescription above from the Wikipedia article Adam Stein, licensed under CC-BY-SA, full list of contributors on Wikipedia.', NULL, '2025-11-15 19:28:10.922507', NULL, 'nm1437652', 'Adam B. Stein', NULL, 'https://image.tmdb.org/t/p/w300/aobQq1YDiny8Fmr9Sk1sh8SqcRM.jpg', 'adam-b-stein', 1938317, '2026-02-14 17:42:21.582117'),
	(103, 'Ole Christian Madsen is a Danish movie director and script writer, responsible for several movies and TV series that has achieved success in Denmark. Among the most successful projects are the movies Flammen og Citronen, Prague, Nordkraft and the TV series Rejseholdet and Edderkoppen.', '1966-06-18', '2025-11-15 19:28:11.464883', NULL, 'nm0535234', 'Ole Christian Madsen', 'Danmark', 'https://image.tmdb.org/t/p/w300/7VQEVB8fw8v0bo4K6u7Z6A7FaDV.jpg', 'ole-christian-madsen', 56195, '2025-11-15 20:22:06.140064'),
	(104, 'Lynne Ramsay (born 5 December 1969) is a Scottish film director, screenwriter, producer, and cinematographer, best known for the feature films Ratcatcher (1999), Morvern Callar (2002), We Need to Talk about Kevin (2011), and You Were Never Really Here (2017).', '1969-12-05', '2025-11-15 19:28:11.821292', NULL, 'nm0708903', 'Lynne Ramsay', 'UK', 'https://image.tmdb.org/t/p/w300/hmSR9lVV65ojYHyyOtzmNPbVjSY.jpg', 'lynne-ramsay', 83287, '2025-11-15 20:22:08.842363'),
	(105, NULL, NULL, '2025-11-15 19:28:13.130725', NULL, 'nm2459442', 'Jean Gabriel Guerra', NULL, 'https://image.tmdb.org/t/p/w300/kXZkISd6d0u5rPTZyxLXQXWQ7ca.jpg', 'jean-gabriel-guerra', 1607943, '2025-11-15 20:22:09.396188'),
	(106, NULL, NULL, '2025-11-15 19:28:14.602851', NULL, NULL, 'Philip W. da Silva', NULL, NULL, 'philip-w-da-silva', 3301370, '2025-11-15 19:28:14.602851'),
	(107, 'Andrés Walter Muschietti, más conocido como Andy Muschietti (Vicente López, Buenos Aires, Argentina, 26 de agosto de 1973), es un director de cine, guionista y publicista argentino. Estudió en la Universidad de Cine (FUC) y comenzó su carrera con un pequeño papel como asistente de producción en Evita (1996), de Alan Parker y como director en Historias Breves, un concurso de cortometrajes impulsados por el Instituto Nacional de Cine y Artes Audiovisuales (INCAA).\n\nEs conocido por su trabajo en películas de terror como Mamá (2013), It (2017), adaptación de la novela de Stephen King y su secuela, It Capítulo Dos (2019) y The Flash (2023).\n\nEs hermano de Bárbara Muschietti, quien trabaja como productora de sus películas.', '1973-08-26', '2025-11-15 19:28:15.242414', NULL, 'nm0615592', 'Andy Muschietti', 'Argentina', 'https://image.tmdb.org/t/p/w300/4ndnP2NNavhfGtJqihD4FVDsYMY.jpg', 'andy-muschietti', 1113116, '2025-11-15 20:22:11.046976'),
	(108, 'Jared Lawrence Hess (born July 18, 1979) and Jerusha Elizabeth Hess (née Demke, born May 12, 1980) are husband-and-wife American filmmakers known for their work on Napoleon Dynamite (2004), Nacho Libre (2006) and Gentlemen Broncos (2009), all of which they co-wrote and which were directed by Jared. (Nacho Libre was co-written with Mike White.) For their film Ninety-Five Senses, they were nominated for the Academy Award for Best Animated Short Film.\n\nThey also produced music videos for The Postal Service\'s third single, "We Will Become Silhouettes", and the Killers\' Christmas charity single "Boots".\n\nDescription above from the Wikipedia article Jared Hess, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1979-07-18', '2025-11-15 19:28:15.457829', NULL, 'nm0381478', 'Jared Hess', 'USA', 'https://image.tmdb.org/t/p/w300/xUob4AE9C39SsNfhE7z63bMJI75.jpg', 'jared-hess', 53925, '2025-11-15 20:22:07.520255'),
	(109, 'Edward Berger (German: [ˈedvart ˈbɛʁɡɐ]; born 1970) is a German-born director and screenwriter who holds Swiss and Austrian citizenship. He is known for the German films Jack (2014), All My Loving (2019), and All Quiet on the Western Front (2022), as well as his English-language debut Conclave (2024). He also directed several television series, including Deutschland 83 (2015) and Patrick Melrose (2018). \n\nFor All Quiet on the Western Front, Berger accepted an Academy Award for Best International Film, was nominated for Best Adapted Screenplay, and won three British Academy Film Awards. For Conclave, Berger also received several accolades, including his first Golden Globe nomination for Best Director and a British Academy Film Award for Outstanding British Film.\n\nDescription above from the Wikipedia article Edward Berger, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1970-01-01', '2025-11-15 19:28:16.154020', NULL, 'nm0074163', 'Edward Berger', 'West Germany [now Germany]', 'https://image.tmdb.org/t/p/w300/st8iwTbaPHmX0lOiyGFC4sIcA8H.jpg', 'edward-berger', 221522, '2025-11-15 20:22:12.502402'),
	(110, NULL, NULL, '2025-11-15 19:28:16.685779', NULL, 'nm5521959', 'Mercedes Bryce Morgan', 'U.S.A.', 'https://image.tmdb.org/t/p/w300/wahJQFDwBE1ezu4DWxJBFjD8Wwl.jpg', 'mercedes-bryce-morgan', 1855321, '2025-11-15 20:22:18.062475'),
	(111, 'Robert Norman Reiner (born March 6, 1947) is an American actor and filmmaker. As an actor, Reiner first came to national prominence with the role of Michael "Meathead" Stivic on the CBS sitcom All in the Family (1971–1979), a performance that earned him two Primetime Emmy Awards.\n\nAs a director, Reiner was recognized by the Directors Guild of America Awards with nominations for the coming of age drama Stand by Me (1986), the romantic comedy When Harry Met Sally... (1989), and the military courtroom drama A Few Good Men (1992), the last of which also earned him a nomination for the Academy Award for Best Picture. He has also received four nominations for the Golden Globe Award for Best Director.\n\nReiner\'s other major directorial film credits include the heavy metal mockumentary This Is Spinal Tap (1984), the romantic comedy fantasy adventure The Princess Bride (1987), the psychological horror-thriller Misery (1990), the romantic comedy-drama The American President (1995), the buddy comedy-drama The Bucket List (2007), and the biographical political drama LBJ (2016).\n\nReiner also appeared in a number of his films and various others, including Throw Momma from the Train (1987), Sleepless in Seattle (1993), Bullets Over Broadway (1994), The First Wives Club (1996), Primary Colors (1998), EDtv (1999), and The Wolf of Wall Street (2013).', '1947-03-06', '2025-11-15 19:28:16.983477', NULL, 'nm0001661', 'Rob Reiner', 'USA', 'https://image.tmdb.org/t/p/w300/rcmPU3YlhHQVzZlV197qhmRsgEL.jpg', 'rob-reiner', 3026, '2025-11-15 20:22:34.155909'),
	(112, 'Jonathan Blair Hensleigh (born February 13, 1959) is an American screenwriter and film director, working primarily in the action-adventure genre, best known for writing films such as Jumanji, Die Hard with a Vengeance, and Armageddon, as well as making his own directorial debut with the 2004 comic book action film The Punisher.\n\nDescription above from the Wikipedia article Jonathan Hensleigh, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1959-02-13', '2025-11-15 19:28:19.498680', NULL, 'nm0378144', 'Jonathan Hensleigh', 'USA', 'https://image.tmdb.org/t/p/w300/5TAo4TG1kqXWFhOf3ahhkQSfdOj.jpg', 'jonathan-hensleigh', 876, '2025-11-15 20:22:15.605100'),
	(113, 'Benjamin Safdie (born February 24, 1986) is an American filmmaker, actor, and editor best known for his collaborations with his older brother, Josh Safdie. Together, the Safdie brothers have established themselves as leading voices in contemporary independent cinema with acclaimed films such as Heaven Knows What (2014), Good Time (2017), and Uncut Gems (2019).\n\nIn addition to directing, Benny has pursued a parallel career as an actor. His performance in Good Time earned him a nomination for the Independent Spirit Award for Best Supporting Male. He has since appeared in high-profile films including Paul Thomas Anderson’s Licorice Pizza (2021), Kelly Fremon Craig’s Are You There God? It’s Me, Margaret. (2023), and Christopher Nolan’s Oppenheimer (2023).\n\nOn television, he co-created, co-wrote, and starred alongside Nathan Fielder and Emma Stone in the Showtime series The Curse (2023).', '1986-02-24', '2025-11-15 19:28:20.023714', NULL, 'nm1509478', 'Benny Safdie', 'USA', 'https://image.tmdb.org/t/p/w300/9tp4PLNyYPNfCJOWBXPPalWIpnq.jpg', 'benny-safdie', 227564, '2025-11-15 20:22:16.010990'),
	(114, NULL, '1978-06-22', '2025-11-15 19:28:21.403706', NULL, 'nm3989471', 'David G. Derrick Jr.', 'USA', 'https://image.tmdb.org/t/p/w300/j5JOtRua5KduoPsQVix0rwY3jOo.jpg', 'david-g-derrick-jr', 4524084, '2026-02-09 17:27:09.037241'),
	(115, 'Louis Leterrier (French: [lwi lətɛʁje]; born 17 June 1973) is a French film and television director. Best known for his work in action films, he directed the first two Transporter films (2002–2005), The Incredible Hulk (2008), Clash of the Titans (2010), Now You See Me (2013), and the tenth and eleventh Fast & Furious instalment, Fast X (2023) and Fast XI (2026). He also directed the streaming television series The Dark Crystal: Age of Resistance (2019) and Lupin (2021).\n\nDescription above from the Wikipedia article Louis Leterrier, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1973-06-17', '2025-11-15 19:28:22.774084', NULL, 'nm0504642', 'Louis Leterrier', 'France', 'https://image.tmdb.org/t/p/w300/bpqqRRyCLeoAup2OAv1Dtm5C8Tn.jpg', 'louis-leterrier', 18865, '2025-11-15 20:22:14.110043'),
	(116, NULL, '1943-03-11', '2025-11-15 19:28:23.344134', '2017-05-15', 'nm0279177', 'Bernd Fischerauer', 'Austria', 'https://image.tmdb.org/t/p/w300/pOafINweD1wA3Irlx1weFPQjeIz.jpg', 'bernd-fischerauer', 36744, '2025-11-15 20:22:14.649827'),
	(117, NULL, NULL, '2025-11-15 19:28:24.891571', NULL, 'nm1626375', 'Kelsey Mann', NULL, 'https://image.tmdb.org/t/p/w300/jT77axUOdirHG85uXkgSiNT3qff.jpg', 'kelsey-mann', 182001, '2025-11-15 20:22:16.499031'),
	(118, NULL, NULL, '2025-11-15 19:28:26.189408', NULL, 'nm0994275', 'Thomas J. Churchill', NULL, 'https://image.tmdb.org/t/p/w300/4w5kKuY430UcoY7Fgj2fITyCHz7.jpg', 'thomas-j-churchill', 1395388, '2025-11-15 20:22:16.969424'),
	(119, 'David Ayer (born January 18, 1968) is an American filmmaker known for making crime films that are set in Los Angeles and deal with gangs and police corruption. His screenplays include Training Day (2001), The Fast and the Furious (2001), and S.W.A.T. (2003). He has also directed Harsh Times (2005), Street Kings (2008), End of Watch (2012), Sabotage (2014), and The Beekeeper (2024). In 2016, he directed the superhero movie Suicide Squad from the DC Extended Universe and then the urban fantasy film Bright (2017) for Netflix. He has twice collaborated with actor Shia LaBeouf: first with the World War II drama Fury (2014), then the crime thriller The Tax Collector (2020). He has also collaborated with his friend Cle Shaheed Sloan, who has appeared in four of his films.\n\nDescription above from the Wikipedia article David Ayer, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1968-01-18', '2025-11-15 19:28:27.765697', NULL, 'nm0043742', 'David Ayer', 'USA', 'https://image.tmdb.org/t/p/w300/7JmWK2wg2StEc9eYjY96s7OJgb7.jpg', 'david-ayer', 19769, '2025-11-15 20:22:18.652867'),
	(120, 'Adam Wingard (/ˈwɪŋɡɑːrd/ WING-gard; born December 3, 1982) is an American filmmaker. He has been a film director, producer, screenwriter, editor, cinematographer, actor, and composer in numerous American films.\n\nFollowing an early career as a member of the mumblecore movement, he became notable for his works in the horror and action genres, especially the films You\'re Next (2011) and The Gust (2014) and the bigger-budget franchise films Blair Witch (2016), Death Note (2017), and Godzilla vs. Kong (2021), and its sequel Godzilla x Kong: The New Empire (2024).\n\nDescription above from the Wikipedia article Adam Wingard, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1982-12-03', '2025-11-15 19:28:30.606070', NULL, 'nm1417392', 'Adam Wingard', 'USA', 'https://image.tmdb.org/t/p/w300/csunrewJCACuvM3Ntd9kIi31twa.jpg', 'adam-wingard', 98631, '2025-11-15 20:22:19.849025'),
	(121, 'Phil Johnston (born October 26, 1971) is an American screenwriter, director and producer.', '1971-10-26', '2025-11-15 19:28:32.763928', NULL, 'nm1601882', 'Phil Johnston', NULL, 'https://image.tmdb.org/t/p/w300/vJyBKru0qi8YKiTPSxaZj08mkOS.jpg', 'phil-johnston', 567562, '2025-11-15 20:22:20.327201'),
	(122, 'Shawn Adam Levy (/ˈliːvaɪ/; born July 23, 1968) is a Canadian filmmaker and actor. He is the founder of 21 Laps Entertainment. His work has spanned numerous genres, and his films as a director have grossed $3.5 billion worldwide.\n\nFollowing early work as a television director, Levy gained recognition in the 2000s for directing comedy films like Big Fat Liar (2002), Just Married (2003), Cheaper by the Dozen (2003) and The Pink Panther (2006). He then found further success as the director of the first three films in the Night at the Museum film franchise (2006–14). In the early 2010s, he directed films including Date Night (2010), Real Steel (2011), and The Internship (2013), and developed several comedy television pilots. Executive produced the ABC sitcom Last Man Standing. Levy produced the 2016 sci-fi film Arrival, earning him an Academy Award nomination for Best Picture.\n\nSince 2016, Levy has been an executive producer on the Netflix original series Stranger Things. He has directed the third and fourth episodes of each of the show\'s four seasons and the Netflix limited series All the Light We CanNot See (2023). Levy has recently collaborated with Ryan Reynolds by directing Free Guy (2021), The Adam Project (2022), and Deadpool & Wolverine (2024), with the latter emerging as his highest-grossing film and the highest-grossing R-rated film of all time.\n\nDescription above from the Wikipedia article Shawn Levy, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1968-07-23', '2025-11-15 19:28:37.932828', NULL, 'nm0506613', 'Shawn Levy', 'Canada', 'https://image.tmdb.org/t/p/w300/oxj7TgUY5bbj0wE838MCobWrak1.jpg', 'shawn-levy', 17825, '2025-11-15 20:22:20.669117'),
	(123, 'Stephen Hopkins is a Jamaican-born film director and producer. He is best-known for his continuation of the Nightmare on Elm Street franchise with A Nightmare on Elm Street 5: The Dream Child and the Predator franchise with Predator 2. His highest grossing film however was the 1998 film adaption of the TV series Lost in Space. He was born in Jamaica and was raised in Australia and England. He was educated at Sutton Valence School. In 2004, Hopkins directed the controversial biopic The Life and Death of Peter Sellers which raised the ire of the actor\'s son Michael Sellers. Hopkins was a co-executive producer for the first season of the Fox action drama 24, and also directed half of the season\'s episodes, including the first and last episodes.', '1958-11-01', '2025-11-15 19:28:39.479238', NULL, 'nm0394280', 'Stephen Hopkins', 'Jamaica', 'https://image.tmdb.org/t/p/w300/vaPQMexdI3I33kVWAK3i3OrDxF.jpg', 'stephen-hopkins', 2042, '2025-11-15 20:22:21.027015'),
	(124, NULL, NULL, '2025-11-15 19:28:41.195508', NULL, 'nm12758753', '成思毅', NULL, NULL, 'director-3534623', 3534623, '2025-11-15 20:22:21.570657'),
	(125, 'Frank Darabont (born January 28, 1959) is a Hungarian-American film director, screenwriter and producer who has been nominated for three Academy Awards and a Golden Globe. He was born in France by Hungarian parents who fled Budapest during the 1956 uprising, but the family moved to Los Angeles while he was still an infant.\n\nHe has directed the films The Shawshank Redemption, The Green Mile, and The Mist, all based on stories by Stephen King. In 2010 he developed and executive produced the first season of the AMC network television series The Walking Dead.', '1959-01-28', '2025-11-15 19:28:41.748793', NULL, 'nm0001104', 'Frank Darabont', 'France', 'https://image.tmdb.org/t/p/w300/vZ50guP86otYTiBSGfi35GNHWVf.jpg', 'frank-darabont', 4027, '2025-11-15 20:22:22.353257'),
	(126, 'Gerard Johnstone is a New Zealand screenwriter and director. He is known for the comedy sitcom series The Jaquie Brown Diaries and the horror films Housebound and M3GAN.\n\nDescription above from the Wikipedia article Gerard Johnstone, licensed under CC-BY-SA, full list of contributors on Wikipedia.', NULL, '2025-11-15 19:28:41.970257', NULL, 'nm2067421', 'Gerard Johnstone', 'New Zealand', 'https://image.tmdb.org/t/p/w300/bPy9ita1lHcYM4pRSapbzBcMdcX.jpg', 'gerard-johnstone', 1288796, '2025-11-15 20:22:22.737592'),
	(127, 'Director, productor y guionista estadounidense, nombre imprescindible del género de ciencia ficción. Nació en Kapuskasing (Ontario, Canadá), pero pronto se trasladó con su familia a Estados Unidos. Su primera película como director fue Piraña II, los vampiros del mar (1981), producida por los estudios de Roger Corman. A la vuelta del rodaje, escribió un guión acerca de un robot asesino que venía del futuro y vendió los derechos por un dólar con la condición de dirigir él la película. Así surgió Terminator (1984), protagonizada por Arnold Schwarzenegger, que a pesar de su modesto presupuesto, se convirtió en un éxito de crítica y público y en su pasaporte de entrada a las grandes superproducciones de efectos especiales. Entre otras muchas, ha dirigido Aliens, el regreso (1986), Abyss (1989), Terminator 2 (1991) y Mentiras arriesgadas (1994). Su mayor éxito de taquilla, Titanic (1997), logró la cifra récord de 11 premios Oscar de la Academia de Hollywood.', '1954-08-16', '2025-11-15 19:28:42.822512', NULL, 'nm0000116', 'James Cameron', 'Canada', 'https://image.tmdb.org/t/p/w300/9NAZnTjBQ9WcXAQEzZpKy4vdQto.jpg', 'james-cameron', 2710, '2025-11-15 20:22:23.098895'),
	(128, NULL, NULL, '2025-11-15 19:28:43.026054', NULL, 'nm0493543', 'Tracie Laymon', 'USA', 'https://image.tmdb.org/t/p/w300/iR5vVudmCVtb9zJPwXarrROEN0s.jpg', 'tracie-laymon', 2826360, '2025-11-15 20:22:23.732469'),
	(129, 'Madeline Sharafian (born February 1, 1993) is an American film director, screenwriter, and storyboard artist. She is best known for her work at Pixar, including directing the short film Burrow (2020) and the feature film Elio (2025).\n\nDescription above from the Wikipedia article Madeline Sharafian, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1993-02-01', '2025-11-15 19:28:43.232613', NULL, 'nm6461347', 'Madeline Sharafian', 'USA', 'https://image.tmdb.org/t/p/w300/qsWEDSX02wr9E2HfL5v9hx0DF2Q.jpg', 'madeline-sharafian', 1171950, '2025-11-15 20:22:24.084898'),
	(130, 'Francis Ford Coppola (born April 7, 1939) is an American film director, producer and screenwriter. He is widely acclaimed as one of Hollywood\'s most celebrated and influential film directors. He epitomized the group of filmmakers known as the New Hollywood, which included George Lucas, Martin Scorsese, Robert Altman, Woody Allen and William Friedkin, who emerged in the early 1970s with unconventional ideas that challenged contemporary filmmaking.\n\nHe co-authored the script for Patton, winning the Academy Award in 1970. His directorial fame escalated with the release of The Godfather in 1972. The film revolutionized movie-making in the gangster genre, garnering universal laurels from critics and public alike. It went on to win three Academy Awards, including his second, which he won for Best Adapted Screenplay, and it was instrumental in cementing his position as one of the prominent American film directors. Coppola followed it with an equally successful sequel The Godfather Part II, which became the first ever sequel to win the Academy Award for Best Picture. The film received yet higher praises than its predecessor, and gave him three Academy Awards—for Best Adapted Screenplay, Best Director and Best Picture. In the same year was released The Conversation, which he directed, produced and wrote. The film went on to win the Palme d\'Or at the 1974 Cannes Film Festival. His next directorial venture was Apocalypse Now in 1979, and it was as notorious for its lengthy and troubled production as it was critically acclaimed for its vivid and stark depiction of the Vietnam War. It won his second Palme d\'Or at the 1979 Cannes Film Festival.\n\nAlthough some of Coppola\'s ventures in the 1980s and early 1990s were critically lauded, Coppola\'s later work has not met the same level of critical and commercial success as his \'70s films.\n\nDescription above from the Wikipedia article Francis Ford Coppola, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1939-04-07', '2025-11-15 19:28:48.155786', NULL, 'nm0000338', 'Francis Ford Coppola', 'USA', 'https://image.tmdb.org/t/p/w300/IwGgkmW6IoJ9vuNF0T9CU3FYUX.jpg', 'francis-ford-coppola', 1776, '2025-11-15 20:22:26.380068'),
	(131, 'Director y productor de cine estadounidense. El humor negro y una estética inspirada en el cómic son el sello de identidad de muchas de sus películas, como la comedia fantástica Bitelchús (1988) o Batman (1989). Antes de dirigir su primer largometraje, Pee-Wee’s Big Adventure (1985), Burton trabajó en el departamento de animación de la productora Walt Disney. Allí realizó varios cortometrajes experimentales entre los que se incluye el premiado Vincent (1982), narrado por Vincent Price. En 1990 estrenó Eduardo manostijeras, una fábula suburbana en la que desplegó todo su mundo de fantasía gótica. Ed Wood (1994), una película rodada en blanco y negro sobre la vida de uno de los peores directores de la historia del cine, fue muy aclamada por la crítica. Su filme Mars Attacks (1996) es una sátira del cine de ciencia ficción. Otros títulos de su filmografía son: Sleepy Hollow (1999) y El planeta de los simios (2001), una nueva versión del clásico de Franklin J. Schaffner. A principios de la década de 1990, Burton pasó a compaginar la dirección con la actividad de productor. En la Disney supervisó la producción de Pesadilla antes de Navidad (1993, de Henry Selick), basada en una historia suya, que se convertiría en la primera película de animación hecha con plastilina realizada por la famosa compañía. Otros títulos como productor incluyen Batman Forever (1995, de Joel Schumacher) y James y el melocotón gigante (1996, de Selick).', '1958-08-25', '2025-11-15 19:28:48.475933', NULL, 'nm0000318', 'Tim Burton', 'USA', 'https://image.tmdb.org/t/p/w300/yHEHAHQpN9PfSEQx1UxZPczhcAi.jpg', 'tim-burton', 510, '2025-11-15 20:22:26.776003'),
	(132, 'Peter Robert Jackson (Pukerua Bay, Porirua; 31 de octubre de 1961) es un director, guionista y productor de cine neozelandés, conocido especialmente por dirigir, producir y coescribir la trilogía cinematográfica de El Señor de los Anillos: La Comunidad del Anillo (2001), Las dos torres (2002) y El retorno del Rey (2003); así como su precuela, la trilogía de El hobbit: Un viaje inesperado (2012), La desolación de Smaug (2013) y La batalla de los Cinco Ejércitos (2014).  Es ganador de tres premios Óscar, un Globo de Oro y tres BAFTA, entre otros galardones. En 2013 fue nombrado miembro de la prestigiosa Orden de Nueva Zelanda.', '1961-10-31', '2025-11-15 19:28:48.899484', NULL, 'nm0001392', 'Peter Jackson', 'New Zealand', 'https://image.tmdb.org/t/p/w300/bNc908d59Ba8VDNr4eCcm4G1cR.jpg', 'peter-jackson', 108, '2025-11-15 20:22:27.019935'),
	(133, NULL, NULL, '2025-11-15 19:28:49.870173', NULL, 'nm3885019', 'Anthony Schatteman', NULL, 'https://image.tmdb.org/t/p/w300/93dfeAYBgPInhCZszkCBsd4UDPi.jpg', 'anthony-schatteman', 1274776, '2025-11-15 20:22:27.519977'),
	(134, 'Matthew Diamond is an American film and television director, producer and choreographer. He was nominated for an Academy Award in 1999 for directing the documentary film The Dancemaker. As well as being nominated for several Primetime Emmy Awards, Daytime Emmy Awards, DGA Awards, and won at the San Francisco International Film Festival.', '1951-11-26', '2025-11-15 19:28:50.074960', NULL, 'nm0224683', 'Matthew Diamond', 'USA', 'https://image.tmdb.org/t/p/w300/tQPsupCIufSkplXO79YzAPEPTuc.jpg', 'matthew-diamond', 116370, '2025-11-15 20:22:27.888518'),
	(135, 'Christopher Joseph Columbus (born September 10, 1958) is an American filmmaker. Born in Spangler, Pennsylvania, Columbus studied film at New York University\'s Tisch School of the Arts where he developed an interest in filmmaking. After writing screenplays for several teen comedies in the mid-1980s, including Gremlins, The Goonies, and Young Sherlock Holmes, he made his directorial debut with a teen adventure, Adventures in Babysitting(1987). Columbus gained recognition soon after with the highly successful Christmas comedy Home Alone (1990) and Home Alone 2: Lost in New York (1992).\n\nThe comedy Mrs. Doubtfire (1993), starring Robin Williams, was another box-office success for Columbus. He went on to direct several other films throughout the 1990s, which were mostly met with lukewarm reception. However, he found commercial success again by directing the film adaptations of J. K. Rowling\'s novels Harry Potter and the Sorcerer\'s Stone (2001) and its sequel, Harry Potter and the Chamber of Secrets (2002). In addition to directing, Columbus was a producer for Harry Potter and the Prisoner of Azkaban (2004), as well as the drama The Help(2011). He also directed the fantasy Percy Jackson & the Olympians: The Lightning Thief(2010) and the 3D action comedy Pixels (2015).\n\nColumbus is the co-founder of 1492 Pictures, a film production company that has produced some of his films since 1995. More recently, he co-founded another production firm with his daughter in 2014 called Maiden Voyage Pictures. In 2017, he launched ZAG Animation Studios, alongside Michael Barnathan, Haim Saban, and Jeremy Zag. Columbus is also known for his collaboration with composer John Williams, with whom he had worked on the film Home Alone and the film series Harry Potter.\n\nDescription above from the Wikipedia article Chris Columbus, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1958-09-10', '2025-11-15 19:28:50.836754', NULL, 'nm0001060', 'Chris Columbus', 'USA', 'https://image.tmdb.org/t/p/w300/yCyEz90NqjEXKZ7HYcEhDXlLlPc.jpg', 'chris-columbus', 10965, '2025-11-15 20:22:28.245197'),
	(136, 'Joseph V. Russo (18 de julio de 1971) es un director, productor, guionista.', '1971-07-18', '2025-11-15 19:28:51.295774', NULL, 'nm0751648', 'Joe Russo', 'USA', 'https://image.tmdb.org/t/p/w300/o0OXjFzL10jCy89iAs7UzzSbyoK.jpg', 'joe-russo', 19272, '2025-11-15 20:22:28.531207'),
	(137, 'Gregor Jordan (born 1966) is an Australian film director and writer.\n\nJordan\'s films include Two Hands (1999), Buffalo Soldiers (2001), and Ned Kelly (2003). He has also directed the concert video These Days: Live in Concert (2004) by Australian rock band Powderfinger. His film Two Hands won the Australian Film Institute Award for Best Direction and Best Screenplay in 1999. He has most recently directed a film version of The Informers written by Bret Easton Ellis and Nicholas Jarecki and the thriller Unthinkable starring Samuel L. Jackson. He has finished production on a live concert DVD of Powderfinger\'s final concert tour \'Sunsets\' and is in production on a documentary about Ian Thorpe\'s return to professional swimming.He is also developing several feature films as well as an interactive film making website called smashcut.com.\n\nGregor is married to a New Zealand actress Simone Kessell. They have one son, Jack, who was born in January 2005 in Los Angeles.\n\nPrior to making films Gregor Jordan played Bassanio in The Merchant of Venice for Shakespeare By The Sea (Australia).', NULL, '2025-11-15 19:28:53.240552', NULL, 'nm0429963', 'Gregor Jordan', 'Australia', 'https://image.tmdb.org/t/p/w300/66hsfK8273nAN97Cu5SWWMei3n0.jpg', 'gregor-jordan', 57030, '2025-11-15 20:22:28.929079'),
	(138, NULL, NULL, '2025-11-15 19:28:53.747838', NULL, 'nm5426690', 'Michael Crum', NULL, NULL, 'michael-crum', 1811173, '2025-11-15 20:22:29.694888'),
	(139, 'Brillante Mendoza is a Filipino independent film director. He was born and raised in San Fernando, Pampanga. He took advertising arts of the then College of Architecture and fine arts at the University of Santo Tomas. He has directed sixteen films since 2005 including Kaleldo (2006), Thy Womb (2012) and Kinatay (2009).', '1960-07-30', '2025-11-15 19:28:54.460303', NULL, 'nm1137289', 'Brillante Ma Mendoza', 'Philippines', 'https://image.tmdb.org/t/p/w300/qJbuPkCD5J4KBKUxfzhpgv9uSEd.jpg', 'brillante-ma-mendoza', 56213, '2025-11-15 20:22:30.099031'),
	(140, 'Klaus Härö is a Finnish film director. Härö studied film directing and screenwriting at the Aalto University School of Arts in Helsinki and graduated with a Master of Arts degree in 1999.\n\nHärö\'s graduation film Nattflykt (Into the Night) won the Children\'s Jury Honorary Mention at the 2000 Berlin Film Festival, The Golden Cairo Award at the 2001 Cairo Children\'s Film Festival and the first prize at the 2001 Argentine Children\'s Film Festival. Härö\'s documentary film Kolme toivetta (Three Wishes) was awarded as the best documentary film of the Nordic public service broadcasters exchange programme Norvision 2001. It also received the Joan Harms Honorary Award in Finland and the Telvis Honorary Award in 2002. In 2009 Postia pappi Jaakobille (Letters to Father Jacob) won both the special award of the church and the festival\'s audience vote at the 2009 Nordic Film Festival Lübeck. At the Mannheim-Heidelberg Film Festival in November 2009, the film won the main prize. In the same month, the film won the main prize, at the Cairo International Film Festival. Estonian-Finnish co-production Vehkleja (The Fencer), directed by Härö, was nominated for the Golden Globe Award for Best Foreign Film. It was also selected as Finland\'s official Academy Award nominee for Best Foreign Language Film.', '1971-03-31', '2025-11-15 19:28:55.011277', NULL, 'nm0405605', 'Klaus Härö', 'Finland', 'https://image.tmdb.org/t/p/w300/4lACJ5CMno1ajcJHQpexqUBL8bh.jpg', 'klaus-haro', 109891, '2025-11-15 20:22:30.453991'),
	(141, 'Director de cine estadounidense nacido en Kalipell, Montana. Rodó su primera película animada a la temprana edad de 11 años y la acabó a los 13. El film acaparó la atención de los estudios Walt Disney donde, con sólo 14 años, Bird fue apadrinado por el legendario animador Milt Kahl, uno de los Nine Old Men, nombre que recibían los más veteranos animadores del estudio. Se graduó en la CalArts cuando conoció al que sería el futuro cofundador de la Pixar y director de sus propias películas, John Lasseter. Finalmente, consiguió un trabajo en la Disney, pero lo abandonaría tras trabajar en Tod y Toby en 1981. Fue contratado en 1989 por Klasky-Csupo y ayudó a desarrollar Los Simpson a partir de las historias de un minuto del Show de Tracey Ullman y a transformarlas en una serie con episodios de media hora de duración. Allí trabajaría durante algunos años más como consultor ejecutivo. Posteriormente trabajó en otras series animadas, incluyendo El crítico, El rey de la colina, Family Dog, antes de ser contratado por Warner Bros para dirigir la película animada El gigante de hierro (1999). Aunque la película recibió halagos de la crítica, no fue tan bien recibida en taquilla debido a la nula promoción que hizo la propia Warner. Bird fue finalmente contratado por su viejo amigo John Lasseter para dirigir Los increíbles (2004). Bird es también el creador, guionista, director y coproductor, del episodio Family Dog de Cuentos asombrosos de Steven Spielberg. Además, coescribió el guión para la película de acción real Nuestros maravillosos aliados (1987), también producida por Spielberg. En el año 2005, ganó el Óscar en la categoría a la Mejor Película de Animación por Los increíbles, su mayor éxito hasta la llegada de Ratatouille (2007), que también obtuvo el mismo galardón. Está considerado como uno de los directores de animación más reputados de la actualidad.', '1957-09-24', '2025-11-15 19:28:56.203703', NULL, 'nm0083348', 'Brad Bird', 'USA', 'https://image.tmdb.org/t/p/w300/z73rItPBDoRUowY5kuWDMlue3DB.jpg', 'brad-bird', 7087, '2025-11-15 20:22:31.428646'),
	(142, 'Justin Tipping is an American television and film director, screenwriter, and executive producer best known for his work on Kicks (2016), Flatbush Misdemeanors (2021), and Joe vs. Carole (2022).\n\nDescription above from the Wikipedia article Justin Tipping, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1985-04-26', '2025-11-15 19:28:56.650928', NULL, 'nm3258390', 'Justin Tipping', 'U.S.', 'https://image.tmdb.org/t/p/w300/ko6CRwv3W45yGSlCKuXMYMS4UIS.jpg', 'justin-tipping', 1354959, '2025-11-15 20:22:31.858572'),
	(143, 'Director, guionista y productor estadounidense nacido en Brooklyn, Nueva York. De familia judía, decidió convertirse en cineasta desde su juventud. Estudió en la Universidad de Harvard y pasó brevemente por el American Film Institute. En este período educativo dirigió sus cortos Supermarket Sweep (1991), Fortune Cookie (1991) y Protozoa (1993). El largometraje debut de Aronofsky fue Pi (1998), una intriga psicológica con trazos surrealistas filmada en blanco y negro que contaba con el protagonismo de un matemático llamado Max Cohen. De tonos alucinatorios y paranoicos, la película, co-escrita entre Aronofsky, Sean Gullette y Eric Watson, tenía influencias de David Lynch. Dos años después estrenó Réquiem Por Un Sueño (2000), adaptación de una novela de Hubert Selby Jr., escritor que redactó con el propio director el guión de este drama urbano sobre adicciones. La Fuente De La Vida (2006) era una mezcla entre drama psicológico y ciencia-ficción protagonizado por Hugh Jackman y Rachel Weisz. En El Luchador (2008), película protagonizada por Mickey Rourke, se narraba la vida del luchador Randy “The Ram” Robinson. Cisne Negro (2010) era una intriga alrededor del mundo del ballet con el protagonismo de Natalie Portman.', '1969-02-12', '2025-11-15 19:28:59.003351', NULL, 'nm0004716', 'Darren Aronofsky', 'USA', 'https://image.tmdb.org/t/p/w300/tOjz8mVI2HeQBvU6KNjIExMBsXL.jpg', 'darren-aronofsky', 6431, '2025-11-15 20:22:32.110686'),
	(144, 'Jeff Fowler is an American film director and animator. He is best known for directing the live-action adaptations of Sonic the Hedgehog (2020) and its sequels. He was also nominated for the Academy Award for Best Animated Short Film for Gopher Broke (2004)\n\nDescription above from the Wikipedia article Jeff Fowler, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1978-07-27', '2025-11-15 19:28:59.722378', NULL, 'nm1733778', 'Jeff Fowler', 'USA', 'https://image.tmdb.org/t/p/w300/wExdubFgeBkEUP8MojKPKoOcgdZ.jpg', 'jeff-fowler', 93364, '2025-11-15 20:22:32.488272'),
	(145, 'MJ Bassett is an English director, writer, and producer of film and television. She began her career directing the cult horror films Deathwatch and Wilderness, the dark fantasy Solomon Kane, and the video game adaptation Silent Hill: Revelation. Since 2012, she has worked as a director and writer on high-profile television series like Strike Back, Ash vs Evil Dead, Power and Altered Carbon.', NULL, '2025-11-15 19:29:00.747363', NULL, 'nm1068186', 'MJ Bassett', 'UK', 'https://image.tmdb.org/t/p/w300/sgoxX8KRIn34s1yLeOvJYyKw8XE.jpg', 'mj-bassett', 69593, '2025-11-15 20:22:32.864984'),
	(146, 'Roy Arne Lennart Andersson is a Swedish film director, best known for his distinctive style of absurdist humor and melancholic depictions of human life. His personal style is characterized by long takes, and stiff caricaturing of Swedish culture and grotesque. Over his career Andersson earned prizes from the Cannes Film Festival, Berlin International Film Festival and Venice International Film Festival.\n\nAndersson spent much of his professional life working on advertisement spots, directing over 400 commercials and two short films; directing six feature-length films in six decades. He made his feature film debut with A Swedish Love Story (1970) followed by Giliap (1975). Anderson received the Cannes Film Festival Jury Prize for Songs from the Second Floor (2000). His film A Pigeon Sat on a Branch Reflecting on Existence (2014) won the Venice International Film Festival\'s Golden Lion. He other notable films include You, the Living (2007), and About Endlessness (2019).\n\nImdb Mini Bio By ; yusufpiskin', '1943-03-31', '2025-11-15 19:29:01.369134', NULL, 'nm0027815', 'Roy Andersson', 'Sweden', 'https://image.tmdb.org/t/p/w300/sFcrQOIWUM1QArvquG3DmVqw3Eu.jpg', 'roy-andersson', 45791, '2025-11-15 20:22:33.335794'),
	(147, 'Makoto Niitsu (新津 誠, Niitsu Makoto), known as Makoto Shinkai (新海 誠, Shinkai Makoto) is a Japanese animation director, author, and manga artist. Shinkai began his career as a video game animator with Nihon Falcom in 1996, and gained recognition as a filmmaker with the release of the original video animation (OVA) She and Her Cat (1999). Beginning his longstanding association with CoMix Wave Films, Shinkai then released the science-fiction OVA Voices of a Distant Star in 2002, and followed this with his debut feature film The Place Promised in Our Early Days (2004). Shinkai\'s second feature film, the romantic drama anthology 5 Centimeters per Second (2007), gained critical acclaim, as did his subsequent releases, the dramas Children Who Chase Lost Voices (2011) and The Garden of Words (2013). Shinkai\'s 2016 fantasy romance Your Name was a critical and commercial success, becoming the third highest-grossing anime film of all time. His 2019 film, Weathering with You, also achieved similar critical and commercial success. His seventh film, Suzume, was released in Japan in November 2022.', '1973-02-09', '2025-11-15 19:29:01.991508', NULL, 'nm1396121', 'Makoto Shinkai', 'Japan', 'https://image.tmdb.org/t/p/w300/mSCk6PmAR99bCsKJYlMx94vq5qe.jpg', 'makoto-shinkai', 74091, '2025-11-15 20:22:33.750024'),
	(148, 'Ryan Coogler (born May 23, 1986) is an American film director, producer, and screenwriter. He is a recipient of ten NAACP Image Awards and four Black Reel Awards. He has been nominated for two Academy Awards, a Golden Globe Award, and a Grammy Award.\n\nHe made his feature-length debut with the independent film Fruitvale Station (2013) before transitioning to directing and writing franchise films such as the Rocky series spinoff, Creed (2015), as well as the Marvel films Black Panther (2018) and Black Panther: Wakanda Forever (2022). Coogler has also produced the historical drama Judas and the Black Messiah (2021) and wrote and directed the supernatural horror film Sinners (2025).\n\nIn 2013, he was included on Time\'s list of the 30 people under 30 who are changing the world. In 2018, Coogler was named the runner-up of Time\'s Person of the Year, and he was included in the annual Time 100 list of the most influential people in the world. In 2021, Coogler, his wife, Zinzi Coogler, and Sev Ohanian founded multimedia production company Proximity Media.\n\nDescription above from the Wikipedia article Ryan Coogler, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1986-05-23', '2025-11-15 19:29:05.212096', NULL, 'nm3363032', 'Ryan Coogler', 'USA', 'https://image.tmdb.org/t/p/w300/dux4DCDaL6c639DTXGiV7nm1wcN.jpg', 'ryan-coogler', 1056121, '2025-11-15 20:22:34.918759'),
	(149, 'Guy Gilles born Guy Chiche (25 August 1938 - 3 February 1996) was a French film director.\n\nHis first feature film, L\'Amour à la mer (1962), starred Juliette Greco, Romy Schneider and Jean-Pierre Léaud. Patrick Jouan featured in many of his films. He also worked for television with productions such as Dim, Dam, Dom and Pour le plaisir.\n\nHis latest films include Le Crime d\'amour (1982), with Richard Berry and Jacques Penot, and Nuit docile (1987). He caught AIDS in the late 1980s, and in experiencing difficulties with production, he struggled to complete Néfertiti, la fille du soleil in 1994 which was released in 1996 on the year of death.\n\nDescription above from the Wikipedia article Guy Gilles, licensed under CC-BY-SA, full list of contributors on Wikipedia', '1938-08-25', '2025-11-15 19:29:10.715880', '1996-02-03', 'nm0318875', 'Guy Gilles', 'Algeria', 'https://image.tmdb.org/t/p/w300/hVf96xm2TfoK6h4Wo073ZcTwCbw.jpg', 'guy-gilles', 617829, '2025-11-15 20:22:35.321969'),
	(150, NULL, '1977-05-12', '2025-11-15 19:29:13.724027', NULL, NULL, 'Michael Jelenic', 'USA', 'https://image.tmdb.org/t/p/w300/rzfpbDQ3S3lDqnyMfcGzDv0QCwZ.jpg', 'michael-jelenic', 113901, '2025-11-15 19:29:13.724027'),
	(151, NULL, NULL, '2025-11-15 19:29:15.084760', NULL, 'nm2885934', 'Omar Deroca', NULL, 'https://image.tmdb.org/t/p/w300/27RF5EGWMEoWCcWkJHkxf9vRHVv.jpg', 'omar-deroca', 3679755, '2025-11-15 20:22:37.186529'),
	(152, 'Topel Lee is a Filipino film, television, and music-video director known for his distinct visual style and work in the horror and thriller genres. He began his career directing music videos for top local bands before moving into television and feature films. His notable works include Ouija (2007), Amorosa (2012), and Basement (2014). Lee is recognized for his cinematic storytelling, strong atmosphere, and visually striking compositions.', NULL, '2025-11-15 19:29:15.414170', NULL, 'nm1760800', 'Topel Lee', NULL, 'https://image.tmdb.org/t/p/w300/rdSuihhgNggOA584YLWWSUDQI4G.jpg', 'topel-lee', 227100, '2025-11-15 20:22:37.730711'),
	(153, NULL, NULL, '2025-11-15 19:29:16.247449', NULL, 'nm0633272', 'Robert Nixon', NULL, NULL, 'robert-nixon', 1279989, '2025-11-15 20:22:38.207456'),
	(154, 'Harry Bradbeer is a British television and film director, most well known for directing all but one episode of Phoebe Waller Bridge\'s TV tragicomedy "Fleabag", directing all of the first season of the spy thriller "Killing Eve" and the Sherlock Holmes spin-off feature film "Enola Holmes".', NULL, '2025-11-15 19:29:16.495215', NULL, 'nm0102873', 'Harry Bradbeer', NULL, 'https://image.tmdb.org/t/p/w300/1fGaCCtKp3ZCXCkWRzOn4l7YnBE.jpg', 'harry-bradbeer', 173847, '2025-11-15 20:22:38.660071'),
	(155, NULL, '1978-05-05', '2025-11-15 19:29:17.687062', NULL, 'nm1090137', 'Juan Jose Meza-Leon', 'Mexico', NULL, 'juan-jose-meza-leon', 1345328, '2025-11-15 20:22:39.447682'),
	(156, NULL, NULL, '2025-11-15 19:29:19.050286', NULL, 'nm5447995', '林见捷', NULL, NULL, 'director-2352905', 2352905, '2025-11-15 20:22:39.913804'),
	(157, 'Ravi Jadhav is an Indian filmmaker working in the Marathi film industry. He studied Visual Communications and Graphic Design at Sir J J Institute of Applied Arts. Jadhav initially worked as a Creative Director at FCBUlka for seven years and left advertising in 2008 to pursue his dream of becoming a filmmaker.', NULL, '2025-11-15 19:29:20.025105', NULL, 'nm2165634', 'Ravi Jadhav', 'India', 'https://image.tmdb.org/t/p/w300/jD5tFHnI42Ip1g4kEqGh3NL3lzm.jpg', 'ravi-jadhav', 1111643, '2025-11-15 20:22:40.269677'),
	(158, 'Nicole Holofcener (/ˈhɒləfsɛnər/; born March 22, 1960) is an American film and television director and screenwriter. She has directed seven feature films, including Walking and Talking, Friends with Money and Enough Said, and various television series. Along with Jeff Whitty, Holofcener received a 2019 Academy Award nomination for Adapted Screenplay, a BAFTA nomination for Best Adapted Screenplay, and won the Writers Guild of America Award for Best Adapted Screenplay for the film Can You Ever Forgive Me? (2018).\n\nDescription above from the Wikipedia article Nicole Holofcener, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1960-03-22', '2025-11-15 19:29:20.865685', NULL, 'nm0392237', 'Nicole Holofcener', 'USA', 'https://image.tmdb.org/t/p/w300/3RYCd2oskQEhGnIANjJXqPCsGXP.jpg', 'nicole-holofcener', 56539, '2025-11-15 20:22:40.628025'),
	(159, NULL, '1968-01-01', '2025-11-15 19:29:22.567218', NULL, 'nm1299690', 'Guan Hu', 'China', 'https://image.tmdb.org/t/p/w300/plI2TWjFcoP8Exjs2p5oNFqbrqM.jpg', 'guan-hu', 131301, '2025-11-15 20:22:41.439667'),
	(160, 'Martin Charles Scorsese (Queens, Nueva York, 17 de noviembre de 1942), conocido como Martin Scorsese, es un director, guionista, actor y productor estadounidense de cine, ganador de un Óscar, tres Globos de Oro, dos premios BAFTA, un Primetime Emmy, y un premio del gremio de directores de Estados Unidos, además de ser uno de los fundadores de World Cinema Foundation. Fue condecorado con la Legión de Honor francesa en 1987.\n\nLas obras de Scorsese abordan principalmente los temas de la vida italo-estadounidense. Le gusta mucho la música, mundo al que ha dedicado alguna de sus películas (No Direction Home sobre Bob Dylan , Shine a Light sobre los Rolling Stones y George Harrison: Living in the Material World acerca del ex miembro de The Beatles). Scorsese es ampliamente considerado como uno de los directores más influyentes de su generación.\n\nGanó un premio MFA por su obra como director de cine otorgado por la prestigiosa Escuela de Cine de la Universidad de Nueva York. Tras múltiples nominaciones a lo largo de su carrera, ganó finalmente el Óscar al mejor director por su película Los infiltrados, la cual también ganó el Óscar a la mejor película en la 79.ª edición de los Premios de la Academia celebrados en 2007. El Óscar le fue entregado por Francis Ford Coppola, George Lucas y Steven Spielberg, quienes son buenos amigos suyos. A su vez, el 17 de enero de 2010 se le otorgó el premio honorífico Cecil B. DeMille en la entrega de los Globos de Oro por su "sobresaliente contribución al campo del entretenimiento".\n\nScorsese es presidente de The Film Foundation, una fundación sin fines de lucro dedicada a la preservación del material fílmico en deterioro.', '1942-11-17', '2025-11-15 19:29:23.343453', NULL, 'nm0000217', 'Martin Scorsese', 'USA', 'https://image.tmdb.org/t/p/w300/9U9Y5GQuWX3EZy39B8nkk4NY01S.jpg', 'martin-scorsese', 1032, '2025-11-15 20:22:41.728364'),
	(161, 'Nia DaCosta (born November 8, 1989) is an American filmmaker. She is best known for directing the films Little Woods (2018), Candyman (2021) and The Marvels (2023).', '1989-11-08', '2025-11-15 19:29:24.925881', NULL, 'nm4804442', 'Nia DaCosta', 'USA', 'https://image.tmdb.org/t/p/w300/zRyaLNXLT2gKgPvLreyg3GeEIdD.jpg', 'nia-dacosta', 1795072, '2025-11-15 20:22:42.589989'),
	(162, 'Aaron James Horvath (born August 19, 1980) is an American animator, screenwriter, producer, and director. He is best known for co-developing the animated series Teen Titans Go! (2013–present) alongside Michael Jelenic for Cartoon Network as well as directing The Super Mario Bros. Movie (2023) along with Jelenic. Horvath made his directorial debut on the feature film Teen Titans Go! To the Movies (2018), which he directed alongside Peter Rida Michail.', '1980-08-19', '2025-11-15 19:29:25.911311', NULL, 'nm1739338', 'Aaron Horvath', 'USA', 'https://image.tmdb.org/t/p/w300/6AOmWzdJas3xh0xJOk1mHPstNs2.jpg', 'aaron-horvath', 1719706, '2025-11-15 20:22:36.528141'),
	(163, 'James Platten Vanderbilt (born November 17, 1975) is an American screenwriter and producer. He is best known for writing the films Zodiac (2007), The Amazing Spider-Man (2012) and its 2014 sequel, and Independence Day: Resurgence (2016). He also co-wrote and produced Scream (2022) and its 2023 sequel. Vanderbilt also contributed as a producer for several films, including The House with a Clock in Its Walls (2018) and Ready or Not (2019).\n\nDescription above from the Wikipedia article James Vanderbilt, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1975-11-17', '2025-11-15 19:29:27.594997', NULL, 'nm0888743', 'James Vanderbilt', 'U.S.', 'https://image.tmdb.org/t/p/w300/pg4kZ7a3GDoSqmuF8Tmw4jw5L6N.jpg', 'james-vanderbilt', 20204, '2025-11-15 20:22:43.693944'),
	(164, 'Gregor Justin "Gore" Verbinski (born March 16, 1964) is an American film director, screenwriter, and producer. He is best known for directing Mouse Hunt, The Ring, the first three Pirates of the Caribbean films, and  Rango. For Rango, Verbinski won both the Academy Award and BAFTA Award for Best Animated Film.\n\nDescription above from the Wikipedia article Gore Verbinski, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1964-03-16', '2025-11-15 19:29:28.646074', NULL, 'nm0893659', 'Gore Verbinski', 'USA', 'https://image.tmdb.org/t/p/w300/rSQRdmLNAwdKxrtvBSSlBmWeSsj.jpg', 'gore-verbinski', 1704, '2025-11-15 20:22:44.148072'),
	(165, 'Danny Philippou and Michael Philippou (born 13 November 1992), known together online as RackaRacka, are Australian twin filmmakers, YouTubers, and stunt performers. They are known for their horror comedy YouTube videos and for the career as horror filmmakers which those videos spawned. They have won numerous awards for their work, including the Best International Channel Streamy Award, Best Overall at the Online Video Awards, and the AACTA Award for the Best Web Show.\n\nOriginally from Adelaide with Greek heritage, the brothers moved to Los Angeles in January 2019 but continue to make films in Australia. They made their feature directorial debut when they wrote and directed the supernatural horror film Talk to Me, which premiered at the 2023 Sundance Film Festival and was released internationally on 27 July 2023. Their second film, Bring Her Back, was released in 2025. Both received positive reviews.\n\nDescription above from the Wikipedia article Danny and Michael Philippou, licensed under CC-BY-SA, full list of contributors on Wikipedia.', '1992-11-13', '2025-11-15 19:29:29.342977', NULL, 'nm6100536', 'Michael Philippou', 'Australia', 'https://image.tmdb.org/t/p/w300/zpkBlS9F4FGbNxaOQY2AuvL18Q8.jpg', 'michael-philippou', 2070452, '2025-11-15 20:22:44.506714'),
	(166, 'Nimród E. Antal is a Hungarian American film director, screenwriter and actor.', '1973-11-30', '2025-11-15 19:29:31.167751', NULL, 'nm0030735', 'Nimród Antal', 'USA', 'https://image.tmdb.org/t/p/w300/x0fSNFKlhcAbbuvFPHPuTSUvOBY.jpg', 'nimrod-antal', 41671, '2025-11-15 20:22:45.429794'),
	(167, 'Maya Da-Rin is a director and screenwriter.\n\nShe was born in Rio de Janeiro in 1979. She studied Design and Philosophy of Art at the Pontifical Catholic University as well as attended film workshops at the Cuban Film School. In 2010 she moved to France to take part in the Le Fresnoy, where she graduated with honors, and in 2013 she has been an artist in residence at the LABoral Art Center, in Spain. Her films and video installations have been shown and INSERT INTO `genre` (`id`, `color_hex`, `created_at`, `description`, `icon`, `name`, `slug`, `tmdb_id`, `updated_at`) VALUES
