INSERT INTO `pelicula` (`id`, `age_rating`, `average_rating`, `backdrop_url`, `budget`, `created_at`, `description`, `duration_minutes`, `imdb_id`, `origin_country`, `original_language`, `popularity`, `poster_url`, `release_date`, `revenue`, `slug`, `status`, `title`, `tmdb_id`, `trailer_url`, `updated_at`, `vote_count`, `director_id`) VALUES
	(1, '16', 7.7, 'https://image.tmdb.org/t/p/w780/ceyakefyCRAgyeFhefa2bz6d9QO.jpg', 120000000, '2025-11-15 19:12:42.444085', 'Un científico brillante y obsesivo, Victor Frankenstein, en su ambición por desafiar a la muerte, da vida a una criatura ensamblada con partes de cadáveres. Pese a tratarse de una proeza científica, Frankenstein considera que la criatura carece de inteligencia y la rechaza. Dolida, esta se rebela contra su creador.', 149, NULL, 'US', 'en', 43.7276, 'https://image.tmdb.org/t/p/w500/hTj8x0ElKldJyAjTYvaqxkQNxxN.jpg', '2025-10-17', 480678, 'frankenstein-2025', 'RELEASED', 'Frankenstein', 1062722, 'https://www.youtube.com/watch?v=EnN6DL2Z7vA', '2026-02-09 17:26:06.106271', 2866, 1),
	(2, '12', 6.301, 'https://image.tmdb.org/t/p/w780/5lQ4euO30sDin5nCifvi0vURFNd.jpg', 0, '2025-11-15 19:12:42.609998', 'Brian acaba de ser despedido de su trabajo, y se convierte en un padre que se queda en casa. Acepta una invitación para jugar de otro padre, que resulta ser un bala perdida.', 95, NULL, 'US', 'en', 369.369, 'https://image.tmdb.org/t/p/w500/sWhglhFoGA0T7n5U6Yi0t8LBGjA.jpg', '2025-11-05', 0, 'juegos-de-ninos-2025', 'RELEASED', 'Juegos de niños', 1248226, 'https://www.youtube.com/watch?v=xGTq0blCPVQ', '2025-11-19 18:33:54.021681', 204, 2),
	(3, '16', 7.735, 'https://image.tmdb.org/t/p/w780/82lM4GJ9uuNvNDOEpxFy77uv4Ak.jpg', 105000000, '2025-11-15 19:12:42.766059', 'Un joven Predator rechazado por su clan encuentra un aliado inesperado en Thia y emprende un peligroso viaje en busca del adversario definitivo.', 107, NULL, 'US', 'en', 190.55, 'https://image.tmdb.org/t/p/w500/8nCEJ5hFJt0h8FhXafHGhEhT8d7.jpg', '2025-11-05', 184561056, 'predator-badlands-2025', 'RELEASED', 'Predator: Badlands', 1242898, 'https://www.youtube.com/watch?v=w2JQW_aTS7I', '2026-02-16 16:49:48.823501', 1969, 3),
	(4, '16', 7.422, 'https://image.tmdb.org/t/p/w780/gre7gyocZSuwd7M51CGlqsJqBmB.jpg', 175000000, '2025-11-15 19:12:42.925876', 'Un ex revolucionario, tras años apartado de la lucha, se ve obligado a volver a la acción para enfrentar a viejos enemigos en un ambiente cargado de tensión política, racismo y violencia militar... Adaptación modernizada de la novela \'Vineland\', de Thomas Pynchon (1990), sobre los movimientos radicales de los años sesenta.', 162, NULL, 'US', 'en', 41.8808, 'https://image.tmdb.org/t/p/w500/iZ1499F6hYxDxiqioy8oSUaxipG.jpg', '2025-09-23', 206311045, 'una-batalla-tras-otra-2025', 'RELEASED', 'Una batalla tras otra', 1054867, 'https://www.youtube.com/watch?v=U_wQ_20g8Jw', '2026-02-14 17:40:34.610840', 2783, 4),
	(5, '16', 6.813, 'https://image.tmdb.org/t/p/w780/vZK3f5N8Fv2LcyFYLwt6dz0HE1H.jpg', 0, '2025-11-15 19:12:43.179045', 'Un paramédico a punto de dejar su trabajo estresante se ve obligado a hacer un último turno de 24 horas para entrenar a su reemplazo. La serie mezcla humor oscuro con una crítica al sistema de salud estadounidense, haciendo que nunca mires a una ambulancia de la misma manera.', 100, NULL, 'US', 'en', 120.7406, 'https://image.tmdb.org/t/p/w500/3hPPcGOS8XUciA2TDLWEE5hwikH.jpg', '2025-09-12', 12140, 'codigo-3-2025', 'RELEASED', 'Código 3', 1161617, 'https://www.youtube.com/watch?v=Np4MAXPz_PM', '2025-11-19 18:34:07.765600', 107, 5),
	(6, '16', 6.755, 'https://image.tmdb.org/t/p/w780/6zKjoOOb3OZnZuiHtQZn4Kd69Gq.jpg', 30000000, '2025-11-15 19:12:43.338441', 'Ambientada en 1982, cuatro años después de que Finney Blake lograra matar al secuestrador y asesino en serie conocido como "The Grabber". Finney, ahora marcado por el trauma, junto a su hermana menor Gwen, que tiene habilidades psíquicas, comienzan a tener visiones relacionadas con asesinatos ocurridos en un campamento cristiano en las Montañas Rocosas. Decididos a descubrir la verdad, viajan junto con Ernesto, un amigo, al campamento donde trabajó su madre, que también tenía dones psíquicos y fue víctima del asesino.', 114, NULL, 'US', 'en', 19.8375, 'https://image.tmdb.org/t/p/w500/i5OfOjbZMxNfiFGkdETdbJUOLAq.jpg', '2025-10-15', 132235319, 'black-phone-2-2025', 'RELEASED', 'Black Phone 2', 1197137, 'https://www.youtube.com/watch?v=vbjRY7KeZe0', '2026-02-14 17:42:18.587507', 903, 6),
	(7, '16', 4.221, 'https://image.tmdb.org/t/p/w780/iZLqwEwUViJdSkGVjePGhxYzbDb.jpg', 10000000, '2025-11-15 19:12:43.494151', 'Will Radford, un destacado analista de ciberseguridad, pasa sus días rastreando posibles amenazas a la seguridad nacional a través de un programa de vigilancia masiva. Un ataque de una entidad desconocida le lleva a cuestionarse si el gobierno le está ocultando algo a él... y al resto del mundo.', 90, NULL, 'US', 'en', 132.0068, 'https://image.tmdb.org/t/p/w500/fjgSlNGECNgVeMJaOdDAXmGh7ZM.jpg', '2025-07-29', 0, 'la-guerra-de-los-mundos-2025', 'RELEASED', 'La guerra de los mundos', 755898, 'https://www.youtube.com/watch?v=VeXEOwwFFG8', '2026-02-16 16:49:52.854335', 888, 7),
	(8, '16', 6.088, 'https://image.tmdb.org/t/p/w780/xmnqFHhGNYHf5JFy4GSfiIEG0ly.jpg', 0, '2025-11-15 19:12:43.643395', 'Bangkok, década de 1980. Un astuto ladrón que da golpes audaces deja perplejos al público y las autoridades… hasta que un policía se propone atraparlo.', 117, NULL, 'TH', 'th', 206.3516, 'https://image.tmdb.org/t/p/w500/wM125GkMUzSyjPzNqvx9j2UHYV7.jpg', '2025-11-13', 0, 'tee-yai-nacido-para-el-crimen-2025', 'RELEASED', 'Tee Yai: Nacido para el crimen', 1429738, 'https://www.youtube.com/watch?v=DlPR3FMvjME', '2025-11-19 18:33:59.926047', 17, 8),
	(9, '16', 5.833, 'https://image.tmdb.org/t/p/w780/qskMJe62v9kPj4tD9UawIGW0WxD.jpg', 0, '2025-11-15 19:12:43.800090', 'Tras el asesinato del líder de una poderosa familia criminal, su hijo Grant busca venganza. Su mejor amigo, Ray, un agente federal, es la única persona que puede frenarlo antes de que se destruya a sí mismo y a la ciudad.', 90, NULL, 'ES', 'en', 152.7528, 'https://image.tmdb.org/t/p/w500/59FFBARbcTO2jPhzzKuITmNC74k.jpg', '2023-03-07', 0, 'lealtad-rota-2023', 'RELEASED', 'Lealtad rota', 1096563, 'https://www.youtube.com/watch?v=jhIv6fSLyaA', '2025-11-15 20:21:23.533922', 6, 9),
	(10, NULL, 5.884, 'https://image.tmdb.org/t/p/w780/tLf5hjuO4gx62lVojPiHsIzCroh.jpg', 0, '2025-11-15 19:12:43.947821', 'Hace 11 años, el inspector Malik no pudo resolver un caso de secuestro y una niña murió. Ahora, a pocos días de que se cierre el caso, decide reabrirlo. Malik se lo debe a la madre y a sí mismo. Mientras indaga en el pasado, una niña vuelve a ser secuestrada. El patrón es el mismo que hace una década, no es casualidad. Malik sabe que dispone de pocos días para arreglar las cosas y hacer justicia. El tiempo corre...', 95, NULL, 'FR', 'fr', 154.5298, 'https://image.tmdb.org/t/p/w500/vTaGbyHe0vJXbE2t90OVQZsE3G4.jpg', '2024-12-11', 0, 'seis-dias-caza-al-asesino-2024', 'RELEASED', 'Seis días: Caza al asesino', 1025527, 'https://www.youtube.com/watch?v=aaspyawO_ag', '2025-11-15 20:21:23.101295', 69, 10),
	(11, '16', 7.688, 'https://image.tmdb.org/t/p/w780/lNYympQM5O6QSInusbyG9eJDIe4.jpg', 20000000, '2025-11-15 19:12:44.177081', 'El Cuerpo de Cazadores de Demonios se enfrenta a los Doce Kizuki restantes antes de enfrentarse a Muzan en el Castillo del Infinito para derrotarlo de una vez por todas.', 155, NULL, 'JP', 'ja', 77.4485, 'https://image.tmdb.org/t/p/w500/iWLV12z9oexSRLz2WKyqCZbKoPA.jpg', '2025-07-18', 724279886, 'guardianes-de-la-noche-kimetsu-no-yaiba-la-fortaleza-infinita-2025', 'RELEASED', 'Guardianes de la noche: Kimetsu no Yaiba La fortaleza infinita', 1311031, 'https://www.youtube.com/watch?v=X3E4zogzWsY', '2026-02-14 17:40:14.018734', 705, 11),
	(12, '16', 5.6, 'https://image.tmdb.org/t/p/w780/ajIRfvb5MkpH8spMJ5OCyg2enVS.jpg', 0, '2025-11-15 19:12:44.405717', 'Un policía investiga secuestros de menores y descubre oscuros secretos, mientras los sucesos sobrenaturales amenazan a su familia y al tranquilo pueblo de Baramulla.', 112, NULL, 'IN', 'hi', 127.1404, 'https://image.tmdb.org/t/p/w500/2raITTyjXVUcsbJ7lJAQt8HzjDK.jpg', '2025-11-06', 0, 'baramulla-2025', 'RELEASED', 'Baramulla', 1561969, NULL, '2025-11-15 20:21:26.317446', 14, 12),
	(13, '16', 8.347, 'https://image.tmdb.org/t/p/w780/gqTz24ZRsCP6AKjARmEivY7m0cK.jpg', 4100000, '2025-11-15 19:12:44.579240', 'Denji trabajaba como cazador de demonios para la yakuza, tratando de saldar la deuda que había heredado de sus padres, pero la yakuza lo traicionó y lo mató. Antes de perder el conocimiento, Pochita, el perro-demonio motosierra de Denji, hizo un trato con él y le salvó la vida. Así se fusionaron, creando al imparable Chainsaw Man. Ahora, en medio de una brutal guerra entre demonios, cazadores y enemigos secretos, una misteriosa chica llamada Reze irrumpe en su mundo y Denji se enfrenta a su batalla más mortífera, impulsado por el amor, en un mundo donde la supervivencia no conoce reglas.', 100, NULL, 'JP', 'ja', 32.7054, 'https://image.tmdb.org/t/p/w500/fJdnp5OO2wh07tdy6noACNyaqMJ.jpg', '2025-09-19', 174502910, 'chainsaw-man-la-pelicula-el-arco-de-reze-2025', 'RELEASED', 'Chainsaw Man - La película: El arco de Reze', 1218925, 'https://www.youtube.com/watch?v=-KpVet_60Yc', '2026-02-14 17:40:59.443263', 704, 13),
	(14, '12', 5.978, 'https://image.tmdb.org/t/p/w780/2OHa6ukEq3Hce7Pc2kvu8wkmMFY.jpg', 70000000, '2025-11-15 19:12:44.841429', 'Xander Cage es XXX, un antiguo ganador de X-Games y atleta profesional de deportes de extremo, que sobrevive vendiendo videos de sus increíbles hazañas, las cuales hacen emitir adrenalina por todo el cuerpo. Pero después de incontables encuentros con la ley, su mundo está a punto de tomar un rumbo aún más extremo... Porque Xander no sabe que ha sido "espiado" por Augustus Gibbons, un agente veterano de la Agencia Nacional de Seguridad que se encuentra en una desesperada situación en la distante ciudad de Praga, en donde su operativo secreto ha sido asesinado por una pandilla de mafiosos con un estilo muy propio, que se llaman así mismos Anarchy 99, encabezados por el brutal ex-Comandante del Ejército Ruso Yorgi.', 124, NULL, 'US', 'en', 45.3176, 'https://image.tmdb.org/t/p/w500/gd4hRY3pFXRY7YVbMdVBpnKV7wC.jpg', '2002-08-09', 277448382, 'xxx-2002', 'RELEASED', 'xXx', 7451, 'https://www.youtube.com/watch?v=NgPdDDzVhkA', '2026-02-14 17:40:26.004595', 4784, 14),
	(15, NULL, 4.972, 'https://image.tmdb.org/t/p/w780/ygOR390GzOX5Quv0kAAcUNDG7fp.jpg', 0, '2025-11-15 19:12:44.990643', 'Tras ser derrotado por el Almirante Smee, el Capitán Hook se refugia en un pueblo maldito. Allí, se alía con un herrero local que busca venganza por el asesinato de su hermana.', 90, NULL, 'GB', 'en', 111.1906, 'https://image.tmdb.org/t/p/w500/bcP7FtskwsNp1ikpMQJzDPjofP5.jpg', '2025-07-11', 0, 'captain-hook-the-cursed-tides-2025', 'RELEASED', 'Captain Hook: The Cursed Tides', 1511789, 'https://www.youtube.com/watch?v=VVrs2GQmUOs', '2025-11-15 20:21:26.922026', 36, 15),
	(16, '16', 6.924, 'https://image.tmdb.org/t/p/w780/kHOfxq7cMTXyLbj0UmdoGhT540O.jpg', 60000000, '2025-11-15 19:12:45.244952', 'Un grupo de cazadores de tesoros postapocalípticos busca reliquias antiguas en una Tierra que ha quedado casi medio destruida por una enorme erupción solar.', 105, NULL, 'US', 'en', 93.3206, 'https://image.tmdb.org/t/p/w500/soZdshVi2nQpCWqQkS8qumUNNqO.jpg', '2025-08-20', 184758, 'afterburn-zona-cero-2025', 'RELEASED', 'Afterburn (Zona cero)', 507244, 'https://www.youtube.com/watch?v=ZkEjle729tI', '2025-11-15 20:21:29.723223', 112, 16),
	(17, '18', 4.75, 'https://image.tmdb.org/t/p/w780/m9k4N5KKGzSyJRyzvYfF0FUmyv8.jpg', 0, '2025-11-15 19:12:45.388305', 'Una mujer busca a un cazador de monstruos desaparecido, dándose cuenta de que tiene un vínculo inextricable con la criatura perseguida.', 96, NULL, 'CA', 'en', 99.274, 'https://image.tmdb.org/t/p/w500/tO4PLOx2Ey9PZunmwEAsGhc4Ah0.jpg', '2025-06-09', 0, 'kryptic-2025', 'RELEASED', 'Kryptic', 1229910, 'https://www.youtube.com/watch?v=oJI7X2AwV5E', '2025-11-15 20:21:28.306312', 16, 17),
	(18, '7', 6.977, 'https://image.tmdb.org/t/p/w780/s94NjfKkcSczZ1FembwmQZwsuwY.jpg', 200000000, '2025-11-15 19:12:45.542996', 'Con un mundo retrofuturista inspirado en los años 60 como telón de fondo, la Primera Familia de Marvel deberá hacer frente a su mayor desafío hasta la fecha. Obligados a buscar el equilibrio entre su papel de héroes y sus fuertes vínculos familiares, tendrán que defender la Tierra de un hambriento dios espacial llamado Galactus y su intrigante heraldo, Estela Plateada.', 115, NULL, 'US', 'en', 30.1042, 'https://image.tmdb.org/t/p/w500/ckfiXWGEMWrUP53cc6QyHijLlhl.jpg', '2025-07-23', 521858728, 'los-cuatro-fantasticos-primeros-pasos-2025', 'RELEASED', 'Los Cuatro Fantásticos: Primeros pasos', 617126, 'https://www.youtube.com/watch?v=L1lCRrgTOc4', '2026-02-14 17:41:04.458094', 2967, 18),
	(19, '16', 6.7, 'https://image.tmdb.org/t/p/w780/1leYKN0DPNffpldGnCWnbXaiWoD.jpg', 0, '2025-11-15 19:12:45.690904', 'Una madre que huye de su marido, relacionado con la mafia, encuentra refugio en casa de un vagabundo llamado Jake, pero cuando los hombres de su marido se acercan, Jake resulta ser más peligroso que cualquiera de los que ella huye.', 89, NULL, 'CA', 'en', 84.165, 'https://image.tmdb.org/t/p/w500/u6DNzvz4y3XS5QYqsvvauIx4Xvc.jpg', '2025-05-16', 0, 'zona-de-caza-2025', 'RELEASED', 'Zona de caza', 1305717, 'https://www.youtube.com/watch?v=sp1LU5eNKhg', '2025-11-15 20:21:31.135817', 56, 19),
	(20, '7', 8.098, 'https://image.tmdb.org/t/p/w780/w3Bi0wygeFQctn6AqFTwhGNXRwL.jpg', 100000000, '2025-11-15 19:12:45.876075', 'Cuando no están llenando estadios, las superestrellas del K-pop Rumi, Mira y Zoey usan sus poderes secretos para proteger a sus fans de una amenaza sobrenatural.', 96, NULL, 'US', 'en', 43.4035, 'https://image.tmdb.org/t/p/w500/6EQMqEmdG5HoGe2zT1WwWUMvVhv.jpg', '2025-06-20', 24690793, 'las-guerreras-k-pop-2025', 'RELEASED', 'Las guerreras k-pop', 803796, 'https://www.youtube.com/watch?v=UQfYUYyhw1c', '2026-02-14 17:40:32.171937', 2366, 20),
	(21, NULL, 4.962, 'https://image.tmdb.org/t/p/w780/7h0qCqkuQzmG5vXN3lGBc06reLd.jpg', 0, '2025-11-15 19:25:00.935779', 'Una joven camarera es secuestrada por una secta religiosa, que está empeñada en curarla de un virus de hombre lobo de transmisión sexual... o matarla en el proceso. Escapará antes de la primera luna llena?', 97, NULL, 'ES', 'en', 185.3064, 'https://image.tmdb.org/t/p/w500/uJ13k79tpmsFDhXX2YUAlsRFzDT.jpg', '2025-05-06', 0, 'first-moon-2025', 'RELEASED', 'First Moon', 1468417, 'https://www.youtube.com/watch?v=EWmVl8eLXSM', '2025-11-19 18:34:02.069373', 26, 21),
	(22, NULL, 6.788, 'https://image.tmdb.org/t/p/w780/7FDVhmCur4LMOfnXMteiSCtsdOb.jpg', 0, '2025-11-15 19:25:01.858552', 'Un arqueólogo nota que la textura de las reliquias descubiertas durante la excavación de un glaciar se parece mucho a un colgante de jade visto en uno de sus sueños. Él y su equipo se embarcan en una expedición a las profundidades del glaciar.', 129, NULL, 'CN', 'zh', 21.2353, 'https://image.tmdb.org/t/p/w500/jvrSYRtgHTu3oqJN1X7LWZoekB6.jpg', '2024-07-05', 11242056, 'el-descubridor-de-leyendas-2024', 'RELEASED', 'El descubridor de leyendas', 1116465, 'https://www.youtube.com/watch?v=7YmBz_Tuzb0', '2026-02-14 17:42:13.245452', 144, 22),
	(23, NULL, 6.5, 'https://image.tmdb.org/t/p/w780/dHSz0tSFuO2CsXJ1CApSauP9Ncl.jpg', 90000000, '2025-11-15 19:25:02.926130', 'Los Cuatro Jinetes regresan junto a una nueva generación de ilusionistas en una extraordinaria aventura que contiene giros asombrosos, sorpresas alucinantes y trucos de magia nunca vistos en la gran pantalla.', 113, NULL, 'US', 'en', 60.9433, 'https://image.tmdb.org/t/p/w500/zPBRr0LhBEiH8r83rnVYLLNvYMd.jpg', '2025-11-12', 242431024, 'ahora-me-ves-3-2025', 'RELEASED', 'Ahora me ves 3', 425274, 'https://www.youtube.com/watch?v=mv3aMnsqfsE', '2026-02-14 17:40:21.930039', 1035, 23),
	(24, NULL, 7.2, 'https://image.tmdb.org/t/p/w780/2YOnE2qmoyyOUqQsFit12gDSauk.jpg', 18000000, '2025-11-15 19:25:03.639127', 'La historia real de Jeffrey Manchester (Tatum), un criminal que asaltó más de 60 McDonald\'s entrando por un agujero que hacía en el techo en medio de la noche. Tras ser arrestado, escapó de prisión y vivió escondido en una tienda de Toys R Us durante aproximadamente seis meses.', 126, NULL, 'US', 'en', 22.4167, 'https://image.tmdb.org/t/p/w500/KPBBH2PeWmaY8FBaEzezwgOnxZ.jpg', '2025-10-08', 34263666, 'roofman-2025', 'RELEASED', 'Roofman: Un ladrón en el tejado', 1242419, 'https://www.youtube.com/watch?v=iITs3mvelok', '2026-02-14 17:41:55.029065', 514, 24),
	(25, NULL, 5.351, 'https://image.tmdb.org/t/p/w780/ueiD0fJokAMaHSc9tVBM3WF8385.jpg', 0, '2025-11-15 19:25:04.106072', 'En 2025, dos amigos se enfrentan a decisiones difíciles mientras luchan por sus ideales en medio de tensiones sociales. Su amistad se pone a prueba y deben aprender a mantenerse firmes, incluso cuando las cosas se complican.', 100, NULL, 'US', 'en', 224.8394, 'https://image.tmdb.org/t/p/w500/3kliZ6mw8ZgnhfmHw14Zye6GyPS.jpg', '2025-05-09', 0, 'venganza-justificada-2025', 'RELEASED', 'Venganza justificada', 1296504, 'https://www.youtube.com/watch?v=Y6MGlxlSYGI', '2025-11-19 18:33:58.961609', 37, 25),
	(26, NULL, 2.333, 'https://image.tmdb.org/t/p/w780/4IB1h88hurwGtX9cdxXmgNImNtW.jpg', 0, '2025-11-15 19:25:04.933570', '', 99, NULL, 'TH', 'th', 86.62, 'https://image.tmdb.org/t/p/w500/pRWBabtsYvqpPmxNYcejIUe6lc3.jpg', '2025-11-06', 0, '2025', 'RELEASED', 'หมู่บ้านโคกะโหลก', 1215106, 'https://www.youtube.com/watch?v=YnjuzdlfyXA', '2025-11-15 20:21:30.713394', 3, 26),
	(27, NULL, 7.289, 'https://image.tmdb.org/t/p/w780/keToI4XlwYVtImAXjoeoaLJKnfc.jpg', 0, '2025-11-15 19:25:05.529620', '', 98, NULL, 'DE', 'en', 82.8705, 'https://image.tmdb.org/t/p/w500/uOEgCIpKtZZ7Iz6kXe3LvTPldje.jpg', '2025-07-24', 2917068, 'el-gran-premio-a-todo-gas-2025', 'RELEASED', 'El Gran Premio; A todo Gas!!', 1316147, 'https://www.youtube.com/watch?v=NdMun0n3z9w', '2025-11-15 20:21:31.729553', 19, 27),
	(28, '12', 6.872, 'https://image.tmdb.org/t/p/w780/qkOw5IZXESOiRH4wzdIYJlBZiCp.jpg', 160000000, '2025-11-15 19:25:05.677986', 'Arthur Curry, también conocido como Aquaman, es un habitante de un poderoso reino subacuático que recibe el nombre de la Atlántida. En esta película repleta de acción, aventura, e incluso partes de terror, conoceremos sus orígenes, desde que era un niño criado por un hombre humano y considerado un paria por los suyos, hasta que crece y debe hacer frente a los problemas que han aparecido en su mundo. Entonces, este hombre mitad humano y mitad atlante, emprenderá el viaje de su vida, en el que tendrá que descubrir quién es realmente y si es digno de ser un rey. Acompañado de Mera, hará frente a este y otros retos, mientras le planta cara a Black Manta y a su propio hermanastro Orm. ¿Será capaz de dirigir a su pueblo y convertirse en un héroe para el mundo?', 142, NULL, 'US', 'en', 82.7719, 'https://image.tmdb.org/t/p/w500/yTzr6Nc4RcTXVw9SsWQNJdcjTz5.jpg', '2018-12-07', 1152028393, 'aquaman-2018', 'RELEASED', 'Aquaman', 297802, 'https://www.youtube.com/watch?v=dXQBL7u7Zlk', '2025-11-15 20:21:32.039138', 14555, 28),
	(29, '16', 3.978, 'https://image.tmdb.org/t/p/w780/42xAe6kVeTjml9Tww6vRoWa5tay.jpg', 17647000, '2025-11-15 19:25:06.048327', 'El viaje de un hombre que se descubre a sí mismo, encuentra el amor y lucha por su patria. ¿Podrá mantener el fuerte en las tres puertas?', 147, NULL, 'IN', 'kn', 77.126, 'https://image.tmdb.org/t/p/w500/rmCJCFrEwPC0u0Y1smihwDo4Cf1.jpg', '2024-10-11', 3247000, 'martin-2024', 'RELEASED', 'Martin', 861451, NULL, '2025-11-15 20:21:32.509302', 23, 29),
	(30, NULL, 6.588, 'https://image.tmdb.org/t/p/w780/qcDDn7WeKBenM4nLlOPXAeJ4hpg.jpg', 26000000, '2025-11-15 19:25:06.300495', 'El mundo de una madre decidida, Mara, se viene abajo cuando su ex marido, Karim, secuestra a su hija pequeña, Amina, y huye a Oriente Medio. Desesperada por traer a su hija a casa, Mara forma equipo con Robeson, un enigmático ex marine y especialista en secuestros de niños. Su misión les lleva a Beirut, donde se ven envueltos en una traicionera red de espionaje internacional, traición y corrupción. Cuando el tiempo se agota, Mara se enfrenta a la decisión más difícil de su vida: recuperar a su hija o dejarla atrás por su propia seguridad.', 110, NULL, 'GB', 'en', 76.0271, 'https://image.tmdb.org/t/p/w500/fFKcNfjOUbfaC8hPuiMxJ8PAudy.jpg', '2025-09-04', 92691, 'sin-rastro-2025', 'RELEASED', 'Sin rastro', 1280450, 'https://www.youtube.com/watch?v=V4bQuYwFtOQ', '2025-11-15 20:21:32.947676', 74, 30),
	(31, '16', 6.919, 'https://image.tmdb.org/t/p/w780/tcBX2dtkNozZ0uDLVaxXrE6rqyN.jpg', 55000000, '2025-11-15 19:25:06.450933', 'Los investigadores de lo paranormal Ed y Lorraine Warren se enfrentan a un último caso aterrador en el que están implicadas entidades misteriosas a las que deben enfrentarse.', 136, NULL, 'US', 'en', 25.6168, 'https://image.tmdb.org/t/p/w500/qdoqogLNR6myoRrxYFxF4UTkFne.jpg', '2025-09-03', 494656445, 'expediente-warren-el-ultimo-rito-2025', 'RELEASED', 'Expediente Warren: El último rito', 1038392, 'https://www.youtube.com/watch?v=FIiiMiC7GGY', '2026-02-09 17:27:00.026780', 1623, 31),
	(32, NULL, 6.7, 'https://image.tmdb.org/t/p/w780/afVowAl99Vqjo3Ji6RyFI17Tk5r.jpg', 0, '2025-11-15 19:25:06.823039', '', 123, NULL, 'PL', 'pl', 72.0569, 'https://image.tmdb.org/t/p/w500/66yeRDx5gN6YQ1VyGpaz8x3vLfK.jpg', '1996-05-10', 0, 'pu-kownik-kwiatkowski-1996', 'RELEASED', 'Pułkownik Kwiatkowski', 145341, NULL, '2025-11-15 20:21:33.927752', 30, 32),
	(33, NULL, 6.525, 'https://image.tmdb.org/t/p/w780/48LdnfGahm8LuM2cg7LFWEmrTEd.jpg', 0, '2025-11-15 19:25:07.077889', 'Perseguidos por su padre, Cameron y su madre se mudan a una granja aislada donde Cameron ve y escucha cosas que no son posibles. Empieza a cuestionarlo todo y debe descubrir los secretos antes de que lo separen.', 97, NULL, 'CA', 'en', 69.5163, 'https://image.tmdb.org/t/p/w500/8dsBBNw3uJkOvLPb2nz8VJAkGbM.jpg', '2025-06-13', 0, 'the-dogs-2025', 'RELEASED', 'The Dogs', 1081208, 'https://www.youtube.com/watch?v=mU_mOWRjPkk', '2025-11-15 20:21:34.294070', 20, 33),
	(34, NULL, 6.235, 'https://image.tmdb.org/t/p/w780/pmDPp0RLfDCGzXKfMoAGbgfVECH.jpg', 0, '2025-11-15 19:25:07.349791', 'Cuando un conserje oprimido, Winston Gooze, sufre un catastrófico accidente tóxico, se transforma en un nuevo tipo de héroe: el Vengador Tóxico. Ahora, Toxie debe pasar de ser un paria a ser un salvador, enfrentándose a despiadados capos corporativos y fuerzas corruptas que amenazan a su hijo, sus amigos y su comunidad.', 102, NULL, 'US', 'en', 66.7969, 'https://image.tmdb.org/t/p/w500/kHrWK8OPsmrUkdrOeY1LOUxrbmS.jpg', '2025-08-28', 3328938, 'the-toxic-avenger-unrated-2025', 'RELEASED', 'The Toxic Avenger Unrated', 338969, 'https://www.youtube.com/watch?v=BO3tPsmx8_8', '2025-11-15 20:21:34.774784', 194, 34),
	(35, '18', 6.8, 'https://image.tmdb.org/t/p/w780/aHj7d7wSLqrg5cjAcgHhiGr97Ih.jpg', 110000000, '2025-11-15 19:25:07.505684', 'En una América distópica en el año 2025, Ben Richards participa en el violento reality show "The Running Man" con el fin de ganar suficiente dinero para revivir a su hija gravemente enferma.', 133, NULL, 'US', 'en', 26.7271, 'https://image.tmdb.org/t/p/w500/5WYxFamHLqroV0TilEw0RqBPzqG.jpg', '2025-11-11', 68615641, 'the-running-man-2025', 'RELEASED', 'The Running Man', 798645, 'https://www.youtube.com/watch?v=gDzch_4Mi68', '2026-02-14 17:41:21.719849', 1143, 35),
	(36, '7', 7.615, 'https://image.tmdb.org/t/p/w780/7nfpkR9XsQ1lBNCXSSHxGV7Dkxe.jpg', 150000000, '2025-11-15 19:25:07.765245', 'Después de resolver el caso más importante en la historia de Zootrópolis, los policías novatos Judy Hopps y Nick Wilde descubren que su asociación no es tan sólida como pensaban cuando el Jefe Bogo les ordena unirse al programa de consejería "Compañeros en Crisis". Pero no pasa mucho tiempo para que su asociación se ponga a prueba al máximo, cuando la llegada de Gary, la serpiente, pone la ciudad patas arriba.', 107, NULL, 'US', 'en', 224.7016, 'https://image.tmdb.org/t/p/w500/4fRdfQPjHiuDSkzaxFAV44k7Iem.jpg', '2025-11-26', 1830000000, 'zootropolis-2-2025', 'RELEASED', 'Zootrópolis 2', 1084242, 'https://www.youtube.com/watch?v=VZU-glDcBAw', '2026-02-16 16:49:46.463270', 1697, 36),
	(37, '16', 6.573, 'https://image.tmdb.org/t/p/w780/2yo2k8CmgZxfBQYAZ8TnHIYzEme.jpg', 0, '2025-11-15 19:25:08.271596', 'A resultas de un asesinato, el nuevo líder de Furioza, Golden, reclama el poder de su violenta banda de ultras y adopta un nuevo enfoque para actuar en el extranjero.', 166, NULL, 'PL', 'pl', 63.5082, 'https://image.tmdb.org/t/p/w500/3f98fpG9s666xLcxX4rL0KRWRiE.jpg', '2025-10-14', 0, 'furioza-2-2025', 'RELEASED', 'Furioza 2', 1072699, NULL, '2025-11-15 20:21:36.018367', 62, 37),
	(38, NULL, 5.628, 'https://image.tmdb.org/t/p/w780/gtKglOSEq3d4MgQE4VsrT1sRkd0.jpg', 0, '2025-11-15 19:25:08.595801', 'Durante Halloween en Shibuya, un misterioso velo atrapa a la multitud dentro del distrito. Como consecuencia, diez colonias japonesas se convierten en zonas dominadas por maldiciones.', 88, NULL, 'JP', 'ja', 28.0574, 'https://image.tmdb.org/t/p/w500/a4QuZ6oW71zCpwVW08u3fHBxc6E.jpg', '2025-11-07', 44559195, 'jujutsu-kaisen-ejecucion-2025', 'RELEASED', 'JUJUTSU KAISEN: Ejecución', 1539104, 'https://www.youtube.com/watch?v=Okh4Zt1UfvI', '2026-02-14 17:41:23.283342', 78, 38),
	(39, '12', 7.189, 'https://image.tmdb.org/t/p/w780/xPNDRM50a58uvv1il2GVZrtWjkZ.jpg', 400000000, '2025-11-15 19:25:08.775706', 'El agente Ethan Hunt continúa su misión de impedir que Gabriel controle el tecnológicamente omnipotente programa de IA conocido como "the Entity".', 169, NULL, 'US', 'en', 43.5025, 'https://image.tmdb.org/t/p/w500/haOjJGUV00dKlZaJWgjM1UD1cJV.jpg', '2025-05-17', 598767057, 'mision-imposible-sentencia-final-2025', 'RELEASED', 'Misión: Imposible - Sentencia final', 575265, 'https://www.youtube.com/watch?v=YqtdLeJSM6o', '2026-02-14 17:40:35.351514', 2533, 39),
	(40, NULL, 5.357, 'https://image.tmdb.org/t/p/w780/oOlG5axHMt0xhXhy77Ixe3xoDtr.jpg', 0, '2025-11-15 19:25:09.075972', 'Tras no poder cumplir el último deseo de su esposa, una serie de trágicos acontecimientos llevan a Henry a creer que ella ha regresado para vengarse.', 90, NULL, 'US', 'en', 61.1851, 'https://image.tmdb.org/t/p/w500/2nUK1Jovq346cZvgJbF4l5uQKOL.jpg', '2025-07-14', 0, 'bury-me-when-i-m-dead-2025', 'RELEASED', 'Bury Me When I\'m Dead', 1012582, 'https://www.youtube.com/watch?v=Bnv6BE7r014', '2025-11-15 20:21:37.303092', 7, 40),
	(41, NULL, 5.391, 'https://image.tmdb.org/t/p/w780/ryOtVdaYyz1HduChYyWPy9dJDB.jpg', 0, '2025-11-15 19:27:23.788456', 'Una actriz en apuros quiere participar en un remake y decide buscar al protagonista de la película original para inspirarse.', 85, NULL, 'ES', 'en', 61.1745, 'https://image.tmdb.org/t/p/w500/nMcBXvnLqoTKXZnyEeYFOIBlwLX.jpg', '2024-05-23', 0, 'wake-2024', 'RELEASED', 'Wake', 1269021, 'https://www.youtube.com/watch?v=rSQNIDwBr4o', '2025-11-15 20:21:37.929099', 23, 41),
	(42, NULL, 6.5, 'https://image.tmdb.org/t/p/w780/jE9PtFwRbTr3WrlGd81SGDSJNSQ.jpg', 0, '2025-11-15 19:27:24.210748', 'Algunos padres experimentan la angustia del “nido vacío” cuando los hijos empiezan a abandonar el hogar. Javier, en cambio, sufre el trauma del “nido repleto”: nadie se va de casa.', 100, NULL, 'ES', 'es', 59.7675, 'https://image.tmdb.org/t/p/w500/7H27uvaPZfq794qVcLFrSEgHseZ.jpg', '2025-06-26', 0, 'padre-no-hay-mas-que-uno-5-nido-repleto-2025', 'RELEASED', 'Padre no hay más que uno 5: Nido repleto', 1328913, 'https://www.youtube.com/watch?v=Os5EVDLcTx8', '2025-11-15 20:21:38.191470', 19, 42),
	(43, NULL, 7.345, 'https://image.tmdb.org/t/p/w780/ev9kxdoJ5IYVprt1OvH2SMWJdU1.jpg', 4250000, '2025-11-15 19:27:24.635241', 'Elvira lucha contra su hermosa hermanastra en un reino donde la belleza reina suprema. Ella recurre a medidas extremas para cautivar al príncipe, en medio de una despiadada competición por la perfección física.', 109, NULL, 'DK', 'no', 59.6305, 'https://image.tmdb.org/t/p/w500/4KjMMLHqKcAxNRTd5mhMDtNXW1P.jpg', '2025-03-07', 5325096, 'la-hermanastra-fea-2025', 'RELEASED', 'La hermanastra fea', 1284120, 'https://www.youtube.com/watch?v=5vZ1_Yxjwzs', '2025-11-15 20:21:38.648063', 655, 43),
	(44, NULL, 7.158, 'https://image.tmdb.org/t/p/w780/69wb2O2QozXRzUhmHAHTIa7UiJy.jpg', 0, '2025-11-15 19:27:26.232508', 'Stevie y su hermano pequeño Elliot viajan al absurdo mundo de sus sueños para pedirle a Sandman que les conceda un deseo: la familia perfecta.', 87, NULL, 'US', 'en', 57.914, 'https://image.tmdb.org/t/p/w500/z2v3lNAA2ymrZuKof4J2vqFIBdw.jpg', '2025-11-07', 0, 'en-suenos-2025', 'RELEASED', 'En sueños', 1117857, 'https://www.youtube.com/watch?v=tZ8pfVOLAZ4', '2025-11-15 20:21:39.066414', 19, 44),
	(45, NULL, 6.634, 'https://image.tmdb.org/t/p/w780/5A01YSCPYoCOZOhh9tU7F3Htxkf.jpg', 0, '2025-11-15 19:27:27.400194', 'Un equipo de varias personas lucha contra espíritus malignos.', 92, NULL, 'KR', 'ko', 57.1492, 'https://image.tmdb.org/t/p/w500/7MGnHpfhF8savUsrUJoI8Q7dTk9.jpg', '2025-04-30', 6500000, 'noche-de-paz-cazadores-de-demonios-2025', 'RELEASED', 'Noche de paz: Cazadores de demonios', 793387, 'https://www.youtube.com/watch?v=0l35oxLd1UI', '2025-11-15 20:21:39.522361', 67, 45),
	(46, '7', 6.394, 'https://image.tmdb.org/t/p/w780/nAzFDoD1Qsg3DfX1nBBEH9iaz6c.jpg', 0, '2025-11-15 19:27:27.729453', 'Por Navidad, Kate y Everett solo piden un divorcio sin dramas y pasar unas últimas fiestas en familia, pero las nuevas pasiones y los sentimientos del pasado lo complican todo.', 89, NULL, 'US', 'en', 54.7922, 'https://image.tmdb.org/t/p/w500/aCh3KvC7abbNex2d4dKMnIeQs3Q.jpg', '2025-11-12', 0, 'una-navidad-ex-cepcional-2025', 'RELEASED', 'Una Navidad ex-cepcional', 1401318, 'https://www.youtube.com/watch?v=CFS4EXM_AZU', '2025-11-15 20:21:39.820365', 34, 46),
	(48, '18', 7.54, 'https://image.tmdb.org/t/p/w780/cpLGPsm8WPIdEBgLyfvr17knhVf.jpg', 15000000, '2025-11-15 19:27:29.499917', 'Un comando de mercenarios es contratados por la CIA para rescatar a unos pilotos apresados por las guerrillas en la selva Centroamericana. La misión resulta satisfactoria, pero durante su viaje de regreso se dan cuenta de que algo está dándoles caza uno a uno, ese algo resulta ser un cazador alienígena que se queda con las calaveras de sus víctimas como trofeos', 102, NULL, 'US', 'en', 53.7274, 'https://image.tmdb.org/t/p/w500/jl5Y5p2pbhgRwREWbll2RbciG5Z.jpg', '1987-06-12', 98267558, 'depredador-1987', 'RELEASED', 'Depredador', 106, 'https://www.youtube.com/watch?v=RinHCS85Wt8', '2025-11-15 20:21:40.781250', 8631, 48),
	(49, '12', 7.369, 'https://image.tmdb.org/t/p/w780/aJDLz1748CIMZkCkyISYe5Hl6I7.jpg', 225000000, '2025-11-15 19:27:29.782822', 'En un mundo que ha perdido la fe en la bondad, Superman lucha por reconciliar su herencia kryptoniana con los valores humanos que moldearon su carácter. Criado en la Tierra, representa la verdad, la justicia y el estilo americano, pero debe enfrentarse a un mundo cínico que cuestiona sus ideales. Entre el deber de proteger a la humanidad y la búsqueda de su identidad, Superman demuestra que la esperanza y la bondad nunca pasan de moda, incluso en los tiempos más oscuros, inspirando a otros a creer en un futuro mejor.', 129, NULL, 'US', 'en', 36.9194, 'https://image.tmdb.org/t/p/w500/fvUJb08yatV2b3NUSwuYdQKYoFd.jpg', '2025-07-09', 616823803, 'superman-2025', 'RELEASED', 'Superman', 1061474, 'https://www.youtube.com/watch?v=KWoJAz9YiPc', '2026-02-14 17:40:45.808152', 4308, 49),
	(50, '12', 6.143, 'https://image.tmdb.org/t/p/w780/vWMt9uu77fJP5PU6MfYXANSH4Cs.jpg', 0, '2025-11-15 19:27:30.095735', 'Adam, que es alérgico al amor, acaba sin saber cómo comprometido con la hija de su jefe y con su primer amor. Ahora debe intentar mantener en secreto su doble vida.', 97, NULL, 'AE', 'ar', 52.9694, 'https://image.tmdb.org/t/p/w500/fY6MkBBN3Hfyb8F87UWxVyTpXnZ.jpg', '2025-11-06', 0, 'un-novio-dos-novias-2025', 'RELEASED', 'Un novio, dos novias', 1446358, 'https://www.youtube.com/watch?v=xCHkv92IagA', '2025-11-15 20:21:41.563136', 7, 50),
	(51, '12', 6.316, 'https://image.tmdb.org/t/p/w780/zNriRTr0kWwyaXPzdg1EIxf0BWk.jpg', 180000000, '2025-11-15 19:27:30.422534', 'Cinco años después de los eventos de "Dominion", la ecología del planeta ha demostrado ser insoportable para los dinosaurios, donde los pocos que quedan viven aislados en las regiones ecuatoriales. Zora Bennett es contratada para dirigir a un equipo de especialistas cuyo objetivo es conseguir el material genético de las tres criaturas más grandes, las cuales tienen en su ADN la clave para fabricar un medicamento que aportará grandes beneficios a la humanidad. Pero la operación se cruzará con una familia cuyo barco volcó y todos acabarán en una isla prohibida ocupada por dinosaurios de numerosas especies, donde tendrán que hacer lo imposible para sobrevivir.', 133, NULL, 'US', 'en', 51.0508, 'https://image.tmdb.org/t/p/w500/2sbGd7kDhMicDkT097FR9a2JyGU.jpg', '2025-07-01', 869146189, 'jurassic-world-el-renacer-2025', 'RELEASED', 'Jurassic World: El renacer', 1234821, 'https://www.youtube.com/watch?v=1R3LTANp7hw', '2026-02-09 17:26:05.469972', 2952, 51),
	(52, NULL, 6.8, 'https://image.tmdb.org/t/p/w780/bWF5ImUscXXYia8owpm8coadR4m.jpg', 0, '2025-11-15 19:27:30.861253', 'Vietnam, 1968. El equipo de reconocimiento Vulture Squad se adentra en un valle aislado para investigar un pelotón de Boinas Verdes desaparecido. Su misión toma un giro oscuro cuando descubren una amenaza invisible.', 133, NULL, 'AU', 'en', 52.2679, 'https://image.tmdb.org/t/p/w500/aJc0Ej0mAIpNPoQh46oOnUQCqxE.jpg', '2025-08-21', 217753, 'primitive-war-2025', 'RELEASED', 'Primitive War', 1257009, 'https://www.youtube.com/watch?v=9F_WwYA7DR0', '2025-11-15 20:21:42.303899', 159, 52),
	(53, NULL, 6.875, 'https://image.tmdb.org/t/p/w780/q2V1q2Xxwqg3uXQKufpdCtrnAdn.jpg', 30000000, '2025-11-15 19:27:31.413448', 'Gabriel (Keanu Reeves), un ángel bienintencionado, pero bastante inepto, baja a la Tierra con el propósito de ayudar a Arj (Aziz Ansari), un organizador de conciertos en apuros y Jeff (Seth Rogen), un rico inversor de capital riesgo. Aunque las intenciones del angelical Gabriel son buenas, las consecuencias de sus actos no serán las esperadas…', 98, NULL, 'US', 'en', 50.8555, 'https://image.tmdb.org/t/p/w500/kDLQP1bbaFBTpOSM2fuPu3yBqxA.jpg', '2025-10-14', 18145814, 'good-fortune-2025', 'RELEASED', 'Good Fortune', 1114967, 'https://www.youtube.com/watch?v=SAMkXY2Ja80', '2025-11-15 20:21:42.708161', 141, 53),
	(54, NULL, 6.6, 'https://image.tmdb.org/t/p/w780/a6RkQIOZ6wThQOEDv6lHsfH53hD.jpg', 3467000, '2025-11-15 19:27:31.737362', 'El hijo adoptivo de la familia Adattu, Marco, se embarca en una despiadada búsqueda de venganza después de que su hermano es brutalmente asesinado, encontrando solo traición, pérdida y una brutalidad inimaginable a cada paso.', 145, NULL, 'IN', 'ml', 50.5048, 'https://image.tmdb.org/t/p/w500/6Nj8Y1A9lcReqZZvRHOSiO3iTl6.jpg', '2024-12-20', 11559000, 'marco-2024', 'RELEASED', 'Marco', 1186350, 'https://www.youtube.com/watch?v=4VQdzTv8E-g', '2025-11-15 20:21:43.172255', 83, 54),
	(55, '16', 7.384, 'https://image.tmdb.org/t/p/w780/srk5NlOnpEsd0hxVFiHfhtQtfDe.jpg', 0, '2025-11-15 19:27:33.181846', 'La boda de Jenna y Lion propicia el tan deseado reencuentro entre Noah y Nick tiempo después de su ruptura. La incapacidad de Nick para perdonar a Noah se alza como una barrera insalvable. Él, heredero de las empresas de su abuelo y ella, empezando su vida laboral, se resisten a alimentar una llama que aún sigue viva. Pero una vez que sus caminos se han vuelto a cruzar, ¿será el amor más fuerte que el rencor? Secuela de "Culpa tuya".', 110, NULL, 'ES', 'es', 24.801, 'https://image.tmdb.org/t/p/w500/6kmi6vmp6iOn4KzI7WfnVtAeJhU.jpg', '2025-10-15', 0, 'culpa-nuestra-2025', 'RELEASED', 'Culpa nuestra', 1156594, 'https://www.youtube.com/watch?v=g4rcFcbYGv8', '2026-02-09 17:27:11.411080', 600, 55),
	(56, '7', 6.681, 'https://image.tmdb.org/t/p/w780/cGbPBHKSFO7hSIjxkb3KOaGdOep.jpg', 150000000, '2025-11-15 19:27:34.501815', 'Mientras la multitud alza su clamor contra la Bruja Malvada, Glinda y Elphaba deberán unirse una vez más. Con su singular amistad convertida en el punto de inflexión de su futuro, tendrán que mirarse a los ojos con honestidad y compasión para afrontar su transformación personal y cambiar el destino de todo Oz.', 137, NULL, 'US', 'en', 24.3542, 'https://image.tmdb.org/t/p/w500/xBfI3jboJ8zGXpoerp8Xk9ku9JN.jpg', '2025-11-19', 524676531, 'wicked-parte-ii-2025', 'RELEASED', 'Wicked Parte II', 967941, 'https://www.youtube.com/watch?v=wweDnEbMvtY', '2026-02-09 17:27:13.769084', 797, 56),
	(57, NULL, 5.2, 'https://image.tmdb.org/t/p/w780/vNUwK5P42m81uG57kKI1WxSZwIQ.jpg', 0, '2025-11-15 19:27:36.061870', '', 134, NULL, 'IN', 'te', 27.2594, 'https://image.tmdb.org/t/p/w500/l4gsNxFPGpzbq0D6QK1a8vO1lBz.jpg', '2025-02-14', 0, '2025-1403735', 'RELEASED', 'లైలా', 1403735, 'https://www.youtube.com/watch?v=FyhFBHpTh6Y', '2026-02-09 17:26:45.592015', 6, 57),
	(58, NULL, 0, 'https://image.tmdb.org/t/p/w780/bQ05oe6OJYCPlqIvldDg45PsiKH.jpg', 0, '2025-11-15 19:27:37.500218', '', 3, NULL, 'ES', 'zh', 47.3422, 'https://image.tmdb.org/t/p/w500/iBsKv6W5gaEnpYf3LBvwaybrnAX.jpg', '2025-06-12', 0, '2025-1496735', 'RELEASED', '原神：尘间星旅', 1496735, 'https://www.youtube.com/watch?v=zxAubNf3EQQ', '2025-11-15 20:21:44.597894', 0, NULL),
	(59, NULL, 4.667, 'https://image.tmdb.org/t/p/w780/f2SUTv6qGGQK9k8gInnG0z9mBN3.jpg', 20000, '2025-11-15 19:27:39.428889', 'Mia, una locutora experta en brujería hace un viaje en carretera para ver a una terapeuta, en el camino se detiene en un motel rural, donde se encuentra con un grupo de jóvenes los cuales comenzarán a morir uno por uno para traer de la muerte a un espíritu maligno.', 100, NULL, 'MX', 'es', 47.1701, 'https://image.tmdb.org/t/p/w500/85rlLCjpHbY0puR1FSL7jYyN1cu.jpg', '2025-09-08', 0, 'eran-brujas-2025', 'RELEASED', 'Eran brujas', 1373276, 'https://www.youtube.com/watch?v=84vUaWyd-4M', '2025-11-15 20:21:45.125073', 3, 58),
	(60, NULL, 7.21, 'https://image.tmdb.org/t/p/w780/zXINNssll2zsPGqd7F7Llrw7Uql.jpg', 0, '2025-11-15 19:27:40.926510', 'Unos astutos y traicioneros ladrones desafian a la Policía Judicial de Macao. La Policía, que se encontraba en una dura batalla, invita de nuevo al experto en rastreo Huang De Zhong, retirado desde hace muchos años, a unir fuerzas con la joven élite del Departamento de Investigación Criminal de la Policía Judicial. Bajo la colisión de las técnicas tradicionales de rastreo y la alta tecnología, la policía y los criminales luchan con ingenio y valentía, y se lanzan a un duelo entre el bien y el mal parecido al juego del gato y el ratón.', 142, NULL, 'CN', 'zh', 165.6856, 'https://image.tmdb.org/t/p/w500/uFsqAak0ClSwtXiZUO1JgzpFH6y.jpg', '2025-08-16', 174400000, '2025-1419406', 'RELEASED', 'The Shadow\'s Edge', 1419406, 'https://www.youtube.com/watch?v=xvmADAJOoCg', '2026-02-16 16:49:48.079292', 431, 59),
	(61, NULL, 7.154, 'https://image.tmdb.org/t/p/w780/8jYyd9mGx5O28FX2OvfcqZfs5tB.jpg', 52000000, '2025-11-15 19:27:41.506387', 'Tras la muerte de su esposa, un príncipe del siglo XV renuncia a Dios y se convierte en vampiro. Siglos más tarde, en el Londres del siglo XIX, ve a una mujer parecida a su difunta esposa y la persigue, sellando así su propio destino.', 130, NULL, 'FR', 'fr', 46.153, 'https://image.tmdb.org/t/p/w500/ff7fyDdtXM2wu9jsm9gOMYtpvOl.jpg', '2025-07-30', 33593404, 'dracula-2025', 'RELEASED', 'Drácula', 1246049, 'https://www.youtube.com/watch?v=hverb7siYJ8', '2026-02-14 17:40:27.783717', 830, 60),
	(62, NULL, 6.184, 'https://image.tmdb.org/t/p/w780/ax2qCKU6tUhdkStiCnrDdXKA5xC.jpg', 0, '2025-11-15 19:27:42.690727', 'Alec Touati es un multimillonario americano que se embarca en un viaje transformador para descubrir sus raíces. A través de una visión de ayahuasca, Alec es transportado a una sangrienta batalla y se encuentra en un castillo encantado de Marruecos. Allí conoce a Hanna, que le cuenta la trágica historia del matrimonio forzado con un príncipe saudí y su relación amorosa secreta con el cuidador del castillo. A medida que el embarazo de la princesa se hace más evidente, la historia de amor de la pareja se enfrenta a peligrosas consecuencias.', 105, NULL, 'US', 'en', 43.8327, 'https://image.tmdb.org/t/p/w500/xXie22VAqXHMYBDTM2XpWRJWZIn.jpg', '2025-10-16', 0, 'la-princesa-perdida-2025', 'RELEASED', 'La princesa perdida', 1086910, NULL, '2025-11-15 20:21:46.329366', 38, 61),
	(63, '16', 5, 'https://image.tmdb.org/t/p/w780/fZMhuFjyQ7QDFIsLDSQKxe3icce.jpg', 0, '2025-11-15 19:27:43.610286', 'Verónica es una joven periodista que necesita encontrar respuestas, necesita saber por qué dos de sus personas más queridas actuaron de la misma forma, e intuye que solo encontrará respuestas a su problema familiar rebuscando en sus orígenes. Su investigación le conduce hasta un misterioso libro que se encuentra atado con unas tijeras amarradas en su interior. A partir de ahí, Verónica debe enfrentarse a las fuerzas de la oscuridad en una batalla sin cuartel.', 85, NULL, 'ES', 'es', 43.4572, 'https://image.tmdb.org/t/p/w500/qlOWxBek4G7Jw52ZBuCKzy4RlKm.jpg', '2024-11-08', 0, 'the-book-2024', 'RELEASED', 'The Book', 1380998, NULL, '2025-11-15 20:21:46.805975', 1, 62),
	(64, '12', 7.772, 'https://image.tmdb.org/t/p/w780/1KFv63mmcBGVbFl3jxxozoSFlhA.jpg', 250000000, '2025-11-15 19:27:44.041712', 'El mítico piloto Sonny Hayes vuelve de su retiro, persuadido para liderar un equipo de Fórmula 1 en apuros y guiar a su joven promesa, en busca de una nueva oportunidad de éxito.', 155, NULL, 'US', 'en', 31.3924, 'https://image.tmdb.org/t/p/w500/wfpqaxoPKvcqzLy8FO0enGXBzU.jpg', '2025-06-25', 631627111, 'f1-la-pelicula-2025', 'RELEASED', 'F1 la película', 911430, 'https://www.youtube.com/watch?v=mizQBIpMrbE', '2026-02-14 17:41:01.779190', 3322, 63),
	(65, '16', 6.672, 'https://image.tmdb.org/t/p/w780/k6tdiMTO39RQj3dhfspuzprfoe0.jpg', 2500000, '2025-11-15 19:27:45.002211', 'Un experto ladrón lleva a cabo el mayor robo de su vida. Parker, junto a Grofield, Zen y un equipo experto, se ven involucrados en un golpe que los enfrenta a la mafia de Nueva York en esta arriesgada misión.', 125, NULL, 'US', 'en', 41.7336, 'https://image.tmdb.org/t/p/w500/70Na5MXfOsFlJvoX6oKYAwOhNN9.jpg', '2025-09-30', 0, 'juego-sucio-2025', 'RELEASED', 'Juego sucio', 941109, 'https://www.youtube.com/watch?v=ey_qiYSaPko', '2025-11-15 20:21:47.511893', 448, 64),
	(66, '16', 7.042, 'https://image.tmdb.org/t/p/w780/uLXK1LQM28XovWHPao3ViTeggXA.jpg', 0, '2025-11-15 19:27:45.552842', 'Tiempo después de los eventos sucedidos tras el último episodio de la serie "Breaking Bad", el fugitivo Jesse Pinkman (Aaron Paul) huye de sus perseguidores, de la ley y de su pasado.', 123, NULL, 'US', 'en', 41.4044, 'https://image.tmdb.org/t/p/w500/hoWADuvXs3Ua4AXBAiZYnppTupO.jpg', '2019-10-11', 0, 'el-camino-una-pelicula-de-breaking-bad-2019', 'RELEASED', 'El Camino: Una película de Breaking Bad', 559969, 'https://www.youtube.com/watch?v=rklOejPnD3Y', '2025-11-15 20:21:47.881368', 5374, 65),
	(67, '12', 6.501, 'https://image.tmdb.org/t/p/w780/pUNfHmVqfwRdILhCkU8TdysVOXo.jpg', 220000000, '2025-11-15 19:27:45.982534', 'La historia de Ares, un programa muy sofisticado que se envía desde el mundo digital al mundo real en una misión peligrosa y que va a representar el primer encuentro de la humanidad con seres creados por la IA.', 119, NULL, 'US', 'en', 32.3847, 'https://image.tmdb.org/t/p/w500/qShQABLVRMZKnv5mWOPXWniBeB3.jpg', '2025-10-08', 142249983, 'tron-ares-2025', 'RELEASED', 'TRON: Ares', 533533, 'https://www.youtube.com/watch?v=Q1bvwjV5u3Q', '2026-02-14 17:41:06.228795', 1162, 66),
	(68, '12', 8.3, 'https://image.tmdb.org/t/p/w780/ajYw16ISz3qsdYTg4zy5rob1iAQ.jpg', 0, '2025-11-15 19:27:46.776035', 'Los Jonas Brothers tratan de llegar a casa a tiempo para pasar la Navidad con sus familias.', 80, NULL, 'US', 'en', 40.7979, 'https://image.tmdb.org/t/p/w500/rQp9P3CigiN3bgNm0NkYoSl3bMv.jpg', '2025-11-10', 0, 'una-navidad-muy-jonas-brothers-2025', 'RELEASED', 'Una Navidad muy Jonas Brothers', 1425122, 'https://www.youtube.com/watch?v=XaZKOFDB8AI', '2025-11-15 20:21:48.650856', 9, 67),
	(69, 'A', 6.9, 'https://image.tmdb.org/t/p/w780/fyZ6SDUS4o9jp2EHxfZa3qS9ean.jpg', 150000000, '2025-11-15 19:27:47.192533', 'Ambientada en la Tierra de Oz, mucho antes de la llegada de Dorothy Gale desde Kansas. Elphaba es una joven incomprendida por su inusual color verde que aún no ha descubierto su verdadero poder. Glinda es una popular joven marcada por sus privilegios y su ambición que aún no ha descubierto su verdadera pasión. Las dos se conocen como estudiantes de la Universidad Shiz, en la fantástica Tierra de Oz, y forjan una insólita pero profunda amistad. La trama abarca los acontecimientos del primer acto del musical de Broadway.', 162, NULL, 'US', 'en', 26.3003, 'https://image.tmdb.org/t/p/w500/hDQXqvmmikekQ15uxhisBDwEA63.jpg', '2024-10-16', 758737211, 'wicked-2024', 'RELEASED', 'Wicked', 402431, 'https://www.youtube.com/watch?v=UNHQgy3jawI', '2026-02-09 17:26:51.918322', 2846, 56),
	(70, '7', 7.939, 'https://image.tmdb.org/t/p/w780/79PNOxNXSe5e0bhEj11QJPlsdCN.jpg', 150000000, '2025-11-15 19:27:47.937130', 'En la escarpada isla de Mema, donde vikingos y dragones han sido enemigos acérrimos durante generaciones, Hipo se desmarca desafiando siglos de tradición cuando entabla amistad con Desdentao, un temido dragón Furia Nocturna. Su insólito vínculo revela la verdadera naturaleza de los dragones y desafía los cimientos de la sociedad vikinga.', 125, NULL, 'US', 'en', 28.8307, 'https://image.tmdb.org/t/p/w500/kjQXYc2Abhy3TBgAZGzJRhN1JaV.jpg', '2025-06-06', 636351148, 'como-entrenar-a-tu-dragon-2025', 'RELEASED', 'Cómo entrenar a tu dragón', 1087192, 'https://www.youtube.com/watch?v=Ns6ZEpQ1xS0', '2026-02-14 17:41:17.878833', 2579, 68),
	(71, '18', 7.281, 'https://image.tmdb.org/t/p/w780/9mKhhHBfIAWy9TNVHAXqMEFokes.jpg', 38000000, '2025-11-15 19:27:48.491144', 'Cuando todos los alumnos de una misma clase, salvo uno, desaparecen misteriosamente la misma noche y exactamente a la misma hora, la pequeña ciudad donde viven se pregunta quién o qué está detrás de su desaparición.', 129, NULL, 'US', 'en', 19.6908, 'https://image.tmdb.org/t/p/w500/nYqEQ3ltw0hHc1kBaNWr7Rb8WNZ.jpg', '2025-08-04', 269072492, 'weapons-2025', 'RELEASED', 'Weapons', 1078605, 'https://www.youtube.com/watch?v=lZyASo3yaTA', '2026-02-09 17:27:26.057756', 2871, 69),
	(72, NULL, 5.425, 'https://image.tmdb.org/t/p/w780/pKIRUTnwY3YYU9urSdsuobdcliP.jpg', 47000000, '2025-11-15 19:27:49.053265', 'Desde las sombras más densas, la India desata a su arma más letal: el superagente Vikram. Un oficial de las Unidades Especiales, imparable, indestructible, implacable. Cuando entra en escena, el peligro es inevitable. Un Terminator atormentado por sus propios demonios, con un único propósito: volarle la cabeza a Kabir. Dos titanes. Un destino. Una persecución sin límites. El mundo entero se convierte en su sangriento y despiadado campo de batalla. En su camino, decisiones imposibles, donde cada elección tiene un precio muy alto. Esta no es solo una guerra. Es una explosión de acción brutal y emociones que desgarran el alma', 173, NULL, 'IN', 'hi', 38.6026, 'https://image.tmdb.org/t/p/w500/j8Gl3S4L7LE8GIF1J1phZ2Cbo72.jpg', '2025-08-13', 3096145, 'war-2-2025', 'RELEASED', 'War 2', 1109086, 'https://www.youtube.com/watch?v=d1wsPSV_lQs', '2025-11-15 20:21:50.256319', 40, 70),
	(73, NULL, 6.944, 'https://image.tmdb.org/t/p/w780/pcJft6lFWsJxutwpLHVYfmZRPQp.jpg', 20000000, '2025-11-15 19:27:49.588840', 'En un futuro distópico, cien adolescentes participan en una brutal competición conocida como "La larga marcha", donde deben caminar sin descanso: si se detienen o reducen la velocidad de la marcha, mueren. Solo uno sobrevivirá. Adaptación cinematográfica de la novela de Stephen King.', 108, NULL, 'US', 'en', 38.4007, 'https://image.tmdb.org/t/p/w500/izA5U09supDy8J2Z4339Po6PIHU.jpg', '2025-09-10', 54054069, 'la-larga-marcha-2025', 'RELEASED', 'La larga marcha', 604079, 'https://www.youtube.com/watch?v=Toj3Zxun7aQ', '2025-11-15 20:21:50.612740', 744, 71),
	(74, NULL, 5.9, 'https://image.tmdb.org/t/p/w780/qvUiNH0VwtIfGNXCBgmWsh22aWb.jpg', 0, '2025-11-15 19:27:50.574933', 'Tras el incidente de Heath Oslo, la existencia de la organización antiterrorista estadounidense-japonesa CIRS se ha convertido en una cuestión de conocimiento público. CIRS ha sido reconstruido desde cero, y sus funciones más encubiertas se han transferido a una nueva agencia: SORD (Operaciones Sociales, Investigación y Desarrollo). El objetivo de SORD es formar a una nueva generación de operativos para defender al país de futuras amenazas. Para ello, la organización ha establecido una serie de escuelas en todo el país. La Academia de Mihama, más o menos abandonada a su suerte tras su abrupto cierre, se ha convertido en una de esas "escuelas de formación especializada".', 80, NULL, 'JP', 'ja', 38.085, 'https://image.tmdb.org/t/p/w500/yEtlPrsyC2Ge3EYKvSXxyAouCzT.jpg', '2019-03-15', 0, 'grisaia-phantom-trigger-the-animation-2019', 'RELEASED', 'Grisaia: Phantom Trigger The Animation', 601980, NULL, '2025-11-15 20:21:50.969061', 11, 72),
	(75, '16', 7.761, 'https://image.tmdb.org/t/p/w780/oz4U9eA6ilYf1tyiVuGmkftdLac.jpg', 0, '2025-11-15 19:27:51.092772', 'Noah debe dejar su ciudad, novio y amigos para mudarse a la mansión de William Leister, el flamante y rico marido de su madre Rafaela. Por otro lado, con 17 años, orgullosa e independiente, Noah se resiste a vivir en una mansión rodeada de lujo. Allí conoce a Nick, su nuevo hermanastro, y el choque de sus fuertes personalidades se hace evidente desde el primer momento.', 117, NULL, 'ES', 'es', 34.1416, 'https://image.tmdb.org/t/p/w500/gp31EwMH5D2bftOjscwkgTmoLAB.jpg', '2023-06-08', 0, 'culpa-mia-2023', 'RELEASED', 'Culpa mía', 1010581, 'https://www.youtube.com/watch?v=1SqMjrE0J6E', '2026-02-14 17:40:53.071029', 3988, 55),
	(76, NULL, 6.805, 'https://image.tmdb.org/t/p/w780/wPSZXVqe84X8SINvJGiKYZhkSG1.jpg', 10000000, '2025-11-15 19:27:51.414851', 'Un helicóptero estadounidense se estrella en el lado norcoreano, ahora los supervivientes deben trabajar juntos para proteger a un civil especialista en tecnología y encontrar la salida sin la ayuda del apoyo militar estadounidense.', 86, NULL, 'US', 'en', 36.721, 'https://image.tmdb.org/t/p/w500/njCc9bEut22FkxoRdPzcLkSa1np.jpg', '2025-01-30', 1236630, 'valiant-one-2025', 'RELEASED', 'Valiant One', 1009640, 'https://www.youtube.com/watch?v=rfXpM39HeZM', '2025-11-15 20:21:51.667885', 77, 73),
	(77, '16', 6.415, 'https://image.tmdb.org/t/p/w780/gQimJqYMKCkwHIo8wwYKhmnCfBr.jpg', 0, '2025-11-15 19:27:52.154824', 'Un exmarine y cazador furtivo llamado Harlan (Joel Kinnaman) descubre un avión cargado con millones de dólares que ha caído en un lago congelado. Tras ser arrestado por una guardabosques nativa, un grupo de criminales y policías corruptos se enteran de su paradero. Por ello, Harlan y la ranger se unen para luchar e intentar escapar a través del peligroso lago antes de que el hielo se derrita.', 99, NULL, 'US', 'en', 67.2605, 'https://image.tmdb.org/t/p/w500/8qQdun8426bfcQePFSZnucWGSbQ.jpg', '2025-10-16', 0, 'ice-fall-2025', 'RELEASED', 'Ice Fall', 1242501, 'https://www.youtube.com/watch?v=GimoXZs1BIs', '2026-02-14 17:40:19.521065', 124, 74),
	(78, '16', 7.068, 'https://image.tmdb.org/t/p/w780/mEW9XMgYDO6U0MJcIRqRuSwjzN5.jpg', 25000000, '2025-11-15 19:27:52.907149', 'Cuatro años después de enfrentarse involuntariamente a la mafia rusa, Hutch Mansell sigue intentando saldar una deuda de 30 millones de dólares con golpes a criminales internacionales. Agotado y distanciado de su familia, organiza unas vacaciones con su esposa e hijos en Plummerville, el lugar donde solía ir con su hermano de niño. Pero un pequeño altercado los convierte en el objetivo de un peligroso mafioso local y de su corrupto sheriff, poniendo en riesgo toda la familia.', 89, NULL, 'US', 'en', 36.6769, 'https://image.tmdb.org/t/p/w500/qwdBh0102NX5fslXv3L9MSlXqKc.jpg', '2025-08-13', 38802325, 'nadie-2-2025', 'RELEASED', 'Nadie 2', 1007734, 'https://www.youtube.com/watch?v=Qe_0NUZTST0', '2025-11-15 20:21:52.551761', 942, 75),
	(79, NULL, 6.5, 'https://image.tmdb.org/t/p/w780/yZtnGzfZER0QU7ZG4r4RaZAaXJH.jpg', 0, '2025-11-15 19:27:53.472426', 'Cuando la maga adolescente Max se cruza con el siniestro Bufón en la noche de Halloween, debe ser más astuta que un asesino sobrenatural cuya magia es demasiado real y cuyos trucos siempre acaban en sangre.', 87, NULL, 'US', 'en', 36.1155, 'https://image.tmdb.org/t/p/w500/47dsw1jSOV0Be5zmy7CtLhYpqU.jpg', '2025-09-15', 146237, 'the-jester-2-2025', 'RELEASED', 'The Jester 2', 1519168, 'https://www.youtube.com/watch?v=7ogVp-d-CdE', '2025-11-15 20:21:53.121910', 31, 76),
	(80, 'Ai', 7.22, 'https://image.tmdb.org/t/p/w780/7Zx3wDG5bBtcfk8lcnCWDOLM4Y4.jpg', 100000000, '2025-11-15 19:27:53.909759', 'La conmovedora y divertidísima historia de una solitaria niña hawaiana y el extraterrestre fugitivo que la ayuda a reparar su desestructurada familia.', 108, NULL, 'US', 'en', 19.2444, 'https://image.tmdb.org/t/p/w500/4oLLOAT55JhAoe73VliaSKFvEEr.jpg', '2025-05-17', 1038027526, 'lilo-y-stitch-2025', 'RELEASED', 'Lilo y Stitch', 552524, 'https://www.youtube.com/watch?v=sa_6BS_VY-M', '2026-02-14 17:42:05.827589', 2014, 77),
	(81, NULL, 7.234, 'https://image.tmdb.org/t/p/w780/amcOpAGkcTEZqmUG1LNM2gYGCam.jpg', 30000000, '2025-11-15 19:27:54.840006', 'Morgan es una madre joven que intenta evitar que su hija Clara, de 16 años, cometa los mismos errores que ella, que se quedó embarazada y se casó demasiado joven, teniendo que aparcar sus propios sueños. La única persona que trae paz a la tensa relación madre-hija es Chris, su marido y padre de Clara. Pero esa paz se rompe cuando un trágico y extraño accidente trae desgarradoras consecuencias para ellas. Mientras lucha por reconstruir sus vidas, Morgan encuentra consuelo en la última persona que esperaba, mientras Clara se vuelve hacia el único chico que le han prohibido ver.', 116, NULL, 'US', 'en', 34.6507, 'https://image.tmdb.org/t/p/w500/4lBPiTShr6vHvtnO7UBr35BarWs.jpg', '2025-10-22', 53985704, 'a-pesar-de-ti-2025', 'RELEASED', 'A pesar de ti', 1327862, 'https://www.youtube.com/watch?v=-Wsx4zQNHw4', '2025-11-15 20:21:56.533450', 65, 78),
	(82, 'Ai', 7.761, 'https://image.tmdb.org/t/p/w780/lB96EMr5A7Og81UhyldJvvy35r.jpg', 80000000, '2025-11-15 19:27:55.570737', 'Un genial equipo de animales que no respetan la ley, los ahora muy reformados Tipos Malos, se esfuerzan (mucho, muchísimo) en ser buenos, pero se ven envueltos involuntariamente en un golpe de envergadura mundial planeado por un inesperado grupo de criminales: las Tipas Malas.', 104, NULL, 'US', 'en', 34.737, 'https://image.tmdb.org/t/p/w500/mZmnKDhIS2yNmtfzde5vtdCYzBF.jpg', '2025-07-24', 224738330, 'los-tipos-malos-2-2025', 'RELEASED', 'Los tipos malos 2', 1175942, 'https://www.youtube.com/watch?v=PnUcgVUuYjs', '2025-11-15 20:21:56.204037', 511, 79),
	(83, 'A', 7.333, 'https://image.tmdb.org/t/p/w780/9Apjnxx4BQ2opZr022r5Me5J8zi.jpg', 0, '2025-11-15 19:27:56.161720', 'En la tripa de Estela hay una estrella. En la de Perla, una luna. Pero ambas son Sneetches, ¿no? ¿Qué les impide ser las mejores amigas?', 45, NULL, 'IE', 'en', 32.7475, 'https://image.tmdb.org/t/p/w500/pBdeeWVarVjq4j3uLLAAXbw2NZZ.jpg', '2025-11-03', 0, 'dr-seuss-los-sneetches-2025', 'RELEASED', 'Dr. Seuss: Los Sneetches', 1497036, 'https://www.youtube.com/watch?v=EDV0sFoFmsQ', '2025-11-15 20:22:01.161186', 6, 80),
	(84, '12', 8.5, 'https://image.tmdb.org/t/p/w780/5XNQBqnBwPA9yT0jZ0p3s8bbLh0.jpg', 165000000, '2025-11-15 19:27:56.635665', 'Un grupo de exploradores hacen uso de un agujero de gusano recientemente descubierto para superar las limitaciones de los viajes espaciales tripulados y vencer las inmensas distancias que tiene un viaje interestelar.', 169, NULL, 'GB', 'en', 44.5641, 'https://image.tmdb.org/t/p/w500/fbUwSqYIP0isCiJXey3staY3DNn.jpg', '2014-11-05', 746606706, 'interstellar-2014', 'RELEASED', 'Interstellar', 157336, 'https://www.youtube.com/watch?v=UoSSbmD9vqc', '2026-02-14 17:40:28.763077', 38851, 81),
	(85, '12', 8.108, 'https://image.tmdb.org/t/p/w780/8btfz81bOJ2lC7cujYBTw03wzg3.jpg', 80000000, '2025-11-15 19:27:57.785665', 'Cuando los cuerpos de los dos amigos, Aobing y Nezha, están a punto de ser destruidos, se les permite que sus almas sigan existiendo. Su maestro, Taiyi Zhenren, restaura sus cuerpos con la ayuda de una flor de loto. Después de esto, Nezha parte en busca de enfrentar al Rey Dragón del Mar del Este, Ao Guang.', 144, NULL, 'CN', 'zh', 29.3181, 'https://image.tmdb.org/t/p/w500/jz5sGlPGf0cWZ0uJPDc8cSjjFcZ.jpg', '2025-01-29', 2259822417, 'ne-zha-2-2025', 'RELEASED', 'Ne Zha 2', 980477, 'https://www.youtube.com/watch?v=ETlOSBR92Fs', '2026-02-14 17:41:13.387971', 583, 82),
	(86, NULL, 6.139, 'https://image.tmdb.org/t/p/w780/yOFqBpJ0PEkBdQqalDEaeOiaKbz.jpg', 0, '2025-11-15 19:27:58.229818', 'La sociedad secreta de asesinos a sueldo se sume en el caos y surge una nueva generación de asesinos. Sin las viejas reglas, ¿quién se atreverá a reclamar las sombras?', 113, NULL, 'KR', 'ko', 32.4209, 'https://image.tmdb.org/t/p/w500/v1vs4RJyqzckfxPjyWN5zN1dEgH.jpg', '2025-09-26', 0, 'mantis-2025', 'RELEASED', 'Mantis', 1267319, 'https://www.youtube.com/watch?v=PItlVyrf15U', '2025-11-15 20:22:01.607525', 101, 83),
	(87, '16', 7.365, 'https://image.tmdb.org/t/p/w780/tN3pTxkQoP96wtaEahYuRVdUWb2.jpg', 50000000, '2025-11-15 19:27:58.680898', 'Dos jóvenes obsesionados con las conspiraciones secuestran a la directora ejecutiva de una reconocida empresa porque están convencidos de que es un alienígena decidido a destruir la Tierra. Remake del film coreano "Save the Green Planet".', 119, NULL, 'IE', 'en', 22.593, 'https://image.tmdb.org/t/p/w500/2C5Vf9VcoXB7SFFcG8vppW5bmtX.jpg', '2025-10-23', 40796580, 'bugonia-2025', 'RELEASED', 'Bugonia', 701387, 'https://www.youtube.com/watch?v=ugTqv5T0-2s', '2026-02-14 17:41:53.030676', 1389, 84),
	(88, '12', 6.48, 'https://image.tmdb.org/t/p/w780/xQc51OBY9UNF2fQKyAOXZE7az2w.jpg', 80000000, '2025-11-15 19:27:59.099101', 'Dos desconocidos se encuentran por culpa de una misteriosa llamada de teléfono de una mujer a la que no conocen. Amenazando sus vidas y a sus familias, consigue que Rachel y Jerry se metan en situaciones cada vez más peligrosas, utilizando la tecnología de la vida cotidiana para seguir todos y cada uno de sus movimientos. A medida que las cosas se complican, estas dos personas normales y corrientes se convierten en los fugitivos más buscados de USA, y tienen que colaborar para averiguar qué está pasando en realidad. Luchando por sus vidas, se convierten en marionetas de un enemigo sin rostro que, al parecer, cuenta con ilimitados poderes para manipular todo lo que hacen.', 115, NULL, 'DE', 'en', 25.0714, 'https://image.tmdb.org/t/p/w500/o7CK2NaNEjnTc4Oh8ZdkNwAl8OX.jpg', '2008-09-25', 178800000, 'la-conspiracion-del-panico-2008', 'RELEASED', 'La conspiración del pánico', 13027, 'https://www.youtube.com/watch?v=lCDA46ELBKs', '2025-11-15 20:22:18.902766', 3002, 85),
	(89, NULL, 5.9, 'https://image.tmdb.org/t/p/w780/z6Pi72HrGhc50GDhDdREUTEh2xm.jpg', 0, '2025-11-15 19:28:00.025253', 'Liana Rojas, una asistente de estilista hambrienta de creatividad, descubre que el edificio histórico del centro de Los Ángeles donde murió misteriosamente su hermana está embrujado por un asesino en serie que asesinó y descuartizó brutalmente a sus víctimas allí medio siglo antes. Esto obliga a Liana y a sus amigas a encontrar la forma de liberarse y escapar del siniestro fantasma antes de perder sus propias partes del cuerpo.', 85, NULL, 'US', 'en', 29.5781, 'https://image.tmdb.org/t/p/w500/oFTpB1gzS02LtrsenTWxOKbsMpM.jpg', '2025-08-24', 0, 'the-mannequin-2025', 'RELEASED', 'The Mannequin', 1169210, 'https://www.youtube.com/watch?v=CDmQaYnyTes', '2025-11-15 20:22:05.711105', 15, 86),
	(90, '16', 6.1, 'https://image.tmdb.org/t/p/w780/nvdLEfAWcfTNn45SpwBnLGBmOR1.jpg', 3, '2025-11-15 19:28:00.589181', 'Decidido a exigir justicia, Django se enfrenta a peligrosos desafíos y sangrientos enfrentamientos para restaurar el orden en un territorio dominado por la anarquía y la injusticia.', 84, NULL, 'IT', 'it', 28.8187, 'https://image.tmdb.org/t/p/w500/l33smCkbpVFvNxGLILrx1PEyxyw.jpg', '2024-04-22', 0, 'django-imbatible-2024', 'RELEASED', 'Django imbatible', 1357886, 'https://www.youtube.com/watch?v=zPPonm5mXaU', '2025-11-15 20:22:07.095042', 9, 87),
	(91, NULL, 0, 'https://image.tmdb.org/t/p/w780/uzaFkjpTYTcvQWuXqKeaceGcsN3.jpg', 0, '2025-11-15 19:28:01.117144', '', 6, NULL, 'FR', 'fr', 23.7136, 'https://image.tmdb.org/t/p/w500/zOkR66P0IBG6nB11pqhfRQIFP3M.jpg', '2016-09-01', 0, 'the-passenger-2016', 'RELEASED', 'The Passenger', 933523, 'https://www.youtube.com/watch?v=pJcG77s6Wz0', '2025-11-15 20:22:25.681070', 0, 88),
	(92, '16', 7.27, 'https://image.tmdb.org/t/p/w780/1yktYsxkmUtUFTUnCAUaqG6FEiz.jpg', 90000000, '2025-11-15 19:28:01.448512', 'Eve Macarro es una asesina entrenada por la Ruska Roma desde su infancia, la misma organización criminal encargada del adiestramiento de John Wick. En esta violenta historia de venganza, Eve intentará por todos los medios averiguar quién está detrás del asesinato de su padre. En su lucha por conocer la verdad, tendrá que atenerse a las normas de la Alta Mesa y, por supuesto, a las del Hotel Continental, donde descubrirá que existen secretos ocultos sobre su pasado.', 125, NULL, 'US', 'en', 21.4482, 'https://image.tmdb.org/t/p/w500/gQCrYmvCK7JCLXjCGTMRF5Lzr5c.jpg', '2025-06-04', 137216585, 'ballerina-2025', 'RELEASED', 'Ballerina', 541671, 'https://www.youtube.com/watch?v=7o8yNS4CYws', '2026-02-14 17:42:04.151332', 2313, 89),
	(93, '12', 4.8, 'https://image.tmdb.org/t/p/w780/6pffDq3yzdRBxKd6y2O2InRzxZe.jpg', 0, '2025-11-15 19:28:02.644174', 'Yann siempre ha soñado con recorrer el mundo, y cuando la prestigiosa guía Routard busca nuevos colaboradores, decide presentarse y consigue el puesto. Su primer destino es Marrakech, donde debe visitar decenas de lugares. Sin embargo, hay un detalle que lo complica todo: Yann nunca ha viajado antes. Lo que prometía ser una aventura profesional se convierte en un divertido y caótico viaje de descubrimiento personal.', 85, NULL, 'FR', 'fr', 32.1311, 'https://image.tmdb.org/t/p/w500/rGLOPU2BruPF4GmSyPLTbSVeR2p.jpg', '2025-04-02', 0, 'un-guia-muy-perdido-2025', 'RELEASED', 'Un guía muy perdido', 1191666, NULL, '2025-11-15 20:22:03.509944', 36, 90),
	(94, NULL, 6.857, 'https://image.tmdb.org/t/p/w780/3Gjo73aMqNWxNdBa7PeEj7AXJ3E.jpg', 0, '2025-11-15 19:28:02.963351', 'En un tren que está a punto de salir de la estación, suena la alarma que obliga a todos los pasajeros a bajarse. Pero entonces el tren arranca de manera improvista, llevándose a bordo los viajeros que no han tenido tiempo de bajar: los animales de compañía. Asombrados, estos descubren que el tren está bajo el control de Hans, un tejón manipulador y rencoroso, que se quiere vengar de Rex, el perro policía que le puso entre rejas hace años. Como los servicios de rescate no consiguen intervenir en el trayecto montañoso del tren, que circula a toda velocidad, los animales de compañía solo pueden contar con Falcon, un mapache un poco tramposo que hará todo lo posible para salvarles.', 87, NULL, 'FR', 'fr', 32.315, 'https://image.tmdb.org/t/p/w500/dJZRImFs3jdMV1I2OzgjGz1rZv9.jpg', '2025-07-02', 3082436, 'pets-on-a-train-2025', 'RELEASED', 'Pets on a Train', 1107216, 'https://www.youtube.com/watch?v=QH8V0wpg18A', '2025-11-15 20:22:03.012513', 28, 91),
	(95, 'A', 6.6, 'https://image.tmdb.org/t/p/w780/MrcSSzWGsXf2IUJpjPPFLlNbjX.jpg', 32000000, '2025-11-15 19:28:04.027197', 'Gabby decide irse de viaje con su abuela Gigi rumbo a la maravillosa ciudad de Cat Francisco. Pero cuando la casa de muñecas de Gabby, su posesión más preciada, acaba en manos de Vera, una excéntrica dama obsesionada con los gatos, Gabby emprende una aventura por el mundo real para volver a reunir a sus mininos y salvar la casa de muñecas antes de que sea demasiado tarde.', 98, NULL, 'US', 'en', 30.8103, 'https://image.tmdb.org/t/p/w500/ruAIbycacQIIXeTf4xh1r1NjvJa.jpg', '2025-09-13', 67600000, 'la-casa-de-munecas-de-gabby-la-pelicula-2025', 'RELEASED', 'La casa de muñecas de Gabby: La película', 1280282, 'https://www.youtube.com/watch?v=speJOtNWaXw', '2025-11-15 20:22:04.857567', 38, 92),
	(96, NULL, 6.111, 'https://image.tmdb.org/t/p/w780/dZlNjVsRSCbupp3i0ltwMJG5yMu.jpg', 0, '2025-11-15 19:28:04.975803', 'Comedia en formato de falso documental que combina fútbol, humor e intriga internacional. El modesto St Peter’s Celtic, un equipo amateur, debe enfrentarse al vigente campeón en la primera ronda de la FAI Cup. Su temperamental segundo entrenador, viral tras un incidente en el sorteo, intenta formar un equipo competitivo mientras lidia con un equipo de rodaje y una investigación por amaño de partidos. Inspirada en una exitosa serie irlandesa, El entrenador mezcla sátira deportiva, caos mediático y apuestas ilegales en un relato tan divertido como imprevisible.', 89, NULL, 'IE', 'en', 25.0496, 'https://image.tmdb.org/t/p/w500/24zTubOP9RCJGVTpUxpQ92JxflC.jpg', '2025-04-11', 0, 'el-entrenador-2025', 'RELEASED', 'El entrenador', 1268552, 'https://www.youtube.com/watch?v=ZyW0MoZI9hY', '2025-11-15 20:22:19.403525', 9, 93),
	(97, NULL, 7, 'https://image.tmdb.org/t/p/w780/tm87rqU4zCiDIJKJDHmmhFSjXiX.jpg', 0, '2025-11-15 19:28:05.422092', '', 0, NULL, 'TW', 'zh', 31.4517, 'https://image.tmdb.org/t/p/w500/eoUcppppVNj8BkgBDkZTv82x3tx.jpg', '2025-08-21', 0, '2025-1468057', 'RELEASED', '角頭－鬥陣欸', 1468057, NULL, '2025-11-15 20:22:04.332917', 3, 94),
	(98, 'A', 8.198, 'https://image.tmdb.org/t/p/w780/g7CHF8gTLGooTbP4GznIGwaqAGL.jpg', 175000000, '2025-11-15 19:28:06.133795', 'Un joven aspirante a músico llamado Miguel se embarca en un viaje extraordinario a la mágica tierra de sus ancestros. Allí, el encantador embaucador Héctor se convierte en su inesperado amigo y le ayuda a descubrir los misterios detrás de las historias y tradiciones de su familia.', 109, NULL, 'US', 'en', 21.0935, 'https://image.tmdb.org/t/p/w500/vwsFGblLYxWBNjg9pdWN1Mm5YfW.jpg', '2017-10-27', 814641172, 'coco-2017', 'RELEASED', 'Coco', 354912, 'https://www.youtube.com/watch?v=4o4ovPKvTOI', '2026-02-14 17:42:16.021115', 20653, 95),
	(99, '16', 5.116, 'https://image.tmdb.org/t/p/w780/en0NbTEjf3qKokHvwGeaq9DBPIP.jpg', 0, '2025-11-15 19:28:06.655770', 'Para llevar a cabo un audaz robo, una banda de forajidos inadaptados tendrá que hacer algo por primera vez: confiar los unos en los otros... y en un brujo trasnochado.', 83, NULL, 'US', 'en', 25.2541, 'https://image.tmdb.org/t/p/w500/7ML1ZEpWjR8IKEb2wpK3k4KMvhK.jpg', '2025-10-29', 0, 'las-ratas-una-historia-de-the-witcher-2025', 'RELEASED', 'Las Ratas: Una historia de \'The Witcher\'', 1571470, NULL, '2025-11-15 20:22:17.485670', 73, 96),
	(100, '16', 7.673, 'https://image.tmdb.org/t/p/w780/sNhzcUw5cg4JwICjnHZ5XhTKNrU.jpg', 65000000, '2025-11-15 19:28:07.477181', 'Ambientada hace 300 años en la Nación Comanche. Naru es una joven guerrera, feroz y altamente hábil, que se crió a la sombra de algunos de los cazadores más legendarios que deambulan por las Grandes Llanuras. Cuando el peligro amenaza su campamento, se dispone a proteger a su gente. La presa a la que acecha y, en última instancia, se enfrenta, resulta ser un depredador alienígena evolucionado con un arsenal técnicamente avanzado, lo que deriva en un enfrentamiento cruel y aterrador entre los dos adversarios.', 100, NULL, 'US', 'en', 27.2787, 'https://image.tmdb.org/t/p/w500/sNAMqQ9T7YnXnvUSufeWzaRgK6Y.jpg', '2022-08-02', 0, 'predator-la-presa-2022', 'RELEASED', 'Predator: La presa', 766507, 'https://www.youtube.com/watch?v=7AWRZuYlEFU', '2025-11-15 20:22:09.612709', 7336, 3),
	(101, '12', 6.391, 'https://image.tmdb.org/t/p/w780/5SVRVwBfHCIkffiq0MmbdvnHWSz.jpg', 0, '2025-11-15 19:28:08.260122', 'Cuando un misil sin identificar es lanzado contra EE. UU., se desata una carrera a contrarreloj por descubrir al responsable y decidir cómo responder.', 112, NULL, 'US', 'en', 29.5806, 'https://image.tmdb.org/t/p/w500/ku4vTAnfTgO5oPPaHqyLtP39LrE.jpg', '2025-10-02', 181125, 'una-casa-llena-de-dinamita-2025', 'RELEASED', 'Una casa llena de dinamita', 1290159, 'https://www.youtube.com/watch?v=_wpw2QHJNco', '2025-11-15 20:22:05.209866', 726, 97),
	(102, '12', 6.929, 'https://image.tmdb.org/t/p/w780/5IHYBbVG1qWv9oNjyh6ZRnn9ZFh.jpg', 0, '2025-11-15 19:28:08.443461', 'Una hotelera ambiciosa viaja a Málaga con su hija, quien acepta a regañadientes. Allí, encuentran lo que buscaban en la idílica finca de mangos de un agricultor.', 96, NULL, 'DK', 'da', 23.9343, 'https://image.tmdb.org/t/p/w500/AqqpXEBk5c2EuDgA6EVMxkrdh9I.jpg', '2025-11-06', 0, 'mango-2025', 'RELEASED', 'Mango', 1426792, 'https://www.youtube.com/watch?v=UHrkf6Y_4ag', '2025-11-15 20:22:24.627745', 22, 98),
	(103, NULL, 5.111, 'https://image.tmdb.org/t/p/w780/znMUHotZRTcyIFWFz2bvcpSx6YP.jpg', 0, '2025-11-15 19:28:09.303682', 'En el año 2046, donde existen los viajes en el tiempo y los combates a muerte son un deporte, un multimillonario realiza improbables peleas televisadas para descubrir al luchador definitivo: samuráis vs vikingos, caballeros vs policías, cowboys vs espartanos… Un policía de los 80 deberá participar en el programa y ganar todos los combates para poder regresar a su pasado.', 108, NULL, 'CA', 'en', 26.6019, 'https://image.tmdb.org/t/p/w500/vmRtkq80lG1SO4wDscDUbuuoa3n.jpg', '2024-10-09', 0, 'el-luchador-definitivo-2024', 'RELEASED', 'El luchador definitivo', 1053008, 'https://www.youtube.com/watch?v=vfzGdEv3EX0', '2025-11-15 20:22:12.070552', 18, 99),
	(104, NULL, 7.6, 'https://image.tmdb.org/t/p/w780/xt3zBU1Ir4JGtVgbKRhi8aSQkpw.jpg', 0, '2025-11-15 19:28:09.698569', '', 90, NULL, 'US', 'en', 23.8435, 'https://image.tmdb.org/t/p/w500/gzuLKf3AWvV6SlXL4ZYGUn1FNdl.jpg', '2024-11-01', 0, 'the-devil-s-trap-2024', 'RELEASED', 'The Devil’s Trap', 873967, 'https://www.youtube.com/watch?v=Tw5X1eYFFPM', '2025-11-15 20:22:25.008624', 5, 100),
	(105, '16', 6, 'https://image.tmdb.org/t/p/w780/cNmGq1bfUDhrZEHvJ77zwiWfoNA.jpg', 0, '2025-11-15 19:28:10.216054', 'Un elixir revive a los muertos en un pueblo. Una familia con conflictos internos deberá unir fuerzas y luchar para sobrevivir cuando su ciudad natal peligra.', 118, NULL, 'ID', 'id', 24.5117, 'https://image.tmdb.org/t/p/w500/eAvV8ITNS4M8Zt8sxOK6g3XBLBr.jpg', '2025-10-22', 0, 'el-elixir-de-la-inmortalidad-2025', 'RELEASED', 'El elixir de la inmortalidad', 1306525, 'https://www.youtube.com/watch?v=XL48F7LGoig', '2025-11-15 20:22:22.008361', 129, 101),
	(106, '18', 7.1, 'https://image.tmdb.org/t/p/w780/uIpJPDNFoeX0TVml9smPrs9KUVx.jpg', 50000000, '2025-11-15 19:28:10.926520', 'Acosada por una violenta pesadilla recurrente, la estudiante universitaria Stefanie se dirige a casa para localizar a la única persona que podría ser capaz de romper el ciclo y salvar a su familia de la espeluznante muerte que inevitablemente les espera a todos.', 110, NULL, 'US', 'en', 20.7704, 'https://image.tmdb.org/t/p/w500/frNkbclQpexf3aUzZrnixF3t5Hw.jpg', '2025-05-14', 315954739, 'destino-final-lazos-de-sangre-2025', 'RELEASED', 'Destino final: Lazos de sangre', 574475, 'https://www.youtube.com/watch?v=jO0pT3Q4Rms', '2026-02-14 17:42:21.582117', 2616, 102),
	(107, NULL, 5.5, 'https://image.tmdb.org/t/p/w780/8JB2ermx5Rg7pL8GtzJ8fpvIdwi.jpg', 0, '2025-11-15 19:28:11.468981', 'Kira, casada con Mads desde hace varios años, ha pasado los dos últimos en una centro de salud mental. Cuando regresa a su casa con Mads y sus dos hijos, no está totalmente recuperada y no sabe muy bien cómo comportarse. Además, la atormenta la sospecha de que Mads haya tenido una aventura durante su ausencia. La cuestión es si su amor es suficientemente fuerte como para superar todos esos problemas.', 93, NULL, 'DK', 'da', 29.5108, 'https://image.tmdb.org/t/p/w500/wr26nFLM7AeV2Zy31hiwvtvmMsD.jpg', '2001-10-26', 0, 'kira-s-reason-a-love-story-2001', 'RELEASED', 'Kira\'s Reason: A Love Story', 15842, 'https://www.youtube.com/watch?v=JVNpVbMU5HQ', '2025-11-15 20:22:06.140064', 12, 103),
	(108, '16', 6.742, 'https://image.tmdb.org/t/p/w780/ltIxMsVJD9iiD5V4SBp4kv3KhVb.jpg', 20000000, '2025-11-15 19:28:11.823303', 'Intenso drama psicológico y comedia negra que sigue a Grace (Jennifer Lawrence), una joven madre y escritora que comienza a sufrir una profunda depresión posparto tras mudarse con su esposo Jackson (Robert Pattinson) a la zona rural de Montana, buscando una vida más tranquila. A medida que la salud mental de Grace se deteriora, su matrimonio se ve afectado, transitando territorios de psicosis, tensión y desesperación. La película explora con crudeza y complejidad temas de maternidad, salud mental y el impacto de la depresión en la pareja. Dirigida por Lynne Ramsay, el filme está basado en la novela de Ariana Harwicz y fue aclamado en el Festival de Cannes 2025, destacando las actuaciones poderosas de Lawrence y Pattinson, junto a un elenco que incluye a LaKeith Stanfield, Nick Nolte y Sissy Spacek. Con una narrativa inquietante y una atmósfera absorbente, "Die My Love" invita a una reflexión profunda sobre las luchas internas y el amor en medio del caos emocional.', 118, NULL, 'US', 'en', 27.5167, 'https://image.tmdb.org/t/p/w500/xDkVW9SkU9QzUqjiB9uAmAsWfO9.jpg', '2025-10-06', 2610583, 'die-my-love-2025', 'RELEASED', 'Die My Love', 1033148, 'https://www.youtube.com/watch?v=2jzXHW6Qe70', '2025-11-15 20:22:08.842363', 31, 104),
	(109, NULL, 7.075, 'https://image.tmdb.org/t/p/w780/4damV6u8Za9p03SH9jvKr3TwHQC.jpg', 0, '2025-11-15 19:28:13.134741', 'En Avispatropolis, el intrépido capitán Avispa emerge como un protector ejemplar de la ciudad, cuyo coraje y convicciones siempre prevalecen sobre las fuerzas del mal. Su poder inquebrantable se nutre de una sinceridad absoluta, pues perdería su fuerza si se atreviera a tejer engaños. Solo en pos de causas nobles se permite desviarse de la verdad. Como es común en historias de este tipo, el capitán Avispa está rodeado de una constelación de amigos cercanos y archienemigos, cuyas historias tienen su origen en las canciones del artista.', 88, NULL, 'DO', 'es', 27.4934, 'https://image.tmdb.org/t/p/w500/zmthz3CuFljmBQcfuaz4hBNwbQ0.jpg', '2024-04-04', 0, 'capitan-avispa-2024', 'RELEASED', 'Capitán Avispa', 1198426, 'https://www.youtube.com/watch?v=DXfcvmQ6LoU', '2025-11-15 20:22:09.396188', 40, 105),
	(110, NULL, 6.3, 'https://image.tmdb.org/t/p/w780/8VZt1Uo07F3CMhzpl8BjIzVOdBh.jpg', 0, '2025-11-15 19:28:14.608516', 'Los guardabosques Angelica y Viktor investigan la desaparición de una mujer en una reserva natural sueca. Exploran cuevas encantadas, enfrentan su pasado y descubren oscuros secretos mientras luchan contra una criatura mítica.', 95, NULL, 'SE', 'sv', 26.8992, 'https://image.tmdb.org/t/p/w500/zzxIUS5GFMmDVActt9IPMQ0XZde.jpg', '2024-03-22', 0, 'from-darkness-2024', 'RELEASED', 'From Darkness', 1202863, NULL, '2025-11-15 20:22:10.802999', 13, 106),
	(111, '18', 6.838, 'https://image.tmdb.org/t/p/w780/6LVSrgm83UYWlrLTCVGmWhFKYO0.jpg', 79000000, '2025-11-15 19:28:15.247315', 'Han pasado casi 30 años desde que el "Club de los Perdedores", formado por Bill, Beverly, Richie, Ben, Eddie, Mike y Stanley, se enfrentaran al macabro y despiadado Pennywise (Bill Skarsgård). En cuanto tuvieron oportunidad, abandonaron el pueblo de Derry, en el estado de Maine, que tantos problemas les había ocasionado. Sin embargo, ahora, siendo adultos, parece que no pueden escapar de su pasado. Todos deberán enfrentarse de nuevo al temible payaso para descubrir si de verdad están preparados para superar sus traumas de la infancia.', 169, NULL, 'US', 'en', 26.6237, 'https://image.tmdb.org/t/p/w500/9oERKIVyTWpHNum3STVsAGD4ojz.jpg', '2019-09-04', 473123154, 'it-capitulo-2-2019', 'RELEASED', 'It: Capítulo 2', 474350, 'https://www.youtube.com/watch?v=nN1CqQgWFCM', '2025-11-15 20:22:11.046976', 9228, 107),
	(112, '7', 6.353, 'https://image.tmdb.org/t/p/w780/2Nti3gYAX513wvhp8IiLL6ZDyOm.jpg', 150000000, '2025-11-15 19:28:15.465797', 'Cuatro inadaptados se encuentran luchando con problemas ordinarios cuando de repente se ven arrastrados a través de un misterioso portal al Mundo Exterior: un extraño país de las maravillas cúbico que se nutre de la imaginación. Para volver a casa, tendrán que dominar este mundo mientras se embarcan en una búsqueda mágica con un inesperado experto artesano, Steve.', 100, NULL, 'SE', 'en', 28.564, 'https://image.tmdb.org/t/p/w500/mFjtmmh4RtK9tLv1aPnUsl6st3m.jpg', '2025-03-31', 957949195, 'una-pelicula-de-minecraft-2025', 'RELEASED', 'Una película de Minecraft', 950387, 'https://www.youtube.com/watch?v=NOAmJa-dhCA', '2025-11-15 20:22:07.520255', 2486, 108),
	(113, '16', 5.916, 'https://image.tmdb.org/t/p/w780/cc48kfehVAkgG73BsPcFLMoxa8h.jpg', 0, '2025-11-15 19:28:16.162095', 'En los deslumbrantes casinos de Macao, un jugador que huye de su pasado queda fascinado por una enigmática mujer en la mesa de bacará.', 102, NULL, 'DE', 'en', 26.5421, 'https://image.tmdb.org/t/p/w500/jd4p4omMZIywNP5vYbrPUfL1phX.jpg', '2025-10-15', 0, 'maldita-suerte-2025', 'RELEASED', 'Maldita suerte', 1272166, 'https://www.youtube.com/watch?v=XrLC-Hsdwbo', '2025-11-15 20:22:12.502402', 172, 109),
	(114, NULL, 6.024, 'https://image.tmdb.org/t/p/w780/168dp7vy3kwOehcMpFaLOfB52NV.jpg', 1000000, '2025-11-15 19:28:16.691007', 'Dos parejas reservan por error la misma propiedad de alquiler vacacional para el mismo fin de semana. Su escapada romántica pronto se convierte en un retorcido laberinto de sexo, mentiras y supervivencia.', 94, NULL, 'US', 'en', 25.1787, 'https://image.tmdb.org/t/p/w500/bV9sEJiznCmZu5Gf35N8m7D7OpX.jpg', '2025-10-02', 1688650, 'bone-lake-2025', 'RELEASED', 'Bone Lake', 1330421, 'https://www.youtube.com/watch?v=SOVT2ServZE', '2025-11-15 20:22:18.062475', 62, 110),
	(115, '16', 6.8, 'https://image.tmdb.org/t/p/w780/czmBLRl98O2nTIzU0td3wDS78pN.jpg', 22600000, '2025-11-15 19:28:16.988015', 'Concebida por los rockeros Guest, McKean, Reiner y Shearer, Spinal Tap II sigue a la banda más ruidosa y puntual de Inglaterra, que se reúne tras 15 años de parón para dar un último concierto.', 84, NULL, 'US', 'en', 21.7728, 'https://image.tmdb.org/t/p/w500/eDeRY3vKQzox1qalZolHMfxmGD.jpg', '2025-09-12', 1674926, 'spinal-tap-ii-el-final-continua-2025', 'RELEASED', 'Spinal Tap II: El final continúa', 975225, 'https://www.youtube.com/watch?v=1ryx-eRSwSs', '2025-11-15 20:22:34.155909', 20, 111),
	(116, '16', 6.3, 'https://image.tmdb.org/t/p/w780/2nwhxEyefcIFKwOrSigiamoIzu2.jpg', 0, '2025-11-15 19:28:19.506412', 'El camionero del hielo Mike McCann, cumpliendo el último deseo de su hermano, viaja a Nepal para esparcir sus cenizas en el monte Everest. En un autobús turístico que atraviesa el territorio de la tristemente célebre Ruta al Cielo, Mike y su guía se topan con un grupo de mercenarios y deberán luchar para salvar sus vidas.', 113, NULL, 'US', 'en', 25.8927, 'https://image.tmdb.org/t/p/w500/5Wb1sOZvFulzzJE5JDWCnFSCvJ5.jpg', '2025-06-27', 0, 'ice-road-venganza-2025', 'RELEASED', 'Ice Road: Venganza', 1119878, 'https://www.youtube.com/watch?v=K6lJh9ADfbQ', '2025-11-15 20:22:15.605100', 514, 112),
	(117, '16', 6.503, 'https://image.tmdb.org/t/p/w780/vfbryKoLrisx8Xh37OaTjTyrFY0.jpg', 50000000, '2025-11-15 19:28:20.029479', 'A finales de los 90, el prometedor artista marcial mixto Mark Kerr aspira a convertirse en el mejor luchador del mundo. Sin embargo, también debe luchar contra su adicción a los opioides y una relación inestable con su novia Dawn.', 123, NULL, 'US', 'en', 25.624, 'https://image.tmdb.org/t/p/w500/3qfyfrY4Sa0fUPVH0rcsfGZZNoY.jpg', '2025-10-01', 10057115, 'the-smashing-machine-2025', 'RELEASED', 'The Smashing Machine', 760329, 'https://www.youtube.com/watch?v=u4A8zfMClCM', '2025-11-15 20:22:16.009975', 174, 113),
	(118, '16', 8.526, 'https://image.tmdb.org/t/p/w780/dqK9Hag1054tghRQSqLSfrkvQnA.jpg', 185000000, '2025-11-15 19:28:20.975049', 'Batman/Bruce Wayne regresa para continuar su guerra contra el crimen. Con la ayuda del teniente Jim Gordon y del Fiscal del Distrito Harvey Dent, Batman se propone destruir el crimen organizado en la ciudad de Gotham. El triunvirato demuestra su eficacia, pero, de repente, aparece Joker, un nuevo criminal que desencadena el caos y tiene aterrados a los ciudadanos.', 152, NULL, 'GB', 'en', 31.5574, 'https://image.tmdb.org/t/p/w500/8QDQExnfNFOtabLDKqfDQuHDsIg.jpg', '2008-07-16', 1004558444, 'el-caballero-oscuro-2008', 'RELEASED', 'El caballero oscuro', 155, 'https://www.youtube.com/watch?v=jXAYAN6jO5k', '2026-02-14 17:41:03.718758', 35164, 81),
	(119, 'A', 7, 'https://image.tmdb.org/t/p/w780/zo8CIjJ2nfNOevqNajwMRO6Hwka.jpg', 150000000, '2025-11-15 19:28:21.414830', 'Tras recibir una inesperada llamada de sus antepasados, Vaiana debe viajar a los lejanos mares de Oceanía y adentrarse en peligrosas aguas perdidas para vivir una aventura sin precedentes.', 100, NULL, 'CA', 'en', 21.6822, 'https://image.tmdb.org/t/p/w500/bit1B5F7IQydiWqdwAAD8f9TkXs.jpg', '2024-11-21', 1059242164, 'vaiana-2-2024', 'RELEASED', 'Vaiana 2', 1241982, 'https://www.youtube.com/watch?v=5REqdy3W3N4', '2026-02-14 17:41:59.420413', 2923, 114),
	(120, '12', 7.678, 'https://image.tmdb.org/t/p/w780/9nhjGaFLKtddDPtPaX5EmKqsWdH.jpg', 70000000, '2025-11-15 19:28:22.106306', 'Mandan a dos operativos de élite a vigilar lados opuestos de un misterioso abismo y allí intiman desde la distancia, pero deberán aunar fuerzas para sobrevivir al mal que esconde el abismo.', 127, NULL, 'US', 'en', 26.3603, 'https://image.tmdb.org/t/p/w500/3s0jkMh0YUhIeIeioH3kt2X4st4.jpg', '2025-02-13', 0, 'el-abismo-secreto-2025', 'RELEASED', 'El abismo secreto', 950396, 'https://www.youtube.com/watch?v=VuzKAeHGuMI', '2025-11-15 20:22:13.748905', 3146, 6),
	(121, 'A', 7.333, 'https://image.tmdb.org/t/p/w780/xEY0MV2jSQBz9iOJfCFvLTiPGMA.jpg', 75000000, '2025-11-15 19:28:22.779844', 'Un equipo del FBI debe enfrentarse a una banda de criminales expertos en magia. Ellos son \'los cuatro jinetes\', un grupo formado por los mejores ilusionistas del mundo, dedicado a realizar grandes robos contra hombres de negocios corruptos. Su gran golpe es pasar desapercibidos para hacer llover el dinero robado a su público. En un mundo de magia y espectáculo, nada es lo que parece.', 115, NULL, 'US', 'en', 26.1448, 'https://image.tmdb.org/t/p/w500/iN3fPrPLozgPDrHO1IILh1Cx0C3.jpg', '2013-05-29', 351723989, 'ahora-me-ves-2013', 'RELEASED', 'Ahora me ves', 75656, 'https://www.youtube.com/watch?v=K1lguoJMFBI', '2025-11-15 20:22:14.110043', 16158, 115),
	(122, NULL, 6.2, 'https://image.tmdb.org/t/p/w780/vHa1nK4YI0ew4Bz4F7O33kiwR6O.jpg', 0, '2025-11-15 19:28:23.347155', 'Mientras la mayor parte de emigrantes comienzan a regresar a Alemania y a sus diferentes países de origen, otros, sin embargo,  están desesperados por alcanzar las orillas de la dictatorial Argentina de Perón.', 90, NULL, 'DE', 'de', 25.9988, 'https://image.tmdb.org/t/p/w500/65H4J3ghS4RfN5X2W5H9OYEEuP9.jpg', '2014-02-15', 0, 'falsa-libertad-2014', 'RELEASED', 'Falsa libertad', 256553, NULL, '2025-11-15 20:22:14.649827', 4, 116),
	(123, 'A', 7.551, 'https://image.tmdb.org/t/p/w780/p5ozvmdgsmbWe0H8Xk7Rc8SCwAB.jpg', 200000000, '2025-11-15 19:28:24.899601', 'Riley entra en la adolescencia y el Cuartel General de su cabeza sufre una repentina reforma para hacerle hueco a algo totalmente inesperado propio de la pubertad: ¡nuevas emociones! Alegría, Tristeza, Ira, Miedo y Asco, con años de impecable gestión a sus espaldas (según ellos...) no saben muy bien qué sentir cuando aparece con enorme ímpetu Ansiedad. Y no viene sola: le acompañan envidia, vergüenza y aburrimiento.', 96, NULL, 'US', 'en', 25.5361, 'https://image.tmdb.org/t/p/w500/lE3DCRI7bQgHSiIuEPcFiXpiuGV.jpg', '2024-06-11', 1698863816, 'del-reves-2-inside-out-2-2024', 'RELEASED', 'Del revés 2 (Inside Out 2)', 1022789, 'https://www.youtube.com/watch?v=wi4E2-Am9hA', '2025-11-15 20:22:16.499031', 6240, 117),
	(124, NULL, 5.8, 'https://image.tmdb.org/t/p/w780/5xgxXZ9C8KZDg0xWbk6rX0XcO9T.jpg', 0, '2025-11-15 19:28:26.194983', '', 80, NULL, 'US', 'fr', 25.4785, 'https://image.tmdb.org/t/p/w500/w0wjPQKhlqisSbylf1sWZiNyc2h.jpg', '2025-07-29', 0, 'night-carnage-2025', 'RELEASED', 'Night Carnage', 986206, 'https://www.youtube.com/watch?v=QgT_a2ilPMQ', '2025-11-15 20:22:16.969424', 60, 118),
	(125, '16', 6.684, 'https://image.tmdb.org/t/p/w780/fTrQsdMS2MUw00RnzH0r3JWHhts.jpg', 40000000, '2025-11-15 19:28:27.773438', 'Levon Cade dejó atrás una condecorada carrera militar en las operaciones encubiertas para vivir una vida sencilla trabajando en la construcción. Pero cuando la hija de su jefe, que para él es como de la familia, es secuestrada por traficantes de personas, su búsqueda para traerla a casa descubre un mundo de corrupción mucho mayor de lo que jamás podría haber imaginado.', 116, NULL, 'GB', 'en', 28.1442, 'https://image.tmdb.org/t/p/w500/aG50Ad3UV8cCQWpNWSHHUqgKGNB.jpg', '2025-03-26', 88200711, 'a-working-man-2025', 'RELEASED', 'A Working Man', 1197306, 'https://www.youtube.com/watch?v=gGOXUdcE6hk', '2026-02-09 17:26:40.086708', 1768, 119),
	(126, '16', 5.227, 'https://image.tmdb.org/t/p/w780/vFktlnv1cEKeyCuSLd02DVNUoRC.jpg', 5000000, '2025-11-15 19:28:30.609107', 'Secuela de "The Blair Witch Project". Unos estudiantes se adentran en los bosques Black Hills de Maryland para intentar descubrir qué pasó en la desaparición de la hermana de James, relacionada con la leyenda de la bruja de Blair. Pronto una pareja de lugareños se ofrece a ser sus guías en los bosques.', 89, NULL, 'CA', 'en', 24.8167, 'https://image.tmdb.org/t/p/w500/umYep3ZxgnyWZ2HZIvnaklynJjO.jpg', '2016-09-15', 45172994, 'blair-witch-2016', 'RELEASED', 'Blair Witch', 351211, 'https://www.youtube.com/watch?v=tRsYzxjLmm0', '2025-11-15 20:22:19.849025', 1985, 120),
	(127, '7', 6.1, 'https://image.tmdb.org/t/p/w780/i4o2aPGlnsxfPmDPF5lmlgjScyv.jpg', 0, '2025-11-15 19:28:32.770994', 'Cuando los villanos más malos y repugnantes se apoderan de la ciudad con un truquito, dos niños valientes se alían con una familia de animales mágicos para acabar con ellos.', 99, NULL, 'GB', 'en', 24.7471, 'https://image.tmdb.org/t/p/w500/fAeHnC35RtbYLm5tRGLveLa0YvH.jpg', '2025-10-17', 0, 'los-cretinos-2025', 'RELEASED', 'Los Cretinos', 927254, 'https://www.youtube.com/watch?v=dMZI0FkYLEs', '2025-11-15 20:22:20.327201', 64, 121),
	(128, '18', 7.559, 'https://image.tmdb.org/t/p/w780/ufpeVEM64uZHPpzzeiDNIAdaeOD.jpg', 200000000, '2025-11-15 19:28:37.939994', 'Un apático Wade Wilson se afana en la vida civil tras dejar atrás sus días como Deadpool, un mercenario moralmente flexible. Pero cuando su mundo natal se enfrenta a una amenaza existencial, Wade debe volver a vestirse a regañadientes con un Lobezno aún más reacio a ayudar.', 127, NULL, 'US', 'en', 24.6513, 'https://image.tmdb.org/t/p/w500/9TFSqghEHrlBMRR63yTx80Orxva.jpg', '2024-07-24', 1338073645, 'deadpool-y-lobezno-2024', 'RELEASED', 'Deadpool y Lobezno', 533535, 'https://www.youtube.com/watch?v=rrgsj6S0_4A', '2026-02-14 17:41:35.272550', 8257, 122),
	(129, '18', 6.292, 'https://image.tmdb.org/t/p/w780/7PoWlbQg7ZxgwofFRrkytvpLvJD.jpg', 35000000, '2025-11-15 19:28:39.485758', 'Un grupo de policías de Los Angeles se enfrenta a un misterioso asesino que descuartiza a sus víctimas con un salvajismo inusitado. Pronto, el jefe del grupo, el capitán Harrigan, descubrirá que su enemigo es un alienígena llegado a la Tierra con el único propósito de practicar la caza.', 108, NULL, 'US', 'en', 24.6216, 'https://image.tmdb.org/t/p/w500/92Lqy293CqAExYXlqDc456eYCWp.jpg', '1990-11-21', 57120318, 'depredador-2-1990', 'RELEASED', 'Depredador 2', 169, 'https://www.youtube.com/watch?v=DCifBGu9NOA', '2025-11-15 20:22:21.027015', 3592, 123),
	(130, '18', 7.5, 'https://image.tmdb.org/t/p/w780/yth78N88nwokepnOe5atwPGfTL1.jpg', 0, '2025-11-15 19:28:41.201024', 'Después de que su esposa e hija sean brutalmente asesinadas a manos de unos misteriosos sicarios vinculados a un sanguinario sindicato del crimen organizado, An Bai (Tony Jaa), un veterano experto en Muay Thai, se propone desentrañar la verdad e inicia una implacable misión de venganza.', 106, NULL, 'CN', 'zh', 24.5802, 'https://image.tmdb.org/t/p/w500/h8DNi9XJKUS2nOzU5qEFEg7R0N6.jpg', '2024-12-05', 0, 'venganza-implacable-2024', 'RELEASED', 'Venganza implacable', 1382406, 'https://www.youtube.com/watch?v=TrfooLjn7YY', '2025-11-15 20:22:21.570657', 139, 124),
	(131, '12', 8.716, 'https://image.tmdb.org/t/p/w780/zfbjgQE1uSd9wiPTX4VzsLi0rGG.jpg', 25000000, '2025-11-15 19:28:41.755503', 'Acusado del asesinato de su mujer, Andrew Dufresne, tras ser condenado a cadena perpetua, es enviado a la prisión de Shawshank. Con el paso de los años conseguirá ganarse la confianza del director del centro y el respeto de sus compañeros presidiarios, especialmente de Red, el jefe de la mafia de los sobornos.', 143, NULL, 'US', 'en', 26.096, 'https://image.tmdb.org/t/p/w500/uRRTV7p6l2ivtODWJVVAMRrwTn2.jpg', '1994-09-23', 28341469, 'cadena-perpetua-1994', 'RELEASED', 'Cadena perpetua', 278, 'https://www.youtube.com/watch?v=4u87tmlj4oE', '2026-02-14 17:41:31.059855', 29715, 125),
	(132, '12', 7.371, 'https://image.tmdb.org/t/p/w780/cT9ZfwoPDk8JbgkessmQgxAWiaM.jpg', 25000000, '2025-11-15 19:28:41.976814', 'Con el futuro de la existencia humana en juego, Gemma se da cuenta de que la única opción es resucitar a M3GAN y darle unas cuantas mejoras, haciéndola más rápida, más fuerte y más letal.', 120, NULL, 'US', 'en', 24.3045, 'https://image.tmdb.org/t/p/w500/zgsdwQ6XciR0IzgeRXyKzVhzVzP.jpg', '2025-06-25', 39085942, 'm3gan-2-0-2025', 'RELEASED', 'M3GAN 2.0', 1071585, 'https://www.youtube.com/watch?v=P9Ku1BE3sDQ', '2025-11-15 20:22:22.737592', 970, 126),
	(133, '12', 7.599, 'https://image.tmdb.org/t/p/w780/cd8YDn7M0lfaHhZdU6MvCDxPalP.jpg', 350000000, '2025-11-15 19:28:42.829341', 'Más de una década después de los acontecimientos de \'Avatar\', los Na\'vi Jake Sully, Neytiri y sus hijos viven en paz en los bosques de Pandora hasta que regresan los hombres del cielo. Entonces comienzan los problemas que persiguen sin descanso a la familia Sully, que decide hacer un gran sacrificio para mantener a su pueblo a salvo y seguir ellos con vida.', 192, NULL, 'US', 'en', 33.9041, 'https://image.tmdb.org/t/p/w500/ckeTumMS4G31UQ9NNkmtW2QhfMF.jpg', '2022-12-14', 2353096253, 'avatar-el-sentido-del-agua-2022', 'RELEASED', 'Avatar: El sentido del agua', 76600, 'https://www.youtube.com/watch?v=inT3MvpxRqE', '2026-02-14 17:40:55.073925', 13680, 127),
	(134, NULL, 7.54, 'https://image.tmdb.org/t/p/w780/m0VOz5KTHxGZB5iegG48U5EjHQD.jpg', 0, '2025-11-15 19:28:43.031222', 'Tras buscar a su padre en Internet, una joven que se siente atraída por la gente establece inesperadamente un estrecho vínculo con un hombre afligido y sin hijos que se llama igual que su padre en Facebook. Inspirada en una historia real.', 102, NULL, 'US', 'en', 24.0293, 'https://image.tmdb.org/t/p/w500/22TqqVfuSrZhPIdtpnNm92sQ4cS.jpg', '2025-03-20', 237416, 'un-like-de-bob-trevino-2025', 'RELEASED', 'Un "like" de Bob Trevino', 1169789, 'https://www.youtube.com/watch?v=ByhOQW5ooSE', '2025-11-15 20:22:23.732469', 75, 128),
	(135, 'A', 6.953, 'https://image.tmdb.org/t/p/w780/bvATKuxz9Wu53caHUJ7SP38gFQ3.jpg', 150000000, '2025-11-15 19:28:43.241357', 'Cuenta la historia de Elio, un niño de 11 años, que lucha por encajar hasta que de repente es transportado por extraterrestres y es elegido para ser el embajador galáctico de la Tierra.', 98, NULL, 'US', 'en', 23.9762, 'https://image.tmdb.org/t/p/w500/fqF7z5A8kFIrNtSdpEfjE539fna.jpg', '2025-06-18', 153797125, 'elio-2025', 'RELEASED', 'Elio', 1022787, 'https://www.youtube.com/watch?v=U0VCAsn51ZU', '2025-11-15 20:22:24.084898', 647, 129),
	(136, '16', 5.629, 'https://image.tmdb.org/t/p/w780/b96OdaJce7Zu70NYe8vmlfOQUUN.jpg', 88000000, '2025-11-15 19:28:45.249917', 'Cuando el pequeño Rory (Jacob Tremblay) activa accidentalmente el regreso a la Tierra de los yautjas, desencadenará la vuelta de los cazadores más letales del universo, una especie extraterrestre caracterizada por convertir en su trofeo al resto de criaturas y por obtener su poder a través de la hibridación. Ahora, estos alienígenas han mejorado su ADN y ahora son aún más peligrosos, fuertes, inteligentes y mortales. Por eso, solo un grupo de exsoldados y una profesora de ciencias podrán evitar el fin de la humanidad.', 101, NULL, 'CA', 'en', 23.7075, 'https://image.tmdb.org/t/p/w500/r6jghOfUGi5TNl9EbdOk5NtfkzQ.jpg', '2018-09-05', 160542134, 'predator-2018', 'RELEASED', 'Predator', 346910, 'https://www.youtube.com/watch?v=pfkcAEvxjDc', '2025-11-15 20:22:25.937979', 4936, 64),
	(137, '16', 8.687, 'https://image.tmdb.org/t/p/w780/tSPT36ZKlP2WVHJLM4cQPLSzv3b.jpg', 6000000, '2025-11-15 19:28:48.161023', 'Don Vito Corleone, conocido dentro de los círculos del hampa como \'El Padrino\', es el patriarca de una de las cinco familias que ejercen el mando de la Cosa Nostra en Nueva York en los años cuarenta. Don Corleone tiene cuatro hijos: una chica, Connie, y tres varones; Sonny, Michael y Fredo. Cuando el Padrino reclina intervenir en el negocio de estupefacientes, empieza una cruenta lucha de violentos episodios entre las distintas familias del crimen organizado.', 175, NULL, 'US', 'en', 36.8427, 'https://image.tmdb.org/t/p/w500/ApiEfzSkrqS4m1L5a2GwWXzIiAs.jpg', '1972-03-14', 245066411, 'el-padrino-1972', 'RELEASED', 'El padrino', 238, 'https://www.youtube.com/watch?v=v72XprPxy3E', '2026-02-14 17:40:45.919194', 22444, 130),
	(138, '7', 7.001, 'https://image.tmdb.org/t/p/w780/yfTZ2MSRWc06cBrFOsAF4Lebi4.jpg', 39000000, '2025-11-15 19:28:48.482193', 'De la mente del director Tim Burton (\'Alicia en el país de las maravillas\', \'La leyenda de Sleepy Hollow\'), surge \'Frankenweenie\', la tierna historia de un chico y su mascota. Cuando el pequeño perro Sparky fallece, Víctor (su amo y amigo) trata de usar diversas técnicas científicas para intentar revivir al animal, y traerlo de vuelta al mundo de los vivos, todo ello mediante algunos ajustes corporales. Aunque el chico intenta que nadie vea a su "monstruo", el perro Sparky consigue escapar, los amigos del colegio del niño, sus profesores e incluso todos sus vecinos sabrán que construir una nueva vida puede llegar a ser algo terrible y escalofriante.', 87, NULL, 'US', 'en', 23.4879, 'https://image.tmdb.org/t/p/w500/4WZaUjHswR2mak767GEXgiWYxeq.jpg', '2012-10-04', 81493846, 'frankenweenie-2012', 'RELEASED', 'Frankenweenie', 62214, 'https://www.youtube.com/watch?v=2e1_XxakM-I', '2025-11-15 20:22:26.776003', 3512, 131),
	(139, '12', 8.427, 'https://image.tmdb.org/t/p/w780/oiwc338EoBgS4sEI2ixAny4KQKg.jpg', 93000000, '2025-11-15 19:28:48.905011', 'En la Tierra Media, el Señor Oscuro Saurón creó los Grandes Anillos de Poder, forjados por los herreros Elfos. Tres para los reyes Elfos, siete para los Señores Enanos, y nueve para los Hombres Mortales. Secretamente, Saurón también forjó un anillo maestro, el Anillo Único, que contiene en sí el poder para esclavizar a toda la Tierra Media. Con la ayuda de un grupo de amigos y de valientes aliados, Frodo emprende un peligroso viaje con la misión de destruir el Anillo Único. Pero el Señor Oscuro Sauron, quien creara el Anillo, envía a sus servidores para perseguir al grupo. Si Sauron lograra recuperar el Anillo, sería el final de la Tierra Media.', 179, NULL, 'NZ', 'en', 25.7149, 'https://image.tmdb.org/t/p/w500/9xtH1RmAzQ0rrMBNUMXstb2s3er.jpg', '2001-12-18', 871368364, 'el-senor-de-los-anillos-la-comunidad-del-anillo-2001', 'RELEASED', 'El señor de los anillos: La comunidad del anillo', 120, 'https://www.youtube.com/watch?v=3GJp6p_mgPo', '2026-02-14 17:41:32.571245', 26996, 132),
	(140, NULL, 8.549, 'https://image.tmdb.org/t/p/w780/A7KwHKB5faRRRRveVQC5TPI35kV.jpg', 0, '2025-11-15 19:28:49.874189', 'Young Hearts, ópera prima de Anthony Schatteman, es una historia de amor adolescente tierna y luminosa, inspirada en su propia infancia. Elías, de 14 años, se enamora de su nuevo vecino, Alexander, y descubre por primera vez lo que significa amar de verdad. Sus relaciones con amigos y familia solo le generan más dudas. Una delicada película de crecimiento que aporta una mirada fresca y emotiva al cine familiar, con una maravillosa historia de amor queer. (Endimaris)', 99, NULL, 'BE', 'nl', 23.4148, 'https://image.tmdb.org/t/p/w500/9dkwCoJFcNRxuXf6W2f3dm1JaTl.jpg', '2024-10-26', 129692, 'corazones-jovenes-2024', 'RELEASED', 'Corazones Jóvenes', 1232449, 'https://www.youtube.com/watch?v=1aCTG9HplF8', '2025-11-15 20:22:27.519977', 162, 133),
	(141, '7i', 6.4, 'https://image.tmdb.org/t/p/w780/dbjyGc3pd02FJ9vkGj1MPGLqFOq.jpg', 0, '2025-11-15 19:28:50.087176', 'Mitchie Torres es una simpática chica que está deseando poder entrar en un campamento de música. Su única opción es trabajar en la cocina del campamento, donde un día la escucha cantar, por casualidad, una atractiva estrella del pop perteneciente al grupo Connect 3 llamada Shane Gray. Shane sólo escucha cantar a Mitchie, no la ve, así que el intenta descubrir quién es ella.', 94, NULL, 'US', 'en', 23.2343, 'https://image.tmdb.org/t/p/w500/7IXMqZnwccogptThay3togKIFWw.jpg', '2008-06-20', 0, 'camp-rock-2008', 'RELEASED', 'Camp Rock', 13655, 'https://www.youtube.com/watch?v=GlOdYPae0Tw', '2025-11-15 20:22:27.888518', 2138, 134),
	(142, '7', 7.9, 'https://image.tmdb.org/t/p/w780/1XAC6RPT01UX9EQGy2JVn5c8pgy.jpg', 125000000, '2025-11-15 19:28:50.841787', 'Harry Potter es un huérfano que vive con sus desagradables tíos, los Dursley, y su repelente primo Dudley. Se acerca su undécimo cumpleaños y tiene pocas esperanzas de recibir algún regalo, ya que nunca nadie se acuerda de él. Sin embargo, pocos días antes de su cumpleaños, una serie de misteriosas cartas dirigidas a él y escritas con una estridente tinta verde rompen la monotonía de su vida: Harry es un mago y sus padres también lo eran.', 152, NULL, 'GB', 'en', 23.3243, 'https://image.tmdb.org/t/p/w500/3MKK7vAJLtSkBTABMTjxf6TOCo3.jpg', '2001-11-16', 976475550, 'harry-potter-y-la-piedra-filosofal-2001', 'RELEASED', 'Harry Potter y la piedra filosofal', 671, 'https://www.youtube.com/watch?v=WE4AJuIvG1Y', '2026-02-14 17:41:46.903384', 29137, 135),
	(143, '12', 8.235, 'https://image.tmdb.org/t/p/w780/mDfJG3LC3Dqb67AZ52x3Z0jU0uB.jpg', 300000000, '2025-11-15 19:28:51.302634', 'El todopoderoso Thanos ha despertado con la promesa de arrasar con todo a su paso, portando el Guantelete del Infinito, que le confiere un poder incalculable. Los únicos capaces de pararle los pies son los Vengadores y el resto de superhéroes de la galaxia, que deberán estar dispuestos a sacrificarlo todo por un bien mayor. Capitán América e Ironman deberán limar sus diferencias, Black Panther apoyará con sus tropas desde Wakanda, Thor y los Guardianes de la Galaxia e incluso Spider-Man se unirán antes de que los planes de devastación y ruina pongan fin al universo. ¿Serán capaces de frenar el avance del titán del caos?', 149, NULL, 'US', 'en', 35.4315, 'https://image.tmdb.org/t/p/w500/ksBQ4oHQDdJwND8H90ay8CbMihU.jpg', '2018-04-25', 2052415039, 'vengadores-infinity-war-2018', 'RELEASED', 'Vengadores: Infinity War', 299536, 'https://www.youtube.com/watch?v=-f5PwE_Q8Fs', '2026-02-14 17:40:48.589833', 31458, 249),
	(144, NULL, 4.8, 'https://image.tmdb.org/t/p/w780/3HJBIGN4ZjX6xwNQsM9GlvZgZCX.jpg', 18000000, '2025-11-15 19:28:53.248886', 'Drama basado en relatos cortos de Bret Easton Ellis (escritor de "American Psycho"). Siete historias entrelazadas y ambientadas en Los Ángeles, protagonizadas por un ejecutivo de Hollywood, su esposa, su amante, una estrella de rock, un vampiro y un secuestrador.', 98, NULL, 'DE', 'en', 23.0081, 'https://image.tmdb.org/t/p/w500/7ZAz7R02n9rshS6Zz8otxUNpIG7.jpg', '2008-11-05', 382174, 'los-confidentes-2008', 'RELEASED', 'Los confidentes', 17436, 'https://www.youtube.com/watch?v=HxkvJkSIOGk', '2025-11-15 20:22:28.929079', 242, 137),
	(145, NULL, 7.289, 'https://image.tmdb.org/t/p/w780/sdZSjtGUTSN8B3al5o0f2WoQfQQ.jpg', 350000000, '2025-11-15 19:28:53.423228', 'Jake Sully y Neytiri enfrentan una nueva amenaza en Pandora: los Ash People, una tribu Na\'vi violenta y sedienta de poder, liderada por la implacable Varang. Tras la devastadora guerra contra la RDA y la pérdida de su hijo mayor, la familia de Jake deberá luchar por su supervivencia y el futuro de Pandora en un conflicto que llevará a los personajes a sus límites emocionales y físicos. Con nuevos y antiguos aliados, esta épica visual y emocional redefine el destino de un mundo al borde del abismo.', 198, NULL, 'US', 'en', 143.8649, 'https://image.tmdb.org/t/p/w500/4n1U0Mwn7djux6VKNYDRWPgS2x6.jpg', '2025-12-17', 1460000000, 'avatar-fuego-y-ceniza-2025', 'RELEASED', 'Avatar: Fuego y ceniza', 83533, 'https://www.youtube.com/watch?v=ndYS51j7G3o', '2026-02-16 16:49:52.091722', 1763, 127),
	(146, '16', 5.2, 'https://image.tmdb.org/t/p/w780/dHoRIZJgwA26zE5WKyEazKUoZAZ.jpg', 0, '2025-11-15 19:28:53.753566', 'Una joven descubre una moda viral que libera seres misteriosos de las paredes. Cuando sus padres no creen su historia, dos compañeros de escuela la ayudan a enfrentar estas criaturas peligrosas.', 93, NULL, 'US', 'en', 22.9132, 'https://image.tmdb.org/t/p/w500/AtBrB2yKyCDrtBEPbm9iZqeDUuZ.jpg', '2024-08-01', 0, 'detras-de-la-pared-2024', 'RELEASED', 'Detrás de la Pared', 1328402, 'https://www.youtube.com/watch?v=02bA2ey9db8', '2025-11-15 20:22:29.694888', 6, 138),
	(147, NULL, 7.889, 'https://image.tmdb.org/t/p/w780/zLg8KveLtTZ3N3SLoE68SYGYQFo.jpg', 0, '2025-11-15 19:28:54.466331', '', 71, NULL, 'PH', 'tl', 22.7136, 'https://image.tmdb.org/t/p/w500/tWFUt3THd6QbSdp4GZekes7Tbv1.jpg', '2025-11-07', 0, 'nympho-2025', 'RELEASED', 'Nympho', 1549512, NULL, '2025-11-15 20:22:30.099031', 18, 139),
	(148, NULL, 6.2, 'https://image.tmdb.org/t/p/w780/aGoPoY9BEmXu4yxO09XXBEAyzBR.jpg', 4900000, '2025-11-15 19:28:55.016888', 'Helsinki, 1942. Mientras Finlandia mantiene una peligrosa alianza con la Alemania nazi, un solo hombre se enfrenta al sistema. Abraham Stiller, un empresario judío, arriesga su vida para impedir que los servicios de seguridad finlandeses entreguen en secreto a refugiados judíos a la Gestapo.', 85, NULL, 'EE', 'fi', 22.6678, 'https://image.tmdb.org/t/p/w500/wLuBrKa6jFpKRQERf0rMDCO8uCU.jpg', '2025-01-17', 0, 'never-alone-nunca-mas-2025', 'RELEASED', 'Never Alone (Nunca más)', 563470, 'https://www.youtube.com/watch?v=17D8e6KoMN8', '2025-11-15 20:22:30.453991', 6, 140),
	(149, '16', 7.2, 'https://image.tmdb.org/t/p/w780/rAQcPrEaPzDRVNX7XX5TWyxCGFN.jpg', 35000000, '2025-11-15 19:28:55.454865', 'Remake del clásico de Stephen King en el que un payaso aterroriza a los niños de un vecindario. En un pequeño pueblo de Maine, siete niños conocidos como el Club de los Perdedores se encuentran cara a cara con problemas de la vida, matones y un monstruo que toma la forma de un payaso llamado Pennywise.', 135, NULL, 'US', 'en', 22.6604, 'https://image.tmdb.org/t/p/w500/sSrj4lnhrb113DOPEPTaO2jaDk3.jpg', '2017-09-06', 704242888, 'it-eso-2017', 'RELEASED', 'It (Eso)', 346364, 'https://www.youtube.com/watch?v=9jhtucvduSw', '2025-11-15 20:22:30.783236', 19789, 107),
	(150, 'Ai', 7.719, 'https://image.tmdb.org/t/p/w780/se5Hxz7PArQZOG3Nx2bpfOhLhtV.jpg', 92000000, '2025-11-15 19:28:56.213096', 'Como Mr. Increíble y Elastigirl, Bob y su esposa Helen estaban entre los mejores luchadores contra el crimen. Por fin pueden volver a la acción cuando una misteriosa llamada cita a Bob en una isla remota.', 115, NULL, 'US', 'en', 22.3383, 'https://image.tmdb.org/t/p/w500/al1jusd4T7JPatZlj4BuYkDDOzr.jpg', '2004-11-05', 631442092, 'los-increibles-2004', 'RELEASED', 'Los Increíbles', 9806, 'https://www.youtube.com/watch?v=eMzejXYKT_Y', '2025-11-15 20:22:31.428646', 18398, 141),
	(151, NULL, 5.8, 'https://image.tmdb.org/t/p/w780/jzzpCJWkVZZwAxzzLmtYN0MBWFd.jpg', 27000000, '2025-11-15 19:28:56.655687', 'Cameron Cade es un quarterback en ciernes que ha dedicado su vida y su identidad al fútbol americano. En vísperas del campeonato anual de fútbol americano profesional, Cam es atacado por un hincha desquiciado y sufre un traumatismo cerebral que podría poner fin a su carrera. Justo cuando todo parece perdido, Cam recibe un salvavidas cuando su héroe, Isaiah White, un legendario quarterback ocho veces campeón y megaestrella cultural, se ofrece a entrenar a Cam en el aislado complejo que Isaiah comparte con su esposa, Elsie White. Pero a medida que el entrenamiento de Cam se acelera, el carisma de Isaiah comienza a cuajar en algo más oscuro, enviando a su protegido a un agujero de conejo desorientador que puede costarle más de lo que jamás esperó.', 96, NULL, 'US', 'en', 22.1708, 'https://image.tmdb.org/t/p/w500/uXE0bHBNY3TL932JhiQJscxnJya.jpg', '2025-09-18', 27601423, 'el-mejor-2025', 'RELEASED', 'El mejor', 986097, 'https://www.youtube.com/watch?v=Dz7z_I4ceTY', '2025-11-15 20:22:31.858572', 211, 142),
	(152, '16', 6.9, 'https://image.tmdb.org/t/p/w780/41043LV7mfluH8iXEUPVseCDAv5.jpg', 40000000, '2025-11-15 19:28:59.011248', 'Cuando su vecino punki Russ le pide que cuide de su gato durante unos días, Hank Thompson se encuentra atrapado en medio de un variopinto grupo de gángsters amenazantes. Todos quieren algo de él; el problema es que él no sabe por qué. Mientras Hank intenta eludir sus cada vez más estrechas garras, tendrá que emplear toda su habilidad para mantenerse con vida el tiempo suficiente para averiguarlo…', 107, NULL, 'US', 'en', 22.0024, 'https://image.tmdb.org/t/p/w500/dpEGQKgOeDo9GmmKDnEWjTLTi4u.jpg', '2025-08-26', 31101846, 'bala-perdida-2025', 'RELEASED', 'Bala perdida', 1245993, 'https://www.youtube.com/watch?v=RiYlMuK_RQA', '2025-11-15 20:22:32.110686', 519, 143),
	(153, '7', 7.63, 'https://image.tmdb.org/t/p/w780/noPEm6Vu9Lm6QUdTGLOyRgk4M6s.jpg', 122000000, '2025-11-15 19:28:59.732147', 'Sonic, Knuckles y Tails se reúnen para enfrentarse a un nuevo y poderoso adversario, Shadow, un misterioso villano cuyos poderes no se parecen a nada de lo que nuestros héroes han conocido hasta ahora. Con sus facultades superadas en todos los sentidos, el Equipo Sonic tendrá que establecer una insólita alianza con la esperanza de detener a Shadow y proteger el planeta.', 112, NULL, 'US', 'en', 24.7842, 'https://image.tmdb.org/t/p/w500/3aDWCRXLYOCuxjrjiPfLd79tcI6.jpg', '2024-12-19', 492162604, 'sonic-3-la-pelicula-2024', 'RELEASED', 'Sonic 3: La película', 939243, 'https://www.youtube.com/watch?v=2YJXP8CKrNE', '2026-02-09 17:27:34.800673', 3128, 144),
	(154, NULL, 5.8, 'https://image.tmdb.org/t/p/w780/xSD0q1FiuZkvHuy7uscOLbmd1hR.jpg', 0, '2025-11-15 19:29:00.753311', 'Nueva adaptación del cómic Red Sonja, una guerrera vengativa conocida como "La diablesa con una espada".', 110, NULL, 'US', 'en', 21.9192, 'https://image.tmdb.org/t/p/w500/aE3yh4y0h96CZZpLo0UDFMWZAA9.jpg', '2025-07-31', 265091, 'red-sonja-2025', 'RELEASED', 'Red Sonja', 13494, 'https://www.youtube.com/watch?v=A1EHM1_NG-8', '2025-11-15 20:22:32.864984', 135, 145),
	(155, NULL, 7.019, 'https://image.tmdb.org/t/p/w780/hdX3esdD6u0gUdU1oSAaNMFlFQk.jpg', 0, '2025-11-15 19:29:01.374165', 'Cuenta la historia de amor entre dos chicos de catorce años, con una audacia inusual porque se anima a registrar la sensualidad e intensidad de los cuerpos y las emociones de estos adolescentes, dejando como fondo el oscuro retrato de sus familias, para focalizar el relato en la amorosa y tierna relación de los protagonistas, refugio frente a un entorno adulto de hostilidad y locura.', 125, NULL, 'SE', 'sv', 21.8782, 'https://image.tmdb.org/t/p/w500/p12FTNVU81gfFJf1A28pzW631ED.jpg', '1970-04-24', 0, 'una-historia-de-amor-sueca-1970', 'RELEASED', 'Una historia de amor sueca', 31304, 'https://www.youtube.com/watch?v=wvrp7zaZq0o', '2025-11-15 20:22:33.335794', 160, 146),
	(156, 'APTA', 8.477, 'https://image.tmdb.org/t/p/w780/8x9iKH8kWA0zdkgNdpAew7OstYe.jpg', 0, '2025-11-15 19:29:01.999520', 'Taki y Mitsuha descubren un día que durante el sueño sus cuerpos se intercambian, y comienzan a comunicarse por medio de notas. A medida que consiguen superar torpemente un reto tras otro, se va creando entre los dos un vínculo que poco a poco se convierte en algo más romántico.', 106, NULL, 'JP', 'ja', 25.9643, 'https://image.tmdb.org/t/p/w500/iaiy3tg9QVkDpObm1IGqmbC9A5C.jpg', '2016-08-26', 358000000, 'your-name-2016', 'RELEASED', 'Your Name', 372058, 'https://www.youtube.com/watch?v=o4-URMnBOPU', '2026-02-09 17:27:09.900769', 12279, 147),
	(157, '7', 7.901, 'https://image.tmdb.org/t/p/w780/k1pJslKr4aDayw9kWwWnlC3MIP3.jpg', 22000000, '2025-11-15 19:29:03.978853', 'Nezha, nacido de una perla celestial con poderes únicos, pronto se encontrará exiliado, odiado y temido por la gente que cree en una profecía que indica que él traerá la destrucción del mundo. Llegará el momento en el que deberá decidir entre el bien y el mal con el propósito de romper los grilletes del destino y convertirse en un héroe. Película inspirada muy libremente en "Fengshen Yanyi" ("La Investidura de los Dioses"), una de las grandes novelas chinas escritas en la Dinastía Ming cuya autoría se atribuye a Xu Zhonglin o Lu Xixing.', 110, NULL, 'CN', 'zh', 21.7355, 'https://image.tmdb.org/t/p/w500/8TpbaMAjrYm2iFB3LCTcVInwhdS.jpg', '2019-07-26', 742718496, 'ne-zha-2019', 'RELEASED', 'Ne Zha', 615453, 'https://www.youtube.com/watch?v=PYSiEFeMbZ0', '2025-11-15 20:22:34.471270', 715, 82),
	(158, '16', 7.5, 'https://image.tmdb.org/t/p/w780/nAxGnGHOsfzufThz20zgmRwKur3.jpg', 90000000, '2025-11-15 19:29:05.218130', 'Tratando de dejar atrás sus problemáticas vidas, dos hermanos gemelos regresan a su pueblo natal para empezar de nuevo, solo para descubrir que un mal aún mayor les espera para darles la bienvenida.', 137, NULL, 'US', 'en', 33.9591, 'https://image.tmdb.org/t/p/w500/zdClwqpYQXBSCGGDMdtvsuggwec.jpg', '2025-04-16', 368389632, 'los-pecadores-2025', 'RELEASED', 'Los pecadores', 1233413, 'https://www.youtube.com/watch?v=XufPTI4PDLg', '2026-02-14 17:40:53.841483', 3665, 148),
	(159, NULL, 4.286, 'https://image.tmdb.org/t/p/w780/vX22jAr0hoTvhfms5E5UFe5vPsU.jpg', 0, '2025-11-15 19:29:10.718862', '', 79, NULL, 'FR', 'fr', 21.6862, 'https://image.tmdb.org/t/p/w500/1tyoj4hZZIrtsuRt7qqKlz30LBq.jpg', '1972-11-01', 0, 'absences-repetees-1972', 'RELEASED', 'Absences répétées', 295912, 'https://www.youtube.com/watch?v=RhZDW6v8BkY', '2025-11-15 20:22:35.321969', 14, 149),
	(160, '18', 7.757, 'https://image.tmdb.org/t/p/w780/6G6nqSW9S7EHA9HrYl0Z8uo2H7f.jpg', 19000000, '2025-11-15 19:29:12.298214', 'En la España falangista de 1944, una joven aficionada a los libros e hijastra de un sádico oficial del ejército huye a un misterioso pero cautivador mundo de fantasía.', 112, NULL, 'MX', 'es', 21.6301, 'https://image.tmdb.org/t/p/w500/953ZprqPxXSfhHvjBVRiIv7fSP6.jpg', '2006-10-11', 83258226, 'el-laberinto-del-fauno-2006', 'RELEASED', 'El laberinto del fauno', 1417, 'https://www.youtube.com/watch?v=NEg7u3boJhU', '2025-11-15 20:22:35.559683', 11096, 1),
	(161, '12', 8.37, 'https://image.tmdb.org/t/p/w780/ii8QGacT3MXESqBckQlyrATY0lT.jpg', 160000000, '2025-11-15 19:29:12.985974', 'Dom Cobb es un ladrón hábil, el mejor de todos, especializado en el peligroso arte de extracción: el robo de secretos valiosos desde las profundidades del subconsciente durante el estado de sueño cuando la mente está más vulnerable. Esta habilidad excepcional de Cobb le ha hecho un jugador codiciado en el traicionero nuevo mundo de espionaje corporativo, pero al mismo tiempo, le ha convertido en un fugitivo internacional y ha tenido que sacrificar todo que le importaba. Ahora a Cobb se le ofrece una oportunidad para redimirse. Con un último trabajo podría recuperar su vida anterior, pero solamente si logra lo imposible.', 148, NULL, 'GB', 'en', 35.5971, 'https://image.tmdb.org/t/p/w500/tXQvtRWfkUUnWJAn2tN3jERIUG.jpg', '2010-07-15', 839030630, 'origen-2010', 'RELEASED', 'Origen', 27205, 'https://www.youtube.com/watch?v=RV9L7ui9Cn8', '2026-02-09 17:26:13.378779', 38642, 81),
	(162, 'Ai', 7.596, 'https://image.tmdb.org/t/p/w780/9n2tJBplPbgR2ca05hS5CKXwP2c.jpg', 100000000, '2025-11-15 19:29:13.735085', 'Mientras trabajan en una avería subterránea, los fontaneros de Brooklyn, Mario y su hermano Luigi, viajan por una misteriosa tubería hasta un nuevo mundo mágico. Pero, cuando los hermanos se separan, Mario deberá emprender una épica misión para encontrar a Luigi. Con la ayuda del champiñón local Toad y unas cuantas nociones de combate de la guerrera líder del Reino Champiñón, la princesa Peach, Mario descubre todo el poder que alberga en su interior.', 92, NULL, 'JP', 'en', 27.4421, 'https://image.tmdb.org/t/p/w500/k36QyeVsy851npTUQL08jO8hqip.jpg', '2023-04-05', 1362000000, 'super-mario-bros-la-pelicula-2023', 'RELEASED', 'Super Mario Bros: La película', 502356, 'https://www.youtube.com/watch?v=8OtTfN6k7_Y', '2026-02-09 17:27:01.229732', 10251, 162),
	(164, NULL, 7, 'https://image.tmdb.org/t/p/w780/jhxtlJ0UgPgSmfw5zA4B6lG3vKT.jpg', 0, '2025-11-15 19:29:15.418833', '', 76, NULL, 'PH', 'tl', 21.1807, 'https://image.tmdb.org/t/p/w500/2C134Lw00utQgrx8lqV9UpadO5A.jpg', '2025-10-28', 0, 'unli-pop-2025', 'RELEASED', 'Unli Pop', 1549508, 'https://www.youtube.com/watch?v=RTmZUixRhfk', '2025-11-15 20:22:37.730711', 1, 152),
	(165, NULL, 7.4, 'https://image.tmdb.org/t/p/w780/gkp83BnUbnXoZpIW5e6u9P6wFzd.jpg', 0, '2025-11-15 19:29:16.251477', 'Documental sobre la campaña de la oceanógrafa Sylvia Earle para salvar los océanos del planeta contra amenazas como los residuos tóxicos o la pesca excesiva.', 94, NULL, 'US', 'en', 21.0851, 'https://image.tmdb.org/t/p/w500/34sR023uQt7gNMFWNIWRHaacrVc.jpg', '2014-01-30', 0, 'mission-blue-2014', 'RELEASED', 'Mission Blue', 286407, 'https://www.youtube.com/watch?v=B1wp2MQCsfQ', '2025-11-15 20:22:38.207456', 43, 153),
	(166, '12', 7.2, 'https://image.tmdb.org/t/p/w780/pQQggUuDMleFSl2tQYxzTmKIiLU.jpg', 21000000, '2025-11-15 19:29:16.503691', 'Enola Holmes, una intrépida joven que busca a su madre, utiliza su brillante instinto investigador para superar a su hermano Sherlock y ayudar a un lord en su fuga.', 123, NULL, 'US', 'en', 21.0003, 'https://image.tmdb.org/t/p/w500/8STWO9pUTqubPV04iXZ2R6SClME.jpg', '2020-09-23', 0, 'enola-holmes-2020', 'RELEASED', 'Enola Holmes', 497582, 'https://www.youtube.com/watch?v=UqGZreSFd4g', '2025-11-15 20:22:38.660071', 6317, 154),
	(167, NULL, 7.842, 'https://image.tmdb.org/t/p/w780/9KSboWOt09J72aMY4x8SS1IaOHK.jpg', 0, '2025-11-15 19:29:17.698161', 'En la época del Imperio Azteca, Yohualli Coatl, un joven azteca, experimenta una tragedia cuando su padre y líder de la aldea, Toltecatzin, es asesinado por los conquistadores españoles. Yohualli escapa a Tenochtitlán para advertir al rey Moctezuma y a su sumo sacerdote, Yoka, del peligro inminente. Usando el templo de Tzinacan, el dios murciélago, como guarida, Yohualli entrena con su mentor y asistente, Acatzin, desarrollando equipo y armamento para enfrentar la invasión española, proteger el templo de Moctezuma y vengar la muerte de su padre.', 90, NULL, 'US', 'es', 20.9776, 'https://image.tmdb.org/t/p/w500/wpMaI2J3ISYZiaIWNkoA1lVb5LQ.jpg', '2025-09-18', 0, 'batman-azteca-choque-de-imperios-2025', 'RELEASED', 'Batman Azteca: Choque de imperios', 987400, 'https://www.youtube.com/watch?v=-bd_AUSkrRA', '2025-11-15 20:22:39.447682', 114, 155),
	(168, '12', 6, 'https://image.tmdb.org/t/p/w780/gJDGWlJbFO4KqB47ng3d0skA6zq.jpg', 0, '2025-11-15 19:29:19.058242', 'El carismático Wei y el tranquilo Shuo se hacen amigos rápidamente tras un incidente en la escuela. Pronto, Shuo se convierte en un invitado frecuente en casa de la familia Wei, pero a medida que se integra más en sus vidas, comienzan a aparecer grietas. La familia perfecta tiene viejas heridas y oscuros secretos que no pueden permanecer ocultos.', 99, NULL, 'CN', 'zh', 20.8598, 'https://image.tmdb.org/t/p/w500/aWrRXgraWTQnjaAh6tqOIL6eplk.jpg', '2024-09-26', 2661, 'breve-historia-de-una-familia-2024', 'RELEASED', 'Breve historia de una familia', 1135176, 'https://www.youtube.com/watch?v=dMbapgN85SA', '2025-11-15 20:22:39.913804', 16, 156),
	(169, NULL, 7.6, NULL, 0, '2025-11-15 19:29:20.031516', '', 109, NULL, 'IN', 'mr', 20.811, 'https://image.tmdb.org/t/p/w500/4evbEDDJuprAVUNxxtFeg2ejWWN.jpg', '2013-01-04', 0, 'balak-palak-2013', 'RELEASED', 'Balak Palak', 139586, 'https://www.youtube.com/watch?v=0vlCrpHlHrc', '2025-11-15 20:22:40.269677', 5, 157),
	(170, '7', 6.715, 'https://image.tmdb.org/t/p/w780/fxWzL0TrIAHYRauGNvF0Qg3tsKo.jpg', 0, '2025-11-15 19:29:20.873765', 'Eva, madre divorciada y masajista a domicilio, se enfrenta a la inminente marcha de su hija a la universidad. En una fiesta conoce a Albert –dulce, divertido y también con síndrome del nido vacío– y y a Marianne, una poetisa que se convierte en su amiga.', 93, NULL, 'GB', 'en', 20.785, 'https://image.tmdb.org/t/p/w500/1dxO6Z6NaZPkO0Zz3n3hNPlbSYu.jpg', '2013-09-18', 25288872, 'sobran-las-palabras-2013', 'RELEASED', 'Sobran las palabras', 209263, 'https://www.youtube.com/watch?v=PeByz4Twigc', '2025-11-15 20:22:40.628025', 885, 158),
	(171, '7', 6.825, 'https://image.tmdb.org/t/p/w780/oFQilRMEq6yQbtMPxIYWpXeQ5ZN.jpg', 120000000, '2025-11-15 19:29:21.875101', 'Un año después de despistar al FBI y conseguir la admiración del público con sus espectáculos mentales, los cuatro jinetes vuelven a la luz pública, pero un nuevo enemigo se propone arruinar su golpe más espectacular y peligroso hasta la fecha... Secuela de "Ahora me ves" del 2013.', 129, NULL, 'HK', 'en', 20.7138, 'https://image.tmdb.org/t/p/w500/pjGt13AXXTLxvkmdF6SpA1feFOw.jpg', '2016-06-02', 334897606, 'ahora-me-ves-2-2016', 'RELEASED', 'Ahora me ves 2', 291805, 'https://www.youtube.com/watch?v=KOzG9YQoE0c', '2025-11-15 20:22:40.871695', 11139, 56),
	(172, '12', 7.2, 'https://image.tmdb.org/t/p/w780/9ZV5XIZVS0hZAfxadPvuFplSCSY.jpg', 0, '2025-11-15 19:29:22.571231', 'En los alrededores del desierto de Gobi, en el norte de China, en los días previos al inicio de los Juegos Olímpicos de Pekín, Lang, un exconvicto, regresa a su ciudad, ahora semiderruida y casi fantasmal, en la que apenas queda ya gente. Allí se encariña con un perro negro desvalido que le acompañará en su recorrido al interior de este árido lugar que un día fue un hogar.', 116, NULL, 'CN', 'zh', 20.5826, 'https://image.tmdb.org/t/p/w500/iGi24k4Mgy7pEgl9HgpWgENtbuC.jpg', '2024-06-15', 4600000, 'black-dog-2024', 'RELEASED', 'Black Dog', 1249423, 'https://www.youtube.com/watch?v=JThmy5H9w1s', '2025-11-15 20:22:41.439163', 180, 159),
	(173, '16', 8.027, 'https://image.tmdb.org/t/p/w780/7Nwnmyzrtd0FkcRyPqmdzTPppQa.jpg', 100000000, '2025-11-15 19:29:23.351505', 'Película basada en hechos reales del corredor de bolsa neoyorquino Jordan Belfort. A mediados de los años 80, Belfort era un joven honrado que perseguía el sueño americano, pero pronto en la agencia de valores aprendió que lo más importante no era hacer ganar a sus clientes, sino ser ambicioso y ganar una buena comisión. Su enorme éxito y fortuna le valió el mote de "El lobo de Wall Street". Dinero. Poder. Mujeres. Drogas. Las tentaciones abundaban y el temor a la ley era irrelevante. Jordan y su manada de lobos consideraban que la discreción era una cualidad anticuada; nunca se conformaban con lo que tenían.', 180, NULL, 'US', 'en', 20.4747, 'https://image.tmdb.org/t/p/w500/uthRoUeTtiep5HCoySlOjQSPCbJ.jpg', '2013-12-25', 407038432, 'el-lobo-de-wall-street-2013', 'RELEASED', 'El lobo de Wall Street', 106646, 'https://www.youtube.com/watch?v=DEMZSa0esCU', '2025-11-15 20:22:41.728364', 25155, 160),
	(174, '7', 7.599, 'https://image.tmdb.org/t/p/w780/vL5LR6WdxWPjLPFRLe133jXWsh5.jpg', 237000000, '2025-11-15 19:29:23.795700', 'Año 2154. Jake Sully, un exmarine en silla de ruedas, es enviado al planeta Pandora, donde se ha creado el programa Avatar, gracias al cual los seres humanos pueden controlar de forma remota un cuerpo biológico con apariencia y genética de la especie nativa. Pronto se encontrará con la encrucijada entre seguir las órdenes de sus superiores o defender al mundo que le ha acogido y siente como suyo.', 161, NULL, 'US', 'en', 64.6544, 'https://image.tmdb.org/t/p/w500/t5T3LPbLLgP2OP6kloM9p2PXpJL.jpg', '2009-12-16', 2923706026, 'avatar-2009', 'RELEASED', 'Avatar', 19995, 'https://www.youtube.com/watch?v=AZS_d_hS2dM', '2026-02-14 17:40:38.713331', 33439, 127),
	(175, '16', 5.17, 'https://image.tmdb.org/t/p/w780/cKZcDKawR79igCgDMSXlpkn8hLR.jpg', 0, '2025-11-15 19:29:24.935022', 'La hija de un general vive en una casa que no quiere, en un matrimonio en el que se siente atrapada y un ex amante que reaparece en su vida... Readaptación de la famosa pieza teatral del dramaturgo Henrik Ibsen.', 107, NULL, 'US', 'en', 20.2856, 'https://image.tmdb.org/t/p/w500/ecflk7AZf0ij205yDswjlvdxlCO.jpg', '2025-10-22', 8393, 'hedda-2025', 'RELEASED', 'Hedda', 997113, 'https://www.youtube.com/watch?v=m3lgD59KrTw', '2025-11-15 20:22:42.589989', 50, 161),
	(176, NULL, 0, 'https://image.tmdb.org/t/p/w780/5U0tqruExz7ssDyr5pwiAGFzI8S.jpg', 0, '2025-11-15 19:29:25.926024', '', 0, NULL, 'JP', 'en', 20.2183, 'https://image.tmdb.org/t/p/w500/zdOZeoRX4exApuCo2Cp57OkHtAJ.jpg', '2026-04-01', 0, 'super-mario-galaxy-la-pelicula-2026', 'IN_PRODUCTION', 'Super Mario Galaxy la película', 1226863, 'https://www.youtube.com/watch?v=Hz57G2KaAp8', '2025-11-15 20:22:42.854805', 0, 162),
	(177, NULL, 4.4, 'https://image.tmdb.org/t/p/w780/gZF6fDtE71Fi3AGcF0PSQAxCgE3.jpg', 0, '2025-11-15 19:29:27.381658', 'Shanghái, 1932. Durante un banquete del ejército japonés, el líder de la resistencia china Mubai realiza una incursión exitosa y conoce al mecenas Sr. Hu, quien lo recluta para asesinar al estratega japonés Kurokawa. Mubai y su equipo enfrentan emboscadas y traiciones en una misión que cambiará sus vidas.', 91, NULL, 'ES', 'zh', 20.109, 'https://image.tmdb.org/t/p/w500/eNriIkhQusncgc5SipEgQUtrybO.jpg', '2025-09-26', 0, 'tiempo-de-asesinos-2025', 'RELEASED', 'Tiempo de asesinos', 1552819, NULL, '2025-11-15 20:22:43.182138', 8, NULL),
	(178, NULL, 7.4, 'https://image.tmdb.org/t/p/w780/xsO1Qgru8sETLTcVla8MrqxOVr0.jpg', 11800000, '2025-11-15 19:29:27.605799', 'Un psiquiatra estadounidense examina a 22 criminales nazis durante los juicios de Núremberg. Su fascinación por Hermann Göring y su obsesiva búsqueda por entender la naturaleza del mal lo llevan a un oscuro destino.', 150, NULL, 'US', 'en', 28.1181, 'https://image.tmdb.org/t/p/w500/7OOQRx9SmkMC3UQfdzj4QsQHtA1.jpg', '2025-11-06', 37009109, 'nuremberg-2025', 'RELEASED', 'Núremberg', 1214931, 'https://www.youtube.com/watch?v=8caQ0aapFp4', '2026-02-14 17:41:19.262353', 572, 163),
	(179, '7', 7.819, 'https://image.tmdb.org/t/p/w780/uRNgkJSkNBFbbn9fPsEjDIy8Sh3.jpg', 140000000, '2025-11-15 19:29:28.653318', 'El aventurero capitán Jack Sparrow recorre las aguas caribeñas. Pero su andanzas terminan cuando su enemigo, el capitán Barbossa le roba su barco, la Perla Negra, y ataca la ciudad de Port Royal, secuestrando a Elizabeth Swann, hija del gobernador. Will Turner, el amigo de la infancia de Elizabeth, se une a Jack para rescatarla y recuperar la Perla Negra. Pero el prometido de Elizabeth, comodoro Norrington, les persigue a bordo del HMS Impávido. Además, Barbossa y su tripulación son víctimas de un conjuro por el que están condenados a vivir eternamente, y a transformarse cada noche en esqueletos vivientes, en fantasmas guerreros.', 143, NULL, 'US', 'en', 22.4243, 'https://image.tmdb.org/t/p/w500/bVG48kmXuLaZYgPfSCmhs6EYFbX.jpg', '2003-07-09', 655011224, 'piratas-del-caribe-la-maldicion-de-la-perla-negra-2003', 'RELEASED', 'Piratas del Caribe: La maldición de la Perla Negra', 22, 'https://www.youtube.com/watch?v=5Itr2jHuJaw', '2026-02-09 17:27:30.255398', 21838, 164),
	(180, '18', 7.422, 'https://image.tmdb.org/t/p/w780/2IIKts2A9vnUdM9tTC76B8tDmuZ.jpg', 15000000, '2025-11-15 19:29:29.346392', 'Un hermano y su hermana descubren un aterrador ritual en la apartada casa de su nueva madre adoptiva. Lo que parece un hogar seguro pronto se convierte en una pesadilla, donde figuras siniestras, extrañas imágenes en vídeo y sucesos paranormales los rodean.', 104, NULL, 'AU', 'en', 19.9385, 'https://image.tmdb.org/t/p/w500/cl3VbcYxzWnDPetd7SbdhSxwWoL.jpg', '2025-05-28', 39123752, 'devuelvemela-2025', 'RELEASED', 'Devuélvemela', 1151031, 'https://www.youtube.com/watch?v=wLMRLWSsfhw', '2025-11-15 20:22:44.506714', 1157, 165),
	(181, '16', 7.134, 'https://image.tmdb.org/t/p/w780/k24eZq5I3jyz4htPkZCRpnUmBzE.jpg', 0, '2025-11-15 19:29:29.854125', 'El amor entre Noah y Nick parece inquebrantable, a pesar de las maniobras de sus padres por separarles. Pero el trabajo de él y la entrada de ella en la universidad, abre sus vidas a nuevas relaciones. La aparición de una exnovia que busca venganza y de la madre Nick con intenciones poco claras, removerán los cimientos no solo de su relación, sino de la propia familia Leister. Cuando tantas personas están dispuestas a destruir una relación, ¿puede realmente acabar bien?', 120, NULL, 'ES', 'es', 19.9313, 'https://image.tmdb.org/t/p/w500/1jvCVdlgInyItAUEvvvCakm1Yxz.jpg', '2024-12-26', 0, 'culpa-tuya-2024', 'RELEASED', 'Culpa tuya', 1156593, 'https://www.youtube.com/watch?v=9wVJR8VfLjk', '2025-11-15 20:22:44.959294', 1452, 55),
	(182, '12', 6.29, 'https://image.tmdb.org/t/p/w780/yVSgw4UyXWg0Edl7KMehdhhgIwL.jpg', 40000000, '2025-11-15 19:29:31.175682', 'Royce es un mercenario que, a regañadientes, encabeza a un grupo de guerreros de élite que acaban dándose cuenta de que los han llevado juntos a otro planeta… para servir de presa. Con la excepción de un médico desprestigiado, todos ellos son unos desalmados asesinos —mercenarios, yakuzas, presidiarios, miembros de escuadrones de la muerte—, “depredadores” humanos que ahora están siendo cazados y eliminados sistemáticamente por una nueva raza de Depredadores extraterrestres.', 107, NULL, 'US', 'en', 19.931, 'https://image.tmdb.org/t/p/w500/mYH9FtLUtaIgiGKrVqo82TklFIY.jpg', '2010-07-07', 127200000, 'predators-2010', 'RELEASED', 'Predators', 34851, 'https://www.youtube.com/watch?v=l7CjfUPmo2M', '2025-11-15 20:22:45.429794', 4407, 166),
	(183, NULL, 6.1, 'https://image.tmdb.org/t/p/w780/vZObAsgOdPUrLHtSM4B1Ys7r4HX.jpg', 60000, '2025-11-15 19:29:34.800915', '', 98, NULL, 'DE', 'pt', 19.8614, 'https://image.tmdb.org/t/p/w500/bcCcRhvmCIfP5BGYBwRkVE1uDKW.jpg', '2021-06-30', 0, 'a-febre-2021', 'RELEASED', 'A Febre', 515985, 'https://www.youtube.com/watch?v=VddwSd67HEk', '2025-11-15 20:22:45.897336', 10, 167),
	(184, '16', 5.7, 'https://image.tmdb.org/t/p/w780/5mPpUkGYzjdZdTB1BE0rSQk0X2v.jpg', 0, '2025-11-15 19:29:43.848931', 'Una madre de familia acomodada contrata a Polly Murphy como niñera, pero pronto descubre que esta mujer no es quien dice ser. Remake de "La mano que mece la cuna" (1992).', 105, NULL, 'US', 'en', 19.8581, 'https://image.tmdb.org/t/p/w500/lRe1CQugJcj5ZA3WSaQnFIDPoK5.jpg', '2025-10-16', 0, 'la-mano-que-mece-la-cuna-2025', 'RELEASED', 'La mano que mece la cuna', 1362315, 'https://www.youtube.com/watch?v=A0SFXzNMthc', '2025-11-15 20:22:46.388640', 55, 168),
	(185, NULL, 8.3, 'https://image.tmdb.org/t/p/w780/8lreZPhAuNjGmqukZWzY9sORmyl.jpg', 0, '2025-11-15 19:29:47.038674', 'Únete al apostol Juan en un asombroso relato visual que desentraña las visiones del Fin de los Tiempos. Experimenta cada visión como nunca antes, con efectos visuales impactantes y escenas épicas que te sumergirán en la narrativa apocalíptica.', 110, NULL, 'AR', 'es', 19.8005, 'https://image.tmdb.org/t/p/w500/zzXU586n4uDBgMtVMPPQW7UJwu8.jpg', '2024-10-07', 0, 'el-apocalipsis-de-san-juan-2024', 'RELEASED', 'El Apocalipsis de san Juan', 1262299, NULL, '2025-11-15 20:22:46.933994', 55, 169),
	(186, '7', 7.9, 'https://image.tmdb.org/t/p/w780/hofnlIyF6bePkgQOpcuRWLvzf15.jpg', 60000000, '2025-11-15 19:29:49.021475', 'Película de animación en la que se nos cuenta la historia de Coraline, una jovencita que descubre en su nueva casa una puerta secreta y decide abrirla. Al hacerlo, descubre una segunda versión de su vida, una vida paralela a la que ella tiene. A primera vista, la realidad paralela es curiosamente parecida a su vida de verdad, aunque mucho mejor. Pero cuando su increíble y maravillosa aventura empieza a tomar un cariz peligroso, su otra madre intenta mantenerla a su lado para siempre. Coraline deberá recurrir a su determinación y coraje, a la ayuda de los vecinos y a un gato negro con el don del habla para salvar a sus auténticos padres, a unos niños fantasmas y regresar a casa.', 101, NULL, 'US', 'en', 19.7418, 'https://image.tmdb.org/t/p/w500/xz1HjxeqpIACyPtJMqv33Z2RjRP.jpg', '2009-02-05', 185860104, 'los-mundos-de-coraline-2009', 'RELEASED', 'Los mundos de Coraline', 14836, 'https://www.youtube.com/watch?v=ksOiRS2YO1U', '2025-11-15 20:22:47.417473', 8641, 170),
	(187, NULL, 6.6, 'https://image.tmdb.org/t/p/w780/7qKH3MKMW4VbG21kAE7enTu4xQZ.jpg', 0, '2025-11-15 19:59:58.309255', 'Utah Blaine salva a un ranchero a quien Nevers, que desea sus tierras, ha colgado y dejado por muerto. Agradecido, el ranchero le deja en herencia la mitad de su rancho (la otra mitad es para la hermosa Angie), pero Nevers y sus hombres no dejarán la cosa así.', 75, NULL, 'US', 'en', 28.9562, 'https://image.tmdb.org/t/p/w500/rVmloeVVqhroLXRMrT3NpuLtAJM.jpg', '1957-02-01', 0, 'utah-blaine-1957', 'RELEASED', 'Utah Blaine', 253837, 'https://www.youtube.com/watch?v=WR6MB1ZmsJs', '2025-11-15 20:22:06.672720', 6, 171),
	(188, NULL, 0, 'https://image.tmdb.org/t/p/w780/iGQmjutq9XqcnaSUSrg7AWWrQ8h.jpg', 0, '2025-11-15 19:59:59.303411', '', 0, NULL, 'PH', 'tl', 28.5299, 'https://image.tmdb.org/t/p/w500/kjjqRBPeo0hsOuM0FWEJmDpdl6W.jpg', '2025-11-28', 0, 'balahibong-pusa-2025', 'POST_PRODUCTION', 'Balahibong Pusa', 1549517, 'https://www.youtube.com/watch?v=Xmgd9pEMswo', '2025-11-15 20:22:08.073535', 0, 172),
	(189, NULL, 6.3, 'https://image.tmdb.org/t/p/w780/lM88cKl8suAWniiAy8IJvfMupDk.jpg', 3000000, '2025-11-15 20:00:00.149969', 'Un chico joven no tiene ninguna posibilidad de sobrevivir tras quemaduras en todo su cuerpo. En su lucha por vivir y demostrarnos lo que es posible, acaba apoyándose en su familia, en su fe y en toda la ciudad.', 111, NULL, 'US', 'en', 27.8821, 'https://image.tmdb.org/t/p/w500/iUMmG3Q0JyAuSx9QpIiMFhI5zDo.jpg', '2025-10-10', 3000000, 'alma-en-llamas-2025', 'RELEASED', 'Alma en llamas', 1196791, 'https://www.youtube.com/watch?v=P4uU-BoNlv4', '2025-11-15 20:22:08.504845', 8, 173),
	(190, 'APTA', 7.759, 'https://image.tmdb.org/t/p/w780/9tOkjBEiiGcaClgJFtwocStZvIT.jpg', 150000000, '2025-11-15 20:00:01.334939', 'La moderna metrópoli mamífera de Zootrópolis es una ciudad absolutamente única. Está compuesta de barrios con diferentes hábitats como la lujosa Plaza Sahara, el Distrito Selva Tropical y el gélido Distrito Tundra. Es un crisol donde los animales de cada entorno conviven, un lugar donde no importa lo que seas. De hecho puedes ser cualquier cosa, desde un elefante enorme hasta la musaraña más diminuta. Pero cuando llega la optimista agente Judy Hopps, descubre que ser la primera conejita de un cuerpo policial compuesto de animales duros y enormes no es nada fácil. Pero está decidida a demostrar su valía y se mete de cabeza en un caso, a pesar de que eso significa trabajar con Nick Wilde, un zorro parlanchín y estafador, para resolver el misterio.', 108, NULL, 'US', 'en', 36.5871, 'https://image.tmdb.org/t/p/w500/i3WnZpJkQYXXbSGplEGmyoyeskM.jpg', '2016-02-11', 1025521689, 'zootropolis-2016', 'RELEASED', 'Zootrópolis', 269149, 'https://www.youtube.com/watch?v=rWq7HL67CsY', '2026-02-14 17:40:46.027471', 17658, 174),
	(191, NULL, 6.717, 'https://image.tmdb.org/t/p/w780/yubYUzjlrIMTHpXwJTRfiRuAu01.jpg', 0, '2025-11-15 20:00:02.012285', 'El juerguista Thomas (Victor Belmondo) se pasa las noches en discotecas y el día en la cama, hasta el día en que su padre, el Doctor Reinhard (Gerard Lanvin), cansado de su vagancia, decide cortar por lo sano y le obliga a cuidar de uno de sus jóvenes pacientes: Marcus (Yoann Eloundou), un niño de solo 12 años que vive solo con su madre. Marcus ha padecido desde su nacimiento una grave enfermedad. Este encuentro trastornará el día a día de unos y otros, y cambiará sus vidas.', 93, NULL, 'FR', 'fr', 26.9835, 'https://image.tmdb.org/t/p/w500/Aviebr72gvK9I73m68Go3K4hq1r.jpg', '2021-05-19', 0, 'hazme-volar-2021', 'RELEASED', 'Hazme volar', 783558, 'https://www.youtube.com/watch?v=7SB12RlcCHA', '2025-11-15 20:22:10.212099', 84, 175),
	(192, 'A', 6.902, 'https://image.tmdb.org/t/p/w780/yQy9Y3p5INwkfTuHSnzYnz4MCV3.jpg', 42000000, '2025-11-15 20:00:03.245692', 'Años después de que Tess y Anna atravesaran una crisis de identidad, Anna ahora tiene una hija y una futura hijastra. Mientras enfrentan los innumerables desafíos que surgen cuando dos familias se fusionan, Tess y Anna descubren que el rayo puede caer dos veces.', 110, NULL, 'US', 'en', 26.6235, 'https://image.tmdb.org/t/p/w500/3XFHVy03Rkr7ITaznFTeVp8dMwL.jpg', '2025-08-06', 152889065, 'ponte-en-mi-lugar-de-nuevo-2025', 'RELEASED', 'Ponte en mi lugar de nuevo', 1125257, 'https://www.youtube.com/watch?v=thctDWzwjY0', '2025-11-15 20:22:11.578019', 403, 176),
	(193, NULL, 5.083, 'https://image.tmdb.org/t/p/w780/vBVRgryngFoqHazyLqFca6xNTeB.jpg', 85000000, '2025-11-15 20:21:54.418777', 'Basada en una vieja serie de televisión de los años sesenta. Samantha (Nicole Kidman) es una bruja que trata de liberarse de sus sobrenaturales poderes para complacer a su mortal marido (Will Ferrell).', 102, NULL, 'US', 'en', 35.6588, 'https://image.tmdb.org/t/p/w500/p5E7ADhRYGOXczrwoH5WpbWXSdW.jpg', '2005-06-21', 131426169, 'embrujada-2005', 'RELEASED', 'Embrujada', 9722, 'https://www.youtube.com/watch?v=hS05j44UKUU', '2025-11-15 20:21:54.418777', 1604, 177),
	(194, NULL, 6.02, 'https://image.tmdb.org/t/p/w780/sSaUmM4bnZJ7PW5dlyRi7iONB65.jpg', 8000000, '2025-11-15 20:21:55.184092', 'De camino a su luna de miel, el vehículo de una pareja se avería, obligándoles a refugiarse en un remoto Airbnb. Al caer la noche, tres desconocidos enmascarados los aterrorizan hasta el amanecer.', 98, NULL, 'GB', 'en', 35.4424, 'https://image.tmdb.org/t/p/w500/fSRRH7UasrE6q240H00dww3vE1c.jpg', '2025-09-25', 21293765, 'los-extranos-capitulo-2-2025', 'RELEASED', 'Los extraños: Capítulo 2', 1010756, 'https://www.youtube.com/watch?v=vxp64gTBSxI', '2025-11-15 20:21:55.184092', 127, 178),
	(195, '16', 7.551, 'https://image.tmdb.org/t/p/w780/AfvIjhDu9p64jKcmohS4hsPG95Q.jpg', 16000000, '2025-11-15 20:21:55.749722', 'En una ciudad de Colorado, en los años 70, un enmascarado secuestra a Finney Shaw, un chico tímido e inteligente de 13 años, y le encierra en un sótano insonorizado donde de nada sirven sus gritos. Cuando un teléfono roto y sin conexión empieza a sonar, Finney descubre que a través de él puede oír las voces de las anteriores víctimas, las cuales están decididas a impedir que Finney acabe igual que ellas.', 102, NULL, 'US', 'en', 35.1341, 'https://image.tmdb.org/t/p/w500/k2owpqGMjmZzA0CVzzreuCtkQs0.jpg', '2022-06-16', 161441914, 'black-phone-2022', 'RELEASED', 'Black Phone', 756999, 'https://www.youtube.com/watch?v=XhcEnHDKHco', '2025-11-15 20:21:55.749722', 5488, 6),
	(196, '7', 7.94, 'https://image.tmdb.org/t/p/w780/9BBTo63ANSmhC4e6r62OJFuK2GL.jpg', 220000000, '2025-11-15 20:21:57.233239', 'Cuando un enemigo inesperado surge como una gran amenaza para la seguridad mundial, Nick Fury, director de la Agencia SHIELD, decide reclutar a un equipo para salvar al mundo de un desastre casi seguro.', 142, NULL, 'US', 'en', 59.2807, 'https://image.tmdb.org/t/p/w500/ugX4WZJO3jEvTOerctAWJLinujo.jpg', '2012-04-25', 1518815515, 'los-vengadores-2012', 'RELEASED', 'Los Vengadores', 24428, 'https://www.youtube.com/watch?v=HQIiYqOVTWo', '2026-02-14 17:40:23.322928', 35840, 179),
	(197, '12', 6.431, 'https://image.tmdb.org/t/p/w780/kzeBfhXMRWiykBsqoL3UbfaM0S.jpg', 42000000, '2025-11-15 20:21:58.289464', 'El torpe teniente Frank Drebin Jr. intenta resolver un asesinato vinculado a un magnate tecnológico. Mientras investiga, su unidad policial corre peligro de ser cerrada. Con la ayuda de una escritora de crímenes, Frank se verá envuelto en situaciones tan absurdas como explosivas. Película reboot basada en la popular franquicia de comedia "Agárralo como puedas" y la serie de televisión "Police Squad!".', 85, NULL, 'US', 'en', 23.273, 'https://image.tmdb.org/t/p/w500/v8FpKw8mOsHxC0YElkgNNSCzGMl.jpg', '2025-07-30', 102147396, 'agarralo-como-puedas-2025', 'RELEASED', 'Agárralo como puedas', 1035259, 'https://www.youtube.com/watch?v=AyF3ttDC8H0', '2026-02-09 17:27:31.139108', 1400, 180),
	(198, '18', 7.872, 'https://image.tmdb.org/t/p/w780/a3F9cXjRH488qcOqFmFZwqawBMU.jpg', 0, '2025-11-15 20:21:59.351203', 'Esta antología original de animación narra las aventuras de tres de los guerreros más fieros de la historia de la humanidad: una saqueadora vikinga que guía a su hijo en su sangrienta búsqueda de la venganza, un ninja del Japón feudal que se enfrenta a su hermano samurái en una brutal batalla por la sucesión y un piloto de la Segunda Guerra Mundial que surca los cielos para investigar una amenaza extraterrestre contra los Aliados.', 85, NULL, 'US', 'en', 33.5415, 'https://image.tmdb.org/t/p/w500/8upWJ1KTR1bAPqXCHAuVOhfuiAZ.jpg', '2025-06-05', 0, 'predator-asesino-de-asesinos-2025', 'RELEASED', 'Predator: Asesino de asesinos', 1376434, 'https://www.youtube.com/watch?v=6LxrgVndwgk', '2025-11-15 20:21:59.351203', 947, 3),
	(199, NULL, 7.211, 'https://image.tmdb.org/t/p/w780/yGByIyqgJerCw7AAphTrTAlrdkJ.jpg', 2000000, '2025-11-15 20:22:00.245997', 'Un comandante británico, prisionero en un campo japonés, se esfuerza por sobrevivir. Su valentía inspira a otros prisioneros y lo convierte en un símbolo de dignidad ante la adversidad.', 113, NULL, 'PH', 'en', 33.1272, 'https://image.tmdb.org/t/p/w500/6paGLyOAvY95XxjfdiTcatwI7dJ.jpg', '2025-09-19', 0, 'prisionero-de-guerra-2025', 'RELEASED', 'Prisionero de guerra', 1328803, 'https://www.youtube.com/watch?v=mKFL8CMoCVk', '2025-11-15 20:22:00.245997', 116, 181),
	(200, 'APTA', 5.972, 'https://image.tmdb.org/t/p/w780/3fUule7CGt4Eq1lPPqyz3qSXa8C.jpg', 6000000, '2025-11-15 20:22:02.475160', 'Los protagonistas de la película son un curioso y excéntrico grupo de criaturas abisales a los que no le queda otro remedio que abandonar su hogar, situado en la grieta más profunda del océano. Al verse sin sitio donde vivir, los animales se deciden a encontrar un nuevo hogar, y en su búsqueda de una nueva casa les ocurrirán disparatadas y extraordinarias aventuras.', 92, NULL, 'BE', 'en', 32.4181, 'https://image.tmdb.org/t/p/w500/tfpJqV97nTgoHQGplkZkUod0joM.jpg', '2017-05-11', 10972300, 'deep-2017', 'RELEASED', 'Deep', 430474, 'https://www.youtube.com/watch?v=03FXd_EMGzM', '2025-11-15 20:22:02.475160', 145, 182),
	(201, NULL, 6.984, 'https://image.tmdb.org/t/p/w780/sUoPlzchsCECqpm3ZmDPeL8QKDK.jpg', 0, '2025-11-19 18:33:55.955491', 'En 1944, un prolífico experto del ocultismo y el whisky, El Reverendo, acompaña a un grupo de militares a una remota isla del Pacífico Sur para investigar la desaparición de las unidades estacionadas allí.', 94, NULL, 'TH', 'en', 293.4397, 'https://image.tmdb.org/t/p/w500/x4hebEzPIn8WeyTEQSj2jotpYzM.jpg', '2024-12-12', 0, 'caza-sangrienta-2024', 'RELEASED', 'Caza sangrienta', 1084222, 'https://www.youtube.com/watch?v=Pt4s2aALIxg', '2025-11-19 18:33:55.955491', 32, 181),
	(202, NULL, 6.935, 'https://image.tmdb.org/t/p/w780/4frrYwamVG0eXhdMTy3cpNNcCBp.jpg', 38500000, '2025-11-19 18:33:57.719549', 'Un exdetective se convierte en fiscal y enfrenta la corrupción en el sistema judicial. Al investigar un caso lleno de dudas, se embarca en una misión personal para hacer justicia, enfrentándose a traficantes de drogas, conspiraciones y jueces corruptos en un intenso thriller de acción.', 117, NULL, 'CN', 'zh', 266.1162, 'https://image.tmdb.org/t/p/w500/hLAek7EiM5NpLiotmQkmS8SIZw9.jpg', '2024-12-08', 128093757, 'the-prosecutor-2024', 'RELEASED', 'The Prosecutor', 1128650, 'https://www.youtube.com/watch?v=j5c13X9j_0o', '2025-11-19 18:33:57.719549', 125, 183),
	(203, '16', 5.8, 'https://image.tmdb.org/t/p/w780/fxKC10HQliVA3Tn5smOclqzL96N.jpg', 0, '2025-11-19 18:34:11.563347', 'Ambientada en el Pacífico, 1942. Un soldado japonés y un prisionero de guerra británico se encuentran varados en una isla desierta, perseguidos por una criatura mortal. Dos enemigos acérrimos deben unirse para sobrevivir a lo desconocido.', 83, NULL, 'JP', 'en', 128.0507, 'https://image.tmdb.org/t/p/w500/x1JOs4xWNr1QYjDAXHxWw1NJ7Sq.jpg', '2025-05-08', 0, 'monster-island-2025', 'RELEASED', 'Monster Island', 1214140, 'https://www.youtube.com/watch?v=Z1V4mciJa8I', '2025-11-19 18:34:11.563347', 60, 184),
	(204, '18', 7.4, 'https://image.tmdb.org/t/p/w780/yCatt8lmp3oRFEcOZF8KHhsiASQ.jpg', 12200000, '2025-12-21 17:47:14.447880', 'Al regresar a la casa donde su familia fue brutalmente asesinada durante la guerra, «el hombre que se niega a morir» la desmantela, la carga en un camión y se propone reconstruirla en un lugar seguro en honor a ellos. Cuando el comandante del Ejército Rojo que mató a su familia regresa empeñado en terminar el trabajo, se produce una implacable y espectacular persecución a través del país, una lucha a muerte llena de escenas de acción increíbles e ingeniosas.', 89, NULL, 'FI', 'fi', 35.0129, 'https://image.tmdb.org/t/p/w500/qQyc6t9dHS5dlIUt3ccCQnRIAc1.jpg', '2025-10-21', 9724644, 'sisu-camino-a-la-venganza-2025', 'RELEASED', 'Sisu: Camino a la venganza', 1223601, 'https://www.youtube.com/watch?v=SzWyH7r5gM8', '2026-02-14 17:41:09.391638', 533, 185),
	(205, '12', 6, 'https://image.tmdb.org/t/p/w780/8vLt9TYFZdAwYtqImvggTM5yFnF.jpg', 0, '2025-12-21 17:47:15.434944', 'En el que podría ser el último día en la Tierra, una lucha a vida o muerte en un piso inundado se convierte en la única esperanza de supervivencia de la humanidad.', 107, NULL, 'KR', 'ko', 34.7509, 'https://image.tmdb.org/t/p/w500/qIzSyT2AmDxkcQ0zOAeTbtZR9EQ.jpg', '2025-09-18', 0, 'el-gran-diluvio-2025', 'RELEASED', 'El gran diluvio', 982843, 'https://www.youtube.com/watch?v=SYF0MxHVAR0', '2026-02-14 17:40:51.511301', 573, 186),
	(206, NULL, 6.137, 'https://image.tmdb.org/t/p/w780/4mZ06VpfpAPuaUPn1SEV0brbbxe.jpg', 0, '2025-12-21 17:47:17.217162', 'Un padre esconde a su hija en una isla para mantenerla a salvo mientras la equipa para la supervivencia y las batallas que se avecinan.', 95, NULL, 'GB', 'en', 34.4741, 'https://image.tmdb.org/t/p/w500/7K8w6mdrJp0oaSoKWGyjSZ4Zv2z.jpg', '2025-10-30', 0, 'worldbreaker-2025', 'RELEASED', 'Worldbreaker', 1196067, 'https://www.youtube.com/watch?v=HkTa_lrY-uc', '2026-02-14 17:40:52.228966', 73, 187),
	(207, '12', 7.21, 'https://image.tmdb.org/t/p/w780/fiRDzpcJe7qz3yIR43hdXIE3NHv.jpg', 210000000, '2025-12-21 17:47:18.989820', 'El detective Benoit Blanc se une a un joven y honesto sacerdote para investigar un crimen totalmente imposible en la iglesia de un pequeño pueblo con una oscura historia.', 145, NULL, 'US', 'en', 23.6926, 'https://image.tmdb.org/t/p/w500/trGWfaYTkzkalkosXfxidpLum50.jpg', '2025-11-26', 4000000, 'punales-por-la-espalda-de-entre-los-muertos-2025', 'RELEASED', 'Puñales por la espalda: De entre los muertos', 812583, 'https://www.youtube.com/watch?v=ek_1vaeoimg', '2026-02-09 17:27:20.010773', 2010, 188),
	(208, NULL, 6, 'https://image.tmdb.org/t/p/w780/AePlQ3osZShJmbNj8tzQ3NoMTQF.jpg', 0, '2025-12-21 17:47:19.881563', 'John tiene 70 años y vive en un lujoso y solitario hotel de la Costa Azul. Se siente intrigado por la mujer de la habitación de al lado, que le recuerda sus años salvajes en la Riviera en la década de 1960, cuando era un elegante espía internacional en un mundo lleno de peligros y promesas. Pero cuando la mujer desaparece misteriosamente, John se ve acosado por recuerdos -o tal vez fantasías- de su glamuroso y grotesco pasado, y de las seductoras mujeres y ruines villanos que vivieron y murieron allí.', 87, NULL, 'BE', 'fr', 206.6559, 'https://image.tmdb.org/t/p/w500/scOBEcIfVlG890tKV5XI42t0EhU.jpg', '2025-06-25', 0, 'reflection-in-a-dead-diamond-2025', 'RELEASED', 'Reflection in a Dead Diamond', 1013446, 'https://www.youtube.com/watch?v=6Zv6zK8N9Lk', '2025-12-21 17:47:19.881563', 45, 189),
	(209, NULL, 4.9, 'https://image.tmdb.org/t/p/w780/hvut2slhhgJ31UNa9Df7jFfAS0x.jpg', 0, '2025-12-21 17:47:20.845069', 'En el gélido desierto de Minnesota, Leland “Lee” Shaw, un desafortunado repartidor se convierte en la presa de un perturbado conductor de una máquina quitanieves, al que apoda Mr. Plow. Lo que empieza como un encuentro fortuito se transforma en una persecución obsesiva y letal, en la que Lee deberá usar todo su ingenio para sobrevivir.', 84, NULL, 'FI', 'en', 183.3981, 'https://image.tmdb.org/t/p/w500/jCbetGJOpo3z7afIuO5TjWph0q5.jpg', '2025-09-10', 0, 'el-diablo-sobre-hielo-2025', 'RELEASED', 'El diablo sobre hielo', 1336189, 'https://www.youtube.com/watch?v=wSQfOI3QriQ', '2025-12-21 17:47:20.845069', 17, 190),
	(210, '16', 6.4, 'https://image.tmdb.org/t/p/w780/hyc9gq0Oq5THKak7tB7oqC2Rd6z.jpg', 0, '2025-12-21 17:47:21.820829', 'Los secretos enterrados de un pueblo de Montana en la década de 1870 provocan una oleada de violencia cuando un joven regresa para reclamar su legado y queda atrapado entre un sheriff decidido a mantener el orden y un misterioso extraño empeñado en destruirlo.', 95, NULL, 'US', 'en', 23.4413, 'https://image.tmdb.org/t/p/w500/g6QtO93J2nVkJ8BduNE1WS9Fg2h.jpg', '2025-06-13', 1000526, 'maldita-trinidad-2025', 'RELEASED', 'Maldita trinidad', 1195518, 'https://www.youtube.com/watch?v=HgiEya5fjWo', '2026-02-14 17:41:46.163053', 157, 191),
	(211, NULL, 7.138, 'https://image.tmdb.org/t/p/w780/eJ0HooOOD1uzI39CfOQNWIiWKlJ.jpg', 0, '2025-12-21 17:47:23.665763', 'Cuando una misteriosa joven aparece en la orilla de un río local, tanto la niña de doce años que la descubre como su sobreprotector padre cambian para siempre con la llegada de esta extraña a su hogar. Mientras, un despiadado capo de la droga no se detendrá ante nada para matarla de una vez por todas.', 93, NULL, 'US', 'en', 30.1379, 'https://image.tmdb.org/t/p/w500/cbryTyaWdqrKpQCw6K7zm2jrB5v.jpg', '2025-12-05', 0, 'hunting-season-2025', 'RELEASED', 'Hunting Season', 1387382, 'https://www.youtube.com/watch?v=O7vKuVadFmo', '2026-02-14 17:41:07.961275', 134, 192),
	(212, '18', 6.701, 'https://image.tmdb.org/t/p/w780/54BOXpX2ieTXMDzHymdDMnUIzYG.jpg', 36000000, '2025-12-21 17:47:24.428096', 'Un año después de la pesadilla sobrenatural en Freddy Fazbear\'s Pizza, las historias sobre lo ocurrido allí se han convertido en una leyenda local extravagante, inspirando el primer Fazfest del pueblo. Con la verdad oculta, Abby se escapa para reencontrarse con Freddy, Bonnie, Chica y Foxy, desencadenando una serie de eventos aterradores que revelarán oscuros secretos sobre el verdadero origen de Freddy\'s y desatarán un horror oculto durante décadas.', 104, NULL, 'US', 'en', 33.8096, 'https://image.tmdb.org/t/p/w500/egHOFSRXrAaugFUD7VMEnXlTnzJ.jpg', '2025-12-03', 239309958, 'five-nights-at-freddy-s-2-2025', 'RELEASED', 'Five Nights at Freddy\'s 2', 1228246, 'https://www.youtube.com/watch?v=d_St1yVHIsI', '2026-02-14 17:40:55.813974', 728, 193),
	(213, NULL, 6.652, 'https://image.tmdb.org/t/p/w780/sW0X1265yuRHUorLKCrJDv9TJD7.jpg', 0, '2025-12-21 17:47:25.425071', '', 88, NULL, 'TH', 'th', 30.3862, 'https://image.tmdb.org/t/p/w500/1kQTLtNy8A5lAWEU2LfjWxg6UQJ.jpg', '2025-07-11', 0, 'bang-2025', 'RELEASED', 'ปัง', 1491902, 'https://www.youtube.com/watch?v=ttIWwPJUGDI', '2026-02-14 17:41:11.538880', 66, 194),
	(214, '16', 7.036, 'https://image.tmdb.org/t/p/w780/1dqFuNiutgBdNF9d5QOQBWHHvft.jpg', 0, '2025-12-21 17:47:27.326636', 'Tras huir del Reino Unido por un trabajo que le salió mal, un asesino a sueldo venido a menos se ve obligado a cuidar del hijo de su nuevo jefe criminal y enseñarle a convertirse en un hombre.', 114, NULL, 'ZA', 'en', 136.7398, 'https://image.tmdb.org/t/p/w500/cpQ4VxBJO7vGV3IUdKzSNf4tH9V.jpg', '2025-09-18', 0, 'london-calling-2025', 'RELEASED', 'London Calling', 1217602, 'https://www.youtube.com/watch?v=Up6t9Fp0_ZE', '2025-12-21 17:47:27.326636', 55, 195),
	(215, NULL, 8, 'https://image.tmdb.org/t/p/w780/vJ1z82bLSfg71sQcJ370N4TpWqf.jpg', 0, '2025-12-21 17:47:28.419321', '', 93, NULL, 'US', 'en', 129.7102, 'https://image.tmdb.org/t/p/w500/kJ87DDxmCRWTJPl0aulDEHCwNzY.jpg', '2024-10-23', 0, 'slaughterhouse-2-2024', 'RELEASED', 'Slaughterhouse 2', 1438030, NULL, '2025-12-21 17:47:28.419321', 2, 196),
	(216, '12', 6.8, 'https://image.tmdb.org/t/p/w780/gtuXARxjGdfsGFqEwggBB8zUJza.jpg', 0, '2025-12-21 17:47:29.345642', 'Un psicoanalista que cumple servicio comunitario ayuda a un inspector destrozado por una infidelidad. Juntos afrontarán el peligro y descubrirán segundas oportunidades.', 107, NULL, 'AR', 'es', 124.6853, 'https://image.tmdb.org/t/p/w500/8ZoDrAbrsSLDVjXsyvOlwjJakUK.jpg', '2025-12-18', 0, 'la-hora-de-los-valientes-2025', 'RELEASED', 'La hora de los valientes', 1589891, NULL, '2025-12-21 17:47:29.345642', 4, 197),
	(217, '16', 7.1, 'https://image.tmdb.org/t/p/w780/vMxOmgmBGegjVObjlb8ugsjGgkD.jpg', 0, '2026-01-10 21:41:14.987710', 'Frente oriental, 1943: la dotación alemana de un tanque Tiger se embarca en una peligrosa misión tras las líneas enemigas. A medida que atraviesan la mortífera tierra de nadie, deberán enfrentarse al enemigo y a sus propios fantasmas del pasado.', 116, NULL, 'DE', 'de', 50.1786, 'https://image.tmdb.org/t/p/w500/td8bh7p876r36OF0P9PN7fitrCG.jpg', '2025-09-18', 0, 'der-tiger-el-tanque-2025', 'RELEASED', 'Der Tiger (El tanque)', 1252037, 'https://www.youtube.com/watch?v=4uZWlKGRZis', '2026-02-14 17:40:24.189804', 324, 198),
	(218, '16', 6.593, 'https://image.tmdb.org/t/p/w780/oIJjO1CvEdTMFNkWfHaV0RB584G.jpg', 0, '2026-01-10 21:41:18.335733', 'Un agente de la DEA y su compañero persiguen un peculiar grupo de ladrones: sus propios hijos adolescentes rebeldes, que han empezado a robar a un peligroso cártel, utilizando para ello las tácticas de sus padres y la información de alto secreto.', 102, NULL, 'GB', 'en', 42.8738, 'https://image.tmdb.org/t/p/w500/p9zbrDpAKyj3jeemkyAoBmlo3KG.jpg', '2025-11-14', 0, 'trap-house-2025', 'RELEASED', 'Trap House', 628847, 'https://www.youtube.com/watch?v=z5mCWsv0Z7U', '2026-02-14 17:40:33.192695', 209, 199),
	(219, NULL, 5.948, 'https://image.tmdb.org/t/p/w780/wCwZ4ljSsWyZyTiyk1tGQtBHTDx.jpg', 65000000, '2026-01-10 21:41:19.203405', 'Cuando una pareja tribal encuentra a un niño misterioso cerca de una estruendosa cascada, lo crían como si fuera suyo. A medida que crece, Sivudu se siente atraído por el mundo más allá de los acantilados, donde descubre el antiguo reino de Mahishmati, gobernado por un tirano cruel, asolado por la rebelión y ligado a su propio pasado. Lo que comienza como una búsqueda por amor, pronto desentraña un legado de traición, sacrificio y un príncipe olvidado.', 224, NULL, 'IN', 'te', 42.665, 'https://image.tmdb.org/t/p/w500/z9YIo2qscyaXYgRqIdRJtND3bw8.jpg', '2025-10-29', 3500000, 'baahubali-the-epic-2025', 'RELEASED', 'Baahubali: The Epic', 1511417, 'https://www.youtube.com/watch?v=q8nbZbHRcEg', '2026-02-09 17:26:06.445768', 29, 200),
	(220, NULL, 7.203, 'https://image.tmdb.org/t/p/w780/tNONILTe9OJz574KZWaLze4v6RC.jpg', 35000000, '2026-01-10 21:41:20.905624', 'Una joven (Sydney Sweeney), con un pasado complicado comienza a trabajar como asistenta en la lujosa casa de los Winchester. A medida que se adentra en la vida de la familia, descubrirá secretos oscuros que pondrán en peligro su seguridad, pero quizá ya sea demasiado tarde... Adaptación de la novela de Freida McFadden.', 131, NULL, 'US', 'en', 221.2291, 'https://image.tmdb.org/t/p/w500/A6S15iqfHpoit02leDfDVnpklys.jpg', '2025-12-18', 334411969, 'la-asistenta-2025', 'RELEASED', 'La asistenta', 1368166, 'https://www.youtube.com/watch?v=IMrebLqjVVQ', '2026-02-16 16:49:43.779697', 1116, 201),
	(221, NULL, 6.534, 'https://image.tmdb.org/t/p/w780/mZGsJUzQ4dONUBccxhImBqxaSQt.jpg', 0, '2026-01-10 21:41:23.396924', 'La novela favorita de Dokja se hace ominosamente realidad; utilizando sus intrincados conocimientos sobre la inminente historia apocalíptica, el oficinista cambia el destino.', 117, NULL, 'KR', 'ko', 33.7939, 'https://image.tmdb.org/t/p/w500/lWQRM7IOCyJT9E5kOnoUvZNELHQ.jpg', '2025-07-23', 9187679, '2025-1131759', 'RELEASED', 'Lector omnisciente: La profecía', 1131759, 'https://www.youtube.com/watch?v=iglaBnDKG2c', '2026-02-14 17:40:56.548777', 59, 186),
	(222, NULL, 7.136, 'https://image.tmdb.org/t/p/w780/novE5UrqfLIFEMe5QBnjm18GG4E.jpg', 0, '2026-01-10 21:41:25.371852', 'Un grupo de strippers busca vengarse de sus jefes robando en los clubes de striptease en los que trabajan.', 91, NULL, 'US', 'en', 116.1836, 'https://image.tmdb.org/t/p/w500/h6OsRrDwbspLnKMvlFl57QFDP7d.jpg', '2025-08-01', 0, 'risque-2025', 'RELEASED', 'Risqué', 1512623, 'https://www.youtube.com/watch?v=dgxE-O2kIlM', '2026-01-10 21:41:25.371852', 33, 202),
	(223, NULL, 6.105, 'https://image.tmdb.org/t/p/w780/b9iQP6brbuGs8mhRPRV0ThiwD5I.jpg', 0, '2026-01-10 21:41:26.247894', 'Carla sueña con convertirse en una gran influencer, para lograrlo decide fingir un embasa en su apartamento. Sin embargo, al jugar con estas fuerzas oscuras, accidentalmente deja entrar a una entidad maligna real.', 83, NULL, 'MX', 'es', 112.1084, 'https://image.tmdb.org/t/p/w500/gop4DwcBeb9T3JTaxwDEHdJNqSq.jpg', '2025-10-30', 1015383, 'no-me-sigas-2025', 'RELEASED', 'No Me Sigas', 772462, 'https://www.youtube.com/watch?v=aBx-Myc1D-M', '2026-01-10 21:41:26.247894', 19, 203),
	(224, NULL, 6.9, 'https://image.tmdb.org/t/p/w780/9pdoEzieGdUTlRWTAO7QP8q1tIo.jpg', 9500000, '2026-01-10 21:41:28.806693', '', 123, NULL, 'KR', 'ko', 23.4891, 'https://image.tmdb.org/t/p/w500/k4yTwFqvQDApqaoFdgubsbYcuno.jpg', '2025-04-16', 24508523, '2025-1137179', 'RELEASED', '야당', 1137179, 'https://www.youtube.com/watch?v=qdgVwlTaVC0', '2026-02-14 17:41:44.331676', 34, 204),
	(225, NULL, 6.76, 'https://image.tmdb.org/t/p/w780/ncI1PlBcANixIkgQSnjsSRz4OyT.jpg', 0, '2026-01-10 21:41:29.685805', 'Jake Rosser está atormentado por el trastorno de estrés postraumático de sus días como oficial K-9 y se esfuerza por llevar una vida pacífica con su familia y su compañero K-9 retirado, Socks. Pero la tranquilidad se disuelve rápidamente cuando una despiadada banda los persigue en un brutal ataque. Decidido a proteger a sus seres queridos, Jake y su nuevo compañero K-9 «Argos» se adentran en los violentos entresijos de la delincuencia, donde Jake se enfrenta a funcionarios corruptos, descubre una peligrosa red de tráfico de drogas y lucha contra sus propios demonios internos.', 93, NULL, 'US', 'en', 27.921, 'https://image.tmdb.org/t/p/w500/yBg2t8vuqrE8nqrxS3VzW3Qvzh3.jpg', '2025-11-13', 0, 'en-busca-de-venganza-2-ciudad-de-los-lobos-2025', 'RELEASED', 'En busca de venganza 2: Ciudad de los lobos', 1439112, 'https://www.youtube.com/watch?v=pmwhUan8QL8', '2026-02-14 17:41:15.435128', 104, 205),
	(226, NULL, 6.4, 'https://image.tmdb.org/t/p/w780/fepnF3W4VP3s8ui8nDtrlsFVYwO.jpg', 0, '2026-01-10 21:41:30.547889', 'A sus 65 años, Hornclaw es una legendaria asesina que empieza a sentir el peso del tiempo. Mientras su cuerpo falla y considera el retiro, se ve acechada por un joven sicario sediento de venganza y por un inesperado despertar de su propia humanidad que pone en peligro su última misión.', 123, NULL, 'KR', 'ko', 23.0156, 'https://image.tmdb.org/t/p/w500/A9yJjkI7GdqeFYMyUe4PebA2NIw.jpg', '2025-04-30', 0, '2025-1247002', 'RELEASED', 'La anciana con el cuchillo', 1247002, 'https://www.youtube.com/watch?v=KU4_jUwI6PQ', '2026-02-14 17:41:50.103160', 53, 206),
	(227, '7', 7.298, 'https://image.tmdb.org/t/p/w780/faV0HuR6WnQoLrVq3r6mhjaABL9.jpg', 200000000, '2026-02-07 22:12:26.211929', 'Han pasado dos años desde que el tranquilo Peter Parker dejó a Mary Jane Watson, su gran amor, y decidió seguir asumiendo sus responsabilidades como Spider-Man. Peter debe afrontar nuevos desafíos mientras lucha contra el don y la maldición de sus poderes equilibrando sus dos identidades: el escurridizo superhéroe Spider-Man y el estudiante universitario. Las relaciones con las personas que más aprecia están ahora en peligro de ser descubiertas con la aparición del poderoso villano de múltiples tentáculos Doctor Octopus, "Doc Ock".', 135, NULL, 'US', 'en', 6.9962, 'https://image.tmdb.org/t/p/w500/bf0KrQZceXP7jQNUxfpMxSGVf5E.jpg', '2004-06-25', 788976453, 'spider-man-2-2004', 'RELEASED', 'Spider-Man 2', 558, 'https://www.youtube.com/watch?v=0EhKGAfNBBw', '2026-02-07 22:12:26.211929', 16034, 207),
	(228, NULL, 6.542, 'https://image.tmdb.org/t/p/w780/tyjXlexbNZQ0ZT1KEJslQtBirqc.jpg', 90000000, '2026-02-07 22:13:07.838551', 'La familia Garrity superviviente debe abandonar la seguridad del búnker de Groenlandia y embarcarse en un peligroso viaje a través del diezmado páramo helado de Europa para encontrar un nuevo hogar.', 98, NULL, 'GB', 'en', 352.5371, 'https://image.tmdb.org/t/p/w500/3yrX2kZ1zXZ1JJeexMobX77VVim.jpg', '2026-01-07', 39924680, 'greenland-2-2026', 'RELEASED', 'Greenland 2', 840464, 'https://www.youtube.com/watch?v=ObUUuWCM-aQ', '2026-02-16 16:49:41.151437', 436, 208),
	(229, '16', 6.876, 'https://image.tmdb.org/t/p/w780/cz4vLJrmaV1zJlRYbxqtvLzeLWB.jpg', 78500000, '2026-02-07 22:13:08.615443', 'Un improbable dúo de hermanastros, uno un impulsivo detective y el otro un disciplinado, se ven atraídos por el asesinato de su padre en Hawai, lo que les lleva a un peligroso viaje para desenmascarar una conspiración de largo alcance.', 124, NULL, 'US', 'en', 246.5259, 'https://image.tmdb.org/t/p/w500/ttEESBvVrO8ngZr19qp6eBMVS9F.jpg', '2026-01-28', 89000000, 'los-hermanos-demolicion-2026', 'RELEASED', 'Los hermanos demolición', 1168190, 'https://www.youtube.com/watch?v=hHSqxP7g8JY', '2026-02-16 16:49:44.534195', 594, 209),
	(230, NULL, 6.4, 'https://image.tmdb.org/t/p/w780/6D6M5z4reppUxo2cnBEKI02Csp1.jpg', 0, '2026-02-07 22:13:12.452259', 'Tras retirarse de la policía, un implacable detective atormentado por la trágica pérdida de su mejor amigo emprende una peligrosa búsqueda de venganza, buscando la redención y luchando también por devolver la justicia a las calles que una vez juró proteger.', 93, NULL, 'ES', 'en', 168.1041, 'https://image.tmdb.org/t/p/w500/tsE3nySukwrfUjouz8vzvKTcXNC.jpg', '2026-01-09', 0, 'oscar-shaw-2026', 'RELEASED', 'Oscar Shaw', 1601243, 'https://www.youtube.com/watch?v=ZMlCJQ2SefU', '2026-02-16 16:49:49.816534', 19, 210),
	(231, '12', 5.7, 'https://image.tmdb.org/t/p/w780/gLXibzLQ4qegvjdqDC0f8yTij2P.jpg', 0, '2026-02-07 22:13:13.339391', '1934. Miranda Green, detective privada, investiga un asesinato perpetrado en la embajada británica en El Cairo, donde se robó un documento de alto secreto, con el riesgo de poner en peligro el Palacio de Buckingham y la paz del mundo.', 83, NULL, 'GB', 'en', 100.0009, 'https://image.tmdb.org/t/p/w500/vW5pt7wPbY2mtsGd26IqV39zRJa.jpg', '2025-11-14', 0, 'asesinato-en-la-embajada-2025', 'RELEASED', 'Asesinato en la Embajada', 1310568, 'https://www.youtube.com/watch?v=sgohJhg82bc', '2026-02-16 16:49:56.494467', 32, 211),
	(232, NULL, 5.765, 'https://image.tmdb.org/t/p/w780/lAtuFCx6cYkNBmTMSNnLE0qlCLx.jpg', 0, '2026-02-07 22:13:14.308936', 'Un experto en bombas y su prometida suben a un tren que contiene explosivos, mientras un profesor de física envuelto en un escándalo toma el mismo tren con la esperanza de reconciliarse con su esposa, quien partió en un tren anterior.', 117, NULL, 'TW', 'zh', 105.5725, 'https://image.tmdb.org/t/p/w500/4XpYp1yrNI49OY8lz4qZuI7baeQ.jpg', '2025-09-05', 0, '96-minutes-2025', 'RELEASED', '96 Minutos', 1271895, NULL, '2026-02-16 16:49:54.824262', 51, 212),
	(233, '16', 5.818, 'https://image.tmdb.org/t/p/w780/swxhEJsAWms6X1fDZ4HdbvYBSf9.jpg', 45000000, '2026-02-07 22:13:15.075194', 'Doug y Griff son muy buenos amigos desde que eran niños y siempre han soñado con hacer un remake de su película favorita de todos los tiempos: el «clásico cinematográfico» Anaconda. Cuando una crisis de mediana edad les anima a lanzarse por fin a la aventura, se adentran en la selva amazónica para empezar a rodar. Pero las cosas se ponen serias cuando aparece una anaconda gigante de verdad, convirtiendo su caótico y cómico plató de rodaje en una situación mortal.', 100, NULL, 'US', 'en', 86.4835, 'https://image.tmdb.org/t/p/w500/zX1KJPiGTrzpFcjfOWlmqdRgpQd.jpg', '2025-12-24', 131454208, 'anaconda-2025', 'RELEASED', 'Anaconda', 1234731, 'https://www.youtube.com/watch?v=FVPjkbmgX74', '2026-02-14 17:40:09.860883', 568, 213),
	(234, NULL, 6.177, 'https://image.tmdb.org/t/p/w780/eUERZRVjCTNdgnESlQxyaOJ2d4K.jpg', 0, '2026-02-07 22:13:16.107940', 'Una asesina entrenada por la CIA recluta a otros graduados de su programa secreto de la infancia, The Internship, para destruir violentamente la organización. La CIA contraataca con fuerza letal.', 91, NULL, 'US', 'en', 117.5942, 'https://image.tmdb.org/t/p/w500/fYqSOkix4rbDiZW0ACNnvZCpT6X.jpg', '2026-01-13', 0, 'the-internship-2026', 'RELEASED', 'The Internship', 1584215, 'https://www.youtube.com/watch?v=uXRFha7MLTM', '2026-02-16 16:49:53.807739', 48, 214),
	(235, '16', 7.059, 'https://image.tmdb.org/t/p/w780/3F2EXWF1thX0BdrVaKvnm6mAhqh.jpg', 100000000, '2026-02-07 22:13:18.538401', 'El descubrimiento de varios millones de dólares en efectivo en un zulo abandonado de Miami quiebra la confianza de un grupo de policías. Ahora, todo y todos están bajo sospecha.', 113, NULL, 'US', 'en', 100.845, 'https://image.tmdb.org/t/p/w500/55C5loKFkw7Cj0nMLWux4FJCRHI.jpg', '2026-01-13', 0, 'el-botin-2026', 'RELEASED', 'El botín', 1306368, 'https://www.youtube.com/watch?v=yeR5bcbRPak', '2026-02-16 16:49:57.216672', 1175, 215),
	(236, NULL, 7.814, 'https://image.tmdb.org/t/p/w780/73BClq9FOcrWrutnpiqhCNEWEwJ.jpg', 35000000, '2026-02-07 22:13:20.108527', 'Descubre la poderosa historia de amor que inspiró la creación de Hamlet, la intemporal obra maestra de Shakespeare.', 126, NULL, 'GB', 'en', 141.77, 'https://image.tmdb.org/t/p/w500/hVo0g5M8z1kuhzxQ51eCbF81wUh.jpg', '2025-11-26', 70561705, 'hamnet-2025', 'RELEASED', 'Hamnet', 858024, 'https://www.youtube.com/watch?v=Ith7z6FzLe0', '2026-02-09 17:26:02.902804', 380, 216),
	(237, 'A', 8.044, 'https://image.tmdb.org/t/p/w780/oN4TQ1TxchynXlFiXFBL3NHLT54.jpg', 60900000, '2026-02-07 22:13:21.131042', 'En un reino gobernado por el miedo, un joven pastor se atreve a enfrentarse a un gigante y a la oscuridad que se oculta tras él. Su valor despertará a una nación y demostrará que la verdadera fuerza proviene de la confianza, no del poder.', 115, NULL, 'US', 'en', 85.0013, 'https://image.tmdb.org/t/p/w500/bESlrLOrsQ9gKzaGQGHXKOyIUtX.jpg', '2025-12-14', 83092325, 'david-2025', 'RELEASED', 'David', 1167307, 'https://www.youtube.com/watch?v=gWgyI6_lR0A', '2026-02-14 17:40:11.089672', 80, 217),
	(238, NULL, 7.659, 'https://image.tmdb.org/t/p/w780/nHxWyy18SvAZ8jJeemtS8k1UNjM.jpg', 50000000, '2026-02-07 22:13:21.733507', 'Un recluso en una remota isla escocesa rescata a una niña del mar, desencadenando una peligrosa secuencia de acontecimientos.', 107, NULL, 'US', 'en', 68.6745, 'https://image.tmdb.org/t/p/w500/j1knvM0CSG1TWWEdgz4AVqb5CXP.jpg', '2026-01-28', 26786795, 'shelter-el-protector-2026', 'RELEASED', 'Shelter: El Protector', 1290821, 'https://www.youtube.com/watch?v=tjRn9EeN3rE', '2026-02-14 17:40:15.419622', 41, 208),
	(239, NULL, 7.02, 'https://image.tmdb.org/t/p/w780/eyvIBnJSxZDyek4s7YytUNmtstR.jpg', 40000000, '2026-02-07 22:13:22.294631', 'Después de que un accidente de avión deje varados en una isla remota a una competente empleada y a su insoportable jefe, ella deberá utilizar sus habilidades de supervivencia para mantenerlos a ambos con vida, a pesar de su difícil relación.', 113, NULL, 'US', 'en', 68.1416, 'https://image.tmdb.org/t/p/w500/m6cubm61t8UfL4KhkP4DJVrWjhj.jpg', '2026-01-22', 53739748, 'send-help-enviad-ayuda-2026', 'RELEASED', 'SEND HELP (Enviad ayuda)', 1198994, 'https://www.youtube.com/watch?v=OTMeWZNhE64', '2026-02-14 17:40:18.623357', 248, 207),
	(240, NULL, 6.673, 'https://image.tmdb.org/t/p/w780/AecGG1XVCmkk7fT10ko3FC0dLIP.jpg', 0, '2026-02-07 22:13:23.171412', 'Una niña de ocho años le pide ayuda a su insidiosa vecina en su misión para matar al monstruo que vive debajo de su cama, el cual, según ella, devoró a su familia.', 106, NULL, 'US', 'en', 84.3189, 'https://image.tmdb.org/t/p/w500/vobigFZFvbYPf6ElYJu07P9rH8C.jpg', '2025-12-11', 928164, 'dust-bunny-2025', 'RELEASED', 'Atrapando a un monstruo', 1043197, 'https://www.youtube.com/watch?v=lQqmOjPDlWg', '2026-02-14 17:40:12.073545', 166, 218),
	(241, NULL, 5.524, 'https://image.tmdb.org/t/p/w780/lALfCsv7YMNrqpWzIaxjS81JKOm.jpg', 0, '2026-02-07 22:13:24.234936', '', 87, NULL, 'US', 'en', 43.3121, 'https://image.tmdb.org/t/p/w500/7tmMQwSVVbijKV4lquYpBld3P9K.jpg', '2026-01-08', 0, 'the-confession-2026', 'RELEASED', 'The Confession', 1454741, 'https://www.youtube.com/watch?v=wSRkwijeNjs', '2026-02-14 17:40:27.059438', 21, 219),
	(242, '16', 6.004, 'https://image.tmdb.org/t/p/w780/eftVUg9R1lys3wT8kHJqMaK64m7.jpg', 0, '2026-02-09 17:18:06.952821', 'Confinado en una apartada residencia de ancianos y atrapado en su cuerpo, que ha sufrido un derrame cerebral, un ex juez debe detener a un anciano psicópata que emplea a una marioneta infantil para abusar de los residentes de la residencia con consecuencias mortales.', 104, NULL, 'NZ', 'en', 45.8113, 'https://image.tmdb.org/t/p/w500/5JclbA9aFQmkipu2S2b80FfwRPj.jpg', '2025-03-07', 422256, 'la-ley-de-jenny-pen-2025', 'RELEASED', 'La ley de Jenny Pen', 1212742, 'https://www.youtube.com/watch?v=MuOnC1VfLlY', '2026-02-14 17:40:29.499828', 126, 220),
	(243, 'A', 7.1, 'https://image.tmdb.org/t/p/w780/knn3OIa9T4yeLjkmeQgJ8JLwdG0.jpg', 0, '2026-02-09 17:18:08.806246', '¡Vuelve "El show de los Muppets"! La rana Gustavo, la Señorita Peggy y el resto de los queridos Muppets regresan con un nuevo programa especial. La música, la comedia y el caos están garantizados cuando los Muppets se suban de nuevo al escenario del Teatro de los Muppets original con una invitada muy especial: ¡Sabrina Carpenter!', 32, NULL, 'US', 'en', 31.8253, 'https://image.tmdb.org/t/p/w500/9UQB40mDmP9l5WsOTYs9FW0ItOI.jpg', '2026-02-03', 0, 'el-show-de-los-muppets-2026', 'RELEASED', 'El show de los Muppets', 1548113, 'https://www.youtube.com/watch?v=hSLE5Psfs6U', '2026-02-14 17:40:40.583210', 60, 221),
	(244, 'A', 6.7, 'https://image.tmdb.org/t/p/w780/gbjK8p5S1aLXWCwOoXqr9aWZvqG.jpg', 64000000, '2026-02-09 17:18:09.620248', 'Desesperado por ser un gran tipo, Bob Esponja se propone demostrar su valentía al Sr. Krabs siguiendo a The Flying Dutchman, un misterioso pirata fantasma, en una aventura marítima que lo lleva a las profundidades más profundas del mar profundo, donde ninguna Esponja ha ido antes.', 88, NULL, 'US', 'en', 63.0515, 'https://image.tmdb.org/t/p/w500/8pE6H7PHwINoQYPPU1fEcQz5gQ6.jpg', '2025-12-16', 163197450, 'bob-esponja-una-aventura-pirata-2025', 'RELEASED', 'Bob Esponja: Una aventura pirata', 991494, 'https://www.youtube.com/watch?v=VPBk6izFecU', '2026-02-14 17:40:20.294079', 187, 222),
	(245, '7', 8.185, 'https://image.tmdb.org/t/p/w780/iL5eGI9ctHdUOV4yG6dyGKctSEX.jpg', 0, '2026-02-09 17:18:12.332101', 'Una alumna de instituto despierta cada día sin recuerdos del día anterior. Al empezar a salir con un compañero tímido, su historia de amor se renueva con cada amanecer.', 106, NULL, 'KR', 'ko', 37.1022, 'https://image.tmdb.org/t/p/w500/lawtchSE4FQch7kNTA5OiMTZ4F3.jpg', '2025-12-24', 5516015, 'aunque-nuestro-amor-se-desvanezca-esta-noche-2025', 'RELEASED', 'Aunque nuestro amor se desvanezca esta noche', 1466115, 'https://www.youtube.com/watch?v=rjAs9Ks-3V0', '2026-02-14 17:40:45.729900', 46, 223),
	(246, NULL, 6.9, 'https://image.tmdb.org/t/p/w780/kHyN3PejjlYWYz1Eah3jS64oV0g.jpg', 1000000, '2026-02-09 17:18:13.322097', 'En un campamento de waterpolo masculino, un preadolescente de doce años con ansiedad social se ve arrastrado a formar parte de una cruel tradición que ataca a un marginado con una enfermedad llamada \'La Plaga\'. Pero a medida que se difuminan los límites entre el juego y la realidad, teme que la broma pueda estar ocultando algo real.', 98, NULL, 'US', 'en', 30.4902, 'https://image.tmdb.org/t/p/w500/b0RWuqzgvyfiIYU4QfgJHhmxZF4.jpg', '2025-12-24', 685153, 'the-plague-2025', 'RELEASED', 'The Plague', 1370814, 'https://www.youtube.com/watch?v=QGMRkHPAaVU', '2026-02-14 17:40:44.762749', 40, 224),
	(247, NULL, 7.411, 'https://image.tmdb.org/t/p/w780/gqGQ0zADV5FIcgMWtWX8FcGQjFp.jpg', 3000000, '2026-02-09 17:18:14.998679', 'En un futuro devastado por "El Rapto Silencioso", un prisionero navega un océano de sangre en una luna desolada usando un submarino llamado "Iron Lung" mientras busca estrellas y planetas perdidos.', 125, NULL, 'US', 'en', 36.0618, 'https://image.tmdb.org/t/p/w500/sIwakdbMGS1krtgendTWpxTY9Hw.jpg', '2026-01-30', 34262807, 'iron-lung-2026', 'RELEASED', 'Iron Lung', 1116201, 'https://www.youtube.com/watch?v=7qRf_f_bbUk', '2026-02-14 17:40:46.932035', 84, 225),
	(248, NULL, 5.292, 'https://image.tmdb.org/t/p/w780/cAaLaaOa6n6sH932IUIVZtKtOef.jpg', 0, '2026-02-09 17:18:16.788908', '', 65, NULL, 'ES', 'en', 31.6374, 'https://image.tmdb.org/t/p/w500/7bzMCW1E1sOWEbjVuQ8iRGrdpcw.jpg', '2025-11-27', 0, 'afterlight-2025', 'RELEASED', 'Afterlight', 1590097, 'https://www.youtube.com/watch?v=lBk150L_zJI', '2026-02-14 17:40:39.681713', 12, 226),
	(249, NULL, 5.783, 'https://image.tmdb.org/t/p/w780/xGbNoh7aWmU81oYuxJoFI07Rz5I.jpg', 0, '2026-02-09 17:18:17.631645', 'La vida de una mujer frustrada da un giro oscuro tras un encuentro fortuito con un misterioso asesino a sueldo. Su romance relámpago les lleva a una matanza de criminales, pero a medida que profundiza en el tema, empieza a cuestionarse la verdadera naturaleza de su compañero y las sombras que ambos ocultan.', 106, NULL, 'US', 'en', 40.6986, 'https://image.tmdb.org/t/p/w500/qDfvIFGOgwGgyRL7AQtAp7d9MrU.jpg', '2024-08-16', 0, 'los-desconocidos-2024', 'RELEASED', 'Los desconocidos', 1326878, 'https://www.youtube.com/watch?v=J9AokZ2fLJo', '2026-02-14 17:40:38.141402', 30, 202),
	(250, NULL, 6.931, 'https://image.tmdb.org/t/p/w780/YCunHbbBUBKx6daM9XZAXkOH8k.jpg', 22500000, '2026-02-09 17:18:18.539308', '', 212, NULL, 'IN', 'hi', 53.5704, 'https://image.tmdb.org/t/p/w500/kOLkpkS2T4HAdA6J7uq4eipNTup.jpg', '2025-12-05', 160000000, '2025-1291608', 'RELEASED', 'धुरंधर', 1291608, 'https://www.youtube.com/watch?v=o--C7AH5SuI', '2026-02-09 17:26:04.283003', 189, 227),
	(251, NULL, 6.311, 'https://image.tmdb.org/t/p/w780/kv8kCuvfhSQ50YxjowqpVn1QqhJ.jpg', 0, '2026-02-09 17:18:19.465109', 'Un niño presencia el asesinato de sus padres por de hombre disfrazado de Papá Noel. Años más tarde, ya adulto, se pone él mismo un disfraz de Papá Noel y se embarca en una violenta búsqueda de venganza contra los responsables.', 96, NULL, 'US', 'en', 23.9063, 'https://image.tmdb.org/t/p/w500/ecpETxTPyVFai17hMMoFGy1ruLO.jpg', '2025-12-11', 0, 'noche-de-paz-noche-de-muerte-2025', 'RELEASED', 'Noche de Paz, Noche de Muerte', 801937, 'https://www.youtube.com/watch?v=qcpcOUW0nbo', '2026-02-14 17:41:39.408122', 74, 228),
	(252, '12', 5.7, 'https://image.tmdb.org/t/p/w780/dFdFQaffaBNBNM5hzinc6Q0oWDZ.jpg', 0, '2026-02-09 17:18:21.180532', 'Cuando la brillante productora de televisión Leah Caldwell (Kelly Rowland) está a punto de hacer historia como la primera mujer en dirigir el programa matutino más importante de Nueva York, su ex, Jarrett Roy (Clifford "Method Man" Smith), aparece para competir por el mismo puesto. Afirma ser un hombre diferente, transformado por la sabiduría del bestseller del New York Times, "Relationship Goals".Mientras su círculo íntimo de amigos se sumerge en el mismo libro transformador, todos comienzan a redescubrir su propósito en el amor. Sin embargo, Leah, completamente centrada en romper el techo de cristal, no está lista para creer en encontrar el amor, incluso cuando la innegable química con su ex amenaza con reavivar viejas llamas.', 96, NULL, 'US', 'en', 21.7959, 'https://image.tmdb.org/t/p/w500/eZRbRa0q9rKkPe0gfJ2a0NhygBX.jpg', '2026-02-04', 0, 'la-meta-es-el-amor-2026', 'RELEASED', 'La Meta es el Amor', 1433842, 'https://www.youtube.com/watch?v=m-dp6lQwGSI', '2026-02-14 17:42:01.789654', 37, 229),
	(253, NULL, 5.7, 'https://image.tmdb.org/t/p/w780/aFqLp6XfmzrYNSVlyKoQU7WT1PX.jpg', 0, '2026-02-09 17:18:23.115250', 'Dos hermanos enfrentan el terror cuando una siniestra bruja, creada en los libros de su difunta madre, parece cobrar vida y acosarlos sin piedad.', 98, NULL, 'ES', 'en', 27.5661, 'https://image.tmdb.org/t/p/w500/q8o2NzIH4ze28NAVs1eRkejAJIk.jpg', '2026-01-20', 0, 'the-calling-witch-2026', 'RELEASED', 'The Calling Witch', 1475490, 'https://www.youtube.com/watch?v=TtROXtptZ4Y', '2026-02-14 17:41:10.564283', 10, 230),
	(254, NULL, 7.588, 'https://image.tmdb.org/t/p/w780/bHtlDAORBQiYKCJMwDP9WBgcQHM.jpg', 65000000, '2026-02-09 17:18:23.869938', 'Biopic de Marty Reisman, un buscavidas convertido en campeón de ping pong, desde que empezó a jugar por apuestas en Manhattan hasta ganar 22 títulos importantes y convertirse en el más veterano en ganar una competición nacional de deportes de raqueta, con 67 años.', 150, NULL, 'US', 'en', 162.2954, 'https://image.tmdb.org/t/p/w500/mijSU0Rws3tBBbhdE5udxPSaZvF.jpg', '2025-12-19', 148800000, 'marty-supreme-2025', 'RELEASED', 'Marty Supreme', 1317288, 'https://www.youtube.com/watch?v=wNQjwR5cCiM', '2026-02-16 16:49:50.592170', 741, 231),
	(255, NULL, 5.88, 'https://image.tmdb.org/t/p/w780/ykigHs1OIyqqV04zfFqIlSHp546.jpg', 0, '2026-02-09 17:18:24.973965', 'Las mejores amigas Maddie y Trish quedan atrapadas en una remota laguna con la peligrosa orca Ceto.', 89, NULL, 'AU', 'en', 35.0031, 'https://image.tmdb.org/t/p/w500/xC6zdIoIHjhOIFmjNyGgtzhuhiF.jpg', '2026-01-16', 0, 'killer-whale-2026', 'RELEASED', 'Killer Whale', 1412598, 'https://www.youtube.com/watch?v=Rymtw1fAPbQ', '2026-02-14 17:40:50.371118', 54, 232),
	(256, '16', 6.329, 'https://image.tmdb.org/t/p/w780/3cVrg7tzSf5AgEecYWDOSAzXAeX.jpg', 0, '2026-02-09 17:18:26.857333', 'Película basada en el videojuego de KOTAKE CREATE "The Exit 8", cuya premisa es que una persona anónima se encuentra en una estación de metro atrapada en un bucle en donde debe avanzar sólo cuando una anomalía no aparezca en su campo de visión... o volverá al inicio sin ser capaz de huir de ese lugar.', 95, NULL, 'JP', 'ja', 48.5431, 'https://image.tmdb.org/t/p/w500/mqlgMvy1d5jIbIE6SPlJq724htT.jpg', '2025-08-28', 33100990, 'exit-8-2025', 'RELEASED', 'Exit 8', 1408208, 'https://www.youtube.com/watch?v=DlRQ1oatOt8', '2026-02-14 17:40:25.084490', 170, 233),
	(257, NULL, 6.152, 'https://image.tmdb.org/t/p/w780/vbkW4KerpshPZnP84w9qwSfYrhu.jpg', 0, '2026-02-09 17:18:27.747239', 'Ava, una mujer desesperada cuyo marido ha desaparecido tras un catastrófico experimento militar, se une a una "unidad de recuperación de cadáveres", pero su búsqueda da un giro escalofriante cuando los cadáveres que está enterrando empiezan a dar señales de vida.', 95, NULL, 'AU', 'en', 70.5912, 'https://image.tmdb.org/t/p/w500/xZqo0yPARmyF8TACVNyaOACkYWG.jpg', '2026-01-01', 3745163, 'we-bury-the-dead-2026', 'RELEASED', 'We Bury the Dead', 1198984, 'https://www.youtube.com/watch?v=YmPyNvrzF0A', '2026-02-14 17:40:14.865099', 89, 234),
	(258, '16', 7.2, 'https://image.tmdb.org/t/p/w780/zhoMwQofjgVec5Sin05hWECJtVQ.jpg', 6000000, '2026-02-09 17:18:31.575206', 'Un hombre conduce de noche con su esposa embarazada cuando atropella y mata a un perro, lo que le obliga a llevar el coche a un taller dirigido por un hombre que se parece al oficial que lo torturó en prisión.', 105, NULL, 'IR', 'fr', 25.4382, 'https://image.tmdb.org/t/p/w500/qyeTL52iQJQN6FrCaVRkiuzJDDp.jpg', '2025-09-27', 9602793, 'un-simple-accidente-2025', 'RELEASED', 'Un simple accidente', 1456349, 'https://www.youtube.com/watch?v=-xtwtUwxwNE', '2026-02-14 17:41:33.295142', 341, 235),
	(259, NULL, 5.523, 'https://image.tmdb.org/t/p/w780/tTDfDHqGkRgBTL4Tw8mU0iwkW8T.jpg', 10000000, '2026-02-09 17:18:32.479168', 'Anna llora la muerte de sus padres cuando se traslada de Nueva York a Florida para quedarse con su abuela. Allí se junta con otros adolescentes, pero cuando ve un espeluznante acto de violencia, se encuentra atrapada.', 101, NULL, 'US', 'en', 48.7258, 'https://image.tmdb.org/t/p/w500/lpepbfVziHJLhVoxTEKs8ok00iu.jpg', '2025-07-03', 0, 'ojo-por-ojo-2025', 'RELEASED', 'Ojo por ojo', 1199869, 'https://www.youtube.com/watch?v=h1Jyk-9id5c', '2026-02-09 17:26:05.702486', 22, 236),
	(260, '12', 5.923, 'https://image.tmdb.org/t/p/w780/1EVHnzF3gescyQZSqwbx5LfQ1EN.jpg', 0, '2026-02-09 17:18:35.761825', 'Thando nunca ha tenido suerte en el amor... Y ahora, su mejor amigo vuelve a casa con una prometida del brazo y se ve obligada a afrontar una nueva emoción: los celos.', 95, NULL, 'ZA', 'en', 44.4177, 'https://image.tmdb.org/t/p/w500/fDcHWsESmG7j8fnVbPxR6dQz0vA.jpg', '2026-02-06', 0, 'uf-solo-amigos-2026', 'RELEASED', '¡Uf! ¿Solo amigos?', 1618945, 'https://www.youtube.com/watch?v=e_IRbQfzgqM', '2026-02-09 17:26:05.938736', 13, 237),
	(261, NULL, 7.097, 'https://image.tmdb.org/t/p/w780/3Y0HoplrL57V9HRiEhz7k2HEgak.jpg', 0, '2026-02-09 17:18:40.183859', '', 94, NULL, 'XC', 'cs', 42.809, 'https://image.tmdb.org/t/p/w500/dNDKXugpW5FkW2VzrSBG8GlA5yk.jpg', '1952-09-26', 0, 'pysna-princezna-1952', 'RELEASED', 'Pyšná princezna', 41228, NULL, '2026-02-09 17:26:06.259909', 31, 238),
	(262, '18', 7.274, 'https://image.tmdb.org/t/p/w780/ryynYdXgP2vLZKH3154bLkNp1kx.jpg', 63000000, '2026-02-09 17:18:41.400576', 'El Dr. Kelson (Ralph Fiennes) se ve envuelto en una nueva y sorprendente relación, cuyas consecuencias podrían cambiar el mundo tal y como se conoce. Por otra parte, el encuentro de Spike (Alfie Williams) con el Gran Lord Jimmy Crystal (Jack O\'Connell) se convierte en una pesadilla de la que el chico no puede escapar. En este mundo, los infectados ya no son la mayor amenaza para la supervivencia, ya que la inhumanidad de los supervivientes puede ser aún más extraña y aterradora.', 109, NULL, 'GB', 'en', 33.6228, 'https://image.tmdb.org/t/p/w500/9qlqDX3lo7CiFCDZV1Qwopwm5rz.jpg', '2026-01-14', 58586229, '28-anos-despues-el-templo-de-los-huesos-2026', 'RELEASED', '28 años después: El templo de los huesos', 1272837, 'https://www.youtube.com/watch?v=RcnPIyUI53Q', '2026-02-14 17:40:57.327285', 323, 161),
	(263, NULL, 7.431, 'https://image.tmdb.org/t/p/w780/hmEbQB5UlcwobldcSDNlLZiUnmA.jpg', 40000000, '2026-02-09 17:18:44.563585', 'Año 2005. A un equipo de élite de las fuerzas especiales SEAL del ejército norteamericano, liderados por Marcus Luttrell junto a otros tres soldados les es encomendada una peligrosa misión, la "Operación red wing": capturar o matar a un líder terrorista talibán, Admad Shad, que se esconde en una zona boscosa de Afganistán. La llegada al punto donde localizaron el objetivo se realizó sin problemas, pero pronto la situación se complicó hasta extremos inimaginables.', 121, NULL, 'US', 'en', 41.9443, 'https://image.tmdb.org/t/p/w500/5ifKF7FCYdkzt5BoQicfeUvfYuS.jpg', '2013-12-24', 149295601, 'el-unico-superviviente-2013', 'RELEASED', 'El único superviviente', 193756, 'https://www.youtube.com/watch?v=4OcXtpLjvVY', '2026-02-09 17:26:06.635989', 4631, 239),
	(264, '12', 7.129, 'https://image.tmdb.org/t/p/w780/2Fk3AB8E9dYIBc2ywJkxk8BTyhc.jpg', 34000000, '2026-02-09 17:18:46.859020', 'Cuando el mundo es consciente de que el asteroide más grande de la historia va a impactar en la Tierra y aniquilar todo rastro de vida, los gobiernos de todo el mundo realizan un sorteo en el cual los afortunados podrán sobrevivir en refugios secretos. Esta decisión desata un caos a nivel mundial. Muchos tendrán que emprender un peligroso viaje donde se enfrentarán a los más imponentes peligros de la naturaleza, lo que les obligará a encontrar la manera de mantenerse unidos mientras encuentran la forma de sobrevivir.', 120, NULL, 'GB', 'en', 30.5104, 'https://image.tmdb.org/t/p/w500/9iFkwShRf5M29yLABAdsEZyr9w6.jpg', '2020-07-29', 52300000, 'greenland-el-ultimo-refugio-2020', 'RELEASED', 'Greenland: El último refugio', 524047, 'https://www.youtube.com/watch?v=KCRkwUGjJfE', '2026-02-14 17:41:06.982519', 5061, 208),
	(265, NULL, 6.665, 'https://image.tmdb.org/t/p/w780/7HKpc11uQfxnw0Y8tRUYn1fsKqE.jpg', 60000000, '2026-02-09 17:18:50.925919', 'Tras ser acusado de un crimen, un detective deberá demostrar su inocencia.', 100, NULL, 'US', 'en', 28.4413, 'https://image.tmdb.org/t/p/w500/9zBNg8koM3fjUTPT7QeJHuGG2r9.jpg', '2026-01-20', 49463290, 'sin-piedad-2026', 'RELEASED', 'Sin piedad', 1236153, 'https://www.youtube.com/watch?v=vvkKYJCQEk0', '2026-02-14 17:41:18.535533', 127, 240),
	(266, '12', 5.9, 'https://image.tmdb.org/t/p/w780/9cd1zsxcOAcBW01WDOWz8EODTS0.jpg', 35000000, '2026-02-09 17:18:52.296704', 'Una joven política idealista hace malabarismos con sus problemas familiares y su estresante vida laboral mientras se prepara para ocupar nada menos que el puesto de gobernadora de su estado, ocupando el puesto de su mentor.', 115, NULL, 'US', 'en', 23.8395, 'https://image.tmdb.org/t/p/w500/kuAObOLDIBnWgGE3vk9wBsrM54.jpg', '2025-12-11', 4546837, 'ella-mccay-2025', 'RELEASED', 'Ella McCay', 1206008, 'https://www.youtube.com/watch?v=OwgayXGF3uM', '2026-02-14 17:41:39.473623', 64, 241),
	(267, '16', 7.902, 'https://image.tmdb.org/t/p/w780/xnHVX37XZEp33hhCbYlQFq7ux1J.jpg', 200000000, '2026-02-09 17:18:54.846002', 'Jack, un joven artista, gana en una partida de cartas un pasaje para viajar a América en el Titanic, el transatlántico más grande y seguro jamás construido. A bordo conoce a Rose, una joven de una buena familia venida a menos que va a contraer un matrimonio de conveniencia con Cal, un millonario engreído a quien sólo interesa el prestigioso apellido de su prometida. Jack y Rose se enamoran, pero el prometido y la madre de ella ponen todo tipo de trabas a su relación. Mientras, el gigantesco y lujoso transatlántico se aproxima hacia un inmenso iceberg.', 194, NULL, 'US', 'en', 29.8839, 'https://image.tmdb.org/t/p/w500/rBTJZrf5UWaxzg5YJd2eqpeaSvm.jpg', '1997-12-18', 2264162353, 'titanic-1997', 'RELEASED', 'Titanic', 597, 'https://www.youtube.com/watch?v=6FKmt1RcLug', '2026-02-14 17:41:09.250881', 26772, 127),
	(268, '16', 5.131, 'https://image.tmdb.org/t/p/w780/sVB8MrQr0x7sqAj3KVpAqpCbapT.jpg', 23000000, '2026-02-09 17:26:11.198307', 'Impulsado por las sombras de su pasado, James Sunderland regresa a Silent Hill para encontrar a su amor perdido, Mary Crane. Pero el pequeño pueblo oscuro y deprimente ya no es el lugar de sus recuerdos. James se encuentra con personajes que le parecen demasiado familiares y que intentan distraerlo de su búsqueda de Mary. Cuanto más busca a Mary, más comienza a preguntarse si esto sigue siendo la realidad, o si ha caído en el oscuro inframundo de Jacob Crane.', 106, NULL, 'FR', 'en', 46.7126, 'https://image.tmdb.org/t/p/w500/5Y2TeCVEnwPbd4FDShGbkKYw6GE.jpg', '2026-01-21', 41586056, 'return-to-silent-hill-2026', 'RELEASED', 'Return to Silent Hill', 680493, 'https://www.youtube.com/watch?v=z10cMFhKbW8', '2026-02-14 17:40:30.402943', 137, 242),
	(269, NULL, 6.631, 'https://image.tmdb.org/t/p/w780/9uakM2woks0JV8HKIc4oatIVS88.jpg', 21000000, '2026-02-09 17:26:11.950490', 'Lucy, una estudiante universitaria, pasa las vacaciones con sus amigos en la casa de su familia en Hawái, donde vive con su mascota, un chimpancé llamado Ben. Sin embargo, cuando Ben contrae rabia tras ser mordido por un animal rabioso, el grupo debe luchar por su vida para evitar al ahora violento chimpancé.', 89, NULL, 'US', 'en', 296.3058, 'https://image.tmdb.org/t/p/w500/cyqEghDphEUunLfongtpmROjpID.jpg', '2026-01-01', 39722402, 'primate-2026', 'RELEASED', 'Primate', 1315303, 'https://www.youtube.com/watch?v=F0fn4knTR2s', '2026-02-16 16:49:43.056787', 298, 243),
	(270, '12', 8.493, 'https://image.tmdb.org/t/p/w780/2u7zbn8EudG6kLlBzUYqP8RyFU4.jpg', 94000000, '2026-02-09 17:26:13.995159', 'Las fuerzas de Saruman han sido destruidas, y su fortaleza sitiada. Ha llegado el momento de que se decida el destino de la Tierra Media, y por primera vez en mucho tiempo, parece que hay una pequeña esperanza. La atención del señor oscuro Sauron se centra ahora en Gondor, el último reducto de los hombres, y del cual Aragorn tendrá que reclamar el trono para ocupar su puesto de rey. Pero las fuerzas de Sauron ya se preparan para lanzar el último y definitivo ataque contra el reino de Gondor, la batalla que decidirá el destino de todos. Mientras tanto, Frodo y Sam continuan su camino hacia Mordor, a la espera de que Sauron no repare en que dos pequeños Hobbits se acercan cada día más al final de su camino, el Monte del Destino.', 202, NULL, 'NZ', 'en', 30.1348, 'https://image.tmdb.org/t/p/w500/mWuFbQrXyLk2kMBKF9TUPtDwuPx.jpg', '2003-12-17', 1118888979, 'el-senor-de-los-anillos-el-retorno-del-rey-2003', 'RELEASED', 'El señor de los anillos: El retorno del rey', 122, 'https://www.youtube.com/watch?v=h-9RYiqyqjk', '2026-02-14 17:41:17.141777', 26017, 132),
	(271, NULL, 6.201, 'https://image.tmdb.org/t/p/w780/lf8IZ86ajGpgbuyHCZrXUeAMmvy.jpg', 0, '2026-02-09 17:26:15.004917', 'En un futuro próximo, la Tierra enfrenta un desastre catastrófico causado por una criatura desconocida. Ma Shan, un joven marginado se une a la misteriosa Oficina 749 para enfrentar la crisis.', 123, NULL, 'CN', 'zh', 31.7043, 'https://image.tmdb.org/t/p/w500/uXQm8PKup6FxXkrd9kPyD2asCZs.jpg', '2024-10-01', 51706251, 'bureau-749-2024', 'RELEASED', 'Bureau 749', 1033462, NULL, '2026-02-14 17:41:05.420838', 87, 244),
	(272, NULL, 6.3, 'https://image.tmdb.org/t/p/w780/pAyImoslSnpMgjRwhaS5ZEdl8UI.jpg', 50000, '2026-02-09 17:26:17.903697', 'Un antiguo escuadrón de operaciones especiales se reúne para una última misión: un robo de alto riesgo para rescatar a la hija pequeña de su comandante.', 99, NULL, 'GB', 'en', 27.9798, 'https://image.tmdb.org/t/p/w500/2eQspDQBLDTvDOQtmErmi6uIi2.jpg', '2025-11-19', 0, 'wildcat-2025', 'RELEASED', 'Wildcat Misión rescate', 1448560, 'https://www.youtube.com/watch?v=noU-vKiA9ts', '2026-02-14 17:41:25.245904', 111, 245),
	(273, NULL, 6.923, 'https://image.tmdb.org/t/p/w780/mBc6RB7VajfykLqGx0ue7qatXky.jpg', 0, '2026-02-09 17:26:18.997704', '', 48, NULL, 'PH', 'tl', 44.7353, 'https://image.tmdb.org/t/p/w500/bZ8xfM705sK59dA1UCdRkEj7LHN.jpg', '2024-05-24', 0, 'kulong-2024', 'RELEASED', 'Kulong', 1266990, NULL, '2026-02-14 17:40:36.475007', 13, 246),
	(274, NULL, 7.6, 'https://image.tmdb.org/t/p/w780/eeGRpU64sIrRApjWXvTpK5Lep2K.jpg', 5000000, '2026-02-09 17:26:19.790521', 'En Brasil, en 1977, Marcelo, un especialista en tecnología que huye de un pasado misterioso, regresa a Recife en busca de paz, pero se da cuenta de que la ciudad está lejos del refugio que busca.', 161, NULL, 'BR', 'pt', 33.5362, 'https://image.tmdb.org/t/p/w500/qYWybdgL6casJxbZE0xLGXsdWOP.jpg', '2025-07-23', 7691569, 'el-agente-secreto-2025', 'RELEASED', 'El agente secreto', 1220564, 'https://www.youtube.com/watch?v=GcyZJpOfX_k', '2026-02-09 17:26:19.790521', 301, 247),
	(275, NULL, 3.2, 'https://image.tmdb.org/t/p/w780/2Ve7sjxLb3rKG8qJ1t7QEuNI0UM.jpg', 0, '2026-02-09 17:26:20.756795', '', 119, NULL, 'PH', 'tl', 32.9482, 'https://image.tmdb.org/t/p/w500/gcK3HgN6IHNOviXnX11W6aFLTGv.jpg', '2024-03-01', 0, 'eks-2024', 'RELEASED', 'EKS', 1241742, 'https://www.youtube.com/watch?v=Cbm4lGglAIw', '2026-02-14 17:41:03.051105', 5, 172),
	(276, '12', 7.1, 'https://image.tmdb.org/t/p/w780/tuDhEdza074bA497bO9WFEPs6O6.jpg', 180000000, '2026-02-09 17:26:21.656102', 'La historia narra las aventuras de cuatro hermanos: Lucy, Edmund, Susan y Peter, que durante la Segunda Guerra Mundial descubren el mundo de Narnia, al que acceden a través de un armario mágico mientras juegan al escondite en la casa de campo de un viejo profesor. En Narnia descubrirán un mundo increíble habitado por animales que hablan, duendes, faunos, centauros y gigantes al que la Bruja Blanca- Jadis- ha condenado al invierno eterno. Con la ayuda del león Aslan, el noble soberano, los niños lucharán para vencer el poder que la Bruja Blanca ejerce sobre Narnia en una espectacular batalla y conseguir así liberarle de la maldición del frío.', 143, NULL, 'GB', 'en', 23.2438, 'https://image.tmdb.org/t/p/w500/2Lv2wKf2YocOcRfzmvQYOUGRhFg.jpg', '2005-12-07', 745013115, 'las-cronicas-de-narnia-el-leon-la-bruja-y-el-armario-2005', 'RELEASED', 'Las crónicas de Narnia: El león, la bruja y el armario', 411, 'https://www.youtube.com/watch?v=3mKPrxjwF7A', '2026-02-14 17:41:47.706750', 11310, 248),
	(278, NULL, 6.417, 'https://image.tmdb.org/t/p/w780/7cQjb8cRbRjF5tM5gOCnqsvC0iT.jpg', 0, '2026-02-09 17:26:25.206465', 'Una psiquiatra investiga a un asesino en serie confeso tras la desaparición de nueve niñas, pero termina cuestionándose si es culpable o víctima de un oscuro juego.', 124, NULL, 'IN', 'ta', 31.4673, 'https://image.tmdb.org/t/p/w500/yUURUJzeSTc47T2VeNw7nZwZ8VJ.jpg', '2025-12-05', 0, 'stephen-2025', 'RELEASED', 'Stephen', 1561955, NULL, '2026-02-09 17:26:25.206465', 12, 251),
	(279, '7', 8.3, 'https://image.tmdb.org/t/p/w780/9xfDWXAUbFXQK585JvByT5pEAhe.jpg', 100000000, '2026-02-09 17:26:26.601298', 'Tras reencontrarse con Gwen Stacy, el amigable vecindario de Spider-Man de Brooklyn al completo es catapultado a través del Multiverso, donde se encuentra con un equipo de Spidermans encargados de proteger su propia existencia. Pero cuando los héroes se enfrentan sobre cómo manejar una nueva amenaza, Miles se encuentra enfrentado a las otras Arañas y debe redefinir lo que significa ser un héroe para poder salvar a la gente que más quiere.', 140, NULL, 'US', 'en', 28.2547, 'https://image.tmdb.org/t/p/w500/37WcNMgNOMxdhT87MFl7tq7FM1.jpg', '2023-05-31', 690897910, 'spider-man-cruzando-el-multiverso-2023', 'RELEASED', 'Spider-Man: Cruzando el Multiverso', 569094, 'https://www.youtube.com/watch?v=b_yMOiRgMmQ', '2026-02-14 17:41:14.336035', 8251, 252),
	(280, NULL, 7.6, 'https://image.tmdb.org/t/p/w780/s6aB9kjxNg0mu2361IkCUSpyHJV.jpg', 12200000, '2026-02-09 17:26:27.366085', 'La historia sigue a un hombre de mediana edad llamado Man-su que se embarca decidido en una búsqueda de trabajo tras ser despedido inesperadamente de la compañía de papel en la que trabajó durante 25 años. "Si no hay una vacante para mí, tendré que crear una para que me contraten. No hay otra opción". Adaptación de la novela "The Ax" de Donald E. Westlake, que ya fue llevada al cine en la película "Arcadia", dirigida por Costa-Gavras en 2005.', 139, NULL, 'KR', 'ko', 30.9553, 'https://image.tmdb.org/t/p/w500/9gu70dhYzzPNLh0hNpzZKdE1Pun.jpg', '2025-09-24', 36314308, 'no-hay-otra-opcion-2025', 'RELEASED', 'No hay otra opción', 639988, 'https://www.youtube.com/watch?v=SK_DEabMNVg', '2026-02-09 17:26:27.366085', 602, 253),
	(281, NULL, 4.3, 'https://image.tmdb.org/t/p/w780/fEaR0uvRZluIEEPtDuaL7CkYsCJ.jpg', 0, '2026-02-09 17:26:29.194296', '', 150, NULL, 'IN', 'ml', 25.8484, 'https://image.tmdb.org/t/p/w500/fMDt3o7CVXDc84WIbOskya8XkSN.jpg', '2025-12-18', 0, '2025-1196995', 'RELEASED', 'ഭ. ഭ. ബ.', 1196995, NULL, '2026-02-09 17:26:29.194296', 3, 254),
	(282, NULL, 7.24, 'https://image.tmdb.org/t/p/w780/1qwhYqg7YEZajh3Q4biqbuQoDq8.jpg', 90000000, '2026-02-09 17:26:29.945513', 'Will es una pequeña cabra con grandes sueños que recibe una oportunidad única en la vida para unirse a los profesionales y jugar al rugebol, un deporte de alta intensidad, mixto y de contacto total dominado por los animales más rápidos y feroces del mundo. A los nuevos compañeros de equipo de Will no les entusiasma tener a una cabrita en su plantilla, pero Will está decidido a revolucionar el deporte y demostrar de una vez por todas que «¡los pequeños saben jugar!».', 100, NULL, 'US', 'en', 100.6133, 'https://image.tmdb.org/t/p/w500/2yblKPC6ZKEU6iv9sEZ0jktjiTU.jpg', '2026-02-11', 47600000, 'goat-como-cabras-2026', 'RELEASED', 'GOAT: Como cabras', 1297842, 'https://www.youtube.com/watch?v=q56pw-zFDP8', '2026-02-16 16:49:55.625029', 25, 255),
	(283, '18', 8.438, 'https://image.tmdb.org/t/p/w780/5TiwfWEaPSwD20uwXjCTUqpQX70.jpg', 63000000, '2026-02-09 17:26:31.423702', 'Un hombre consumido por el insomnio y una vida sin sentido conoce a Tyler Durden, un carismático anarquista que lo arrastra a un club secreto donde el dolor despierta algo dormido. Lo que comienza como liberación pronto se convierte en una guerra contra el sistema…', 139, NULL, 'DE', 'en', 29.5339, 'https://image.tmdb.org/t/p/w500/sgTAWJFaB2kBvdQxRGabYFiQqEK.jpg', '1999-10-15', 100853753, 'el-club-de-la-lucha-1999', 'RELEASED', 'El Club de la Lucha', 550, 'https://www.youtube.com/watch?v=aIo4Adm96EA', '2026-02-09 17:26:31.423702', 31393, 256),
	(284, 'Ai', 7.756, 'https://image.tmdb.org/t/p/w780/sRvXNDItGlWCqtO3j6wks52FmbD.jpg', 60000000, '2026-02-09 17:26:32.875355', 'Hace mucho, mucho tiempo, en una lejanísima ciénaga vivía un intratable ogro llamado Shrek. Pero de repente, un día, su absoluta soledad se ve interrumpida por una invasión de sorprendentes personajes de cuento. Hay ratoncitos ciegos en su comida, un enorme y malísimo lobo en su cama, tres cerditos sin hogar y otros muchos seres increíbles que han sido deportados de su reino por el malvado Lord Farquaad. Para conseguir salvar su terreno, y de paso a sí mismo, Shrek hace un pacto con Farquaad y emprende viaje para conseguir que la preciosa princesa Fiona sea la novia del Lord. En tan importante misión le acompañan un burro chistoso, dispuesto a hacer cualquier cosa por Shrek. Todo, menos estarse calladito. Rescatar a la princesa de una dragona enamoradiza que suelta fuego al respirar va a resultar una tontería comparado con lo que ocurre cuando el oscuro secreto que la joven guardaba es revelado.', 92, NULL, 'US', 'en', 22.5719, 'https://image.tmdb.org/t/p/w500/jTQONM7jt1yv2lL972TtmWO0UIZ.jpg', '2001-05-18', 488628188, 'shrek-2001', 'RELEASED', 'Shrek', 808, 'https://www.youtube.com/watch?v=B88JfTyJ1Fw', '2026-02-14 17:41:53.620758', 18390, 248),
	(285, '12', 7.933, 'https://image.tmdb.org/t/p/w780/nqUThBjou0TAWXu93Q4SNFpgqai.jpg', 200000000, '2026-02-09 17:26:33.745171', 'Peter Parker es desenmascarado y por tanto no es capaz de separar su vida normal de los enormes riesgos que conlleva ser un súper héroe. Cuando pide ayuda a Doctor Strange, los riesgos pasan a ser aún más peligrosos, obligándole a descubrir lo que realmente significa ser Spider-Man.', 148, NULL, 'US', 'en', 31.2664, 'https://image.tmdb.org/t/p/w500/miZFgV81xG324rpUknQX8dtXuBl.jpg', '2021-12-15', 1921847111, 'spider-man-no-way-home-2021', 'RELEASED', 'Spider-Man: No Way Home', 634649, 'https://www.youtube.com/watch?v=Df00ZNYEcAY', '2026-02-14 17:41:00.189375', 21551, 257),
	(286, '16', 6.823, 'https://image.tmdb.org/t/p/w780/rcL91tOOOe3EXe2yifwh4jprYp8.jpg', 80000000, '2026-02-09 17:26:34.539662', 'Una audaz y original reinterpretación de una de una de las historias de amor más grandes de todos los tiempos, “CUMBRES BORRASCOSAS” de Emerald Fennell está protagonizada por Margot Robbie como Cathy y Jacob Elordi como Heathcliff, cuya pasión prohibida se transforma de romántica a intoxicante en una épica historia de lujuria, amor y locura.', 136, NULL, 'US', 'en', 179.0089, 'https://image.tmdb.org/t/p/w500/afGUJcMBJloAUp9uC27MQiqkD7X.jpg', '2026-02-11', 82000000, 'cumbres-borrascosas-2026', 'RELEASED', '“Cumbres Borrascosas”', 1316092, 'https://www.youtube.com/watch?v=RNynG8dMp5w', '2026-02-16 16:49:51.358378', 164, 258),
	(287, NULL, 8.4, 'https://image.tmdb.org/t/p/w780/y5haKgSz1hCDatwIOMuqZ1CFKPW.jpg', 0, '2026-02-09 17:26:35.274241', 'La prodigio húngara del ajedrez Judit Polgár desafió al campeón Garry Kaspárov y a su controlador padre durante 15 años, rompiendo las barreras de género para hacerse hueco entre los grandes nombres de este juego.', 93, NULL, 'US', 'en', 25.1464, 'https://image.tmdb.org/t/p/w500/ag5TZNcK3vHdCCpZIY8syjwzgfr.jpg', '2026-01-27', 0, 'la-reina-del-ajedrez-2026', 'RELEASED', 'La reina del ajedrez', 1596291, 'https://www.youtube.com/watch?v=mSPuFggF6Y0', '2026-02-09 17:26:35.274241', 11, 259),
	(288, '16', 8.495, 'https://image.tmdb.org/t/p/w780/TU9NIjwzjoKPwQHoHshkFcQUCG.jpg', 11363000, '2026-02-09 17:26:36.006932', 'Tanto Gi Taek (Song Kang-ho) como su familia están sin trabajo. Cuando su hijo mayor, Gi Woo (Choi Woo-sik), empieza a dar clases particulares en casa de Park (Lee Seon-gyun), las dos familias, que tienen mucho en común pese a pertenecer a dos mundos totalmente distintos, comienzan una interrelación de resultados imprevisibles.', 132, NULL, 'KR', 'ko', 19.556, 'https://image.tmdb.org/t/p/w500/4N55tgxDW0RRATyrZHbx0q9HUKv.jpg', '2019-05-30', 257591776, 'parasitos-2019', 'RELEASED', 'Parásitos', 496243, 'https://www.youtube.com/watch?v=-PtU49Aol00', '2026-02-14 17:42:00.687263', 20125, 260),
	(289, '12', 7.777, 'https://image.tmdb.org/t/p/w780/wYMbnrdRCREjNLwFlG5SLWzBjui.jpg', 165000000, '2026-02-09 17:26:36.759857', 'En un lejano futuro, la galaxia conocida es gobernada mediante un sistema feudal de casas nobles bajo el mandato del Emperador. Las alianzas y la política giran entorno a un pequeño planeta, Dune,  del que extrae la \'especia melange\', la materia prima que permite los viajes espaciales. La Casa Atreides, bajo el mandato del Duque Leto Atreides recibe el encargo de custodiar el planeta, relevando en la encomienda a sus históricos enemigos, los Harkonnen. Paul Atreides, hijo del duque, se verá atrapado en las intrigas políticas mientras descubre el destino que le deparan los desiertos de Dune.', 155, NULL, 'US', 'en', 25.47, 'https://image.tmdb.org/t/p/w500/szcew6yyjcDvaL0isaPBk2e3nkF.jpg', '2021-09-15', 410668500, 'dune-2021', 'RELEASED', 'Dune', 438631, 'https://www.youtube.com/watch?v=kPjOcWHVNGo', '2026-02-14 17:41:33.222173', 14429, 261),
	(290, NULL, 6.444, 'https://image.tmdb.org/t/p/w780/fPfDB0IHOqvmKIzFP9CA51OOS1N.jpg', 8500000, '2026-02-09 17:26:37.619995', 'Los supervivientes se enfrentan a nuevas amenazas de extraños enmascarados. Secretos salen a la luz, poniendo en peligro sus vidas mientras la línea entre realidad y peligro se difumina en su lucha por sobrevivir. Tercera y última de la trilogía de películas basadas en "Los extraños" (2008)', 92, NULL, 'GB', 'en', 23.1908, 'https://image.tmdb.org/t/p/w500/yPegTig8dQNYiW2UW21LTNChGkK.jpg', '2026-02-05', 4771000, 'strangers-capitulo-3-2026', 'RELEASED', 'Strangers: Capítulo 3', 1010755, 'https://www.youtube.com/watch?v=B2fZEIHamVs', '2026-02-14 17:41:49.238911', 9, 178),
	(291, '12', 8.238, 'https://image.tmdb.org/t/p/w780/tlm8UkiQsitc8rSuIAscQDCnP8d.jpg', 63000000, '2026-02-09 17:26:38.351772', 'Thomas Anderson lleva una doble vida: por el día es programador en una importante empresa de software, y por la noche un hacker informático llamado Neo. Su vida no volverá a ser igual cuando unos misteriosos personajes le inviten a descubrir la respuesta a la pregunta que no le deja dormir: ¿qué es Matrix?', 138, NULL, 'US', 'en', 23.5566, 'https://image.tmdb.org/t/p/w500/ejmTPNAkgZaVJ4AI9zb9SehAYU0.jpg', '1999-03-31', 463517383, 'matrix-1999', 'RELEASED', 'Matrix', 603, 'https://www.youtube.com/watch?v=Zd8Jw1Z_j4w', '2026-02-14 17:41:43.480933', 27364, 262),
	(292, '12', 8.504, 'https://image.tmdb.org/t/p/w780/b6HWTOxn1xevvyHU2K9ICvaRU6g.jpg', 60000000, '2026-02-09 17:26:39.731336', 'En el sur de los Estados Unidos, en plena Depresión, Paul Edgecomb es un vigilante penitenciario a cargo de la Milla Verde, un pasillo que separa las celdas de los reclusos condenados a la silla eléctrica. Esperando su ejecución está John Coffey, un gigantesco negro acusado de asesinar brutalmente a dos hermanas de nueve años. Tras una personalidad ingenua, Coffey esconde un don sobrenatural prodigioso. A medida que transcurre la historia, Paul Edgecomb aprende que los milagros ocurren... incluso en los lugares más insospechados.', 189, NULL, 'US', 'en', 20.9101, 'https://image.tmdb.org/t/p/w500/aBQiJRxGRrX0mXFMjxyzWYFtEnf.jpg', '1999-12-10', 286801374, 'la-milla-verde-1999', 'RELEASED', 'La milla verde', 497, 'https://www.youtube.com/watch?v=hBtSF4-cnzk', '2026-02-14 17:42:17.855963', 18844, 125),
	(293, '12', 7.89, 'https://image.tmdb.org/t/p/w780/zdXnJqBaGFVtLoPNuMeKfEYUViZ.jpg', 29000000, '2026-02-09 17:26:41.759162', 'En una residencia de ancianos, un hombre mayor lee a una mujer una historia de amor escrita en su viejo libro de notas. El libro cuenta la vida en los años 40 de Noah Calhoun y Allie Nelson, dos jóvenes adolescentes de Carolina del Norte que, a pesar de vivir en dos ambientes sociales muy diferentes, pasaron un verano idílico juntos y profundamente enamorados, antes de ser separados, primero por sus padres, y más tarde por la Segunda Guerra Mundial.', 124, NULL, 'US', 'en', 27.975, 'https://image.tmdb.org/t/p/w500/gFCnDKfsZWzyv9sweizVC4EWn06.jpg', '2004-06-25', 115600000, 'el-diario-de-noa-2004', 'RELEASED', 'El diario de Noa', 11036, 'https://www.youtube.com/watch?v=FC6biTjEyZw', '2026-02-09 17:26:41.759162', 12311, 263),
	(294, '7i', 7.725, 'https://image.tmdb.org/t/p/w780/4s2d3xdyqotiVNHTlTlJjrr3q0H.jpg', 165000000, '2026-02-09 17:26:43.691288', 'En la metrópolis de San Fransokio (cruce de San Francisco y Tokio), vive Hiro Hamada, quien aprende a sacar provecho de su capacidad gracias a su brillante hermano Tadashi y sus también brillantes amigos: la buscadora de adrenalina GoGo Tamago, el meticuloso de la limpieza Wasabi-No-Ginger, la genio de la química Honey Lemon y el fanático de los cómics Fred. Cuando tras un devastador giro de los acontecimientos, se ven envueltos en una peligrosa conspiración que tiene lugar en las calles de San Fransokio, Hiro recurre a su amigo más íntimo: un robot llamado Baymax, y transforma al grupo en una banda de héroes de última tecnología decididos a resolver el misterio.', 101, NULL, 'US', 'en', 27.5801, 'https://image.tmdb.org/t/p/w500/qVU0ag4i5BCmH5h4o04cdvUo0Zf.jpg', '2014-10-24', 657870525, 'big-hero-6-2014', 'RELEASED', 'Big Hero 6', 177572, 'https://www.youtube.com/watch?v=UC7KNAthiVQ', '2026-02-09 17:27:02.724323', 16337, 264),
	(295, 'A', 6.93, 'https://image.tmdb.org/t/p/w780/3N5QNUqS76GFYNoEayfkkJyAyTN.jpg', 145000000, '2026-02-09 17:26:46.414361', 'Barbie vive en Barbieland donde todo es ideal y lleno de música y color. Un buen día decide conocer el mundo real. Cuando el CEO de Mattel se entere, tratará de evitarlo a toda costa y devolver a Barbie a una caja.', 114, NULL, 'GB', 'en', 23.4792, 'https://image.tmdb.org/t/p/w500/fNtqD4BTFj0Bgo9lyoAtmNFzxHN.jpg', '2023-07-19', 1447138421, 'barbie-2023', 'RELEASED', 'Barbie', 346698, 'https://www.youtube.com/watch?v=EZzABx9RWoY', '2026-02-14 17:41:45.188005', 10753, 265),
	(296, NULL, 0, 'https://image.tmdb.org/t/p/w780/yWCZc2TcsCYbMMjvUIsczmQi2TX.jpg', 0, '2026-02-09 17:26:47.225622', 'Cuando un nuevo asesino Ghostface aparece en el tranquilo pueblo donde Sidney Prescott ha construido una nueva vida, sus peores miedos se hacen realidad cuando su hija se convierte en el siguiente objetivo. Decidida a proteger a su familia, Sidney debe enfrentarse a los horrores de su pasado para poner fin a la masacre de una vez por todas.', 114, NULL, 'US', 'en', 33.9454, 'https://image.tmdb.org/t/p/w500/hflipaW7mtfKZM9WFEyzUdFsgSk.jpg', '2026-02-25', 0, 'scream-7-2026', 'POST_PRODUCTION', 'Scream 7', 1159559, 'https://www.youtube.com/watch?v=bK-Sam8baFU', '2026-02-14 17:40:54.577410', 0, 266),
	(297, NULL, 5.571, 'https://image.tmdb.org/t/p/w780/zhoYj0OCQtuOFsFhRx7ivcjM8C.jpg', 0, '2026-02-09 17:26:48.194587', 'Una enfermera se encuentra en un mundo oscuro y misterioso.', 82, NULL, 'CA', 'en', 26.916, 'https://image.tmdb.org/t/p/w500/cRI8vg9WfYguw6cI8urjCc6Myjk.jpg', '2017-11-26', 0, 'darken-2017', 'RELEASED', 'Darken', 460952, 'https://www.youtube.com/watch?v=Itt-itaQZi0', '2026-02-09 17:26:48.194587', 7, 267),
	(298, 'APTA', 7.248, 'https://image.tmdb.org/t/p/w780/rj58WQ9ImI0mYDptXdM7euX1Wjt.jpg', 150000000, '2026-02-09 17:26:49.003731', 'Cuando una profecía condena a un reino a un invierno eterno, Anna, una joven optimista se une a un temerario montañero llamado Kristoff y a su compinche el reno Sven. Juntos emprenden un viaje épico en busca de Elsa, hermana de Anna y reina de Las Nieves para poner fin al gélido hechizo.', 102, NULL, 'US', 'en', 19.7838, 'https://image.tmdb.org/t/p/w500/sGNuWC4BwqOB4l0tkbKwLy70tXC.jpg', '2013-11-20', 1274219009, 'frozen-el-reino-del-hielo-2013', 'RELEASED', 'Frozen: El reino del hielo', 109445, 'https://www.youtube.com/watch?v=QTvcYow0Z5U', '2026-02-14 17:42:06.885141', 17346, 324),
	(299, NULL, 7.875, 'https://image.tmdb.org/t/p/w780/ufuabtiOem0kHeYz6b8x8MjBb2L.jpg', 0, '2026-02-09 17:26:49.763472', 'Ambientada en el Tokio actual, sigue a un actor estadounidense que lucha por encontrar un propósito en la vida hasta que consigue un trabajo inusual: trabajar para una agencia japonesa de "familias de alquiler", interpretando papeles de suplente para desconocidos. A medida que se sumerge en el mundo de sus clientes, comienza a establecer vínculos genuinos que difuminan las líneas entre la actuación y la realidad. Al enfrentarse a las complejidades morales de su trabajo, redescubre el propósito, la pertenencia y la tranquila belleza de las relaciones humanas.', 110, NULL, 'US', 'en', 21.1826, 'https://image.tmdb.org/t/p/w500/9z5dHWiX8EjZBRhJ2OzmYZGW7jS.jpg', '2025-11-20', 10706787, 'rental-family-2025', 'RELEASED', 'Rental Family', 1208348, 'https://www.youtube.com/watch?v=gtDTQATpSi8', '2026-02-14 17:42:13.662826', 355, 269),
	(300, NULL, 7.017, 'https://image.tmdb.org/t/p/w780/w57nxiBIODAYHLRs1xmrCY9zEFe.jpg', 14000000, '2026-02-09 17:26:50.791216', 'Durante el reinado de los Kadamba, el rey Vijayendra, gobernante de la ficticia tierra feudataria de Bangra, encuentra su destino final mientras se aventura en el místico bosque de Kantara. Testigo de ello, su hijo Rajashekara sella las fronteras de su reino. Más tarde, el príncipe Kulashekara las reabre mediante una brutal masacre. El protagonista, Berme, en busca de prosperidad, cruza la brecha y enciende un conflicto de fe, poder y destino entre el Reino y la Naturaleza.', 165, NULL, 'IN', 'kn', 23.9666, 'https://image.tmdb.org/t/p/w500/ehQPboTPaIMkMUOoNOh8e7pZ5Rp.jpg', '2025-10-01', 91000000, 'kantara-2-2025', 'RELEASED', 'Kantara 2', 1083637, 'https://www.youtube.com/watch?v=TMQUFhWm8C0', '2026-02-14 17:41:38.422490', 58, 270),
	(301, '12', 8.036, 'https://image.tmdb.org/t/p/w780/ycnO0cjsAROSGJKuMODgRtWsHQw.jpg', 100000000, '2026-02-09 17:26:52.509758', 'Película sobre el físico J. Robert Oppenheimer y su papel como desarrollador de la bomba atómica. Basada en el libro \'American Prometheus: The Triumph and Tragedy of J. Robert Oppenheimer\' de Kai Bird y Martin J. Sherwin.', 181, NULL, 'GB', 'en', 25.3645, 'https://image.tmdb.org/t/p/w500/5t05uhX5ULn8Um2f1ZuznVvIffU.jpg', '2023-07-19', 952000000, 'oppenheimer-2023', 'RELEASED', 'Oppenheimer', 872585, 'https://www.youtube.com/watch?v=JpUd4BS7yI0', '2026-02-14 17:41:33.398755', 11329, 81),
	(302, NULL, 5.865, 'https://image.tmdb.org/t/p/w780/5UYCuHb0kfFzrZ5l9SKzScguDbu.jpg', 0, '2026-02-09 17:26:53.535046', 'Gina odia que su cumpleaños caiga en el Día de San Valentín y viaja a Grecia para evitar la propuesta de matrimonio de su novio. Con la ayuda de Johnny y su hermana Mickey, que están de vacaciones, planea retrasarla, mientras cuestiona su relación.', 95, NULL, 'US', 'en', 26.5488, 'https://image.tmdb.org/t/p/w500/8zPExowfpfZOTpS1W4J7G27lH4H.jpg', '2026-02-12', 0, 'f-valentine-s-day-2026', 'RELEASED', 'F Valentine\'s Day', 1429605, 'https://www.youtube.com/watch?v=qHxAYI_YMb4', '2026-02-14 17:41:20.220766', 26, 271),
	(303, '18', 7.5, 'https://image.tmdb.org/t/p/w780/aC6wW62V6b0csr5iUnbOjYAqfhg.jpg', 65000000, '2026-02-09 17:26:55.404417', 'William Harford es un respetable médico neoyorquino cuya vida parece ir muy bien: está casado con una preciosa mujer, tiene una hija y tiene un trabajo que le gusta. Pero, al día siguiente de asistir a una fiesta, su esposa Alice le habla de unas fantasías eróticas y de cómo estuvo a punto de romper su matrimonio por un desconocido. Abrumado por esta confesión, acaba entrando en un local, donde un antiguo compañero le habla de una congregación secreta dedicada al hedonismo y al placer sin límites. A partir de entonces un mundo dominado por el sexo y el erotismo se abre ante él.', 159, NULL, 'GB', 'en', 22.7231, 'https://image.tmdb.org/t/p/w500/gh0YQsW7Zibtt50xtwRM62m1L97.jpg', '1999-07-16', 162100000, 'eyes-wide-shut-1999', 'RELEASED', 'Eyes Wide Shut', 345, 'https://www.youtube.com/watch?v=VSS47StLOhk', '2026-02-14 17:41:52.292053', 6831, 272),
	(304, '12', 8.4, 'https://image.tmdb.org/t/p/w780/1jdPUUSy37Wzw3xuc8otI86X2gv.jpg', 0, '2026-02-09 17:26:56.534666', 'La vida de Iroha se sale de control cuando Kaguya, una despreocupada fugitiva de la Luna, se muda con ella y la convence para actuar juntas en un mundo virtual.', 141, NULL, 'JP', 'ja', 24.9947, 'https://image.tmdb.org/t/p/w500/9YrbOSKoreS4oIjuwx9YjkAU8KP.jpg', '2026-01-22', 0, 'la-princesa-kaguya-del-cosmos-2026', 'RELEASED', 'La princesa Kaguya del cosmos', 1575337, 'https://www.youtube.com/watch?v=uine6d15yGE', '2026-02-09 17:26:56.534666', 43, 273),
	(305, NULL, 4.5, 'https://image.tmdb.org/t/p/w780/qg6wGnkBhCcsGfNz1eGtPMtKGDs.jpg', 93, '2026-02-09 17:26:57.378474', 'Dos millennials venden apartamentos de Nueva York que no son de su propiedad a nuevos compradores que no saben que están siendo estafados. La estafa funciona a las mil maravillas hasta que se topan con un propietario de apartamentos con un oscuro secreto que les da la vuelta a la tortilla.', 93, NULL, 'US', 'en', 73.572, 'https://image.tmdb.org/t/p/w500/rF6txsM6cgF9vg6Ra5sNbkvUwrw.jpg', '2026-02-06', 0, 'twisted-2026', 'RELEASED', 'Twisted', 1373198, 'https://www.youtube.com/watch?v=fAkM20N5YV0', '2026-02-14 17:40:12.966484', 24, 274),
	(306, '18', 7.14, 'https://image.tmdb.org/t/p/w780/9Whl7RAzes0oMaFAeSqD8ttN3fl.jpg', 17500000, '2026-02-09 17:26:58.131061', '\'Tú, pero mejor en todos los sentidos\'. Esa es la promesa de la sustancia, un producto revolucionario basado en la división celular, que crea un alter ego más joven, más bello, más perfecto.', 141, NULL, 'FR', 'en', 24.2816, 'https://image.tmdb.org/t/p/w500/w1PiIqM89r4AM7CiMEP4VLCEFUn.jpg', '2024-09-07', 76506196, 'la-sustancia-2024', 'RELEASED', 'La sustancia', 933260, 'https://www.youtube.com/watch?v=2M03oTyJdHc', '2026-02-09 17:27:14.225232', 5641, 275),
	(308, NULL, 6.674, 'https://image.tmdb.org/t/p/w780/smbIQ9Fzx9LaWtTDm8x7GAaDvCe.jpg', 0, '2026-02-09 17:27:01.019361', '', 75, NULL, 'US', 'en', 20.3933, 'https://image.tmdb.org/t/p/w500/534y0Pt72VEAUTV3THKpMxzCoB3.jpg', '2025-12-19', 0, 'dave-chappelle-the-unstoppable-2025', 'RELEASED', 'Dave Chappelle: The Unstoppable...', 1601195, 'https://www.youtube.com/watch?v=yWDhs-xyC2c', '2026-02-09 17:27:01.019361', 46, 277),
	(309, NULL, 6.313, 'https://image.tmdb.org/t/p/w780/cb3xdCXws4OLcXNNqQmZHDfAKCY.jpg', 0, '2026-02-09 17:27:02.499589', 'Una terapeuta pierde el control de la realidad cuando un niño de diez años afirma que puede controlar su futuro.', 108, NULL, 'LU', 'en', 22.3035, 'https://image.tmdb.org/t/p/w500/wNNAGw2TsYW4c3if252c6Il1fEc.jpg', '2020-09-28', 0, 'marionette-2020', 'RELEASED', 'Marionette', 662659, 'https://www.youtube.com/watch?v=nObwABpmHgI', '2026-02-09 17:27:02.499589', 67, 278),
	(310, '18', 6.723, 'https://image.tmdb.org/t/p/w780/mPtPJzBkwksUoMEKpkZqxBrlKpZ.jpg', 70000, '2026-02-09 17:27:03.547571', 'Un perro leal se muda a una casa rural con su dueño Todd. Allí descubre fuerzas sobrenaturales que acechan en las sombras. Mientras oscuras entidades amenazan a su compañero humano, el valiente cachorro debe luchar para proteger a quien más quiere.', 73, NULL, 'US', 'en', 18.5496, 'https://image.tmdb.org/t/p/w500/6rZOKB5EhGcTLaSPoyX8La44ZDT.jpg', '2025-10-01', 8781040, 'good-boy-2025', 'RELEASED', 'Good Boy', 1422096, 'https://www.youtube.com/watch?v=q4-CRkd_74g', '2026-02-14 17:42:02.643337', 513, 279),
	(311, '12', 6.975, 'https://image.tmdb.org/t/p/w780/fuacZLpnohQtLD0AhtCErcPVL98.jpg', 12000000, '2026-02-09 17:27:04.384861', 'En un más allá donde las almas tienen una semana para decidir dónde pasarán la eternidad, Joan (Elizabeth Olsen) se enfrenta a la diabólica disyuntiva de elegir entre el hombre con el que ha compartido su vida (Miles Teller) y su primer amor (Callum Turner), que murió joven y ha estado décadas esperando a que ella llegara.', 114, NULL, 'US', 'en', 24.2993, 'https://image.tmdb.org/t/p/w500/5zCTIGICQ9ykuBXDmS4rL1kEK9l.jpg', '2025-11-26', 32867848, 'eternity-2025', 'RELEASED', 'Eternity', 1259102, 'https://www.youtube.com/watch?v=CRhIbHregpk', '2026-02-09 17:27:14.011023', 391, 280),
	(312, NULL, 6.541, 'https://image.tmdb.org/t/p/w780/7F1djgcBJkMWFOeQ0ZK4b5Q3LPb.jpg', 0, '2026-02-09 17:27:05.254658', 'Lost in Beijing, nos traslada al submundo de los centros de masajes de Beijing, en donde una joven trabaja como masajista y debe esconder la identidad y existencia de su esposo, un limpia vidrios que un día en su trabajo se topa con la insufrible noticia que su esposa le era infiel con su jefe (Tony Leung Kai Fai) sin saber que, ella en estado de ebriedad habia sido violada por el dueño del Centro de Masajes.', 112, NULL, 'CN', 'zh', 19.7463, 'https://image.tmdb.org/t/p/w500/bqfeXqCSpWObWmVuZVgdezOEnS1.jpg', '2007-09-26', 5095696, 'perdidos-en-pekin-lost-in-beijing-2007', 'RELEASED', 'Perdidos en Pekín (Lost in Beijing)', 30112, 'https://www.youtube.com/watch?v=ue_-qEvvglg', '2026-02-09 17:27:05.254658', 61, 281),
	(313, '7', 8.009, 'https://image.tmdb.org/t/p/w780/vbk5CfaAHOjQPSAcYm6AoRRz2Af.jpg', 130000000, '2026-02-09 17:27:05.945144', 'Harry está deseando que termine el verano para comenzar un nuevo curso en Hogwarts, y abandonar lo antes posible la casa de sus despreciables tíos, los Dursley. Lo que desconoce Harry es que va a tener que abandonar Privet Drive antes de tiempo e inesperadamente después de convertir a su tía Marge en un globo gigante. Un autobús noctámbulo, y encantado por supuesto, le llevará a la taberna El Caldero Chorreante, donde le espera nada menos que Cornelius Fudge, el Ministro de Magia.', 141, NULL, 'GB', 'en', 25.6675, 'https://image.tmdb.org/t/p/w500/wF9aoo4YZmpKP4bZPSy4Zwwek6G.jpg', '2004-05-31', 789804554, 'harry-potter-y-el-prisionero-de-azkaban-2004', 'RELEASED', 'Harry Potter y el prisionero de Azkaban', 673, 'https://www.youtube.com/watch?v=Z1rhsNYESF0', '2026-02-09 17:27:05.945144', 22809, 282),
	(314, NULL, 5.45, 'https://image.tmdb.org/t/p/w780/kCwmLYy9ZMto1eMH8BI9KcVVIH2.jpg', 50000000, '2026-02-09 17:27:06.803858', '', 186, NULL, 'IN', 'te', 19.1733, 'https://image.tmdb.org/t/p/w500/nvK6gYa4diCnQkDVN42uoYXPrdT.jpg', '2026-01-08', 21000000, '2026', 'RELEASED', 'ది రాజాసాబ్', 1022453, 'https://www.youtube.com/watch?v=YFZMBqyXkqQ', '2026-02-14 17:42:23.061106', 20, 283),
	(315, '7', 8.202, 'https://image.tmdb.org/t/p/w780/2w4xG178RpB4MDAIfTkqAuSJzec.jpg', 11000000, '2026-02-09 17:27:08.141857', 'La princesa Leia, líder del movimiento rebelde que desea reinstaurar la República en la galaxia en los tiempos ominosos del Imperio, es capturada por las malévolas Fuerzas Imperiales, capitaneadas por el implacable Darth Vader, el sirviente más fiel del emperador. El intrépido Luke Skywalker, ayudado por Han Solo, capitán de la nave espacial "El Halcón Milenario", y los androides, R2D2 y C3PO, serán los encargados de luchar contra el enemigo y rescatar a la princesa para volver a instaurar la justicia en el seno de la Galaxia.', 121, NULL, 'US', 'en', 26.0476, 'https://image.tmdb.org/t/p/w500/ahT4ObS7XKedQkOSpGr1wQ97aKA.jpg', '1977-05-25', 775398007, 'la-guerra-de-las-galaxias-1977', 'RELEASED', 'La guerra de las galaxias', 11, 'https://www.youtube.com/watch?v=beAH5vea99k', '2026-02-09 17:27:08.141857', 21907, 284),
	(316, '7', 7.329, 'https://image.tmdb.org/t/p/w780/tPpYGm2mVecue7Bk3gNVoSPA5qn.jpg', 175000000, '2026-02-09 17:27:12.788454', 'Peter Parker comienza a experimentar su recién descubierta identidad como el superhéroe Spider-Man. Después de la experiencia vivida con los Vengadores, Peter regresa a casa, donde vive con su tía. Bajo la atenta mirada de su mentor Tony Stark, Peter intenta mantener una vida normal como cualquier joven de su edad, pero interrumpe en su rutina diaria el nuevo villano Vulture y, con él, lo más importante de la vida de Peter comenzará a verse amenazado.', 133, NULL, 'US', 'en', 25.266, 'https://image.tmdb.org/t/p/w500/yJfPC6pjSJ5VOsVyXhx5PXBe0mR.jpg', '2017-07-05', 880978185, 'spider-man-homecoming-2017', 'RELEASED', 'Spider-Man: Homecoming', 315635, 'https://www.youtube.com/watch?v=8lI3_UpQyYA', '2026-02-14 17:41:33.473737', 22842, 257),
	(317, 'A', 8.255, 'https://image.tmdb.org/t/p/w780/q00H8EqULYSK74lgevMkhmGGLHn.jpg', 45000000, '2026-02-09 17:27:13.609880', 'La sabana africana es el escenario en el que tienen lugar las aventuras de Simba, un pequeño león que es el heredero del trono. Sin embargo, se ve forzado a exiliarse al ser injustamente acusado de la muerte de su padre. Durante su destierro, hará buenas amistades y, finalmente, regresará para recuperar lo que legítimamente le corresponde.', 85, NULL, 'US', 'en', 24.4867, 'https://image.tmdb.org/t/p/w500/b0MxU37dNmMwKtoPVYPKOZSIrIn.jpg', '1994-06-15', 763455561, 'el-rey-leon-1994', 'RELEASED', 'El rey león', 8587, 'https://www.youtube.com/watch?v=bjJvvrKl83M', '2026-02-09 17:27:13.609880', 19356, 285),
	(318, '12', 7.589, 'https://image.tmdb.org/t/p/w780/ilRyazdMJwN05exqhwK4tMKBYZs.jpg', 150000000, '2026-02-09 17:27:15.347484', 'Han pasado 30 años desde los acontecimientos ocurridos en Blade Runner (1982). El oficial K, un blade runner caza-replicantes del Departamento de Policía de Los Ángeles, descubre un secreto que ha estado enterrado durante mucho tiempo y que tiene el potencial de llevar a la sociedad al caos. Su investigación le conducirá a la búsqueda del legendario Rick Deckard, un antiguo blade runner en paradero desconocido, que lleva desaparecido 30 años.', 164, NULL, 'CA', 'en', 26.1534, 'https://image.tmdb.org/t/p/w500/cOt8SQwrxpoTv9Bc3kyce3etkZX.jpg', '2017-10-04', 259239658, 'blade-runner-2049-2017', 'RELEASED', 'Blade Runner 2049', 335984, 'https://www.youtube.com/watch?v=zRy9zzc1FLo', '2026-02-14 17:41:22.389856', 14767, 261),
	(319, '18', 8.452, 'https://image.tmdb.org/t/p/w780/gILte6Zd7m1YneIr6MVhh30S9pr.jpg', 25000000, '2026-02-09 17:27:16.070993', 'Henry, un niño de trece años de Brooklyn, vive fascinado con el mundo de los gángsters. Su sueño se hace realidad cuando entra a formar parte de la familia Pauline, dueña absoluta de la zona, que lo educan como un miembro más de la banda convirtiéndole en un destacado mafioso.', 146, NULL, 'US', 'en', 23.8394, 'https://image.tmdb.org/t/p/w500/3Yy0zBO9AlyAZH1cTI8Ko2ouCi.jpg', '1990-09-12', 47072327, 'uno-de-los-nuestros-1990', 'RELEASED', 'Uno de los nuestros', 769, 'https://www.youtube.com/watch?v=Shj-QWYDn_M', '2026-02-14 17:41:40.214523', 14004, 160),
	(320, '12', 7.297, 'https://image.tmdb.org/t/p/w780/jYCyTdPfgT01IOJWDnnetr9RDX6.jpg', 180000000, '2026-02-09 17:27:16.981007', 'Un grupo de supervillanos poco convencional es reclutado para hacer misiones para el gobierno: Yelena Belova, Bucky Barnes, Red Guardian, Ghost, Taskmaster y John Walker. Después de verse atrapados en una trampa mortal urdida por Valentina Allegra de Fontaine, estos marginados deben embarcarse en una peligrosa misión que les obligará a enfrentarse a los recovecos más oscuros de su pasado.', 127, NULL, 'US', 'en', 22.9489, 'https://image.tmdb.org/t/p/w500/yDWU8YyFkPnlVY627QXPvct8bz9.jpg', '2025-04-30', 382436917, 'thunderbolts-2025', 'RELEASED', 'Thunderbolts*', 986056, 'https://www.youtube.com/watch?v=QCbzHZ1Q2lw', '2026-02-14 17:41:50.924586', 3194, 286),
	(321, '7', 7.672, 'https://image.tmdb.org/t/p/w780/pkxPkHOPJjOvzfQOclANEBT8OfK.jpg', 150000000, '2026-02-09 17:27:17.717015', 'Harry Potter regresa por quinto año a Hogwarts aún sacudido por la tragedia ocurrida en el Torneo de los Tres Magos. Debido a que el Ministro de la Magia niega el regreso de Lord Voldemort, Harry se convierte en el centro de atención de la comunidad mágica. Mientras lucha con sus problemas en el colegio, incluyendo a la nueva profesora Dolores Umbridge, intentará aprender más sobre la misteriosa Orden del Fénix.', 138, NULL, 'GB', 'en', 23.8542, 'https://image.tmdb.org/t/p/w500/xxXiM2Ij7plbzibKWW9BfDk23aI.jpg', '2007-07-08', 938212738, 'harry-potter-y-la-orden-del-fenix-2007', 'RELEASED', 'Harry Potter y la Orden del Fénix', 675, 'https://www.youtube.com/watch?v=zqMjQXcpacg', '2026-02-09 17:27:35.058543', 20499, 287),
	(322, '16', 7.47, 'https://image.tmdb.org/t/p/w780/jlGmlFOcfo8n5tURmhC7YVd4Iyy.jpg', 185000000, '2026-02-09 17:27:19.141037', 'Un grupo de super villanos se encuentran encerrados en Belle Reve, una prisión de alta seguridad con la tasa de mortalidad más alta de Estados Unidos. Para salir de allí harán cualquier cosa, incluso unirse al grupo Task Force X, dedicado a llevar a cabo misiones suicidas bajo las órdenes de Amanda Waller. Fuertemente armados son enviados a la isla Corto Maltese, una jungla repleta de enemigos.', 132, NULL, 'US', 'en', 23.7214, 'https://image.tmdb.org/t/p/w500/fPJWlhXA2VXf4MlQ3JenVsz1iba.jpg', '2021-07-28', 168717425, 'el-escuadron-suicida-2021', 'RELEASED', 'El escuadrón suicida', 436969, 'https://www.youtube.com/watch?v=qv8eF1u0-QU', '2026-02-09 17:27:19.141037', 9374, 49),
	(323, '12', 8.567, 'https://image.tmdb.org/t/p/w780/zb6fM1CX41D9rF9hdgclu0peUmy.jpg', 22000000, '2026-02-09 17:27:20.681209', 'Oskar Schindler, un hombre de enorme astucia y talento para las relaciones públicas, organiza un ambicioso plan para ganarse la simpatía de los nazis. Después de la invasión de Polonia por los alemanes, consigue, gracias a sus relaciones con los nazis, la propiedad de una fábrica de Cracovia. Allí emplea a cientos de operarios judíos, cuya explotación le hace prosperar rápidamente. Su gerente, también judío, es el verdadero director en la sombra, pues Schindler no tiene el menor conocimiento industrial.', 195, NULL, 'US', 'en', 23.6829, 'https://image.tmdb.org/t/p/w500/3Ho0pXsnMxpGJWqdOi0KDNdaTkT.jpg', '1993-12-15', 321365567, 'la-lista-de-schindler-1993', 'RELEASED', 'La lista de Schindler', 424, 'https://www.youtube.com/watch?v=0Z9cLiliBh0', '2026-02-09 17:27:31.313957', 17087, 288),
	(324, 'A', 8.324, 'https://image.tmdb.org/t/p/w780/qskzmLTbarKnXDbo2HRj4NJ3vcW.jpg', 19000000, '2026-02-09 17:27:21.444746', 'El adolescente Marty McFly es amigo de Doc, un científico al que todos toman por loco. Cuando Doc crea una máquina para viajar en el tiempo, un error fortuito hace que Marty llegue a 1955, año en el que sus futuros padres aún no se habían conocido. Después de impedir su primer encuentro, deberá conseguir que se conozcan y se casen; de lo contrario, su existencia no sería posible.', 116, NULL, 'US', 'en', 23.6458, 'https://image.tmdb.org/t/p/w500/owk40tn1sFJmC7bhamEpmhdZPKa.jpg', '1985-07-03', 381109762, 'regreso-al-futuro-1985', 'RELEASED', 'Regreso al futuro', 105, 'https://www.youtube.com/watch?v=xxSo8ZEvzE8', '2026-02-09 17:27:28.737519', 21363, 289),
	(325, '12', 6.528, 'https://image.tmdb.org/t/p/w780/7nAVXGHHtaNcdsqvDXmY6R9N0fG.jpg', 0, '2026-02-09 17:27:22.538258', 'Dan ha dejado atrás su pasado como asesino y lo único que quiere esta Navidad es pasar tiempo de calidad con sus hijos. Pero, al ver que su hija tiene otros planes, organiza un viaje familiar a Londres... y los pone a todos en la mira de un enemigo inesperado.', 106, NULL, 'US', 'en', 21.3425, 'https://image.tmdb.org/t/p/w500/sxoN17pPyL6SiqD8F6DXmTPILwJ.jpg', '2025-11-11', 0, 'plan-en-familia-2-2025', 'RELEASED', 'Plan en familia 2', 1363123, 'https://www.youtube.com/watch?v=dqolYtJGuf4', '2026-02-14 17:42:12.179708', 493, 290),
	(326, NULL, 5.3, 'https://image.tmdb.org/t/p/w780/sOLBfzX9hmFxrSMEIk3RKbV9QP6.jpg', 0, '2026-02-09 17:27:23.669206', 'Un virus almacenado en una instalación gubernamental sale al exterior y causa estragos en el mundo.', 99, NULL, 'US', 'en', 23.47, 'https://image.tmdb.org/t/p/w500/aioKGmYADqq09GEIY9vPhK5xoza.jpg', '2026-01-29', 0, 'alerta-extincion-2026', 'RELEASED', 'Alerta extinción', 696393, 'https://www.youtube.com/watch?v=kea7gnh1uYA', '2026-02-09 17:27:23.669206', 7, 291),
	(327, '16', 8.167, 'https://image.tmdb.org/t/p/w780/cEobq5QrnOJjO6giDs8q4RxmMKh.jpg', 11000000, '2026-02-09 17:27:24.455187', 'De regreso a la Tierra, la nave de carga Nostromo interrumpe su viaje y despierta a sus siete tripulantes. El ordenador central, MADRE, ha detectado la misteriosa transmisión de una forma de vida desconocida, procedente de un planeta cercano aparentemente deshabitado. La nave se dirige entonces al extraño planeta para investigar el origen de la comunicación.', 117, NULL, 'US', 'en', 23.4599, 'https://image.tmdb.org/t/p/w500/pZ9cAe5FxexJjpCaeiETbXzz3Fs.jpg', '1979-05-25', 104931801, 'alien-el-octavo-pasajero-1979', 'RELEASED', 'Alien, el octavo pasajero', 348, 'https://www.youtube.com/watch?v=D3oC17nILkw', '2026-02-09 17:27:24.455187', 15989, 292),
	(328, '16', 8.138, 'https://image.tmdb.org/t/p/w780/ztBeLd2UCbUATJ1cXwwHev3G3xX.jpg', 102000000, '2026-02-09 17:27:25.289058', 'Ha pasado once años desde que Sarah Connor fue marcada como objetivo para ser eliminada por un cyborg del futuro. Ahora su hijo John, el futuro líder de la resistencia, es el objetivo de un Terminator más moderno, más mortífero. Una vez más, la resistencia se las ha ingeniado para enviar un protector de vuelta al pasado para intentar salvar a John y a su madre Sarah.', 137, NULL, 'FR', 'en', 22.8636, 'https://image.tmdb.org/t/p/w500/10xtoK2SFv6ADIeWxr3mcrjko72.jpg', '1991-07-03', 517778573, 'terminator-2-el-juicio-final-1991', 'RELEASED', 'Terminator 2: El juicio final', 280, 'https://www.youtube.com/watch?v=VQd38bFMoIg', '2026-02-09 17:27:25.289058', 13920, 127),
	(329, 'APTA', 7.32, 'https://image.tmdb.org/t/p/w780/zQ8AxTPiCiS5nnwXpwTBPBHSaa5.jpg', 139000000, '2026-02-09 17:27:26.563297', 'Peter Parker es un joven y tímido estudiante que vive con su tía May y su tío Ben desde la muerte de sus padres. Un día es mordido por una araña que ha sido modificada genéticamente, descubriendo al día siguiente que posee unos poderes poco habituales: tiene la fuerza y agilidad de una araña.', 121, NULL, 'US', 'en', 20.9172, 'https://image.tmdb.org/t/p/w500/bCDaKZLRkrVVtPNyHxUfKvepW1N.jpg', '2002-05-01', 821708551, 'spider-man-2002', 'RELEASED', 'Spider-Man', 557, 'https://www.youtube.com/watch?v=zWT32yFM8bU', '2026-02-14 17:42:17.760084', 20278, 207),
	(330, NULL, 7.5, 'https://image.tmdb.org/t/p/w780/fTG8itSb1a4O2BgUMjXdwO64qTz.jpg', 4000000, '2026-02-09 17:27:27.546738', '', 100, NULL, 'US', 'en', 21.6896, 'https://image.tmdb.org/t/p/w500/fFjCz7pX9gZofqgbEnYxk3C1Ixo.jpg', '2026-02-05', 7200000, 'solo-mio-2026', 'RELEASED', 'Solo Mio', 1291335, 'https://www.youtube.com/watch?v=Vy45xJxnCZM', '2026-02-09 17:27:27.546738', 2, 293),
	(331, NULL, 7.167, 'https://image.tmdb.org/t/p/w780/d3z8MH9OvTOOSxy5QwAG0cS6GKU.jpg', 175000000, '2026-02-09 17:27:28.258089', 'A lo largo de los tiempos, los hombres han hecho la guerra. Unos por poder, otros por gloria o por honor, y algunos por amor. En la antigua Grecia, la pasión de dos de los amantes más legendarios de la historia, Paris, príncipe de Troya y Helena, reina de Esparta, desencadena una guerra que asolará una civilización. El rapto de Helena por Paris, separándola de su esposo, el rey Menelao, es un insulto que El orgullo familiar establece que una afrenta a Menelao es una afrenta a su hermano Agamenón, el poderoso rey de Micenas, que no tarda en reunir a todas las grandes tribus de Grecia para recuperar a Helena de manos de los troyanos y defender el honor de su hermano. La verdad es que la lucha por el honor por parte de Agamenón está corrompida por su incontenible codicia ya que necesita conquistar Troya para asumir el control del mar Egeo.', 163, NULL, 'GB', 'en', 19.4938, 'https://image.tmdb.org/t/p/w500/mBiDQT28DnuYaJSL4nDD43ORE6p.jpg', '2004-05-13', 497409852, 'troya-2004', 'RELEASED', 'Troya', 652, 'https://www.youtube.com/watch?v=ORKSndBYAPk', '2026-02-09 17:27:28.258089', 10824, 294),
	(332, '12', 7.33, 'https://image.tmdb.org/t/p/w780/3UbaCMmqOd7mca4Y5DOzY2ZVTyX.jpg', 250000000, '2026-02-09 17:27:29.451966', 'Después de haber recuperado el reino del Dragón Smaug, la Compañía ha desencadenado, sin querer, una potencia maligna. Un Smaug enfurecido vuela hacia la Ciudad del Lago para acabar con cualquier resto de vida. Obsesionado sobre todo con el reino recuperado, Thorin sacrifica la amistad y el honor para mantenerlo mientras que Bilbo intenta frenéticamente hacerle ver la razón por la que el hobbit toma una decisión desesperada y peligrosa. Pero hay aún mayores peligros por delante. Sin la ayuda aparente del mago Gandalf, su gran enemigo Sauron ha enviado legiones de orcos hacia la Montaña Solitaria en un ataque furtivo. Cuando la oscuridad se cierna sobre ellos, las razas de los Enanos, Elfos y Hombres deben decidir si unirse o ser destruidos. Bilbo se encontrará así en la batalla épica de los Cinco Ejércitos, donde el futuro de la Tierra Media está en juego.', 144, NULL, 'NZ', 'en', 21.59, 'https://image.tmdb.org/t/p/w500/6OiNSLcRKJsBLXwb6DEi6IQ0JFk.jpg', '2014-12-10', 956019788, 'el-hobbit-la-batalla-de-los-cinco-ejercitos-2014', 'RELEASED', 'El hobbit: La batalla de los cinco ejércitos', 122917, 'https://www.youtube.com/watch?v=ZlOwYNS7-ec', '2026-02-09 17:27:29.451966', 15077, 132),
	(333, '7', 7.61, 'https://image.tmdb.org/t/p/w780/cWczNud8Y8i8ab0Z4bxos4myWYO.jpg', 260000000, '2026-02-09 17:27:32.335573', 'Flynn Rider, el más buscado -y encantador- bandido del reino, se esconde en una misteriosa torre y allí se encuentra con Rapunzel, una bella y avispada adolescente con una cabellera dorada de 21 metros de largo, que vive encerrada allí desde hace años. Ambos sellan un pacto y a partir de ese momento la pareja vivirá emocionantes aventuras en compañía de un caballo superpolicía, un camaleón sobreprotector y una ruda pandilla de matones', 101, NULL, 'US', 'en', 23.3091, 'https://image.tmdb.org/t/p/w500/z5kvXWek4smCyeWBDJQkT5sLc9T.jpg', '2010-11-24', 592461732, 'enredados-2010', 'RELEASED', 'Enredados', 38757, 'https://www.youtube.com/watch?v=ee3XOCH-pok', '2026-02-09 17:27:32.335573', 12176, 295),
	(334, NULL, 0, 'https://image.tmdb.org/t/p/w780/3eOINbgRs8WiWfQfViXeuZ3enrs.jpg', 0, '2026-02-09 17:27:33.817849', 'Quinta entrega de la saga \'Vengadores\' incluida en el Universo Cinematográfico Marvel (UCM). Sinopsis desconocido.', 0, NULL, 'US', 'en', 21.606, 'https://image.tmdb.org/t/p/w500/rQKabpeIewLLNStFr3anEXI0xqu.jpg', '2026-12-16', 0, 'vengadores-doomsday-2026', 'POST_PRODUCTION', 'Vengadores: Doomsday', 1003596, 'https://www.youtube.com/watch?v=Ikd3NSMY058', '2026-02-09 17:27:33.817849', 0, 136),
	(335, '12', 7.19, 'https://image.tmdb.org/t/p/w780/eTlcNXGv32zkVI7ZDHhfeaKHXKQ.jpg', 34000000, '2026-02-09 17:27:34.562113', 'Thomas abre los ojos y se da cuenta que está en un ascensor. Lo extraño es que no recuerda nada, ni dónde está, ni quién es. Lo único que aún permanece intacto en su memoria es su nombre, y ya es mucho. Antes de que le dé tiempo a cuestionarse algo sobre sí mismo las puertas se abrirán y aparecerá ante él un extraño mundo. Todo lo que ve son chicos de su edad que tienen su mismo estado de amnesia. Una aventura fantástica que pronto destapará la dura realidad bajo ese velo de incertidumbre: todos ellos están atrapados en un laberinto. Si quieren tener alguna posibilidad de salir de allí y recuperar su antigua vida y aquello que no son capaces de recordar deberán unir fuerzas para escapar. Un mundo post-apocalíptico que les acorralará e irá un paso por delante será el desafío que tengan que pasar estos jóvenes por la libertad.', 113, NULL, 'US', 'en', 17.7069, 'https://image.tmdb.org/t/p/w500/egKi4jZKKVZzR8NaaNjEwMpEgHs.jpg', '2014-09-10', 348319861, 'el-corredor-del-laberinto-2014', 'RELEASED', 'El corredor del laberinto', 198663, 'https://www.youtube.com/watch?v=RxNV8uAacjU', '2026-02-14 17:42:03.349924', 17862, 296),
	(336, 'A', 7.909, 'https://image.tmdb.org/t/p/w780/jJKZaTBNenlFclQyjrnvzkRmvWE.jpg', 175000000, '2026-02-09 17:27:36.089302', 'Riley es una chica que disfruta o padece toda clase de sentimientos. Aunque su vida ha estado marcada por la Alegría, también se ve afectada por otro tipo de emociones. Lo que Riley no entiende muy bien es por qué motivo tiene que existir la Tristeza en su vida. Una serie de acontecimientos hacen que Alegría y Tristeza se mezclen en una peligrosa aventura que dará un vuelco al mundo de Riley.', 95, NULL, 'US', 'en', 22.3885, 'https://image.tmdb.org/t/p/w500/sG3bHZWCMOZwhUq71WbPG9Vrrwc.jpg', '2015-06-17', 857611174, 'del-reves-inside-out-2015', 'RELEASED', 'Del revés (Inside Out)', 150540, 'https://www.youtube.com/watch?v=x-xlkjPwaOY', '2026-02-09 17:27:36.089302', 23146, 297),
	(337, '16', 4.667, 'https://image.tmdb.org/t/p/w780/1Xdsq7U7bvJJd2X7Jg4qNaKVkYO.jpg', 0, '2026-02-14 17:39:58.518762', 'En medio de una ola de violencia inédita que sacude São Paulo, una abogada ligada al mundo criminal debe pactar con la policía para salvar a su sobrina secuestrada.', 103, NULL, 'BR', 'pt', 243.1407, 'https://image.tmdb.org/t/p/w500/xdyCFS4jUzp7kghoptaiYqir48X.jpg', '2026-02-10', 0, 'hermandad-estado-de-terror-2026', 'RELEASED', 'Hermandad: Estado de terror', 1426964, 'https://www.youtube.com/watch?v=syg6TKsx8aU', '2026-02-16 16:49:45.498187', 24, 298),
	(338, NULL, 6.1, 'https://image.tmdb.org/t/p/w780/o0jRpVznKXuLvoXQX9UTKVtGjxK.jpg', 0, '2026-02-14 17:40:08.242158', 'Tras la muerte de su hermano, June se muda a Milán para empezar de nuevo. Allí encuentra refugio en Will, el alumno perfecto de su instituto internacional. Pero James, el problemático mejor amigo de Will, que oculta una peligrosa vida en peleas clandestinas de MMA, convierte la rivalidad en una atracción irresistible que obliga a June a elegir entre una vida segura y un amor que lo cambia todo.', 99, NULL, 'IT', 'en', 205.1834, 'https://image.tmdb.org/t/p/w500/4QWAPETLYZosiwXQCTMu1KerXxI.jpg', '2026-02-12', 0, 'love-me-love-me-2026', 'RELEASED', 'Love Me Love Me', 1317672, 'https://www.youtube.com/watch?v=IQoh4U5GOfo', '2026-02-16 16:49:47.226952', 68, 299),
	(339, NULL, 8.2, 'https://image.tmdb.org/t/p/w780/2t25zHKX3PAUZWppuLD36JGdgCA.jpg', 93000000, '2026-02-14 17:40:16.158199', 'Davis es un escurridizo ladrón cuyos atracos de alto riesgo tienen desconcertada a la policía. Davis está planeando su mayor golpe, con la esperanza de que sea el último, cuando se cruza en su camino Sharon, una desilusionada ejecutiva de seguros con la que se ve obligado a trabajar, y Orman un ladrón rival, con métodos mucho más inquietantes que los de Davis. A medida que se acerca el golpe multimillonario, el implacable teniente Lubesnik, se acerca a la operación, aumentando considerablemente el riesgo de lo que está en juego y difuminando la línea entre cazador y presa. Pronto, cada uno tendrá que aceptar el coste de sus decisiones asumiendo que no hay vuelta atrás.', 140, NULL, 'GB', 'en', 72.351, 'https://image.tmdb.org/t/p/w500/wkmzt08vghSGlLYuqJpx4e2moRX.jpg', '2026-02-11', 0, 'ruta-de-escape-2026', 'RELEASED', 'Ruta de escape', 1171145, 'https://www.youtube.com/watch?v=fx72CaxjqNA', '2026-02-14 17:40:16.158199', 20, 300),
	(340, NULL, 6.286, 'https://image.tmdb.org/t/p/w780/eTodr0PX3fIDM4VFKJakpPGMZbp.jpg', 0, '2026-02-14 17:40:17.187097', '', 100, NULL, 'ES', 'en', 71.0045, 'https://image.tmdb.org/t/p/w500/z1lwn6GWAjJ7CSn80ZcURb0Cj4G.jpg', '2025-08-11', 0, 'holy-ghost-2025', 'RELEASED', 'Holy Ghost', 1528660, 'https://www.youtube.com/watch?v=7Fv7jBCgGXU', '2026-02-14 17:40:17.187097', 7, 301),
	(341, NULL, 0, 'https://image.tmdb.org/t/p/w780/cJEfGBcVQElkQwD6nop9AcZy8X.jpg', 0, '2026-02-14 17:40:21.173493', 'El protagonista es Juhan Liiv, un poeta y detective que resuelve truculentos casos de asesinato en la Estonia 1890 bajo la sombra del tiránico Imperio ruso.', 90, NULL, 'EE', 'et', 60.982, 'https://image.tmdb.org/t/p/w500/t6hPGT2hGxn4E5VMWjEiLjkGNzt.jpg', '2024-10-18', 0, 'vari-2024', 'RELEASED', 'Vari', 1194388, 'https://www.youtube.com/watch?v=Dw8wn4YEnjs', '2026-02-14 17:40:21.173493', 0, 302),
	(342, '18', 5.3, 'https://image.tmdb.org/t/p/w780/dbr3eceKuGnKc9v5GaVTVtegZNK.jpg', 0, '2026-02-14 17:40:33.907146', 'En esta alocada aventura, Joe, el hermano faltón de Madea, se lleva de viaje a su nieto, criado entre algodones, para que sepa cómo es la vida antes de ir a la universidad.', 111, NULL, 'US', 'en', 43.381, 'https://image.tmdb.org/t/p/w500/zp5RN4grAHUeCc9B7LKZcuu6HH5.jpg', '2026-02-12', 0, 'el-tour-universitario-con-joe-2026', 'RELEASED', 'El tour universitario con Joe', 1243460, 'https://www.youtube.com/watch?v=4cXcUFdaVA4', '2026-02-14 17:40:33.907146', 11, 303),
	(343, '12', 6.4, 'https://image.tmdb.org/t/p/w780/q2tUReeNgsYTs7tIJ98I4450QeM.jpg', 0, '2026-02-14 17:40:37.283863', 'David es un romántico empedernido que tiene una agencia de viajes especializada en viajes relacionados con comedias románticas. Su relación de 15 años con Quique está estancada. Entonces, David decide darle a Quique un viaje por la Ruta 66 con una parada especial en Las Vegas.', 94, NULL, 'AR', 'es', 44.0168, 'https://image.tmdb.org/t/p/w500/8kyqyI6mQmIVdLPRvIaFskVIcQW.jpg', '2025-06-26', 0, 'quien-quiere-casarse-con-un-astronauta-2025', 'RELEASED', '¿Quién quiere casarse con un astronauta?', 1254754, 'https://www.youtube.com/watch?v=ry69R1vw9hk', '2026-02-14 17:40:37.283863', 5, 304),
	(344, '18', 6.9, 'https://image.tmdb.org/t/p/w780/ceTxx1kqdygf9mBvVOT9oE1OCil.jpg', 0, '2026-02-14 17:40:42.211327', 'Tras la trágica muerte de Nat a causa de la contaminación por polvo, March se ve consumido por el dolor. Pero su vida cotidiana da un vuelco cuando descubre que el espíritu de su mujer se ha reencarnado en una aspiradora. Por absurdo que parezca, su vínculo se reaviva, haciéndose más fuerte que nunca...', 130, NULL, 'TH', 'th', 40.0227, 'https://image.tmdb.org/t/p/w500/7bUn53aMQGlj1GGlIuxptyNtI3G.jpg', '2025-08-27', 0, 'un-fantasma-util-2025', 'RELEASED', 'Un fantasma útil', 1364904, 'https://www.youtube.com/watch?v=_noSHYl4GI4', '2026-02-14 17:40:42.211327', 18, 305),
	(345, '16', 6.68, 'https://image.tmdb.org/t/p/w780/xQTSGz5dvIAYFssPWhD160AcR7Z.jpg', 12000000, '2026-02-14 17:40:45.620773', 'Un duro policía se asocia a regañadientes con un criminal sabelotodo que se encuentra temporalmente en libertad condicional, con el fin de localizar a un asesino.', 96, NULL, 'US', 'en', 37.2647, 'https://image.tmdb.org/t/p/w500/cHE4O3MjvH8Pv3qXEYaRtKbTwdR.jpg', '1982-12-07', 78868508, 'limite-48-horas-1982', 'RELEASED', 'Límite: 48 horas', 150, 'https://www.youtube.com/watch?v=24XiqMIC6q8', '2026-02-14 17:40:45.620773', 1653, 306),
	(346, NULL, 6.1, 'https://image.tmdb.org/t/p/w780/AgQJVTaZY2Oh30bbosZtXfwsQAn.jpg', 0, '2026-02-14 17:40:47.887527', '', 10, NULL, 'US', 'en', 35.4971, 'https://image.tmdb.org/t/p/w500/wrvCz8jo5eOaA9W3CvrCxPNtZS4.jpg', '2018-10-12', 0, 'the-hidebehind-2018', 'RELEASED', 'The Hidebehind', 575466, NULL, '2026-02-14 17:40:47.887527', 15, 307),
	(347, NULL, 7.506, 'https://image.tmdb.org/t/p/w780/baIjN7xPyw2In1CuHACTgzcsF20.jpg', 24500000, '2026-02-14 17:41:01.031060', 'Mariano De Santis, presidente (ficiticio) de la República italiana, es un veterano político demócrata, humanista y católico, que de repente comienza a dudar sobre varias importantes decisiones que debe tomar, en especial sobre si aprueba o no una ley de eutanasia, planteándose un gran dilema moral.', 133, NULL, 'IT', 'it', 29.5017, 'https://image.tmdb.org/t/p/w500/d86ctnc1Kl9xZHJ1xBPcwTKmaGa.jpg', '2025-12-05', 68995, 'la-grazia-2025', 'RELEASED', 'La grazia', 1397364, 'https://www.youtube.com/watch?v=zvQn44a_IHo', '2026-02-14 17:41:01.031060', 250, 308),
	(348, NULL, 4, 'https://image.tmdb.org/t/p/w780/ez8EB8pWGZYDWx9OEVqDR5r9hQc.jpg', 0, '2026-02-14 17:41:02.776454', '', 81, NULL, 'US', 'en', 75.049, 'https://image.tmdb.org/t/p/w500/sYDbxAPS7pD5S1HBvwvhvh80fxr.jpg', '2025-08-08', 58558, 'die-ced-reloaded-2025', 'RELEASED', 'Die\'ced: Reloaded', 1503900, 'https://www.youtube.com/watch?v=5byvy5-XWAU', '2026-02-14 17:41:02.776454', 5, 309),
	(349, NULL, 0, 'https://image.tmdb.org/t/p/w780/keSSTiy7lKWL5sW2ta47fAlKPpe.jpg', 0, '2026-02-14 17:41:12.358839', 'Wentinam, un niño huérfano que sobrevive en las calles de Kara, encuentra una nueva oportunidad en la “Ciudad de los Muchachos” gracias al apoyo de un misionero español.', 107, NULL, 'ES', 'es', 31.1481, 'https://image.tmdb.org/t/p/w500/4JgCz8ZUUsmsfAGhaMvDE2PUvIP.jpg', '2025-11-14', 0, 'te-protegeran-mis-alas-2025', 'RELEASED', 'Te protegerán mis alas', 1475637, 'https://www.youtube.com/watch?v=K6ycwLS_0lk', '2026-02-14 17:41:12.358839', 0, 310),
	(350, NULL, 2.5, 'https://image.tmdb.org/t/p/w780/5pP3kpWWPJrtIafL0o5lxOova7N.jpg', 0, '2026-02-14 17:41:16.415598', '', 107, NULL, 'PH', 'tl', 30.555, 'https://image.tmdb.org/t/p/w500/cTi6t2F7i5MjhqRIEBjav6GJLfa.jpg', '2023-03-22', 0, 'baby-boy-baby-girl-2023', 'RELEASED', 'Baby Boy, Baby Girl', 1097046, NULL, '2026-02-14 17:41:16.415598', 2, 311),
	(351, NULL, 6.786, 'https://image.tmdb.org/t/p/w780/xL5eX4090b5TCfKy5wNJdAC0rZz.jpg', 0, '2026-02-14 17:41:26.931993', 'Un niño adoptivo se une a una comunidad pentecostal que manipula serpientes, pero descubre verdades siniestras. Debe elegir entre denunciar los crímenes del pastor o preservar su nuevo sistema de apoyo, arriesgando su seguridad personal por un sentido de pertenencia.', 89, NULL, 'US', 'en', 48.408, 'https://image.tmdb.org/t/p/w500/qxBpsKyyyjSenFGnQEUbR5Eq3Ub.jpg', '2025-08-19', 0, 'hogar-siniestro-2025', 'RELEASED', 'Hogar Siniestro', 1563506, 'https://www.youtube.com/watch?v=RH2YvVhl-RY', '2026-02-14 17:41:26.931993', 7, 312),
	(352, '12', 8.132, 'https://image.tmdb.org/t/p/w780/o869RihWTdTyBcEZBjz0izvEsVf.jpg', 190000000, '2026-02-14 17:41:28.054374', 'Sigue el viaje mítico de Paul Atreides mientras se une a Chani y los Fremen en una guerra de venganza contra los conspiradores que destruyeron a su familia. Al enfrentarse a una elección entre el amor de su vida y el destino del universo conocido, Paul se esfuerza por evitar un futuro terrible que solo él puede prever.', 167, NULL, 'US', 'en', 25.994, 'https://image.tmdb.org/t/p/w500/xCHmhHeO7aOCMlzcNukGH6Q7EiD.jpg', '2024-02-27', 714844358, 'dune-parte-dos-2024', 'RELEASED', 'Dune: Parte dos', 693134, 'https://www.youtube.com/watch?v=nWzes49-2DA', '2026-02-14 17:41:31.983222', 7500, 261),
	(354, '12', 8.157, 'https://image.tmdb.org/t/p/w780/AaV1YIdWKnjAIAOe8UUKBFm327v.jpg', 170000000, '2026-02-14 17:41:30.183901', 'Después de más de 30 años de servicio como uno de los mejores aviadores de la Armada, Pete "Maverick" Mitchell se encuentra dónde siempre quiso estar, empujando los límites como un valiente piloto de prueba y esquivando el alcance en su rango, que no le dejaría volar emplazándolo en tierra. Cuando se encuentra entrenando a un destacamento de graduados de Top Gun para una misión especializada, Maverick se encuentra allí con el teniente Bradley Bradshaw, el hijo de su difunto amigo "Goose".', 131, NULL, 'US', 'en', 25.6468, 'https://image.tmdb.org/t/p/w500/AlWpEpQq0RgZIXVHAHZtFhEvRgd.jpg', '2022-05-21', 1488732821, 'top-gun-maverick-2022', 'RELEASED', 'Top Gun: Maverick', 361743, 'https://www.youtube.com/watch?v=zmFdhZ6gyUM', '2026-02-14 17:41:32.751704', 10576, 63),
	(355, '16', 7.629, 'https://image.tmdb.org/t/p/w780/l0eIS009XtEO80aC6zjM3o3AkEl.jpg', 150000000, '2026-02-14 17:41:31.812749', 'Perseguido por su turbulento pasado, Mad Max cree que la mejor forma de sobrevivir es ir solo por el mundo. Sin embargo, se ve arrastrado a formar parte de un grupo que huye a través del desierto en un War Rig conducido por una Emperatriz de élite: Furiosa. Escapan de una Ciudadela tiranizada por Immortan Joe, a quien han arrebatado algo irreemplazable. Enfurecido, el Señor de la Guerra moviliza a todas sus bandas y persigue implacablemente a los rebeldes en una \'guerra de la carretera\' de altas revoluciones.', 120, NULL, 'AU', 'en', 26.0296, 'https://image.tmdb.org/t/p/w500/fnY0VRsb31A5RLVCBjuR6EFUlo2.jpg', '2015-05-13', 378858340, 'mad-max-furia-en-la-carretera-2015', 'RELEASED', 'Mad Max: Furia en la carretera', 76341, 'https://www.youtube.com/watch?v=UyqFAle_4aE', '2026-02-14 17:41:31.812749', 23747, 313),
	(356, NULL, 0, NULL, 0, '2026-02-14 17:41:34.444250', '', 75, NULL, 'ES', 'en', 25.0287, 'https://image.tmdb.org/t/p/w500/3S2FhREtmkWAkMfOib1DLo1Bs7C.jpg', '2009-12-01', 0, 'tracy-2009', 'RELEASED', 'Tracy', 362668, NULL, '2026-02-14 17:41:34.444250', 0, 314),
	(357, NULL, 6.146, 'https://image.tmdb.org/t/p/w780/fvpDegC0EGBZCZPDHDineAL4P8F.jpg', 24000000, '2026-02-14 17:41:36.055314', 'Nick Lang es un famoso actor que necesita desesperadamente acabar con su imagen cinematográfica de niño bueno. Piensa que conseguirá un papel de valiente detective de homicidios si logra hacerlo en la vida real. Con ese objetivo, Lang se va de Hollywood a pasar unas semanas en las calles de Nueva York con el detective John Moss. Moss es un enérgico policía que se toma su trabajo muy en serio. Ahora le sigue la pista a un despiadado asesino en serie, y lo último que necesita es llevar a cuestas a un pesado. Pero su jefe, admirador de Nick Lang, insiste, y Moss tendrá que pensar cómo quitarse a Lang de encima mientras persigue al asesino.', 95, NULL, 'US', 'en', 24.4746, 'https://image.tmdb.org/t/p/w500/3w0gebKKFXEN8Eou0xlLeAkNKdA.jpg', '1991-03-08', 65595485, 'colegas-a-la-fuerza-1991', 'RELEASED', 'Colegas a la fuerza', 11384, 'https://www.youtube.com/watch?v=0axnlV3jAFc', '2026-02-14 17:41:36.055314', 463, 315),
	(358, '7', 8.236, 'https://image.tmdb.org/t/p/w780/7RyHsO4yDXtBv1zUU3mTpHeQ0d5.jpg', 356000000, '2026-02-14 17:41:36.757561', 'Tras el chasquido de Thanos que eliminó a la mitad de la vida en el universo, los Vengadores supervivientes quedan devastados y divididos. Cinco años después, una inesperada oportunidad les permite intentar revertir la catástrofe. Reuniéndose una vez más, los héroes emprenden una misión extrema que los obliga a viajar al pasado, enfrentarse a sus propias pérdidas y hacer sacrificios definitivos para restaurar el equilibrio del universo.', 181, NULL, 'US', 'en', 24.4649, 'https://image.tmdb.org/t/p/w500/br6krBFpaYmCSglLBWRuhui7tPc.jpg', '2019-04-24', 2799439100, 'vengadores-endgame-2019', 'RELEASED', 'Vengadores: Endgame', 299534, 'https://www.youtube.com/watch?v=UQ3bqYKnyhM', '2026-02-14 17:41:36.757561', 27239, 136),
	(359, '18', 8.486, 'https://image.tmdb.org/t/p/w780/96hiUXEuYsu4tcnvlaY8tEMFM0m.jpg', 8000000, '2026-02-14 17:41:37.539303', 'Jules y Vincent, dos asesinos a sueldo con muy pocas luces, trabajan para Marsellus Wallace. Vincent le confiesa a Jules que Marsellus le ha pedido que cuide de Mia, su mujer. Jules le recomienda prudencia porque es muy peligroso sobrepasarse con la novia del jefe. Cuando llega la hora de trabajar, ambos deben ponerse manos a la obra. Su misión: recuperar un misterioso maletín.', 154, NULL, 'US', 'en', 24.2171, 'https://image.tmdb.org/t/p/w500/hNcQAuquJxTxl2fJFs1R42DrWcf.jpg', '1994-09-10', 213928762, 'pulp-fiction-1994', 'RELEASED', 'Pulp Fiction', 680, 'https://www.youtube.com/watch?v=Yydi7TMo5n0', '2026-02-14 17:42:00.834509', 29672, 316),
	(360, NULL, 6.507, 'https://image.tmdb.org/t/p/w780/4IrOhjmbvDcl4czUTB15CLfKtL0.jpg', 0, '2026-02-14 17:41:39.309750', 'Ellen Gulden es una ambiciosa periodista que tan sólo vive para su trabajo. Cuando un día recibe la noticia de que su madre está gravemente enferma, se ve en la obligación de regresar a su pueblo natal. La intensa convivencia con sus padres le permitirá conocerlos a fondo, descubrir aspectos singulares de su pasado y madurar como persona.', 127, NULL, 'US', 'en', 23.9438, 'https://image.tmdb.org/t/p/w500/22Oy0KwqTsdNG9PwNLSxt1V4Pnn.jpg', '1998-09-18', 0, 'cosas-que-importan-1998', 'RELEASED', 'Cosas que importan', 53113, 'https://www.youtube.com/watch?v=lXJv1BQr1iI', '2026-02-14 17:41:39.309750', 134, 317),
	(361, '12', 8.462, 'https://image.tmdb.org/t/p/w780/67HggiWaP9ZLv5sPYmyRV37yAJM.jpg', 55000000, '2026-02-14 17:41:41.140085', 'Forrest Gump es un chico con deficiencias mentales no muy profundas y con alguna incapacidad motora que, a pesar de todo, llegará a convertirse, entre otras cosas, en un héroe durante la Guerra del Vietnam. Su persistencia y bondad le llevarán a conseguir una gran fortuna, ser objeto del clamor popular y a codearse con las más altas esferas sociales y políticas del país. Siempre sin olvidar a Jenny, su gran amor desde que era niño.', 142, NULL, 'US', 'en', 23.7683, 'https://image.tmdb.org/t/p/w500/oiqKEhEfxl9knzWXvWecJKN3aj6.jpg', '1994-06-23', 677387716, 'forrest-gump-1994', 'RELEASED', 'Forrest Gump', 13, 'https://www.youtube.com/watch?v=aSEPD9w_dLM', '2026-02-14 17:41:41.140085', 29232, 289),
	(362, NULL, 4.643, 'https://image.tmdb.org/t/p/w780/dC15RaDX4mmPB0omILrjTKMGy6W.jpg', 7000000, '2026-02-14 17:41:42.001831', 'En 1849, una esclava recién liberada cree que su misteriosa hija caucásica está poseída porque todo lo que toca muere, y convence a un médico viudo para que las lleve en un viaje para encontrar a un sanador de fe que se encuentra en una zona remota.', 108, NULL, 'US', 'en', 23.6813, 'https://image.tmdb.org/t/p/w500/dm1BORnIjKnKSCtOUU3ZJ8O18ty.jpg', '2025-10-03', 0, 'miradas-asesinas-2025', 'RELEASED', 'Miradas asesinas', 1200320, 'https://www.youtube.com/watch?v=BSWqjl_rvWY', '2026-02-14 17:41:42.001831', 21, 318),
	(363, '18', 7.282, 'https://image.tmdb.org/t/p/w780/wNAfVj1ObGNye5fQM4tJXJGtU0.jpg', 55000000, '2026-02-14 17:41:42.745104', 'Robert McCall, un antiguo agente de la CIA que lleva ahora una vida tranquila, abandona su retiro para ayudar a Teri, que está siendo explotada por la mafia rusa. A pesar de que aseguró no volver a ser violento, contemplar tanta crueldad despertará en Robert un implacable y renovado deseo de justicia.', 128, NULL, 'US', 'en', 23.6018, 'https://image.tmdb.org/t/p/w500/7tiub1UB4KF9zpacEldfbWAXDi6.jpg', '2014-09-24', 192330738, 'the-equalizer-el-protector-2014', 'RELEASED', 'The equalizer (El protector)', 156022, 'https://www.youtube.com/watch?v=rlMaxFG7blg', '2026-02-14 17:41:42.745104', 9735, 319),
	(364, '16', 7.4, 'https://image.tmdb.org/t/p/w780/aQLygZOIKai6aaiBAeeKpIWO5nc.jpg', 95000000, '2026-02-14 17:41:48.363099', 'Los Angeles, 1969. La estrella de televisión Rick Dalton, un actor en horas bajas especializado en westerns, y el doble de acción Cliff Booth, su mejor amigo, tratan de sobrevivir a una industria cinematográfica en constante cambio. Dalton es vecino de la joven y prometedora actriz y modelo Sharon Tate, que acaba de casarse con el prestigioso director polaco Roman Polanski…', 162, NULL, 'CN', 'en', 23.1999, 'https://image.tmdb.org/t/p/w500/vKSyaptSA7zZ9H8mSfaDnvyQl9k.jpg', '2019-07-24', 392105159, 'erase-una-vez-en-hollywood-2019', 'RELEASED', 'Érase una vez en… Hollywood', 466272, 'https://www.youtube.com/watch?v=_mUZobwljrc', '2026-02-14 17:41:48.363099', 14533, 316),
	(365, '12', 7.791, 'https://image.tmdb.org/t/p/w780/y2DB71C4nyIdMrANijz8mzvQtk6.jpg', 250000000, '2026-02-14 17:41:51.422222', 'Hace ocho años que Batman desapareció, dejando de ser un héroe para convertirse en un fugitivo. Al asumir la culpa por la muerte del fiscal del distrito Harvey Dent, el Caballero Oscuro decidió sacrificarlo todo por lo que consideraba, al igual que el Comisario Gordon, un bien mayor. La mentira funciona durante un tiempo, ya que la actividad criminal de la ciudad de Gotham se ve aplacada gracias a la dura Ley Dent. Pero todo cambia con la llegada de una astuta gata ladrona que pretende llevar a cabo un misterioso plan. Sin embargo, mucho más peligrosa es la aparición en escena de Bane, un terrorista enmascarado cuyos despiadados planes obligan a Bruce a regresar de su voluntario exilio.', 165, NULL, 'GB', 'en', 22.8381, 'https://image.tmdb.org/t/p/w500/rrS7K8tXVFUBliIKWaRuSq65nWr.jpg', '2012-07-17', 1081041287, 'el-caballero-oscuro-la-leyenda-renace-2012', 'RELEASED', 'El caballero oscuro: La leyenda renace', 49026, 'https://www.youtube.com/watch?v=e0qwi-4iOpE', '2026-02-14 17:41:51.422222', 23987, 81),
	(366, '16', 6.618, 'https://image.tmdb.org/t/p/w780/6WqqEjiycNvDLjbEClM1zCwIbDD.jpg', 60000000, '2026-02-14 17:41:54.225472', 'Años transcurridos tras los sucesos de "28 semanas después", el virus de la ira ha regresado y un grupo de supervivientes debe sobrevivir en un mundo asolado por hordas de infectados. Realizada con un iPhone 15 Pro Max y con la ayuda de numerosos accesorios especializados.', 115, NULL, 'GB', 'en', 22.4724, 'https://image.tmdb.org/t/p/w500/rlqdMZRPK8IELWcI5cJXLoA18XW.jpg', '2025-06-18', 151308832, '28-anos-despues-2025', 'RELEASED', '28 años después', 1100988, 'https://www.youtube.com/watch?v=d-4F7jJUoOE', '2026-02-14 17:41:56.485982', 2197, 320),
	(367, NULL, 4.4, 'https://image.tmdb.org/t/p/w780/1bRxlfuI7woxnxM8Z8LIgaKpffH.jpg', 0, '2026-02-14 17:41:56.166825', '', 94, NULL, 'PH', 'tl', 22.3666, 'https://image.tmdb.org/t/p/w500/xsUjSNFXyEWe3zkcHOWm7Hw7dR6.jpg', '2024-09-13', 0, 'uhaw-2024', 'RELEASED', 'Uhaw', 1302017, NULL, '2026-02-14 17:42:07.201752', 5, 321),
	(368, '12', 7.7, 'https://image.tmdb.org/t/p/w780/rvtdN5XkWAfGX6xDuPL6yYS2seK.jpg', 185000000, '2026-02-14 17:41:57.420385', 'Cuando un asesino se dirige a la élite de Gotham con una serie de maquinaciones sádicas, un rastro de pistas crípticas envía Batman a una investigación en los bajos fondos. A medida que las pruebas comienzan a acercarse a su casa y se hace evidente la magnitud de los planes del autor, Batman debe forjar nuevas relaciones, desenmascarar al culpable y hacer justicia al abuso de poder y la corrupción que durante mucho tiempo han asolado Gotham City.', 176, NULL, 'US', 'en', 20.9437, 'https://image.tmdb.org/t/p/w500/mo7teil1qH0SxgLijnqeYP1Eb4w.jpg', '2022-03-01', 772775278, 'the-batman-2022', 'RELEASED', 'The Batman', 414906, 'https://www.youtube.com/watch?v=L6DEcPaNdLs', '2026-02-14 17:41:57.420385', 11602, 322),
	(369, '18', 8.128, 'https://image.tmdb.org/t/p/w780/hO7KbdvGOtDdeg0W4Y5nKEHeDDh.jpg', 55000000, '2026-02-14 17:41:58.517382', 'Arthur Fleck es un hombre ignorado por la sociedad, cuya motivación en la vida es hacer reír. Pero una serie de trágicos acontecimientos le llevarán a ver el mundo de otra forma. Película basada en Joker, el popular personaje de DC Comics y archivillano de Batman, pero que en este film toma un cariz más realista y oscuro.', 122, NULL, 'CA', 'en', 20.9838, 'https://image.tmdb.org/t/p/w500/v0eQLbzT6sWelfApuYsEkYpzufl.jpg', '2019-10-01', 1078958629, 'joker-2019', 'RELEASED', 'Joker', 475557, 'https://www.youtube.com/watch?v=ygUHhImN98w', '2026-02-14 17:42:16.429806', 27283, 323),
	(370, '12', 8.412, 'https://image.tmdb.org/t/p/w780/kWYfW2Re0rUDE6IHhy4CRuKWeFr.jpg', 79000000, '2026-02-14 17:41:59.929241', 'La Compañía del Anillo se ha disuelto. El portador del anillo Frodo y su fiel amigo Sam se dirigen hacia Mordor para destruir el Anillo Único y acabar con el poder de Sauron. Mientras, y tras la dura batalla contra los orcos donde cayó Boromir, el hombre Aragorn, el elfo Legolas y el enano Gimli intentan rescatar a los medianos Merry y Pipin, secuestrados por los ogros de Mordor. Por su parte, Saurón y el traidor Sarumán continúan con sus planes en Mordor, en espera de la guerra contra las razas libres de la Tierra Media.', 180, NULL, 'NZ', 'en', 22.1561, 'https://image.tmdb.org/t/p/w500/z632eZtXaw76ZE5mMMGOBXCpm1T.jpg', '2002-12-18', 926287400, 'el-senor-de-los-anillos-las-dos-torres-2002', 'RELEASED', 'El señor de los anillos: Las dos torres', 121, 'https://www.youtube.com/watch?v=h-9RYiqyqjk', '2026-02-14 17:41:59.929241', 23423, 132),
	(371, '12', 5.985, 'https://image.tmdb.org/t/p/w780/8eifdha9GQeZAkexgtD45546XKx.jpg', 180000000, '2026-02-14 17:42:08.080789', 'Tras reunirse con el recién elegido presidente de los EE. UU., Thaddeus Ross, Sam se encuentra en medio de un incidente internacional. Debe descubrir el motivo que se esconde tras un perverso complot global, antes de que su verdadero artífice enfurezca al mundo entero.', 119, NULL, 'US', 'en', 21.832, 'https://image.tmdb.org/t/p/w500/vUNj55xlF0pSU5FU3yDHC6L5wVX.jpg', '2025-02-12', 415101577, 'capitan-america-brave-new-world-2025', 'RELEASED', 'Capitán América: Brave New World', 822119, 'https://www.youtube.com/watch?v=EFa6QSfk4TM', '2026-02-14 17:42:13.170621', 2922, 325),
	(372, '12', 6.7, 'https://image.tmdb.org/t/p/w780/3V4kLQg0kSqPLctI5ziYWabAZYF.jpg', 120000000, '2026-02-14 17:42:09.017526', 'Eddie y Venom están a la fuga. Perseguidos por sus sendos mundos y cada vez más cercados, el dúo se ve abocado a tomar una decisión devastadora que hará que caiga el telón sobre el último baile de Venom y Eddie.', 109, NULL, 'US', 'en', 21.2286, 'https://image.tmdb.org/t/p/w500/toZiAd0n0NKhiuHTiGk7kBMmhtG.jpg', '2024-10-22', 478937618, 'venom-el-ultimo-baile-2024', 'RELEASED', 'Venom: El último baile', 912649, 'https://www.youtube.com/watch?v=wuXjTZjYZQY', '2026-02-14 17:42:13.468972', 4006, 326),
	(373, '12', 7.005, 'https://image.tmdb.org/t/p/w780/4XM8DUTQb3lhLemJC51Jx4a2EuA.jpg', 340000000, '2026-02-14 17:42:11.073202', 'Durante numerosas misiones más que imposibles, Dom Toretto y su familia han sido capaces de ser más listos, de tener más valor y de ir más rápido que cualquier enemigo que se cruzara con ellos. Pero ahora tendrán que enfrentarse al oponente más letal que jamás hayan conocido: Un terrible peligro que resurge del pasado, que se mueve por una sangrienta sed de venganza y que está dispuesto a destrozar a la familia y destruir para siempre todo lo que a Dom le importa.', 140, NULL, 'US', 'en', 19.7562, 'https://image.tmdb.org/t/p/w500/3P9QvWVN02Etn4kYGC702WVoXEb.jpg', '2023-05-17', 704709660, 'fast-furious-x-2023', 'RELEASED', 'Fast & Furious X', 385687, 'https://www.youtube.com/watch?v=KOQy0AwA7k8', '2026-02-14 17:42:16.235312', 6191, 115),
	(374, 'A', 6.993, 'https://image.tmdb.org/t/p/w780/twsxsfao6ZOVvT8LfudH603MMi6.jpg', 100000000, '2026-02-14 17:42:12.919895', 'Gru, Lucy y las niñas -Margo, Edith y Agnes- dan la bienvenida a un nuevo miembro en la familia: Gru Junior, que parece llegar con el propósito de ser un suplicio para su padre. Gru tendrá que enfrentarse en esta ocasión a su nueva némesis Maxime Le Mal y su sofisticada y malévola novia Valentina, lo que obligará a la familia a tener que darse a la fuga. Cuarta entrega de \'Gru, mi villano favorito\'.', 94, NULL, 'US', 'en', 21.2378, 'https://image.tmdb.org/t/p/w500/b6JX0fBne5yPFNBtdp4Imi3CpiE.jpg', '2024-06-20', 969597394, 'gru-4-mi-villano-favorito-2024', 'RELEASED', 'Gru 4. Mi villano favorito', 519182, 'https://www.youtube.com/watch?v=zUFt9_WOoPc', '2026-02-14 17:42:12.919895', 3065, 327),
	(375, 'APTA', 7.847, 'https://image.tmdb.org/t/p/w780/sDTnMOJ3H5wI38OxObmCtK7wfd5.jpg', 115000000, '2026-02-14 17:42:14.451239', 'Monsters Inc. es la mayor empresa de miedo del mundo, y James P. Sullivan es uno de sus mejores empleados. Asustar a los niños no es un trabajo fácil, ya que todos creen que los niños son tóxicos y no pueden tener contacto con ellos. Pero un día una niña se cuela sin querer en la empresa, provocando el caos.', 88, NULL, 'US', 'en', 21.1475, 'https://image.tmdb.org/t/p/w500/g3SgHEb5ej2MioGfYLrZVshF909.jpg', '2001-11-01', 579700000, 'monstruos-s-a-2001', 'RELEASED', 'Monstruos, S.A.', 585, 'https://www.youtube.com/watch?v=feRnlEHTCY0', '2026-02-14 17:42:14.451239', 19467, 297),
	(376, '7', 7.27, 'https://image.tmdb.org/t/p/w780/kIBK5SKwgqIIuRKhhWrJn3XkbPq.jpg', 235000000, '2026-02-14 17:42:15.139034', 'Cuando Tony Stark intenta reactivar un programa caído en desuso cuyo objetivo es mantener la paz, las cosas empiezan a torcerse y los héroes más poderosos de la Tierra, incluyendo a Iron Man, Capitán América, Thor, El Increíble Hulk, Viuda Negra y Ojo de Halcón, tendrán que afrontar la prueba definitiva cuando el destino del planeta se ponga en juego. Cuando el villano Ultron emerge, le corresponderá a Los Vengadores detener sus terribles planes, que junto a incómodas alianzas llevarán a una inesperada acción que allanará el camino para una épica y única aventura.', 141, NULL, 'US', 'en', 21.116, 'https://image.tmdb.org/t/p/w500/3Lz6h5rlCFNNyCZRaRJ2ZjtBnAE.jpg', '2015-04-22', 1405403694, 'vengadores-la-era-de-ultron-2015', 'RELEASED', 'Vengadores: La era de Ultrón', 99861, 'https://www.youtube.com/watch?v=JQWGle-bKmE', '2026-02-14 17:42:15.139034', 24102, 179),
	(377, '16', 7.889, 'https://image.tmdb.org/t/p/w780/iWak7wT0j6ycCc8lKr4NBz9c7n5.jpg', 61000000, '2026-02-14 17:42:17.153419', 'El día de su quinto aniversario de boda, Nick Dunne informa de que su esposa Amy ha desaparecido misteriosamente. Pronto la presión policial y mediática hace que el retrato de felicidad doméstica que ofrece Nick empiece a tambalearse. Además, su extraña conducta lo convierte en sospechoso, y todo el mundo comienza a preguntase si Nick mató a su esposa...', 149, NULL, 'US', 'en', 20.5671, 'https://image.tmdb.org/t/p/w500/bkIhygnbv9ydlDo4SEsOcqGgQD4.jpg', '2014-10-01', 370890259, 'perdida-2014', 'RELEASED', 'Perdida', 210577, 'https://www.youtube.com/watch?v=UXyP5leMzf8', '2026-02-14 17:42:17.153419', 19642, 256),
	(378, '12', 7.928, 'https://image.tmdb.org/t/p/w780/hoVj2lYW3i7oMd1o7bPQRZd1lk1.jpg', 250000000, '2026-02-14 17:42:19.367655', 'La querida banda de los Guardianes se instala en Knowhere. Pero sus vidas no tardan en verse alteradas por los ecos del turbulento pasado de Rocket. Peter Quill, aún conmocionado por la pérdida de Gamora, debe reunir a su equipo en una peligrosa misión para salvar la vida de Rocket, una misión que, si no se completa con éxito, podría muy posiblemente conducir al final de los Guardianes tal y como los conocemos.', 153, NULL, 'US', 'en', 19.6365, 'https://image.tmdb.org/t/p/w500/6GkKzdNosVAL7UGgwTtCHSxLQ67.jpg', '2023-05-03', 845550000, 'guardianes-de-la-galaxia-volumen-3-2023', 'RELEASED', 'Guardianes de la Galaxia: Volumen 3', 447365, 'https://www.youtube.com/watch?v=FTGm7EexNmw', '2026-02-14 17:42:19.367655', 8000, 49),
	(379, '16', 6.633, 'https://image.tmdb.org/t/p/w780/4hvK1uenpT7VVClzoNqXanvgdjX.jpg', 310000000, '2026-02-14 17:42:20.651861', 'Dieciséis años después de la muerte de Marco Aurelio, Roma está gobernada por los despiadados emperadores gemelos Geta y Caracalla. El nieto de Aurelio, Lucio Vero, vive bajo el seudónimo de Hanno con su esposa Arishat en el reino norteafricano de Numidia. El ejército romano dirigido por el general Acacio invade y conquista el reino, esclavizando a Lucio junto con otros supervivientes. Los esclavos son llevados a Ostia, donde Lucio es comprado por el maestro de cuadra Macrinus, que le promete la oportunidad de vengarse matando a Acacio si gana suficientes combates para llegar al Coliseo.', 148, NULL, 'US', 'en', 20.819, 'https://image.tmdb.org/t/p/w500/fbcs5AxrdXwyj1b8bGGMgC9kXrM.jpg', '2024-11-13', 462180717, 'gladiator-ii-2024', 'RELEASED', 'Gladiator II', 558449, 'https://www.youtube.com/watch?v=I6ConidIXz0', '2026-02-14 17:42:20.651861', 4176, 292),
	(380, '12', 6.85, 'https://image.tmdb.org/t/p/w780/7lmBufEG7P7Y1HClYK3gCxYrkgS.jpg', 200000000, '2026-02-14 17:42:22.183953', 'El mundo sabe que el multimillonario Tony Stark es Iron Man, el superhéroe enmascarado. Sometido a presiones por parte del gobierno, la prensa y la opinión pública para que comparta su tecnología con el ejército, Tony es reacio a desvelar los secretos de la armadura de Iron Man porque teme que esa información pueda caer en manos indeseables.', 125, NULL, 'US', 'en', 20.729, 'https://image.tmdb.org/t/p/w500/ayyJVOV5I4MGjti7nIHC3mVCagR.jpg', '2010-04-28', 623933331, 'iron-man-2-2010', 'RELEASED', 'Iron Man 2', 10138, 'https://www.youtube.com/watch?v=HlOQqg8qy70', '2026-02-14 17:42:22.183953', 22060, 328),
	(381, NULL, 0, 'https://image.tmdb.org/t/p/w780/lnoP7r3PmAy1sYzaRjbbt6OHXKY.jpg', 155000000, '2026-02-14 18:07:59.001745', 'El viaje de Michael Jackson más allá de la música, desde el descubrimiento de su extraordinario talento como líder de los Jackson Five hasta convertirse en una visionaria estrella cuya ambición creativa despertó un incansable afán por consagrarse como el mayor icono de la industria del entretenimiento.', 0, NULL, 'GB', 'en', 7.1095, 'https://image.tmdb.org/t/p/w500/mB3zisIw3bsQcoDSnvMPAQhjrTM.jpg', '2026-04-22', 0, 'michael-2026', 'POST_PRODUCTION', 'Michael', 936075, 'https://www.youtube.com/watch?v=o1HQSh6zZ8s', '2026-02-14 18:07:59.001745', 0, 319),
	(382, NULL, 0, 'https://image.tmdb.org/t/p/w780/tAeiebNAyYC23FjUEkgyUm9SnEo.jpg', 68000000, '2026-02-14 18:16:06.958693', 'Los campeones favoritos de los fans, ahora acompañados por el propio Johnny Cage, se enfrentan cara a cara en la definitiva y sangrienta batalla a muerte para vencer al oscuro régimen de Shao Kahn, que amenaza la existencia del Reino de la Tierra y a sus defensores.', 116, NULL, 'US', 'en', 5.1456, 'https://image.tmdb.org/t/p/w500/dxUg4OCHJJdQURZdLiMcTv7OZfn.jpg', '2026-05-06', 0, 'mortal-kombat-ii-2026', 'POST_PRODUCTION', 'Mortal Kombat II', 931285, 'https://www.youtube.com/watch?v=nUfwLpIiWCU', '2026-02-14 18:16:06.958693', 0, 329),
	(383, NULL, 0, 'https://image.tmdb.org/t/p/w780/yt0sZFDhB3ROrusxKT4Ogus4cEl.jpg', 200000000, '2026-02-14 18:18:40.448755', 'En las regiones más lejanas del espacio, el reino de Eternia está amenazado por el villano Skeletor y sus traviesos ejércitos de oscuridad. Para salvar el reino de su padre y proteger las vidas de sus seres queridos, el joven príncipe Adam tiene que recuperar una espada mítica y convertirse en el legendario guerrero conocido como "He-Man".', 0, NULL, 'US', 'en', 8.6763, 'https://image.tmdb.org/t/p/w500/nm2ianYVp7OXElUZVeeAbNTqBLr.jpg', '2026-06-03', 0, 'amos-del-universo-2026', 'POST_PRODUCTION', 'Amos del Universo', 454639, 'https://www.youtube.com/watch?v=ZmEx7wQI6RY', '2026-02-14 18:18:40.448755', 0, 330),
	(384, NULL, 0, 'https://image.tmdb.org/t/p/w780/28PGUwfIkAByymJOb6KkJt5SgYw.jpg', 0, '2026-02-14 18:19:28.213942', 'Tomando como referencia la reciente miniserie escrita por Tom King, esta película promete una visión diferente de lo que la mayoría piensa cuando le viene a la mente la prima de Superman. "Veremos la diferencia entre Superman, que fue enviado a la Tierra y criado por unos padres cariñosos desde que era un bebé, y Supergirl, criada en una roca, una astilla de Krypton, y que vio morir y ser asesinados de formas terribles a todos los que la rodeaban durante los primeros 14 años de su vida para luego venir a la Tierra. Ella es mucho más dura y no es la Supergirl a la que estamos acostumbrados".', 0, NULL, 'US', 'en', 9.0605, 'https://image.tmdb.org/t/p/w500/j1FSus4RoDJpY8zzfwjaqBktlUk.jpg', '2026-06-24', 0, 'supergirl-2026', 'POST_PRODUCTION', 'Supergirl', 1081003, 'https://www.youtube.com/watch?v=BqmDRWORkbI', '2026-02-14 18:19:28.213942', 0, 331),
	(385, NULL, 5.8, 'https://image.tmdb.org/t/p/w780/w1Z1I9PqTK5UjG6RVAFXLCjp1Sw.jpg', 0, '2026-02-16 16:49:42.220439', 'Después de que un ensayo desastroso paralizara su proyecto, un equipo de científicos caídos en desgracia se adentra en el mundo del crimen para reconstruir un motor prohibido capaz de doblar el espacio/tiempo, que podría salvar a la humanidad o aniquilarla por completo.', 90, NULL, 'AU', 'en', 340.418, 'https://image.tmdb.org/t/p/w500/uje1ecKMnNpZp0at5TxlvVgVXqI.jpg', '2025-05-01', 0, 'space-time-2025', 'RELEASED', 'Space/Time', 434853, 'https://www.youtube.com/watch?v=Bl6Yd-OT4FA', '2026-02-16 16:49:42.220439', 15, 332);
